struct sycl_load_summary_state {
    size_t weight_device_bytes = 0;
    size_t weight_host_bytes   = 0;
    size_t weight_device_count = 0;
    size_t weight_host_count   = 0;
    bool   have_actual_weights = false;
};

static std::mutex                                                 g_sycl_load_summary_mutex;
static std::array<sycl_load_summary_state, GGML_SYCL_MAX_DEVICES> g_sycl_load_summary{};

static bool ggml_sycl_layout_summary_enabled() {
    static std::atomic<int> cached{ -1 };
    int                     value = cached.load(std::memory_order_acquire);
    if (value == -1) {
        const char * env = std::getenv("GGML_SYCL_LAYOUT_SUMMARY");
        value            = (env && *env && std::atoi(env) != 0) ? 1 : 0;
        cached.store(value, std::memory_order_release);
    }
    return value == 1;
}

static void ggml_sycl_reset_load_summary() {
    std::lock_guard<std::mutex> lock(g_sycl_load_summary_mutex);
    for (auto & state : g_sycl_load_summary) {
        state = sycl_load_summary_state{};
    }
}

static void ggml_sycl_record_weight_load_summary(int    device,
                                                 size_t weight_device_bytes,
                                                 size_t weight_host_bytes,
                                                 size_t weight_device_count,
                                                 size_t weight_host_count) {
    if (device < 0 || device >= GGML_SYCL_MAX_DEVICES) {
        return;
    }

    std::lock_guard<std::mutex> lock(g_sycl_load_summary_mutex);
    auto &                      state = g_sycl_load_summary[device];
    state.weight_device_bytes         = weight_device_bytes;
    state.weight_host_bytes           = weight_host_bytes;
    state.weight_device_count         = weight_device_count;
    state.weight_host_count           = weight_host_count;
    state.have_actual_weights         = true;
}

static void ggml_sycl_log_load_summary(int          device,
                                       size_t       kv_device_bytes,
                                       size_t       kv_host_bytes,
                                       uint32_t     kv_device_layers,
                                       uint32_t     kv_host_layers,
                                       const char * kv_basis) {
    if (device < 0 || device >= GGML_SYCL_MAX_DEVICES) {
        return;
    }

    size_t weight_device_bytes = 0;
    size_t weight_host_bytes   = 0;
    size_t weight_device_count = 0;
    size_t weight_host_count   = 0;
    bool   actual_weights      = false;

    {
        std::lock_guard<std::mutex> lock(g_sycl_load_summary_mutex);
        const auto &                state = g_sycl_load_summary[device];
        weight_device_bytes               = state.weight_device_bytes;
        weight_host_bytes                 = state.weight_host_bytes;
        weight_device_count               = state.weight_device_count;
        weight_host_count                 = state.weight_host_count;
        actual_weights                    = state.have_actual_weights;
    }

    auto * cache = ggml_sycl::get_unified_cache_for_device(device);
    if (!actual_weights && cache && cache->has_placement_plan()) {
        const auto & plan   = cache->get_placement_plan();
        weight_device_bytes = plan.weight_vram_bytes;
        weight_host_bytes   = plan.weight_host_bytes;
    }

    const char * weight_basis   = actual_weights ? "actual" : "planned";
    const char * onednn_source  = cache ? cache->onednn_scratch_source_name() : "unavailable";
    const size_t weight_total   = weight_device_bytes + weight_host_bytes;
    const size_t kv_total       = kv_device_bytes + kv_host_bytes;
    const size_t onednn_weights = cache ? cache->onednn_weights_scratch_size() : 0;
    const size_t onednn_acts    = cache ? cache->onednn_activations_scratch_size() : 0;

    char summary[512];
    snprintf(
        summary, sizeof(summary),
        "[LOAD-SUMMARY] Device %d: weights=%s %.1f MB device / %.1f MB host (%zu device / %zu host, %.1f MB total), "
        "kv=%s %.1f MB device / %.1f MB host (%u device layers / %u host layers, %.1f MB total), "
        "oneDNN scratch=%s (weights=%.1f MB, activations=%.1f MB)\n",
        device, weight_basis, weight_device_bytes / (1024.0 * 1024.0), weight_host_bytes / (1024.0 * 1024.0),
        weight_device_count, weight_host_count, weight_total / (1024.0 * 1024.0), kv_basis,
        kv_device_bytes / (1024.0 * 1024.0), kv_host_bytes / (1024.0 * 1024.0), kv_device_layers, kv_host_layers,
        kv_total / (1024.0 * 1024.0), onednn_source, onednn_weights / (1024.0 * 1024.0),
        onednn_acts / (1024.0 * 1024.0));

    GGML_LOG_INFO("%s", summary);
    if (ggml_sycl_layout_summary_enabled()) {
        fputs(summary, stderr);
    }
}

// Returns true when the unified cache should manage weight placement.
// The cache is always active when initialized — it handles VRAM placement for all model sizes.
static bool unified_cache_active() {
    return ggml_sycl::unified_cache_enabled();
}

// Model-exceeds-VRAM is computed on-the-fly from model size vs VRAM budget.
// No global flag needed — the unified cache manages budget internally.

// ============================================================================
// FP16 Weight Cache: Persistent pre-dequantized FP16 weights in VRAM
//
// When GGML_SYCL_FP16_CACHE=1, the first PP pass dequantizes quantized weights
// to FP16 and stores the result in a persistent VRAM buffer. Subsequent PP
// passes skip the dequantization kernel entirely, reading cached FP16 directly.
//
// GGML_SYCL_FP16_CACHE_MB=N sets the VRAM limit (default 512MB).
// Only device-resident weights are eligible (no VRAM expansion for host weights).
// ============================================================================
struct fp16_cache_entry {
    sycl::half * ptr = nullptr;
};

struct fp16_weight_cache {
    std::unordered_map<uint64_t, fp16_cache_entry> entries;
    std::mutex                                     mtx;
    size_t                                         total_bytes = 0;
    size_t                                         limit_bytes = 0;
    bool                                           enabled     = false;

    // Slab allocator: single large VRAM block, sub-allocated linearly
    char *                  slab_ptr       = nullptr;
    size_t                  slab_size      = 0;
    size_t                  slab_offset    = 0;
    bool                    slab_ready     = false;
    int                     slab_device_id = -1;
    // Use .as_mem_handle() for read/resolve access; unified_free(alloc_handle) for ownership
    ggml_sycl::alloc_handle slab_alloc;

    std::once_flag init_flag_;

    void init_once() {
        std::call_once(init_flag_, [this]() {
            const char * env     = std::getenv("GGML_SYCL_FP16_CACHE");
            enabled              = (env != nullptr && std::atoi(env) != 0);
            const char * lim_env = std::getenv("GGML_SYCL_FP16_CACHE_MB");
            size_t       lim_mb  = lim_env ? static_cast<size_t>(std::atoi(lim_env)) : 512;
            if (lim_mb < 1) {
                lim_mb = 512;
            }
            limit_bytes = lim_mb * 1024 * 1024;
            if (enabled) {
                GGML_LOG_INFO("[SYCL] FP16 weight cache enabled (limit=%zuMB)\n", lim_mb);
            }
        });
    }

    // Lazily allocate the VRAM slab on first store attempt.
    // Called under lock.
    bool ensure_slab(sycl::queue & queue) {
        if (slab_ready) {
            return slab_ptr != nullptr;
        }
        slab_ready = true;
        ggml_sycl::alloc_request req{};
        req.queue                          = &queue;
        req.device                         = ggml_sycl_get_device_id_from_queue(queue);
        req.size                           = limit_bytes;
        req.intent.role                    = ggml_sycl::alloc_role::WEIGHT;
        req.intent.category                = ggml_sycl::runtime_category::OTHER;
        req.intent.constraints.must_device = true;
        if (ggml_sycl::unified_alloc(req, &slab_alloc)) {
            slab_ptr = static_cast<char *>(slab_alloc.ptr);
        } else {
            slab_alloc = {};
            slab_ptr   = nullptr;
        }
        if (slab_ptr) {
            slab_device_id = ggml_sycl_get_device_id_from_queue(queue);
            slab_size      = limit_bytes;
            GGML_LOG_INFO("[SYCL] FP16 weight cache: allocated %.1fMB VRAM slab\n", limit_bytes / (1024.0f * 1024.0f));
        } else {
            GGML_LOG_WARN("[SYCL] FP16 weight cache: failed to allocate %.1fMB slab\n",
                          limit_bytes / (1024.0f * 1024.0f));
        }
        return slab_ptr != nullptr;
    }

    // Returns cached FP16 pointer or nullptr if not cached
    sycl::half * lookup(uint64_t name_hash) {
        std::lock_guard<std::mutex> lock(mtx);
        auto                        it = entries.find(name_hash);
        if (it != entries.end()) {
            return it->second.ptr;
        }
        return nullptr;
    }

    // Store a new FP16 weight in VRAM (sub-allocated from slab).
    // The copy is submitted on the in-order queue without .wait() -- it
    // completes before any subsequent kernel on the same queue touches the
    // scratch buffer that holds `src`.
    bool store(uint64_t name_hash, const sycl::half * src, size_t bytes, sycl::queue & queue) {
        std::lock_guard<std::mutex> lock(mtx);
        if (!ensure_slab(queue)) {
            return false;
        }
        // Align to 256 bytes for GPU cache line alignment
        const size_t aligned_bytes = (bytes + 255) & ~size_t(255);
        if (slab_offset + aligned_bytes > slab_size) {
            return false;  // Slab exhausted
        }
        sycl::half * buf = reinterpret_cast<sycl::half *>(slab_ptr + slab_offset);
        // Async copy on in-order queue: completes before next kernel reads scratch
        ggml_sycl_trace_memcpy_during_recording("ggml-sycl.cpp:scratch_pool_fill", bytes);
        ggml_sycl_graph_safe_memcpy(queue, buf, src, bytes);
        entries[name_hash] = { buf };
        slab_offset += aligned_bytes;
        total_bytes += bytes;
        return true;
    }

    void clear(sycl::queue & queue) {
        std::lock_guard<std::mutex> lock(mtx);
        if (slab_ptr) {
            queue.wait();  // Drain any pending copies
            ggml_sycl::unified_free(slab_alloc);
            slab_alloc     = {};
            slab_ptr       = nullptr;
            slab_size      = 0;
            slab_device_id = -1;
        }
        entries.clear();
        slab_offset = 0;
        total_bytes = 0;
        slab_ready  = false;
    }

    bool has_entries() {
        std::lock_guard<std::mutex> lock(mtx);
        return !entries.empty();
    }
};

static fp16_weight_cache g_fp16_cache;

// ============================================================================
// PP split timing: GGML_SYCL_PP_SPLIT_TIMING=1 → per-op split of dequant vs
// activations-cast vs oneDNN GEMM wall time on the oneDNN FP16 PP path.
// Diagnostic only — queue-sync'd timing destroys any parallelism; read the
// ratios, not the absolute numbers.
// ============================================================================
static bool pp_split_timing_enabled() {
    static const bool enabled = []() {
        const char * env = std::getenv("GGML_SYCL_PP_SPLIT_TIMING");
        return env && std::atoi(env) != 0;
    }();
    return enabled;
}

struct pp_split_timing {
    uint64_t n_ops         = 0;
    double   us_dequant_w  = 0;  // weight dequant (Q4_0 → FP16)
    double   us_cache_hit  = 0;  // FP16 cache hit ops (dequant skipped)
    double   us_dequant_a  = 0;  // activation cast (FP32 → FP16)
    double   us_gemm       = 0;  // oneDNN FP16 GEMM
    uint64_t n_cache_hits  = 0;
    uint64_t n_cache_miss  = 0;
};

static thread_local pp_split_timing g_pp_split_timing;

static void pp_split_timing_dump_if_due(int period = 500) {
    if (!pp_split_timing_enabled()) {
        return;
    }
    auto & t = g_pp_split_timing;
    if (t.n_ops == 0 || (t.n_ops % period) != 0) {
        return;
    }
    const double total = t.us_dequant_w + t.us_cache_hit + t.us_dequant_a + t.us_gemm;
    fprintf(stderr,
            "[PP-SPLIT] n=%llu (hits=%llu miss=%llu) total=%.1f ms  weight_dequant=%.1f ms (%.1f%%)  "
            "cache_hit_dequant=%.1f ms (%.1f%%)  act_cast=%.1f ms (%.1f%%)  gemm=%.1f ms (%.1f%%)\n",
            (unsigned long long) t.n_ops, (unsigned long long) t.n_cache_hits, (unsigned long long) t.n_cache_miss,
            total / 1000.0, t.us_dequant_w / 1000.0, 100.0 * t.us_dequant_w / total, t.us_cache_hit / 1000.0,
            100.0 * t.us_cache_hit / total, t.us_dequant_a / 1000.0, 100.0 * t.us_dequant_a / total, t.us_gemm / 1000.0,
            100.0 * t.us_gemm / total);
}

// ============================================================================
// PP Pipeline: Double-buffered PCIe pipelining for oneDNN FP16 weight prefetch
// ============================================================================
// By default, overlaps the dequant (PCIe read + FP16 convert)
// of the next weight matrix with the GEMM of the current weight matrix.
// Two scratch buffers alternate: while GEMM runs on buffer A, dequant for the
// next MUL_MAT fills buffer B on a separate in-order DMA queue.
// Set GGML_SYCL_PP_PIPELINE=0 to disable this overlap path.
//
// Pre-scan: at graph_compute start, build a schedule of oneDNN-PP-eligible
// MUL_MAT nodes. During execution, the pipeline uses this schedule for
// look-ahead prefetch.
// ============================================================================

struct pp_pipeline_entry {
    const void *   src0_data    = nullptr;  // Host-pinned weight pointer
    to_fp16_sycl_t dequant_fn   = nullptr;  // Dequant function for this weight type
    int64_t        n_elems      = 0;        // N * K elements to dequant
    size_t         weight_bytes = 0;        // n_elems * sizeof(half)
    layout_mode    layout       = GGML_LAYOUT_AOS;
    // oneDNN-GEMM expects row-major FP16. For COALESCED Q4_0, the generic
    // to_fp16 dispatch emits tile-interleaved output — wrong layout for GEMM.
    // When these dims are set, use dequantize_row_q4_0_coalesced_to_fp16_rowmajor
    // instead to match the consumption-site selection in the oneDNN PP branch.
    bool           use_coalesced_rowmajor = false;
    int            blocks_per_row         = 0;  // K / QK4_0
    int            nrows                  = 0;  // N
};

struct pp_pipeline_state {
    bool                           enabled = false;
    std::unique_ptr<sycl::queue>   dma_queue;  // In-order queue for async dequant (same context/device as ctx.stream())
    void *                         scratch_buf[2]   = { nullptr, nullptr };  // Double-buffered weights
    ggml_sycl::alloc_handle        scratch_alloc[2] = {};                    // Owning handles (mubmt.12)
    size_t                         scratch_size[2]  = { 0, 0 };
    int                            prefetch_buf     = -1;       // Buffer index with prefetched data (-1 = none)
    const void *                   prefetch_src0    = nullptr;  // src0_data that was prefetched
    int64_t                        prefetch_elems   = 0;        // Elements that were prefetched
    std::vector<pp_pipeline_entry> schedule;                    // Pre-scanned MUL_MAT schedule
    int                            schedule_idx = 0;            // Current position in schedule
    int                            device_id    = -1;

    ~pp_pipeline_state() {
        if (dma_queue) {
            dma_queue->wait();
            for (int b = 0; b < 2; b++) {
                if (scratch_alloc[b].ptr != nullptr) {
                    ggml_sycl::unified_free(scratch_alloc[b]);
                    scratch_alloc[b] = {};
                } else if (scratch_buf[b]) {
                    // Legacy fallback for pre-migration buffers — dead code after migration
                    GGML_ASSERT(false &&
                                "pipeline scratch_buf: legacy sycl::free path — scratch_alloc should always be set");
                }
                scratch_buf[b]  = nullptr;
                scratch_size[b] = 0;
            }
        }
    }

    void reset_graph() {
        schedule.clear();
        schedule_idx   = 0;
        prefetch_buf   = -1;
        prefetch_src0  = nullptr;
        prefetch_elems = 0;
    }
};

static bool pp_pipeline_env_enabled() {
    // Default OFF: pipeline is correct but provides no measured throughput
    // gain on Arc B580 — the dequant and GEMM compete for the same compute
    // engine, so the theoretical dequant-vs-GEMM overlap doesn't materialize.
    // Earlier "+19.6% PP" result was fake: the pre-scan picked the generic
    // to_fp16 dispatch for COALESCED Q4_0 (tile-interleaved output) while the
    // GEMM consumer expects row-major FP16. The wrong-layout dequant kernel
    // is cheaper, so throughput went up while output became garbage. That
    // selection is now synchronized with the consumption site, so output is
    // correct — but no free lunch. Left opt-in for future overlap research.
    static int val = -1;
    if (val < 0) {
        const char * env = std::getenv("GGML_SYCL_PP_PIPELINE");
        val              = (env && std::atoi(env) != 0) ? 1 : 0;
        if (val) {
            GGML_LOG_INFO("[SYCL] PP pipeline: double-buffered dequant prefetch ENABLED (opt-in)\n");
        }
    }
    return val != 0;
}

static thread_local pp_pipeline_state g_pp_pipeline;

// Submit async dequant for the next scheduled entry on the DMA queue.
// Writes dequantized FP16 weights into scratch_buf[buf_idx].
// Returns true if prefetch was submitted.
static bool pp_pipeline_submit_prefetch(pp_pipeline_state & pipe, int buf_idx) {
    if (pipe.schedule_idx >= (int) pipe.schedule.size()) {
        return false;  // No more entries to prefetch
    }
    const auto & entry = pipe.schedule[pipe.schedule_idx];
    if (!entry.src0_data || !entry.dequant_fn || entry.n_elems == 0) {
        return false;
    }
    // Ensure scratch buffer is large enough
    if (entry.weight_bytes > pipe.scratch_size[buf_idx]) {
        return false;
    }
    // Submit dequant kernel on the in-order DMA queue. For COALESCED Q4_0,
    // the oneDNN GEMM path requires row-major FP16 (not the tile-interleaved
    // default from the generic to_fp16 dispatch). This selection must mirror
    // the consumption-site logic in the oneDNN PP branch exactly, or the
    // GEMM reads data in the wrong layout and produces garbage.
    sycl::half * dst = static_cast<sycl::half *>(pipe.scratch_buf[buf_idx]);
    if (entry.use_coalesced_rowmajor) {
        dequantize_row_q4_0_coalesced_to_fp16_rowmajor(entry.src0_data, dst, entry.blocks_per_row, entry.nrows,
                                                       pipe.dma_queue.get());
    } else {
        entry.dequant_fn(entry.src0_data, dst, entry.n_elems, pipe.dma_queue.get());
    }
    pipe.prefetch_buf   = buf_idx;
    pipe.prefetch_src0  = entry.src0_data;
    pipe.prefetch_elems = entry.n_elems;
    return true;
}

int ggml_sycl_graph_inflight_count() {
    return g_sycl_graph_inflight.load(std::memory_order_acquire);
}

static bool ggml_sycl_parse_device_id_token(const std::string & token, int & out_id) {
    if (token.empty()) {
        return false;
    }
    std::string_view view(token);
    const size_t     colon = view.rfind(':');
    if (colon != std::string_view::npos && colon + 1 < view.size()) {
        view = view.substr(colon + 1);
    }
    char *     end = nullptr;
    const long val = std::strtol(std::string(view).c_str(), &end, 10);
    if (!end || *end != '\0') {
        return false;
    }
    out_id = static_cast<int>(val);
    return true;
}

static std::vector<int> ggml_sycl_parse_device_list_env(const char * env) {
    std::vector<int> ids;
    if (!env || !*env) {
        return ids;
    }
    std::string token;
    for (const char c : std::string(env)) {
        if (c == ',' || c == '/' || std::isspace(static_cast<unsigned char>(c))) {
            if (!token.empty()) {
                int id = -1;
                if (ggml_sycl_parse_device_id_token(token, id)) {
                    ids.push_back(id);
                }
                token.clear();
            }
            continue;
        }
        token.push_back(c);
    }
    if (!token.empty()) {
        int id = -1;
        if (ggml_sycl_parse_device_id_token(token, id)) {
            ids.push_back(id);
        }
    }
    return ids;
}

