// B50 local aggregation: when multiple experts for the same token land on a
// secondary GPU, compute the weighted sum on that GPU and transfer only the
// aggregate result (~1×N floats) instead of per-expert results (~K×N floats).
// Requires gating weights from g_moe_weights_by_layer pre-scan.
// Opt-out: GGML_SYCL_B50_LOCAL_AGG=0
static bool ggml_sycl_b50_local_agg_enabled() {
    static std::atomic<int> cached{ -1 };
    int                     v = cached.load(std::memory_order_acquire);
    if (v < 0) {
        const char * env     = getenv("GGML_SYCL_B50_LOCAL_AGG");
        int          new_val = env ? std::atoi(env) : 1;  // Default: enabled
        cached.compare_exchange_strong(v, new_val, std::memory_order_release, std::memory_order_acquire);
        v = cached.load(std::memory_order_acquire);
    }
    return v != 0;
}

// -----------------------------------------------------------------------
// Popularity-aware expert placement: warmup profiling + re-placement.
// During the first WARMUP_TOKENS tokens, count activations per expert per
// layer.  After warmup, sort experts by frequency and update the placement
// table with popularity ranks.  Hot experts are placed on B580 (GPU0),
// warm on B50 (GPU1), cold remain on CPU.
// -----------------------------------------------------------------------
static constexpr int MOE_MAX_LAYERS  = 128;
static constexpr int MOE_MAX_EXPERTS = 256;

struct moe_warmup_state {
    std::atomic<uint32_t> counts[MOE_MAX_LAYERS][MOE_MAX_EXPERTS] = {};
    std::atomic<int>      token_count{ 0 };
    std::atomic<bool>     warmup_done{ false };
    int                   warmup_tokens = 8;  // configurable via env
    int                   n_layers      = 0;
    int                   n_experts     = 0;

    // Periodic re-ranking state (active after initial warmup completes)
    std::atomic<uint32_t> epoch_counts[MOE_MAX_LAYERS][MOE_MAX_EXPERTS] = {};
    std::atomic<int>      epoch_token_count{ 0 };
    std::atomic<bool>     reranking_enabled{ false };
    int                   rerank_interval = 100;  // tokens between re-ranks

    void init(int nl, int ne) {
        n_layers  = std::min(nl, MOE_MAX_LAYERS);
        n_experts = std::min(ne, MOE_MAX_EXPERTS);
        // Unified cache path: default to gate norms instead of inference-based profiling.
        // Gate norms take ~100-200ms vs 5-10s for synthetic inference, with comparable
        // cache hit rates. Skip inference profiling when unified cache manages placement.
        if (ggml_sycl::unified_cache_enabled()) {
            warmup_tokens = 0;  // Use gate norms, skip inference profiling
        }
        // Read env var for warmup token count (0 = skip warmup, use gate norms).
        // Placed AFTER the S1 default so the user can still override.
        const char * env = getenv("GGML_SYCL_MOE_WARMUP_TOKENS");
        if (env) {
            warmup_tokens = std::max(0, std::atoi(env));
        }
        // Read env var for re-rank interval (0 disables periodic re-ranking)
        const char * rerank_env = getenv("GGML_SYCL_MOE_RERANK_INTERVAL");
        if (rerank_env) {
            rerank_interval = std::max(0, std::atoi(rerank_env));
        }
        if (warmup_tokens == 0) {
            GGML_LOG_INFO(
                "[MOE-WARMUP] Zero-warmup mode: %d layers x %d experts, "
                "using gate weight norms for initial placement\n",
                n_layers, n_experts);
        } else {
            GGML_LOG_INFO(
                "[MOE-WARMUP] Profiling %d layers x %d experts for %d tokens, "
                "re-rank every %d tokens\n",
                n_layers, n_experts, warmup_tokens, rerank_interval);
        }
    }

    void record(int layer_id, const int32_t * expert_ids, int n_selected) {
        if (layer_id < 0 || layer_id >= n_layers) {
            return;
        }
        // Always record into epoch counters (for periodic re-ranking)
        if (reranking_enabled.load(std::memory_order_acquire)) {
            for (int i = 0; i < n_selected; i++) {
                int eid = expert_ids[i];
                if (eid >= 0 && eid < n_experts) {
                    epoch_counts[layer_id][eid].fetch_add(1, std::memory_order_relaxed);
                }
            }
            return;  // Warmup counters frozen after initial warmup
        }
        // During initial warmup: record into warmup counters
        if (warmup_done.load(std::memory_order_acquire)) {
            return;
        }
        for (int i = 0; i < n_selected; i++) {
            int eid = expert_ids[i];
            if (eid >= 0 && eid < n_experts) {
                counts[layer_id][eid].fetch_add(1, std::memory_order_relaxed);
            }
        }
    }

    // Called once per token.  Returns true on the token that ends warmup.
    bool tick_token() {
        if (warmup_done.load(std::memory_order_acquire)) {
            return false;
        }
        int t = token_count.fetch_add(1, std::memory_order_relaxed) + 1;
        if (t >= warmup_tokens) {
            warmup_done.store(true, std::memory_order_release);
            return true;
        }
        return false;
    }

    // Called once per token after warmup.  Returns true when a re-rank epoch completes.
    // Uses aggressive initial re-ranking: first 5 epochs use interval/10 (min 10)
    // to fill VRAM cache 10x faster during warmup, then settles to normal interval.
    std::atomic<int> epoch_number{ 0 };

    bool tick_epoch() {
        if (!reranking_enabled.load(std::memory_order_acquire)) {
            return false;
        }
        if (rerank_interval <= 0) {
            return false;
        }
        int t = epoch_token_count.fetch_add(1, std::memory_order_relaxed) + 1;

        int effective_interval = rerank_interval;
        if (epoch_number.load(std::memory_order_relaxed) < 5) {
            effective_interval = std::max(10, rerank_interval / 10);
        }

        if (t >= effective_interval) {
            epoch_token_count.store(0, std::memory_order_relaxed);
            epoch_number.fetch_add(1, std::memory_order_relaxed);
            return true;
        }
        return false;
    }

    // Enable periodic re-ranking (called after initial warmup + prestage completes)
    void enable_reranking() {
        if (rerank_interval <= 0) {
            return;
        }
        // Zero out epoch counters for fresh accumulation
        for (int l = 0; l < n_layers; l++) {
            for (int e = 0; e < n_experts; e++) {
                epoch_counts[l][e].store(0, std::memory_order_relaxed);
            }
        }
        epoch_token_count.store(0, std::memory_order_relaxed);
        reranking_enabled.store(true, std::memory_order_release);
    }
};

static moe_warmup_state g_moe_warmup;

// Apply warmup results: sort experts by popularity and update popularity ranks.
// Called once after warmup completes.
static void moe_apply_popularity_placement() {
    const int nl = g_moe_warmup.n_layers;
    const int ne = g_moe_warmup.n_experts;
    if (nl <= 0 || ne <= 0) {
        return;
    }

    // Build reverse map: sequential layer index -> hash-based layer_id.
    // g_moe_layer_seq[device] maps hash -> sequential; we invert it.
    // Use device 0 as the canonical source (all devices share the same mapping).
    std::unordered_map<int, int> seq_to_hash;
    for (const auto & [hash_id, seq_id] : g_moe_layer_seq[0]) {
        seq_to_hash[seq_id] = hash_id;
    }

    int total_placed = 0;
    for (int l = 0; l < nl; l++) {
        // Map sequential index back to hash-based layer_id for popularity ranking
        auto it = seq_to_hash.find(l);
        if (it == seq_to_hash.end()) {
            continue;
        }
        int hash_layer_id = it->second;

        // Collect (count, expert_id) pairs and sort descending by count
        std::vector<std::pair<uint32_t, int>> sorted_experts;
        sorted_experts.reserve(ne);
        for (int e = 0; e < ne; e++) {
            uint32_t c = g_moe_warmup.counts[l][e].load(std::memory_order_relaxed);
            sorted_experts.push_back({ c, e });
        }
        std::sort(sorted_experts.begin(), sorted_experts.end(),
                  [](const auto & a, const auto & b) { return a.first > b.first; });

        // Assign popularity ranks using hash-based layer_id
        for (int rank = 0; rank < (int) sorted_experts.size(); rank++) {
            int eid = sorted_experts[rank].second;
            ggml_sycl::set_expert_popularity_rank(hash_layer_id, eid, rank);
        }
        total_placed += (int) sorted_experts.size();
    }

    GGML_LOG_INFO("[MOE-WARMUP] Popularity profiling complete: %d layers, %d total experts ranked\n", nl, total_placed);

    // Log top-3 most popular experts per layer (first 4 layers)
    for (int l = 0; l < std::min(nl, 4); l++) {
        std::vector<std::pair<uint32_t, int>> layer_counts;
        for (int e = 0; e < ne; e++) {
            uint32_t c = g_moe_warmup.counts[l][e].load(std::memory_order_relaxed);
            if (c > 0) {
                layer_counts.push_back({ c, e });
            }
        }
        std::sort(layer_counts.begin(), layer_counts.end(),
                  [](const auto & a, const auto & b) { return a.first > b.first; });
        if (layer_counts.size() >= 3) {
            GGML_LOG_INFO("[MOE-WARMUP] Layer %d top-3: expert %d (%u), expert %d (%u), expert %d (%u)\n", l,
                          layer_counts[0].second, layer_counts[0].first, layer_counts[1].second, layer_counts[1].first,
                          layer_counts[2].second, layer_counts[2].first);
        }
    }

    // Signal that popularity data is now available.
    // The next update_moe_ptr_table call for each layer will use
    // direct_stage_expert to pre-stage popular experts that weren't
    // already GPU-resident. The eviction scoring in unified-cache.cpp
    // also uses popularity_rank to retain hot experts in cache.
    GGML_LOG_INFO(
        "[MOE-WARMUP] Popularity ranks applied. Cache eviction "
        "now favors popular experts; pre-staging on next dispatch.\n");
}

// Forward declaration: zero-warmup gate-norm placement (defined before moe_hybrid_init_once).
static void moe_compute_gate_norm_placement(ggml_cgraph * cgraph, int device);

// ---------------------------------------------------------------------------
// MoE expert tensor type classification.
// In MoE FFN: hidden -> gate*up -> SiLU -> down -> output
// gate+up are read first (enables SiLU overlap), down is read second.
// ---------------------------------------------------------------------------
enum moe_tensor_type : int {
    MOE_TENSOR_GATE    = 0,  // ffn_gate_exps — read first
    MOE_TENSOR_UP      = 1,  // ffn_up_exps   — read first (with gate)
    MOE_TENSOR_DOWN    = 2,  // ffn_down_exps — read second (after SiLU)
    MOE_TENSOR_UNKNOWN = 3,
};

// Classify tensor type from its name (e.g. "blk.5.ffn_gate_exps").
static moe_tensor_type moe_classify_tensor(const char * name) {
    if (!name) {
        return MOE_TENSOR_UNKNOWN;
    }
    if (strstr(name, "ffn_gate_exps")) {
        return MOE_TENSOR_GATE;
    }
    if (strstr(name, "ffn_up_exps")) {
        return MOE_TENSOR_UP;
    }
    if (strstr(name, "ffn_down_exps")) {
        return MOE_TENSOR_DOWN;
    }
    return MOE_TENSOR_UNKNOWN;
}

// Extract block number from tensor name (e.g. "blk.5.ffn_gate_exps" -> 5).
// Returns -1 if not found.  Used to group gate/up/down tensors from the same block.
static int moe_extract_block_number(const char * name) {
    if (!name) {
        return -1;
    }
    const char * blk = strstr(name, "blk.");
    if (!blk) {
        return -1;
    }
    return atoi(blk + 4);
}

// ---------------------------------------------------------------------------
// Per-expert metadata for proactive pre-staging after warmup.
// Populated once during moe_hybrid_init_once(), keyed by (hash_layer_id, expert_idx).
// ---------------------------------------------------------------------------
struct moe_expert_meta {
    const ggml_tensor *     tensor;       // src0 tensor for cache key generation
    ggml_tensor_extra_gpu * extra;        // tensor extra for cache UUID
    ggml_type               type;         // weight quantization type
    int64_t                 ne0;          // columns (K)
    int64_t                 ne1;          // rows (N)
    const void *            data_ptr;     // host-accessible weight data
    size_t                  bytes;        // per-expert weight bytes
    int                     layer_id;     // hash-based layer_id
    int                     expert_idx;   // expert index within layer
    moe_tensor_type         tensor_role;  // gate/up/down classification
    int                     block_num;    // transformer block number (-1 if unknown)
};

static std::vector<moe_expert_meta> g_moe_expert_meta;
static std::shared_mutex            g_moe_expert_meta_mutex;

// ---------------------------------------------------------------------------
// Expert group registry: maps (block_id, expert_id) -> cache keys for all 3
// tensors (gate, up, down).  Built during moe_hybrid_init_once() and used by
// is_expert_resident() to check whether an expert is fully cached in VRAM.
//
// The struct and key helper are defined in unified-cache.hpp so that both
// ggml-sycl.cpp and unified-cache.cpp can use them for atomic staging/eviction.
// ---------------------------------------------------------------------------
using ggml_sycl::expert_group_key;
using ggml_sycl::expert_tensor_group;

static std::unordered_map<int64_t, expert_tensor_group> g_expert_groups;
static std::shared_mutex                                g_expert_groups_mutex;

// ---------------------------------------------------------------------------
// Lightweight popularity ranking: maps (layer_id, expert_id) -> popularity rank.
// Replaces ExpertPlacementTable's popularity_rank field.
// Rank 0 = most popular, -1 = unranked.
// Thread-safe via shared_mutex (writes rare, reads frequent on eviction path).
// ---------------------------------------------------------------------------
static std::unordered_map<int64_t, int> g_expert_popularity;
static std::shared_mutex                g_expert_popularity_mutex;
static bool                             g_expert_popularity_initialized = false;

static int64_t make_popularity_key(int layer_id, int expert_id) {
    return (int64_t(layer_id) << 32) | int64_t(uint32_t(expert_id));
}

// llama.cpp-n04bq — compile-gated probe for the "plan vs dispatch" invariant
// audit.  Default OFF.  Enabled with GGML_SYCL_N04BQ_PROBE=1 at runtime.  We
// only log for blk.16 to keep output tractable.  Scope kept tight: no
// control-flow changes, only fprintf.
static bool n04bq_probe_enabled() {
    static std::atomic<int> cached{ -1 };
    int                     v = cached.load(std::memory_order_acquire);
    if (v < 0) {
        const char * env = std::getenv("GGML_SYCL_N04BQ_PROBE");
        v                = (env && std::atoi(env) != 0) ? 1 : 0;
        cached.store(v, std::memory_order_release);
    }
    return v != 0;
}

// Log once per (tag, tensor_name, expert_id) triple to avoid flooding.
__attribute__((format(printf, 4, 5)))
static void n04bq_probe_log(const char * tag, const char * tname, int expert_id,
                            const char * fmt, ...) {
    if (!n04bq_probe_enabled() || !tname) {
        return;
    }
    if (!strstr(tname, "blk.16.")) {
        return;
    }
    struct key_t {
        std::string tag;
        std::string tname;
        int         expert_id;
        bool        operator==(const key_t & o) const {
            return tag == o.tag && tname == o.tname && expert_id == o.expert_id;
        }
    };
    struct key_hash {
        size_t operator()(const key_t & k) const {
            return std::hash<std::string>()(k.tag) ^ std::hash<std::string>()(k.tname) ^
                   std::hash<int>()(k.expert_id);
        }
    };
    static std::mutex                          logged_mtx;
    static std::unordered_set<key_t, key_hash> logged;
    key_t k{ tag ? std::string(tag) : std::string(), std::string(tname), expert_id };
    {
        std::lock_guard<std::mutex> lk(logged_mtx);
        if (!logged.insert(k).second) {
            return;
        }
    }
    va_list ap;
    va_start(ap, fmt);
    fprintf(stderr, "[N04BQ] %s tensor=%s eid=%d ", tag, tname, expert_id);
    vfprintf(stderr, fmt, ap);
    fputc('\n', stderr);
    va_end(ap);
}

namespace ggml_sycl {

int get_expert_popularity_rank(int layer_id, int expert_id) {
    std::shared_lock<std::shared_mutex> lock(g_expert_popularity_mutex);
    auto                                it = g_expert_popularity.find(make_popularity_key(layer_id, expert_id));
    return (it != g_expert_popularity.end()) ? it->second : -1;
}

void set_expert_popularity_rank(int layer_id, int expert_id, int rank) {
    std::unique_lock<std::shared_mutex> lock(g_expert_popularity_mutex);
    g_expert_popularity[make_popularity_key(layer_id, expert_id)] = rank;
    g_expert_popularity_initialized                               = true;
}

bool is_expert_popularity_initialized() {
    std::shared_lock<std::shared_mutex> lock(g_expert_popularity_mutex);
    return g_expert_popularity_initialized;
}

}  // namespace ggml_sycl

// Tracks whether initial expert prestage has completed. Defined here (before
// is_expert_resident) so startup-time cache misses can be suppressed.
static std::atomic<bool> g_prestage_completed{ false };

// Upfront VRAM budget reserved for MoE experts at inventory time (Phase 1).
// Released after prestage completes and actual usage is tracked in cache (Phase 2).
static std::array<size_t, GGML_SYCL_MAX_DEVICES> g_moe_expert_vram_reserve = {};

// Check if an expert's weights are fully resident in VRAM on a given device.
// Checks the unified cache for ALL 3 tensors (gate, up, down) across multiple
// layout modes (SOA, COALESCED, AOS, XMX_TILED).
// Returns true only if all 3 tensors that have been registered are found.
static bool is_expert_resident(int block_id, int expert_id, int device_id) {
    std::shared_lock<std::shared_mutex> lock(g_expert_groups_mutex);
    auto                                it = g_expert_groups.find(expert_group_key(block_id, expert_id));
    if (it == g_expert_groups.end()) {
        return false;
    }

    const auto &               grp   = it->second;
    ggml_sycl::unified_cache * cache = ggml_sycl::get_unified_cache_for_device(device_id);
    if (!cache) {
        return false;
    }

    // Try multiple layouts — prestage may use SOA, COALESCED, XMX_TILED, or AOS
    static const ggml_layout_mode layouts[] = { GGML_LAYOUT_SOA, GGML_LAYOUT_COALESCED, GGML_LAYOUT_XMX_TILED,
                                                GGML_LAYOUT_AOS };

    // Only check device-resident (VRAM) entries.  Host-pinned and mmap entries
    // should not count as "resident on this GPU device" — they live in host memory
    // and would cause page faults if passed directly to GPU kernels.
    auto check_key = [&](const ggml_sycl_cache_id & key, const char * /*role*/) -> bool {
        if (!key.valid) {
            return false;
        }
        for (auto layout : layouts) {
            if (cache->lookup_device_only(key, layout) != nullptr) {
                return true;
            }
        }
        return false;
    };

    // All registered roles must be cached
    if (grp.has_gate && !check_key(grp.gate_key, "gate")) {
        // Suppress during startup: before initial prestage completes, experts
        // aren't cached yet (expected).  Only log after prestage has run.
        if (g_prestage_completed.load(std::memory_order_acquire)) {
            static std::atomic<int> fail_log{ 0 };
            if (fail_log.fetch_add(1, std::memory_order_relaxed) < 3) {
                fprintf(stderr,
                        "[IS-EXPERT-FAIL] blk=%d exp=%d gate MISS model=%llu hash=0x%llx aux=0x%llx "
                        "entries=%zu\n",
                        block_id, expert_id, (unsigned long long) grp.gate_key.model_id,
                        (unsigned long long) grp.gate_key.name_hash, (unsigned long long) grp.gate_key.aux_id,
                        cache->entry_count());
            }
        }
        return false;
    }
    if (grp.has_up && !check_key(grp.up_key, "up")) {
        return false;
    }
    if (grp.has_down && !check_key(grp.down_key, "down")) {
        return false;
    }

    // At least one role must be registered
    return grp.has_gate || grp.has_up || grp.has_down;
}

// Look up the device pointer for a specific expert tensor on a given device.
// Returns nullptr if not cached.  Used for secondary GPU dispatch where the
// actual device_ptr is needed (not just a presence check).
static void * get_expert_device_ptr(int block_id, int expert_id, moe_tensor_type role, int device_id) {
    std::shared_lock<std::shared_mutex> lock(g_expert_groups_mutex);
    auto                                it = g_expert_groups.find(expert_group_key(block_id, expert_id));
    if (it == g_expert_groups.end()) {
        return nullptr;
    }

    const auto &               grp     = it->second;
    const ggml_sycl_cache_id * key_ptr = nullptr;
    switch (role) {
        case MOE_TENSOR_GATE:
            key_ptr = grp.has_gate ? &grp.gate_key : nullptr;
            break;
        case MOE_TENSOR_UP:
            key_ptr = grp.has_up ? &grp.up_key : nullptr;
            break;
        case MOE_TENSOR_DOWN:
            key_ptr = grp.has_down ? &grp.down_key : nullptr;
            break;
        default:
            return nullptr;
    }
    if (!key_ptr || !key_ptr->valid) {
        return nullptr;
    }

    ggml_sycl::unified_cache * cache = ggml_sycl::get_unified_cache_for_device(device_id);
    if (!cache) {
        return nullptr;
    }

    // Only return device-resident (VRAM) pointers.  Host-pinned and mmap entries
    // must NOT be returned here — GPU kernels receive these pointers directly and
    // would page fault on mmap addresses or incur unexpected PCIe zero-copy latency
    // on host-pinned pointers.  Experts without VRAM copies should route to CPU
    // dispatch via the standard fallback path.
    static const ggml_layout_mode layouts[] = { GGML_LAYOUT_SOA, GGML_LAYOUT_COALESCED, GGML_LAYOUT_XMX_TILED,
                                                GGML_LAYOUT_AOS };
    for (auto layout : layouts) {
        void * ptr = cache->lookup_device_only(*key_ptr, layout);
        if (ptr) {
            return ptr;
        }
    }
    return nullptr;
}

// Forward declarations needed by moe_prestage_popular_experts (defined later in file).
static ggml_sycl_cache_id ggml_sycl_get_moe_expert_cache_key(const ggml_tensor *     tensor,
                                                             ggml_tensor_extra_gpu * extra,
                                                             int                     expert_id);

struct ggml_sycl_reorder_fill_ctx {
    ggml_type type;

    int64_t ncols;
    int64_t nrows;

    size_t      nbytes;
    size_t      dst_bytes;
    layout_mode layout;
    bool        src_is_device;
    int         device_id;
};

static sycl::event ggml_sycl_fill_reordered_host(sycl::queue &                    queue,
                                                 void *                           dst,
                                                 size_t                           dst_size,
                                                 const void *                     src,
                                                 size_t                           src_size,
                                                 const void *                     ctx_void,
                                                 const std::vector<sycl::event> & deps);
static size_t      ggml_sycl_layout_bytes_for_dims(ggml_type   type,
                                                   int64_t     ncols,
                                                   int64_t     nrows,
                                                   layout_mode layout,
                                                   int         device_id);
static bool        ggml_sycl_reorder_weight_cpu(void * dst, const void * src, const ggml_sycl_reorder_fill_ctx & ctx);

// Forward declarations for GPU-side AOS -> SOA reorder (defined later in file).
// The struct is fully defined here because prestage code creates instances.
struct ggml_sycl_gpu_reorder_fill_ctx {
    ggml_type             type;
    int64_t               ncols;
    int64_t               nrows;
    size_t                src_bytes;                     // AOS size
    size_t                dst_bytes;                     // SOA size
    std::vector<void *> * temp_bufs;                     // fallback: deferred free list (nullptr when using prealloc)
    sycl::queue *         owner_queue;                   // queue that owns temp_bufs allocations
    void *                prealloc_temp      = nullptr;  // pre-allocated reorder temp buffer (from cache)
    size_t                prealloc_temp_size = 0;        // size of pre-allocated buffer
    sycl::queue *         bcs_queue          = nullptr;  // BCS (copy-only) queue for H2D pipelining
};

static sycl::event ggml_sycl_fill_reordered_gpu(sycl::queue &                    queue,
                                                void *                           dst,
                                                size_t                           dst_size,
                                                const void *                     src,
                                                size_t                           src_size,
                                                const void *                     ctx_void,
                                                const std::vector<sycl::event> & deps);
static bool        ggml_sycl_gpu_reorder_disabled();

static bool ggml_sycl_graph_has_host_inputs(const ggml_cgraph * cgraph) {
    if (!cgraph) {
        return false;
    }

    auto is_host_tensor = [](const ggml_tensor * tensor) -> bool {
        if (!tensor) {
            return false;
        }
        if (!ggml_sycl_tensor_is_weight(tensor) && tensor->buffer && ggml_backend_buffer_is_host(tensor->buffer)) {
            return true;
        }
        if (tensor->view_src && !ggml_sycl_tensor_is_weight(tensor->view_src) && tensor->view_src->buffer &&
            ggml_backend_buffer_is_host(tensor->view_src->buffer)) {
            return true;
        }
        return false;
    };

    static bool logged_first = false;

    for (int i = 0; i < cgraph->n_nodes; ++i) {
        const ggml_tensor * node = cgraph->nodes[i];
        if (!node) {
            continue;
        }
        if (is_host_tensor(node)) {
            if (!logged_first) {
                logged_first = true;
                GGML_LOG_INFO("[GRAPH-DIAG] host tensor found: node[%d] name='%s' op=%s buffer=%s\n",
                              i, node->name, ggml_op_name(node->op),
                              node->buffer ? ggml_backend_buffer_name(node->buffer) : "null");
            }
            return true;
        }
        for (int s = 0; s < GGML_MAX_SRC; ++s) {
            const ggml_tensor * src = node->src[s];
            if (!src) {
                break;
            }
            if (is_host_tensor(src)) {
                if (!logged_first) {
                    logged_first = true;
                    GGML_LOG_INFO("[GRAPH-DIAG] host tensor found: node[%d].src[%d] name='%s' op=%s buffer=%s\n",
                                  i, s, src->name, ggml_op_name(src->op),
                                  src->buffer ? ggml_backend_buffer_name(src->buffer) : "null");
                }
                return true;
            }
        }
    }

    return false;
}

static bool ggml_sycl_legacy_prestage_enabled() {
    static int cached = -1;
    if (cached < 0) {
        const char * env = std::getenv("GGML_SYCL_LEGACY_PRESTAGE");
        cached           = (env && std::atoi(env) != 0) ? 1 : 0;
    }
    return cached != 0;
}

static bool ggml_sycl_runtime_prestage_enabled() {
    if (ggml_sycl_legacy_prestage_enabled()) {
        return true;
    }
    if (ggml_sycl::unified_cache * cache = ggml_sycl::get_unified_cache_for_device(0)) {
        return !cache->has_placement_plan();
    }
    return true;
}

// ---------------------------------------------------------------------------
// Proactive pre-staging: upload popular experts to GPU0 VRAM after warmup.
// Called immediately after moe_apply_popularity_placement() sets popularity ranks.
// ---------------------------------------------------------------------------
// g_prestage_completed defined earlier (before is_expert_resident).

static void moe_prestage_popular_experts() {
    if (!ggml_sycl_runtime_prestage_enabled()) {
        static std::atomic<int> logged{ 0 };
        if (logged.fetch_add(1, std::memory_order_relaxed) < 1) {
            GGML_LOG_INFO(
                "[MOE-PRESTAGE] Placement-plan preload active; runtime prestage disabled "
                "(set GGML_SYCL_LEGACY_PRESTAGE=1 to restore legacy behavior)\n");
        }
        g_prestage_completed.store(true, std::memory_order_release);
        return;
    }
    if (g_prestage_completed.load(std::memory_order_acquire)) {
        return;
    }
    if (!ggml_sycl::is_expert_popularity_initialized()) {
        return;
    }

    std::shared_lock<std::shared_mutex> lock(g_moe_expert_meta_mutex);
    if (g_moe_expert_meta.empty()) {
        return;
    }

    // Count unique layer IDs for budget calculations.
    std::unordered_set<int> layer_ids;
    for (const auto & meta : g_moe_expert_meta) {
        layer_ids.insert(meta.layer_id);
    }

    const int n_layers = static_cast<int>(layer_ids.size());
    if (n_layers == 0) {
        return;
    }

    const size_t expert_bytes = g_moe_expert_meta[0].bytes;
    if (expert_bytes == 0) {
        return;
    }

    // Phase 1: Pre-stage popular experts to GPU0 VRAM.
    // S1-PRELOAD fills VRAM with AOS copies of dense weights —
    // available_for_compute() may return 0.  But these AOS entries are evictable:
    // the cache does LRU eviction internally.  Use total managed cache capacity MINUS
    // a compute reserve as the budget so hot SOA experts can replace cold AOS entries
    // while leaving room for compute buffers, KV cache, and other runtime allocations
    // that will be reserved after prestage.
    // Without this reserve, prestage fills ALL VRAM and later runtime reservations
    // trigger "Budget exceeded" when update_reserved_bytes shrinks the budget.
    const int                  device = 0;
    ggml_sycl::unified_cache * cache  = ggml_sycl::get_unified_cache_for_device(device);
    size_t                     avail;
    if (cache) {
        // AOS entries are evictable — use total managed capacity minus compute reserve
        // and runtime reservations (KV cache, compute buffers).
        // Runtime bytes include device-side KV cache which must not be evicted.
        cache->unpin_experts();
        const size_t total_managed = ggml_sycl::unified_cache_total_managed(device);
        const size_t runtime_bytes = ggml_sycl::unified_cache_get_runtime_bytes(device);
        size_t       free_vram = 0, total_vram = 0;
        ggml_backend_sycl_get_device_memory(device, &free_vram, &total_vram);
        const size_t compute_reserve = std::max(size_t(256) << 20, total_vram / 10);
        const size_t total_reserve   = compute_reserve + runtime_bytes;
        avail                        = (total_managed > total_reserve) ? total_managed - total_reserve : 0;
        GGML_LOG_INFO(
            "[MOE-PRESTAGE] total_managed=%zu MB, compute_reserve=%zu MB, "
            "runtime_reserved=%zu MB, prestage budget=%zu MB (evictable AOS entries)\n",
            total_managed >> 20, compute_reserve >> 20, runtime_bytes >> 20, avail >> 20);
    } else {
        avail = ggml_sycl::unified_cache_available_for_compute(device);
    }

    // Build a global priority list shared by Phase 1 (GPU0) and Phase 2 (secondary GPUs).
    // Sort order: popularity rank (ascending), then tensor_role (gate < up < down).
    // This ensures gate+up tensors are cached before down tensors for each expert,
    // which matches MoE FFN data flow: gate*up computed first, down computed second.
    // Under VRAM pressure, down_exps are dropped first since they can be prefetched
    // during the gate*up -> SiLU computation.
    std::vector<const moe_expert_meta *> priority_list;
    priority_list.reserve(g_moe_expert_meta.size());
    for (const auto & meta : g_moe_expert_meta) {
        priority_list.push_back(&meta);
    }
    std::sort(priority_list.begin(), priority_list.end(), [&](const moe_expert_meta * a, const moe_expert_meta * b) {
        int ra_raw = ggml_sycl::get_expert_popularity_rank(a->layer_id, a->expert_idx);
        int rb_raw = ggml_sycl::get_expert_popularity_rank(b->layer_id, b->expert_idx);
        int ra     = (ra_raw >= 0) ? ra_raw : INT_MAX;
        int rb     = (rb_raw >= 0) ? rb_raw : INT_MAX;
        if (ra != rb) {
            return ra < rb;
        }
        // Same popularity: gate before up before down
        return static_cast<int>(a->tensor_role) < static_cast<int>(b->tensor_role);
    });

    int prestaged     = 0;
    int skipped       = 0;
    int down_deferred = 0;

    if (avail > 0 && cache) {
        // --- Phase 1a: Group metadata by (block_num, expert_idx) for atomic staging ---
        // Instead of per-tensor work items, we build per-expert groups.  Each group
        // contains the gate/up/down metadata.  stage_expert_group stages all 3
        // atomically (all succeed or none).
        struct expert_meta_group {
            const moe_expert_meta * gate       = nullptr;
            const moe_expert_meta * up         = nullptr;
            const moe_expert_meta * down       = nullptr;
            int                     block_num  = -1;
            int                     expert_idx = -1;
            int                     pop_rank   = INT_MAX;
        };

        // Build expert groups from the metadata, keyed by (block_num, expert_idx)
        std::unordered_map<int64_t, expert_meta_group> meta_groups;
        for (const auto & meta : g_moe_expert_meta) {
            if (meta.block_num < 0) {
                continue;
            }

            // Skip experts already resident in VRAM on any device
            if (is_expert_resident(meta.block_num, meta.expert_idx, device)) {
                skipped++;
                continue;
            }

            const int64_t gkey = expert_group_key(meta.block_num, meta.expert_idx);
            auto &        mg   = meta_groups[gkey];
            mg.block_num       = meta.block_num;
            mg.expert_idx      = meta.expert_idx;

            int pop_rank = ggml_sycl::get_expert_popularity_rank(meta.layer_id, meta.expert_idx);
            int rank     = (pop_rank >= 0) ? pop_rank : INT_MAX;
            mg.pop_rank  = std::min(mg.pop_rank, rank);

            switch (meta.tensor_role) {
                case MOE_TENSOR_GATE:
                    mg.gate = &meta;
                    break;
                case MOE_TENSOR_UP:
                    mg.up = &meta;
                    break;
                case MOE_TENSOR_DOWN:
                    mg.down = &meta;
                    break;
                default:
                    break;
            }
        }

        // Sort expert groups by popularity rank
        std::vector<const expert_meta_group *> sorted_groups;
        sorted_groups.reserve(meta_groups.size());
        for (const auto & [gkey, mg] : meta_groups) {
            sorted_groups.push_back(&mg);
        }
        std::sort(sorted_groups.begin(), sorted_groups.end(),
                  [](const expert_meta_group * a, const expert_meta_group * b) { return a->pop_rank < b->pop_rank; });

        // Decide whether to use GPU-side or CPU-side reorder
        const bool use_gpu_reorder = !ggml_sycl_gpu_reorder_disabled();

        // Get pre-allocated reorder temp buffer from cache (reserved during moe_hybrid_init_once).
        // Falls back to per-expert dynamic alloc if not reserved.
        void * prealloc_temp      = cache ? cache->get_reorder_temp_buffer() : nullptr;
        size_t prealloc_temp_size = cache ? cache->get_reorder_temp_size() : 0;

        // Fallback: deferred free list for dynamically allocated temp buffers
        // (only used if pre-allocated buffer is unavailable or too small).
        std::vector<void *> temp_vram_bufs;
        if (use_gpu_reorder && !prealloc_temp) {
            temp_vram_bufs.reserve(sorted_groups.size() * 3);
        }

        auto t0 = std::chrono::high_resolution_clock::now();

        // Helper: build staging data + cache_layout_request for one tensor
        auto build_tensor_data = [&](const moe_expert_meta * meta, ggml_sycl::staging_tensor_data & sd,
                                     ggml_sycl::cache_layout_request & req, ggml_sycl_gpu_reorder_fill_ctx & gpu_fctx,
                                     ggml_sycl_reorder_fill_ctx & host_fctx) -> bool {
            if (!meta || !meta->tensor || !meta->extra) {
                return false;
            }

            ggml_sycl_cache_id ckey = ggml_sycl_get_moe_expert_cache_key(meta->tensor, meta->extra, meta->expert_idx);
            if (!ckey.valid) {
                return false;
            }

            const size_t soa_bytes =
                ggml_sycl_layout_bytes_for_dims(meta->type, meta->ne0, meta->ne1, GGML_LAYOUT_SOA, device);
            const size_t dst_bytes = (soa_bytes > 0) ? soa_bytes : meta->bytes;

            sd.src_ptr   = meta->data_ptr;
            sd.src_size  = meta->bytes;
            sd.dst_size  = dst_bytes;
            sd.layer_id  = meta->layer_id;
            sd.expert_id = meta->expert_idx;

            req.key              = ckey;
            req.src_ptr          = meta->data_ptr;
            req.src_size         = meta->bytes;
            req.dst_size         = dst_bytes;
            req.type             = ggml_sycl::cache_entry_type::MOE_EXPERT;
            req.layer_id         = meta->layer_id;
            req.expert_id        = meta->expert_idx;
            req.layout           = GGML_LAYOUT_SOA;
            req.validate_content = false;

            if (use_gpu_reorder) {
                gpu_fctx.type               = meta->type;
                gpu_fctx.ncols              = meta->ne0;
                gpu_fctx.nrows              = meta->ne1;
                gpu_fctx.src_bytes          = meta->bytes;
                gpu_fctx.dst_bytes          = dst_bytes;
                gpu_fctx.temp_bufs          = prealloc_temp ? nullptr : &temp_vram_bufs;
                gpu_fctx.owner_queue        = nullptr;
                gpu_fctx.prealloc_temp      = prealloc_temp;
                gpu_fctx.prealloc_temp_size = prealloc_temp_size;
                gpu_fctx.bcs_queue          = cache ? &cache->get_bcs_queue() : nullptr;

                req.fill_fn  = ggml_sycl_fill_reordered_gpu;
                req.fill_ctx = &gpu_fctx;
            } else {
                host_fctx.type          = meta->type;
                host_fctx.ncols         = meta->ne0;
                host_fctx.nrows         = meta->ne1;
                host_fctx.nbytes        = meta->bytes;
                host_fctx.dst_bytes     = dst_bytes;
                host_fctx.layout        = GGML_LAYOUT_SOA;
                host_fctx.src_is_device = false;
                host_fctx.device_id     = device;

                req.fill_fn  = ggml_sycl_fill_reordered_host;
                req.fill_ctx = &host_fctx;
            }

            return true;
        };

        int expert_groups_staged = 0;

        // Pre-allocate fill context storage (must outlive stage_expert_group calls)
        // 3 fill contexts per expert group for GPU and host paths
        std::vector<ggml_sycl_gpu_reorder_fill_ctx> all_gpu_fill_ctxs(sorted_groups.size() * 3);
        std::vector<ggml_sycl_reorder_fill_ctx>     all_host_fill_ctxs(sorted_groups.size() * 3);

        for (size_t gi = 0; gi < sorted_groups.size(); gi++) {
            const auto & mg = *sorted_groups[gi];

            // Look up the expert group registry to get canonical cache keys
            std::shared_lock<std::shared_mutex> grp_lock(g_expert_groups_mutex);
            const int64_t                       gkey   = expert_group_key(mg.block_num, mg.expert_idx);
            auto                                grp_it = g_expert_groups.find(gkey);
            if (grp_it == g_expert_groups.end()) {
                continue;
            }
            const auto & grp = grp_it->second;
            grp_lock.unlock();

            // Build staging data for each tensor
            ggml_sycl::staging_tensor_data  gate_sd{}, up_sd{}, down_sd{};
            ggml_sycl::cache_layout_request gate_req{}, up_req{}, down_req{};
            auto &                          gate_gpu_fctx  = all_gpu_fill_ctxs[gi * 3 + 0];
            auto &                          up_gpu_fctx    = all_gpu_fill_ctxs[gi * 3 + 1];
            auto &                          down_gpu_fctx  = all_gpu_fill_ctxs[gi * 3 + 2];
            auto &                          gate_host_fctx = all_host_fill_ctxs[gi * 3 + 0];
            auto &                          up_host_fctx   = all_host_fill_ctxs[gi * 3 + 1];
            auto &                          down_host_fctx = all_host_fill_ctxs[gi * 3 + 2];

            // P4: Check placement plan — skip experts planned for host.
            // Each tensor (gate/up/down) is checked individually.  If the plan
            // says an expert is not on device, skip its staging to avoid
            // exhausting the WEIGHT zone on MoE models.
            if (cache->has_placement_plan()) {
                const auto & pp                  = cache->get_placement_plan();
                auto         check_expert_tensor = [&](const moe_expert_meta * meta) -> bool {
                    if (!meta || !meta->tensor || !meta->tensor->name) {
                        return true;
                    }
                    const std::string tname(meta->tensor->name);
                    return pp.expert_on_device(tname, mg.expert_idx, device);
                };
                bool gate_on_dev = check_expert_tensor(mg.gate);
                bool up_on_dev   = check_expert_tensor(mg.up);
                bool down_on_dev = check_expert_tensor(mg.down);
                if (!gate_on_dev && !up_on_dev && !down_on_dev) {
                    skipped++;
                    continue;
                }
            }

            bool gate_ok = build_tensor_data(mg.gate, gate_sd, gate_req, gate_gpu_fctx, gate_host_fctx);
            bool up_ok   = build_tensor_data(mg.up, up_sd, up_req, up_gpu_fctx, up_host_fctx);
            bool down_ok = build_tensor_data(mg.down, down_sd, down_req, down_gpu_fctx, down_host_fctx);

            if (!gate_ok && !up_ok && !down_ok) {
                continue;
            }

            // Stage all 3 tensors atomically
            bool ok = cache->stage_expert_group(mg.block_num, mg.expert_idx, grp, gate_sd, up_sd, down_sd,
                                                GGML_LAYOUT_SOA, gate_ok ? &gate_req : nullptr,
                                                up_ok ? &up_req : nullptr, down_ok ? &down_req : nullptr);

            if (ok) {
                // Cache already has the staged pointers — no separate tracking needed.
                // is_expert_resident() / get_expert_device_ptr() query the cache directly.
                expert_groups_staged++;
                prestaged += (gate_ok ? 1 : 0) + (up_ok ? 1 : 0) + (down_ok ? 1 : 0);
            } else {
                // VRAM exhausted — stop pre-staging
                break;
            }

            // Periodic batch yield every 2 expert groups.
            // With BCS/CCS engine split, individual CCS reorder kernels are ~10us
            // and naturally preemptible.  The yield ensures:
            //   1. ALL queues (CCS compute, DMA, BCS) drain pending work
            //   2. Watchdog heartbeat prevents host-side timeout
            // Without this, back-to-back submissions accumulate a non-preemptible
            // command list that triggers xe driver GT engine resets.
            // Reduced from 8 to 2 after 120B stability testing showed engine
            // resets even with BCS/DMA draining — CCS compute queue was the
            // missing piece (reorder kernels submit to CCS, not BCS).
            constexpr int YIELD_BATCH = 2;
            if (expert_groups_staged > 0 && expert_groups_staged % YIELD_BATCH == 0) {
                try {
                    cache->get_queue().wait();  // CCS compute queue
                    cache->get_dma_queue().wait();
                    cache->get_bcs_queue().wait();
                    // Process deferred frees NOW — all queues drained, safe to unmap VRAM.
                    // evict_one defers frees to prevent BCS CAT errors during prestage.
                    cache->process_deferred_frees_public();
                } catch (...) {
                }
                ggml_sycl_watchdog_heartbeat();
            }
        }

        // Final flush: wait for all remaining in-flight fills
        if (prestaged > 0) {
            try {
                cache->get_queue().wait();  // CCS compute queue
                cache->get_dma_queue().wait();
                cache->get_bcs_queue().wait();
                // Process any deferred frees accumulated during eviction.
                cache->process_deferred_frees_public();
            } catch (...) {
            }
        }

        // Free temp VRAM buffers (GPU reorder path)
        if (use_gpu_reorder && !temp_vram_bufs.empty()) {
            sycl::queue & cache_queue = cache->get_queue();
            cache_queue.wait();
            size_t temp_freed = 0;
            for (void * buf : temp_vram_bufs) {
                if (buf) {
                    sycl::free(buf, cache_queue);
                    temp_freed += expert_bytes;  // Each temp buf = expert_bytes
                }
            }
            (void) temp_freed;
        }

        auto   t1       = std::chrono::high_resolution_clock::now();
        double total_ms = std::chrono::duration<double, std::milli>(t1 - t0).count();
        GGML_LOG_INFO(
            "[MOE-PRESTAGE] Staged %d expert groups (%d tensors, 3 tensors each), "
            "%.1f ms total (%s reorder)\n",
            expert_groups_staged, prestaged, total_ms, use_gpu_reorder ? "GPU" : "CPU");

        // Post-prestage verification: check is_expert_resident() for STAGED experts.
        // Uses sorted_groups (popularity-sorted) to check the ones we actually staged.
        {
            int ok = 0, fail = 0, checked = 0;
            for (size_t gi = 0; gi < sorted_groups.size() && checked < 10; gi++) {
                const auto & mg = *sorted_groups[gi];
                checked++;
                if (is_expert_resident(mg.block_num, mg.expert_idx, device)) {
                    ok++;
                } else {
                    fail++;
                }
            }
            GGML_LOG_INFO(
                "[MOE-PRESTAGE] Verification: %d/%d expert groups resident on device %d "
                "(cache entries=%zu)\n",
                ok, checked, device, cache->entry_count());
        }
    }

    GGML_LOG_INFO(
        "[MOE-PRESTAGE] Pre-staged %d popular expert tensors to GPU0 VRAM "
        "(%d already cached, %d down_exps deferred, %d layers, avail=%zu)\n",
        prestaged, skipped, down_deferred, n_layers, avail);

    ggml_sycl_watchdog_heartbeat();

    // Release per-device expert reserves now that actual staging is tracked
    // in the cache's used_ bytes via allocate_slot().  Keeping the reserve would
    // double-count: reserved_ + used_ both consuming budget.
    for (int d = 0; d < GGML_SYCL_MAX_DEVICES; d++) {
        if (g_moe_expert_vram_reserve[d] > 0) {
            GGML_LOG_INFO("[MOE-PRESTAGE] Released device %d upfront VRAM reserve: %.1f MB\n", d,
                          g_moe_expert_vram_reserve[d] / (1024.0 * 1024.0));
            g_moe_expert_vram_reserve[d] = 0;
        }
    }

    // Phase 2: Fill secondary GPUs with the NEXT TIER of popular experts.
    // Uses the same global priority list from Phase 1 (sorted by popularity
    // rank then tensor_role: gate < up < down).  Experts already placed on
    // GPU0 are skipped — only experts that did NOT fit on GPU0 overflow here.
    // Under tight VRAM, down_exps tensors are deferred (gate+up are needed
    // first in MoE FFN; down can be prefetched during the SiLU computation).
    //
    // Budget is SOA-aware: each device tracks remaining bytes, not just slot
    // counts, because SOA layout may expand expert size beyond AOS bytes.
    {
        struct sec_budget {
            int                        dev;
            size_t                     bytes_remaining;
            ggml_sycl::unified_cache * cache;
            int                        staged;
            int                        skipped;
            int                        down_deferred;
        };

        std::vector<sec_budget> sec_budgets;

        for (int dev = 1; dev < GGML_SYCL_MAX_DEVICES; dev++) {
            if (!g_expert_prefetchers[dev].is_initialized()) {
                continue;
            }

            ggml_sycl::unified_cache * sec_cache = ggml_sycl::get_unified_cache_for_device(dev);
            if (!sec_cache) {
                continue;
            }

            // Use total cache capacity minus compute reserve: after unpinning,
            // init-time entries are evictable.  The cache handles LRU
            // eviction internally.  Reserve space for compute buffers + runtime.
            const size_t sec_managed = ggml_sycl::unified_cache_total_managed(dev);
            size_t       sec_free = 0, sec_total_vram = 0;
            ggml_backend_sycl_get_device_memory(dev, &sec_free, &sec_total_vram);
            const size_t sec_reserve = std::max(size_t(256) << 20, sec_total_vram / 10);
            const size_t sec_total   = (sec_managed > sec_reserve) ? sec_managed - sec_reserve : 0;
            if (sec_total == 0 || expert_bytes == 0) {
                continue;
            }

            // Unpin expert entries so the cache can evict cold experts when full.
            sec_cache->unpin_experts();

            sec_budgets.push_back({ dev, sec_total, sec_cache, 0, 0, 0 });
        }

        GGML_LOG_INFO("[MOE-PRESTAGE] Phase 2: %zu secondary device(s) with budget\n", sec_budgets.size());
        for (const auto & b : sec_budgets) {
            GGML_LOG_INFO("[MOE-PRESTAGE] Phase 2: GPU%d budget=%.1f MB\n", b.dev,
                          b.bytes_remaining / (1024.0 * 1024.0));
        }

        if (!sec_budgets.empty()) {
            // --- Phase 2a: Collect work items for secondary GPUs ---
            struct sec_work_item {
                const moe_expert_meta * meta;
                ggml_sycl_cache_id      key;
                size_t                  dst_bytes;
                int                     budget_idx;  // index into sec_budgets
            };

            std::vector<sec_work_item> sec_work;

            for (const auto * meta : priority_list) {
                if (sec_budgets.empty()) {
                    break;
                }

                // Skip experts already resident on GPU0 (cache IS the placement)
                if (meta->block_num >= 0 && is_expert_resident(meta->block_num, meta->expert_idx, 0)) {
                    continue;
                }

                // Skip experts already resident on a secondary GPU
                bool already_on_secondary = false;
                for (auto & b : sec_budgets) {
                    if (meta->block_num >= 0 && is_expert_resident(meta->block_num, meta->expert_idx, b.dev)) {
                        b.skipped++;
                        already_on_secondary = true;
                        break;
                    }
                }
                if (already_on_secondary) {
                    continue;
                }

                // P4: Check placement plan — skip experts not planned for any
                // secondary device.  Without this, Phase 2 tries to stage
                // host-planned experts onto secondary GPUs, exhausting VRAM.
                if (meta->tensor && meta->tensor->name) {
                    bool              planned_for_secondary = false;
                    const std::string tname(meta->tensor->name);
                    for (const auto & b : sec_budgets) {
                        auto * sec_cache = b.cache;
                        if (sec_cache && sec_cache->has_placement_plan() &&
                            sec_cache->get_placement_plan().expert_on_device(tname, meta->expert_idx, b.dev)) {
                            planned_for_secondary = true;
                            break;
                        }
                    }
                    if (!planned_for_secondary) {
                        continue;
                    }
                }

                const size_t soa_bytes =
                    ggml_sycl_layout_bytes_for_dims(meta->type, meta->ne0, meta->ne1, GGML_LAYOUT_SOA, 0);
                const size_t dst_bytes = (soa_bytes > 0) ? soa_bytes : meta->bytes;

                int    best_idx   = -1;
                size_t best_space = 0;
                for (int i = 0; i < static_cast<int>(sec_budgets.size()); i++) {
                    if (sec_budgets[i].bytes_remaining >= dst_bytes && sec_budgets[i].bytes_remaining > best_space) {
                        best_idx   = i;
                        best_space = sec_budgets[i].bytes_remaining;
                    }
                }
                if (best_idx < 0) {
                    sec_budgets.erase(
                        std::remove_if(sec_budgets.begin(), sec_budgets.end(),
                                       [dst_bytes](const sec_budget & b) { return b.bytes_remaining < dst_bytes; }),
                        sec_budgets.end());
                    continue;
                }

                auto & budget = sec_budgets[best_idx];

                const size_t total_slots = budget.bytes_remaining / dst_bytes;
                if (total_slots < 32 && meta->tensor_role == MOE_TENSOR_DOWN) {
                    budget.down_deferred++;
                    continue;
                }

                ggml_sycl_cache_id key =
                    ggml_sycl_get_moe_expert_cache_key(meta->tensor, meta->extra, meta->expert_idx);
                if (!key.valid) {
                    continue;
                }

                // Deduct budget eagerly during collection so device selection
                // remains accurate for subsequent experts.
                budget.bytes_remaining -= std::min(dst_bytes, budget.bytes_remaining);

                sec_work.push_back({ meta, key, dst_bytes, best_idx });
            }

            const bool sec_use_gpu = !ggml_sycl_gpu_reorder_disabled();

            if (sec_use_gpu && !sec_work.empty()) {
                // --- Phase 2b (GPU path): GPU reorder for secondary devices ---
                // Per-device fallback temp buffer tracking for deferred free
                // (only used when pre-allocated buffer is unavailable).
                std::unordered_map<int, std::vector<void *>> sec_temp_bufs;
                std::vector<ggml_sycl_gpu_reorder_fill_ctx>  sec_fill_ctxs(sec_work.size());

                auto t0 = std::chrono::high_resolution_clock::now();

                for (size_t i = 0; i < sec_work.size(); i++) {
                    auto & item   = sec_work[i];
                    auto & budget = sec_budgets[item.budget_idx];
                    auto & fctx   = sec_fill_ctxs[i];

                    // Get pre-allocated reorder temp buffer for this secondary device
                    void * sec_prealloc      = budget.cache ? budget.cache->get_reorder_temp_buffer() : nullptr;
                    size_t sec_prealloc_size = budget.cache ? budget.cache->get_reorder_temp_size() : 0;

                    fctx.type               = item.meta->type;
                    fctx.ncols              = item.meta->ne0;
                    fctx.nrows              = item.meta->ne1;
                    fctx.src_bytes          = item.meta->bytes;
                    fctx.dst_bytes          = item.dst_bytes;
                    fctx.temp_bufs          = sec_prealloc ? nullptr : &sec_temp_bufs[budget.dev];
                    fctx.owner_queue        = nullptr;
                    fctx.prealloc_temp      = sec_prealloc;
                    fctx.prealloc_temp_size = sec_prealloc_size;
                    fctx.bcs_queue          = budget.cache ? &budget.cache->get_bcs_queue() : nullptr;

                    try {
                        auto result = budget.cache->direct_stage_expert(
                            item.key, item.meta->data_ptr, item.meta->bytes, item.dst_bytes, GGML_LAYOUT_SOA,
                            ggml_sycl_fill_reordered_gpu, &fctx, &budget.cache->get_queue());
                        if (result.ok && result.ptr) {
                            budget.staged++;
                        }
                    } catch (...) {
                    }
                }

                // Finalize + free temp VRAM per secondary device
                for (auto & b : sec_budgets) {
                    if (b.staged > 0) {
                        sycl::queue & q = b.cache->get_queue();
                        q.wait();
                        for (void * buf : sec_temp_bufs[b.dev]) {
                            if (buf) {
                                sycl::free(buf, q);
                            }
                        }
                    }
                }

                auto   t1     = std::chrono::high_resolution_clock::now();
                double sec_ms = std::chrono::duration<double, std::milli>(t1 - t0).count();
                GGML_LOG_INFO("[MOE-PRESTAGE] Phase 2 GPU reorder: %d experts, %.1f ms\n",
                              static_cast<int>(sec_work.size()), sec_ms);
            } else if (!sec_work.empty()) {
                // --- Phase 2b (CPU fallback): Parallel CPU reorder + DMA ---
                struct sec_cpu_item {
                    const moe_expert_meta *    meta;
                    ggml_sycl_cache_id         key;
                    size_t                     dst_bytes;
                    int                        budget_idx;
                    ggml_sycl_reorder_fill_ctx reorder_ctx;
                    void *                     reorder_buf;
                    bool                       ok;
                };

                std::vector<sec_cpu_item> sec_cpu;
                sec_cpu.reserve(sec_work.size());

                for (auto & item : sec_work) {
                    auto &       budget = sec_budgets[item.budget_idx];
                    sec_cpu_item ci{};
                    ci.meta       = item.meta;
                    ci.key        = item.key;
                    ci.dst_bytes  = item.dst_bytes;
                    ci.budget_idx = item.budget_idx;
                    ci.ok         = false;

                    ci.reorder_ctx.type          = item.meta->type;
                    ci.reorder_ctx.ncols         = item.meta->ne0;
                    ci.reorder_ctx.nrows         = item.meta->ne1;
                    ci.reorder_ctx.nbytes        = item.meta->bytes;
                    ci.reorder_ctx.dst_bytes     = item.dst_bytes;
                    ci.reorder_ctx.layout        = GGML_LAYOUT_SOA;
                    ci.reorder_ctx.src_is_device = false;
                    ci.reorder_ctx.device_id     = budget.dev;

                    ci.reorder_buf = std::malloc(item.dst_bytes);
                    if (!ci.reorder_buf) {
                        continue;
                    }

                    sec_cpu.push_back(ci);
                }

                // Parallel CPU reorder
                if (!sec_cpu.empty()) {
                    const int hw_threads = static_cast<int>(std::thread::hardware_concurrency());
                    const int n_threads  = std::max(1, std::min(hw_threads - 2, 16));
                    const int n_items    = static_cast<int>(sec_cpu.size());

                    auto t0 = std::chrono::high_resolution_clock::now();

                    if (n_items <= n_threads || n_threads <= 1) {
                        for (auto & ci : sec_cpu) {
                            ci.ok = ggml_sycl_reorder_weight_cpu(ci.reorder_buf, ci.meta->data_ptr, ci.reorder_ctx);
                        }
                    } else {
                        std::vector<std::thread> threads;
                        threads.reserve(n_threads);
                        const int items_per_thread = (n_items + n_threads - 1) / n_threads;

                        for (int t = 0; t < n_threads; t++) {
                            const int begin = t * items_per_thread;
                            const int end   = std::min(begin + items_per_thread, n_items);
                            if (begin >= end) {
                                break;
                            }

                            threads.emplace_back([&sec_cpu, begin, end]() {
                                for (int i = begin; i < end; i++) {
                                    auto & ci = sec_cpu[i];
                                    ci.ok =
                                        ggml_sycl_reorder_weight_cpu(ci.reorder_buf, ci.meta->data_ptr, ci.reorder_ctx);
                                }
                            });
                        }
                        for (auto & t : threads) {
                            t.join();
                        }
                    }

                    auto   t1         = std::chrono::high_resolution_clock::now();
                    double reorder_ms = std::chrono::duration<double, std::milli>(t1 - t0).count();
                    GGML_LOG_INFO("[MOE-PRESTAGE] Phase 2 CPU reorder fallback: %d experts, %d threads, %.1f ms\n",
                                  n_items, n_threads, reorder_ms);
                }

                // DMA pre-reordered data to secondary devices
                for (auto & ci : sec_cpu) {
                    if (!ci.ok) {
                        std::free(ci.reorder_buf);
                        ci.reorder_buf = nullptr;
                        continue;
                    }

                    auto & budget = sec_budgets[ci.budget_idx];

                    // Route raw H2D to BCS (copy engine) on the secondary GPU.
                    sycl::queue * sec_bcs = &budget.cache->get_bcs_queue();
                    try {
                        auto result =
                            budget.cache->direct_stage_expert(ci.key, ci.reorder_buf, ci.dst_bytes, ci.dst_bytes,
                                                              GGML_LAYOUT_SOA, nullptr, nullptr, sec_bcs);
                        if (result.ok && result.ptr) {
                            budget.staged++;
                        }
                    } catch (...) {
                    }
                }

                // Free staging buffers
                for (auto & ci : sec_cpu) {
                    std::free(ci.reorder_buf);
                    ci.reorder_buf = nullptr;
                }
            }

            // Log summary per secondary device
            for (const auto & b : sec_budgets) {
                if (b.staged > 0 || b.skipped > 0) {
                    GGML_LOG_INFO(
                        "[MOE-PRESTAGE] Secondary GPU %d: %d experts staged, "
                        "%d already cached, %d down_exps deferred "
                        "(budget remaining=%.1f MB)\n",
                        b.dev, b.staged, b.skipped, b.down_deferred, b.bytes_remaining / (1024.0 * 1024.0));
                }
            }
        }
    }
    ggml_sycl_watchdog_heartbeat();

    // --- Initial Zipf-biased pinning: pin the top 25% of experts per layer ---
    // Experts staged during Phase 1 + Phase 2 are now in cache. Pin the hottest
    // ones so they survive LRU eviction under memory pressure.
    {
        const int n_experts_total = g_moe_warmup.n_experts;
        const int hot_per_layer   = std::max(1, n_experts_total / 4);
        int       pinned_init     = 0;

        for (const auto * meta_ptr : priority_list) {
            if (meta_ptr->block_num < 0) {
                continue;
            }
            int rank_raw = ggml_sycl::get_expert_popularity_rank(meta_ptr->layer_id, meta_ptr->expert_idx);
            int rank     = (rank_raw >= 0) ? rank_raw : INT_MAX;
            if (rank >= hot_per_layer) {
                continue;  // only pin top 25%
            }

            const int n_gpus_pin = ggml_sycl_info().total_gpu_count;
            for (int d = 0; d < n_gpus_pin && d < GGML_SYCL_MAX_DEVICES; d++) {
                if (!is_expert_resident(meta_ptr->block_num, meta_ptr->expert_idx, d)) {
                    continue;
                }
                ggml_sycl::unified_cache * pin_cache = ggml_sycl::get_unified_cache_for_device(d);
                if (!pin_cache) {
                    continue;
                }

                std::shared_lock<std::shared_mutex> grp_lock(g_expert_groups_mutex);
                auto grp_it = g_expert_groups.find(expert_group_key(meta_ptr->block_num, meta_ptr->expert_idx));
                if (grp_it == g_expert_groups.end()) {
                    continue;
                }
                const auto & grp = grp_it->second;

                static const ggml_layout_mode pin_layouts[] = { GGML_LAYOUT_SOA, GGML_LAYOUT_COALESCED,
                                                                GGML_LAYOUT_XMX_TILED, GGML_LAYOUT_AOS };
                auto                          pin_key       = [&](const ggml_sycl_cache_id & key) {
                    if (!key.valid) {
                        return;
                    }
                    for (auto layout : pin_layouts) {
                        if (pin_cache->lookup(key, layout)) {
                            pin_cache->pin(key, layout);
                            break;
                        }
                    }
                };
                if (grp.has_gate) {
                    pin_key(grp.gate_key);
                }
                if (grp.has_up) {
                    pin_key(grp.up_key);
                }
                if (grp.has_down) {
                    pin_key(grp.down_key);
                }
                pinned_init++;
            }
        }

        if (pinned_init > 0) {
            GGML_LOG_INFO("[MOE-PRESTAGE] Zipf pinning: %d expert groups pinned (top %d per layer)\n", pinned_init,
                          hot_per_layer);
        }
    }

    g_prestage_completed.store(true, std::memory_order_release);
}

// ---------------------------------------------------------------------------
// SOA-correct expert caching: single-expert wrapper around direct_stage_expert.
// Used by ExpertPrefetcher::hint() to upload experts with correct SOA layout
// instead of raw AOS memcpy.  Returns device pointer on success, nullptr on failure.
// ---------------------------------------------------------------------------
namespace ggml_sycl {
void * moe_expert_ensure_soa_cached(int layer_idx, int expert_idx, int device_id) {
    // Look up expert metadata (type, dims, data pointer)
    const moe_expert_meta * meta = nullptr;
    {
        std::shared_lock<std::shared_mutex> lock(g_moe_expert_meta_mutex);
        for (const auto & m : g_moe_expert_meta) {
            if (m.layer_id == layer_idx && m.expert_idx == expert_idx) {
                meta = &m;
                break;
            }
        }
    }
    if (!meta) {
        return nullptr;
    }

    // Validate data pointer — skip if corrupt (non-canonical address on x86-64)
    const uintptr_t data_addr = reinterpret_cast<uintptr_t>(meta->data_ptr);
    if (data_addr == 0 || (data_addr >> 47) != 0) {
        return nullptr;
    }

    // Get unified cache for target device
    unified_cache * cache = get_unified_cache_for_device(device_id);
    if (!cache) {
        return nullptr;
    }

    // P4: Check placement plan — skip device staging for experts planned for host.
    // Without this, adaptive prestage and ExpertPrefetcher::hint() bypass the plan
    // and exhaust the WEIGHT zone on MoE models that exceed VRAM.
    if (cache->has_placement_plan() && meta->tensor && meta->tensor->name) {
        const std::string tname(meta->tensor->name);
        if (!cache->get_placement_plan().expert_on_device(tname, expert_idx, device_id)) {
            return nullptr;  // Expert planned for host — caller handles host fallback
        }
    }

    // Build cache key from expert tensor metadata
    ggml_sycl_cache_id key = ggml_sycl_get_moe_expert_cache_key(meta->tensor, meta->extra, meta->expert_idx);
    if (!key.valid) {
        return nullptr;
    }

    if (cache->has_placement_plan()) {
        return cache->lookup(key, GGML_LAYOUT_SOA);
    }

    // Compute SOA byte count for this expert's dimensions
    const size_t soa_bytes =
        ggml_sycl_layout_bytes_for_dims(meta->type, meta->ne0, meta->ne1, GGML_LAYOUT_SOA, device_id);
    const size_t dst_bytes = (soa_bytes > 0) ? soa_bytes : meta->bytes;

    // Build AOS→SOA reorder context
    ggml_sycl_reorder_fill_ctx reorder_ctx{};
    reorder_ctx.type          = meta->type;
    reorder_ctx.ncols         = meta->ne0;
    reorder_ctx.nrows         = meta->ne1;
    reorder_ctx.nbytes        = meta->bytes;
    reorder_ctx.dst_bytes     = dst_bytes;
    reorder_ctx.layout        = GGML_LAYOUT_SOA;
    reorder_ctx.src_is_device = false;
    reorder_ctx.device_id     = device_id;

    // Route H2D to BCS (copy-only) queue to keep SOA reorder off CCS.
    // Without this, runtime expert staging during inference monopolizes CCS
    // and can trigger xe driver GT engine resets (>640ms preempt timeout).
    sycl::queue * bcs_q = &cache->get_bcs_queue();

    try {
        auto result = cache->direct_stage_expert(key, meta->data_ptr, meta->bytes, dst_bytes, GGML_LAYOUT_SOA,
                                                 ggml_sycl_fill_reordered_host, &reorder_ctx, bcs_q);
        if (result.ok && result.ptr) {
            return result.ptr;
        }
    } catch (...) {
        // VRAM exhausted or SYCL error — caller falls back to CPU dispatch
    }

    return nullptr;
}

static void ggml_sycl_configure_host_zones_for_plan(ggml_sycl::unified_cache * cache) {
    if (!cache || !cache->has_placement_plan()) {
        return;
    }

    if (cache->host_zones_configured()) {
        return;
    }

    const auto &     plan             = cache->get_placement_plan();
    constexpr size_t min_kv_zone      = 64ull * 1024ull * 1024ull;
    constexpr size_t scratch_headroom = 32ull * 1024ull * 1024ull;
    // KV is co-located with attention weights via the plan. If a layer's attention
    // weights are on host, its KV goes on host too. plan.kv_host_bytes reflects this.
    // Use the plan's value, but also compute from actual context size as a floor:
    // layers with host-resident attention weights need kv_per_layer * n_host_kv_layers
    // of host KV. The plan already accounts for this, so use it directly.
    const size_t     kv_zone_bytes = std::max(plan.host_zone_kv_bytes, min_kv_zone);
    const size_t scratch_zone_bytes = std::max(
        plan.host_zone_scratch_bytes, cache->onednn_weights_scratch_size() + cache->onednn_activations_scratch_size() +
                                          plan.max_tensor_bytes + scratch_headroom);
    const size_t total_host_needed =
        plan.host_zone_weight_bytes + kv_zone_bytes + plan.host_zone_staging_bytes + scratch_zone_bytes;

    // Zone-config preflight: grow the pinned-pool to total capacity before configure_host_zones()
    // carves it into sub-zones. Without this, the first zone alloc triggers incremental chunk growth
    // mid-inference (HOST_ALLOC_PHASE_GATE warnings) instead of upfront at model load.
    cache->pre_allocate_host_pool(total_host_needed);
    cache->configure_host_zones(plan.host_zone_weight_bytes, kv_zone_bytes, plan.host_zone_staging_bytes,
                                scratch_zone_bytes);

    // Pre-allocate runtime pool to prevent lazy growth during inference.
    // Covers oneDNN reorder scratch + DMA staging; prevents HOST_ALLOC_PHASE_GATE warnings.
    const size_t runtime_bytes =
        plan.onednn_scratchpad_bytes + plan.dma_staging_pool_bytes + plan.pp_pipeline_scratch_bytes;
    if (runtime_bytes > 0) {
        cache->pre_allocate_runtime_chunks(runtime_bytes);
    }

    if (cache->host_zones_configured()) {
        GGML_LOG_INFO("[HOST-ARENA] Zones configured: WEIGHT=%.1f MB KV=%.1f MB STAGING=%.1f MB SCRATCH=%.1f MB\n",
                      plan.host_zone_weight_bytes / (1024.0 * 1024.0), kv_zone_bytes / (1024.0 * 1024.0),
                      plan.host_zone_staging_bytes / (1024.0 * 1024.0), scratch_zone_bytes / (1024.0 * 1024.0));
    } else {
        GGML_LOG_WARN(
            "[HOST-ARENA] Host zones disabled for this plan; model load will use fallback pinned allocations\n");
    }
}

static bool ggml_sycl_is_device_expert_ptr(const void * ptr) {
    return ptr && ggml_sycl_get_alloc_type(ptr) == sycl::usm::alloc::device;
}

struct expert_resolve_result {
    const void *          ptr     = nullptr;
    bool                  is_host = false;  // true = safe for CPU vec_dot
    ggml_sycl::mem_handle lease{};           // llama.cpp-0k543: chunk lease for ptr when host-resident
};

static expert_resolve_result ggml_sycl_resolve_expert_ptr(
    const ggml_tensor * src0, int device, int expert_id) {
    auto * extra = static_cast<ggml_tensor_extra_gpu *>(src0 ? src0->extra : nullptr);
    if (!src0 || !extra) {
        return {};
    }

    // llama.cpp-0k543: when ptr lands on a host-arena chunk (unified cache
    // HOST_PINNED expert, or host-arena-backed GGUF load), wrap it in a
    // CHUNK_LEASE handle so the backing chunk cannot be sycl::free'd while
    // the caller still holds the raw pointer.  For non-arena pointers
    // (mmap-backed GGUF, plain device USM, external allocations) the
    // factory degrades to DIRECT — no lease is attached, which is correct
    // for those lifetimes.
    auto make_host_result = [device](const void * p) -> expert_resolve_result {
        expert_resolve_result r{};
        r.ptr     = p;
        r.is_host = true;
        r.lease   = ggml_sycl::mem_handle::from_chunk_ptr(const_cast<void *>(p), device,
                                                          GGML_LAYOUT_AOS, false);
        return r;
    };

    // 1. Try unified cache lookup
    unified_cache * cache = get_unified_cache_for_device(device);
    ggml_sycl_cache_id key = ggml_sycl_get_moe_expert_cache_key(src0, extra, expert_id);
    if (cache && key.valid) {
        if (const weight_entry * entry = cache->lookup_expert(key);
            entry && entry->ptr) {
            bool host = (entry->location != cache_location::DEVICE);
            if (host) {
                n04bq_probe_log("resolve/cache-host", src0->name, expert_id,
                                "loc=%d ptr=%p size=%zu",
                                (int) entry->location, entry->ptr, entry->size);
                return make_host_result(entry->ptr);
            }
            // Device-resident: caller routes to GPU, no lease needed on the
            // device VRAM pointer (CPU dispatch skips is_host==false paths).
            n04bq_probe_log("resolve/cache-device", src0->name, expert_id,
                            "ptr=%p size=%zu", entry->ptr, entry->size);
            expert_resolve_result r{};
            r.ptr     = entry->ptr;
            r.is_host = false;
            return r;
        }
    }

    // 2. Cache miss -- check tensor buffer type
    if (src0->buffer && ggml_backend_buffer_is_host(src0->buffer)) {
        const size_t expert_offset = static_cast<size_t>(expert_id) * src0->nb[2];
        const void * fallback_ptr  = static_cast<const char *>(src0->data) + expert_offset;
        n04bq_probe_log("resolve/fallback-buffer-host", src0->name, expert_id,
                        "tensor_data=%p expert_offset=%zu fallback_ptr=%p src0->nb[2]=%zu",
                        src0->data, expert_offset, fallback_ptr, src0->nb[2]);
        return make_host_result(fallback_ptr);
    }

    // 3. Device-resident, not in cache -- return device pointer, mark NOT host
    void * dev_ptr = extra->data_device_ptr(device);
    if (dev_ptr) {
        const size_t expert_offset = static_cast<size_t>(expert_id) * src0->nb[2];
        n04bq_probe_log("resolve/fallback-device", src0->name, expert_id,
                        "dev_base=%p expert_offset=%zu",
                        dev_ptr, expert_offset);
        expert_resolve_result r{};
        r.ptr     = static_cast<const char *>(dev_ptr) + expert_offset;
        r.is_host = false;
        return r;
    }

    n04bq_probe_log("resolve/nothing", src0->name, expert_id, "returning empty result");
    return {};
}

bool moe_get_expert_stage_info(int layer_idx, int expert_idx, int device_id, expert_stage_info & out) {
    out                          = {};
    const moe_expert_meta * meta = nullptr;
    {
        std::shared_lock<std::shared_mutex> lock(g_moe_expert_meta_mutex);
        for (const auto & m : g_moe_expert_meta) {
            if (m.layer_id == layer_idx && m.expert_idx == expert_idx) {
                meta = &m;
                break;
            }
        }
    }
    if (!meta) {
        return false;
    }
    const uintptr_t data_addr = reinterpret_cast<uintptr_t>(meta->data_ptr);
    if (data_addr == 0 || (data_addr >> 47) != 0) {
        return false;
    }
    ggml_sycl_cache_id key = ggml_sycl_get_moe_expert_cache_key(meta->tensor, meta->extra, meta->expert_idx);
    if (!key.valid) {
        return false;
    }
    // Determine optimal layout for this expert type/dimensions.
    // MXFP4 experts use SOA (COALESCED requires blocks_per_row%32==0 which
    // fails for 120B's 2880-col experts with blocks_per_row=90).
    const layout_mode optimal_layout = GGML_LAYOUT_SOA;
    const size_t      layout_bytes =
        ggml_sycl_layout_bytes_for_dims(meta->type, meta->ne0, meta->ne1, optimal_layout, device_id);
    const size_t dst_bytes = (layout_bytes > 0) ? layout_bytes : meta->bytes;
    out.cache_key          = key;
    out.src_ptr            = meta->data_ptr;
    out.src_size           = meta->bytes;
    out.dst_size           = dst_bytes;
    out.layout             = optimal_layout;
    out.type               = meta->type;
    out.ncols              = meta->ne0;
    out.nrows              = meta->ne1;
    out.layer_id           = meta->layer_id;
    out.expert_id          = meta->expert_idx;
    out.valid              = true;
    return true;
}

sycl::event fill_reordered_host(sycl::queue &                    queue,
                                void *                           dst,
                                size_t                           dst_size,
                                const void *                     src,
                                size_t                           src_size,
                                const void *                     ctx_void,
                                const std::vector<sycl::event> & deps) {
    const auto *               ctx = static_cast<const reorder_fill_ctx *>(ctx_void);
    ggml_sycl_reorder_fill_ctx internal_ctx{};
    internal_ctx.type          = ctx->type;
    internal_ctx.ncols         = ctx->ncols;
    internal_ctx.nrows         = ctx->nrows;
    internal_ctx.nbytes        = ctx->nbytes;
    internal_ctx.dst_bytes     = ctx->dst_bytes;
    internal_ctx.layout        = ctx->layout;
    internal_ctx.src_is_device = ctx->src_is_device;
    internal_ctx.device_id     = ctx->device_id;
    return ggml_sycl_fill_reordered_host(queue, dst, dst_size, src, src_size, &internal_ctx, deps);
}

uint32_t get_expert_frequency(int layer_hash, int expert_id) {
    auto & seq_map = g_moe_layer_seq[0];
    auto   it      = seq_map.find(layer_hash);
    if (it == seq_map.end()) {
        return 0;
    }
    int seq_layer = it->second;
    if (seq_layer < 0 || seq_layer >= g_moe_warmup.n_layers) {
        return 0;
    }
    if (expert_id < 0 || expert_id >= g_moe_warmup.n_experts) {
        return 0;
    }
    return g_moe_warmup.epoch_counts[seq_layer][expert_id].load(std::memory_order_relaxed);
}

}  // namespace ggml_sycl

// ---------------------------------------------------------------------------
// Periodic re-ranking: re-evaluate expert popularity from epoch counters and
// update placement table ranks.  Called every rerank_interval tokens after the
// initial warmup.  Only updates ranks — triggers re-staging of newly-popular
// experts via moe_prestage_popular_experts() when ranks change.
// ---------------------------------------------------------------------------
static void moe_periodic_rerank() {
    if (!ggml_sycl::is_expert_popularity_initialized()) {
        return;
    }

    const int nl = g_moe_warmup.n_layers;
    const int ne = g_moe_warmup.n_experts;

    // Build reverse map: sequential layer index -> hash-based layer_id.
    std::unordered_map<int, int> seq_to_hash;
    for (const auto & [hash_id, seq_id] : g_moe_layer_seq[0]) {
        seq_to_hash[seq_id] = hash_id;
    }

    int ranks_changed = 0;
    for (int l = 0; l < nl; l++) {
        auto it = seq_to_hash.find(l);
        if (it == seq_to_hash.end()) {
            continue;
        }
        int hash_layer_id = it->second;

        // Collect epoch counts and sort descending
        std::vector<std::pair<uint32_t, int>> sorted_experts;
        sorted_experts.reserve(ne);
        for (int e = 0; e < ne; e++) {
            uint32_t c = g_moe_warmup.epoch_counts[l][e].load(std::memory_order_relaxed);
            sorted_experts.push_back({ c, e });
        }
        std::sort(sorted_experts.begin(), sorted_experts.end(),
                  [](const auto & a, const auto & b) { return a.first > b.first; });

        // Update ranks, count changes
        for (int rank = 0; rank < (int) sorted_experts.size(); rank++) {
            int eid      = sorted_experts[rank].second;
            int old_rank = ggml_sycl::get_expert_popularity_rank(hash_layer_id, eid);
            if (old_rank != rank) {
                ranks_changed++;
            }
            ggml_sycl::set_expert_popularity_rank(hash_layer_id, eid, rank);
        }

        // Reset epoch counters for this layer for the next epoch
        for (int e = 0; e < ne; e++) {
            g_moe_warmup.epoch_counts[l][e].store(0, std::memory_order_relaxed);
        }
    }

    // Query VRAM budget for logging
    size_t vram_avail = ggml_sycl::unified_cache_available_for_compute(0);

    GGML_SYCL_DEBUG(
        "[MOE-RERANK] Periodic re-rank complete: %d rank changes, "
        "VRAM available=%.1f MB\n",
        ranks_changed, vram_avail / (1024.0 * 1024.0));

    // If significant rank changes occurred, trigger pre-staging of newly
    // popular experts that may not yet be in VRAM.
    if (ranks_changed > 0) {
        moe_prestage_popular_experts();
    }
}

// ---------------------------------------------------------------------------
// KV-expert rebalance monitoring: periodically checks whether cold KV layers
// could be promoted to VRAM by evicting unpopular experts.  Advisory only —
// logs the opportunity but does not migrate KV data mid-inference.
// Gated by GGML_SYCL_KV_REBALANCE=0 to disable.
// ---------------------------------------------------------------------------

static bool kv_rebalance_enabled() {
    static int cached = -1;
    if (cached == -1) {
        const char * env = std::getenv("GGML_SYCL_KV_REBALANCE");
        cached           = (env && std::atoi(env) == 0) ? 0 : 1;
    }
    return cached != 0;
}

static void kv_expert_rebalance_check(int device) {
    if (!kv_rebalance_enabled()) {
        return;
    }

    auto & mgr = ggml_sycl::get_kv_tier_manager(device);
    if (!mgr.is_active()) {
        return;  // All KV on device — nothing to rebalance
    }

    ggml_sycl::unified_cache * cache = ggml_sycl::get_unified_cache_for_device(device);
    if (!cache) {
        return;
    }

    size_t evictable    = cache->evictable_expert_bytes();
    size_t kv_per_layer = mgr.kv_per_layer();
    if (kv_per_layer == 0 || evictable < kv_per_layer) {
        return;
    }

    uint32_t promotable  = static_cast<uint32_t>(evictable / kv_per_layer);
    uint32_t current_hot = mgr.hot_layers();
    uint32_t new_hot     = std::min(current_hot + promotable, mgr.total_layers());

    if (new_hot <= current_hot) {
        return;
    }

    GGML_LOG_INFO(
        "[KV-REBALANCE] Could promote %u KV layers from host to device "
        "(evictable expert VRAM: %.1f MB, KV/layer: %.1f MB)\n",
        new_hot - current_hot, evictable / (1024.0 * 1024.0), kv_per_layer / (1024.0 * 1024.0));
}

// ---------------------------------------------------------------------------
// Adaptive expert prestage: background thread that promotes hot CPU-resident
// experts to VRAM based on runtime routing frequency.  Gated by env var
// GGML_SYCL_ADAPTIVE_PRESTAGE=1 (off by default).
//
// Unlike periodic re-ranking (which updates popularity ranks and re-runs the
// full moe_prestage_popular_experts on the inference thread), adaptive prestage
// runs on a BACKGROUND thread and only promotes individual experts that cross a
// hit-count threshold while the inference thread is free to continue.
// ---------------------------------------------------------------------------
struct adaptive_prestage_state {
    std::atomic<bool>       enabled{ false };
    std::atomic<bool>       shutdown{ false };
    std::atomic<int>        token_count{ 0 };
    int                     check_interval = 10;  // tokens between checks
    uint32_t                hit_threshold  = 3;   // min hits to trigger promotion
    std::thread             worker_thread;
    std::mutex              wake_mutex;
    std::condition_variable wake_cv;

    // Snapshot of epoch counts -- the background thread reads these to decide
    // which experts to promote.
    struct promotion_candidate {
        int      seq_layer;      // sequential layer index
        int      hash_layer_id;  // hash-based layer_id for cache/placement table
        int      expert_id;
        uint32_t hit_count;
    };

    std::mutex                       candidates_mutex;
    std::vector<promotion_candidate> pending_candidates;

    void init() {
        const char * env = getenv("GGML_SYCL_ADAPTIVE_PRESTAGE");
        if (!env || std::atoi(env) != 1) {
            return;
        }

        const char * interval_env = getenv("GGML_SYCL_ADAPTIVE_PRESTAGE_INTERVAL");
        if (interval_env) {
            check_interval = std::max(1, std::atoi(interval_env));
        }

        const char * threshold_env = getenv("GGML_SYCL_ADAPTIVE_PRESTAGE_THRESHOLD");
        if (threshold_env) {
            hit_threshold = static_cast<uint32_t>(std::max(1, std::atoi(threshold_env)));
        }

        enabled.store(true, std::memory_order_release);
        shutdown.store(false, std::memory_order_release);

        worker_thread = std::thread([this]() { worker_loop(); });

        GGML_LOG_INFO(
            "[ADAPTIVE-PRESTAGE] Enabled: check every %d tokens, "
            "promote threshold=%u hits\\n",
            check_interval, hit_threshold);
    }

    void stop() {
        if (!enabled.load(std::memory_order_acquire)) {
            return;
        }
        shutdown.store(true, std::memory_order_release);
        wake_cv.notify_all();
        if (worker_thread.joinable()) {
            worker_thread.join();
        }
        enabled.store(false, std::memory_order_release);
    }

    // Called from inference thread after expert recording.
    // Lightweight: just increments a counter and occasionally signals the worker.
    void tick() {
        if (!enabled.load(std::memory_order_acquire)) {
            return;
        }
        int t = token_count.fetch_add(1, std::memory_order_relaxed) + 1;
        if (t % check_interval != 0) {
            return;
        }

        // Build candidate list from current epoch counts
        scan_candidates();

        // Signal the background worker
        wake_cv.notify_one();
    }

  private:
    void scan_candidates() {
        if (!ggml_sycl::is_expert_popularity_initialized()) {
            return;
        }

        const int nl = g_moe_warmup.n_layers;
        const int ne = g_moe_warmup.n_experts;
        if (nl <= 0 || ne <= 0) {
            return;
        }

        // Build reverse map: sequential layer index -> hash-based layer_id
        std::unordered_map<int, int> seq_to_hash;
        for (const auto & [hash_id, seq_id] : g_moe_layer_seq[0]) {
            seq_to_hash[seq_id] = hash_id;
        }

        std::vector<promotion_candidate> candidates;

        // We need block_num for is_expert_resident checks. Build layer_hash->block_num map
        // from g_moe_expert_meta.
        std::unordered_map<int64_t, int> expert_block_nums;
        {
            std::shared_lock<std::shared_mutex> meta_lock(g_moe_expert_meta_mutex);
            for (const auto & meta : g_moe_expert_meta) {
                if (meta.block_num >= 0) {
                    int64_t key            = (int64_t(meta.layer_id) << 32) | int64_t(uint32_t(meta.expert_idx));
                    expert_block_nums[key] = meta.block_num;
                }
            }
        }

        for (int l = 0; l < nl; l++) {
            auto it = seq_to_hash.find(l);
            if (it == seq_to_hash.end()) {
                continue;
            }
            int hash_layer_id = it->second;

            for (int e = 0; e < ne; e++) {
                uint32_t count = g_moe_warmup.epoch_counts[l][e].load(std::memory_order_relaxed);
                if (count < hit_threshold) {
                    continue;
                }

                // Check if expert is already in VRAM via the cache
                int64_t ekey  = (int64_t(hash_layer_id) << 32) | int64_t(uint32_t(e));
                auto    bn_it = expert_block_nums.find(ekey);
                if (bn_it != expert_block_nums.end() && is_expert_resident(bn_it->second, e, 0)) {
                    continue;
                }

                // CPU-resident expert with high hit count -- candidate for promotion
                candidates.push_back({ l, hash_layer_id, e, count });
            }
        }

        if (!candidates.empty()) {
            // Sort by hit count descending so hottest experts are promoted first
            std::sort(
                candidates.begin(), candidates.end(),
                [](const promotion_candidate & a, const promotion_candidate & b) { return a.hit_count > b.hit_count; });

            std::lock_guard<std::mutex> lock(candidates_mutex);
            pending_candidates = std::move(candidates);
        }
    }

    void worker_loop() {
        while (!shutdown.load(std::memory_order_acquire)) {
            // Wait for signal from inference thread
            {
                std::unique_lock<std::mutex> lock(wake_mutex);
                wake_cv.wait_for(lock, std::chrono::milliseconds(500), [this]() {
                    return shutdown.load(std::memory_order_acquire) || !pending_candidates_empty();
                });
            }

            if (shutdown.load(std::memory_order_acquire)) {
                break;
            }

            // Grab candidates
            std::vector<promotion_candidate> work;
            {
                std::lock_guard<std::mutex> lock(candidates_mutex);
                work.swap(pending_candidates);
            }

            if (work.empty()) {
                continue;
            }

            // Check VRAM budget before promoting
            size_t vram_avail = ggml_sycl::unified_cache_available_for_compute(0);
            if (vram_avail == 0) {
                continue;
            }

            // Estimate per-expert size from metadata
            size_t expert_bytes = 0;
            {
                std::shared_lock<std::shared_mutex> lock(g_moe_expert_meta_mutex);
                if (!g_moe_expert_meta.empty()) {
                    expert_bytes = g_moe_expert_meta[0].bytes;
                }
            }
            if (expert_bytes == 0) {
                continue;
            }

            int promoted = 0;
            int skipped  = 0;

            for (const auto & c : work) {
                // Re-check VRAM budget -- stop if exhausted
                vram_avail = ggml_sycl::unified_cache_available_for_compute(0);
                if (vram_avail < expert_bytes) {
                    skipped += static_cast<int>(work.size()) - promoted - skipped;
                    break;
                }

                // Re-check cache -- another thread may have promoted it.
                // Use metadata to get block_num for is_expert_resident check.
                {
                    int block_num = -1;
                    {
                        std::shared_lock<std::shared_mutex> meta_lock(g_moe_expert_meta_mutex);
                        for (const auto & meta : g_moe_expert_meta) {
                            if (meta.layer_id == c.hash_layer_id && meta.expert_idx == c.expert_id &&
                                meta.block_num >= 0) {
                                block_num = meta.block_num;
                                break;
                            }
                        }
                    }
                    if (block_num >= 0 && is_expert_resident(block_num, c.expert_id, 0)) {
                        skipped++;
                        continue;
                    }
                }

                // Use the existing SOA caching infrastructure for promotion.
                // moe_expert_ensure_soa_cached handles: metadata lookup, cache key,
                // SOA reorder, direct_stage_expert, and placement table update.
                void * result = ggml_sycl::moe_expert_ensure_soa_cached(c.hash_layer_id, c.expert_id, /*device_id=*/0);

                if (result) {
                    promoted++;
                    GGML_SYCL_DEBUG(
                        "[ADAPTIVE-PRESTAGE] Promoted expert L%d/E%d "
                        "to VRAM (hits=%u)\\n",
                        c.seq_layer, c.expert_id, c.hit_count);
                } else {
                    skipped++;
                }

                if (shutdown.load(std::memory_order_acquire)) {
                    break;
                }
            }

            if (promoted > 0) {
                GGML_LOG_INFO(
                    "[ADAPTIVE-PRESTAGE] Background promotion: %d promoted, "
                    "%d skipped (VRAM avail=%.1f MB)\\n",
                    promoted, skipped, ggml_sycl::unified_cache_available_for_compute(0) / (1024.0 * 1024.0));
            }
        }
    }

    bool pending_candidates_empty() {
        std::lock_guard<std::mutex> lock(candidates_mutex);
        return pending_candidates.empty();
    }
};

static adaptive_prestage_state g_adaptive_prestage;

struct managed_host_pinned_buffer {
    ggml_sycl::alloc_handle handle{};
    size_t                  bytes = 0;

    bool ensure(sycl::queue &               q,
                int                         device,
                size_t                      needed_bytes,
                ggml_sycl::alloc_role       role,
                ggml_sycl::runtime_category category,
                const char *                cohort_id,
                bool                        zero_init = false) {
        if (handle.ptr != nullptr && bytes >= needed_bytes) {
            return true;
        }

        reset();

        ggml_sycl::alloc_request req{};
        req.queue                               = &q;
        req.device                              = device;
        req.size                                = needed_bytes;
        req.intent.role                         = role;
        req.intent.category                     = category;
        req.intent.cohort_id                    = cohort_id;
        req.intent.constraints.must_host_pinned = true;
        req.intent.constraints.use_pinned_pool  = true;

        if (!ggml_sycl::unified_alloc(req, &handle) || handle.ptr == nullptr) {
            handle = {};
            bytes  = 0;
            return false;
        }

        bytes = needed_bytes;
        if (zero_init) {
            // Use cache-aware dispatch: routes to stream.memset for device memory,
            // std::memset for host-pinned. Correct even if tier changes.
            auto mh = handle.as_mem_handle();
            auto r  = mh.resolve();
            if (r.on_device) { q.memset(r.ptr, 0, needed_bytes); }
            else { std::memset(r.ptr, 0, needed_bytes); }
        }
        return true;
    }

    void reset() {
        if (handle.ptr != nullptr) {
            (void) ggml_sycl::unified_free(handle);
            handle = {};
        }
        bytes = 0;
    }

    template <typename T = void> T * as() const { return static_cast<T *>(handle.ptr); }
};

static bool allocate_managed_host_pinned(sycl::queue &               q,
                                         int                         device,
                                         size_t                      bytes,
                                         ggml_sycl::alloc_role       role,
                                         ggml_sycl::runtime_category category,
                                         const char *                cohort_id,
                                         ggml_sycl::alloc_handle *   out,
                                         bool                        zero_init = false) {
    GGML_ASSERT(out != nullptr);
    *out = {};

    ggml_sycl::alloc_request req{};
    req.queue                               = &q;
    req.device                              = device;
    req.size                                = bytes;
    req.intent.role                         = role;
    req.intent.category                     = category;
    req.intent.cohort_id                    = cohort_id;
    req.intent.constraints.must_host_pinned = true;

    if (!ggml_sycl::unified_alloc(req, out) || out->ptr == nullptr) {
        *out = {};
        return false;
    }

    if (zero_init) {
        // Use cache-aware dispatch: routes to stream.memset for device memory,
        // std::memset for host-pinned. Correct even if tier changes.
        auto mh = out->as_mem_handle();
        auto r  = mh.resolve();
        if (r.on_device) { q.memset(r.ptr, 0, bytes); }
        else { std::memset(r.ptr, 0, bytes); }
    }
    return true;
}

// Per-secondary-GPU staging buffers (malloc_host, readable from primary GPU).
// Allocated once during init, sized for max_dispatch_count * max_N floats.
static float *                    g_secondary_staging_buffer[GGML_SYCL_MAX_DEVICES] = {};
static size_t                     g_secondary_staging_size[GGML_SYCL_MAX_DEVICES]   = {};
static size_t                     g_secondary_staging_max_N[GGML_SYCL_MAX_DEVICES]  = {};
static managed_host_pinned_buffer g_secondary_staging_alloc[GGML_SYCL_MAX_DEVICES];
// Dedicated in-order queues for secondary GPU compute submissions.
// Created during moe_hybrid_init_once() when multi-GPU is enabled.
// MUST be in-order: cross-device OOQ depends_on is broken on Level Zero.
static sycl::queue *              g_secondary_queues[GGML_SYCL_MAX_DEVICES] = {};
// Backward compat alias: g_gpu1_queue points to g_secondary_queues[1].
static sycl::queue *&             g_gpu1_queue                              = g_secondary_queues[1];

// Compute a stable, unique cache layer ID from a tensor name.
// This ensures each distinct weight tensor (e.g. blk.0.ffn_gate_exps vs
// blk.0.ffn_up_exps) gets a unique key in the expert cache, even though
// ggml_sycl_tp_extract_layer_number returns the same block number for both.
static int moe_cache_layer_id(const char * name) {
    if (!name) {
        return 0;
    }
    // FNV-1a 32-bit hash for deterministic, low-collision mapping
    uint32_t h = 2166136261u;
    for (const char * p = name; *p; ++p) {
        h ^= static_cast<uint32_t>(*p);
        h *= 16777619u;
    }
    return static_cast<int>(h & 0x7FFFFFFF);
}

// Forward declaration: assign a persistent cache UUID to a tensor extra (defined later).
static uint64_t ggml_sycl_assign_cache_uuid(ggml_tensor_extra_gpu * extra);

// Forward declaration: check if tensor's buffer is in device VRAM (defined after buffer context struct).
static bool ggml_sycl_is_device_vram_buffer(const ggml_tensor * t);
// Forward declaration: check if tensor's weights are host-resident (defined after buffer context struct).
static bool ggml_sycl_is_host_resident_weight(const ggml_tensor * src0, sycl::queue * stream);
// Forward declaration: check if weight executes on host rather than GPU (defined in dispatch section).
static bool ggml_sycl_weight_executes_on_host(const ggml_tensor * tensor, int device);
// Forward declaration: check if blind preload should be skipped (defined in MoE preload section).
bool        ggml_sycl_should_skip_blind_preload(int64_t n_experts);

// ---------------------------------------------------------------------------
// Gate+Up tensor pairing for fused CPU expert dispatch
// ---------------------------------------------------------------------------
// Maps gate tensor data pointer → up tensor data pointer.
// Built during moe_hybrid_init_once() by scanning MUL_MAT_ID nodes for
// paired ffn_gate_exps/ffn_up_exps tensors in the same block.
// Used by CPU-TG fast-path to precompute up matmul during gate dispatch.
struct gate_up_pair {
    const void * up_data;  // mmap pointer to up tensor's data
    size_t       nb02;     // bytes per expert (stride for expert_id indexing)
    ggml_type    type;     // weight quant type (must match gate)
    int64_t      K;        // input dimension (ne[0])
    int64_t      N;        // output dimension (ne[1])
};

static std::unordered_map<const void *, gate_up_pair> g_gate_up_pairs;  // gate data ptr → up info

// Precomputed up results cache: keyed by up tensor data pointer.
// Populated during gate MUL_MAT_ID dispatch, consumed during up dispatch.
// Entries are valid for one token (cleared at graph boundary).
struct precomputed_up_result {
    std::vector<float>   data;        // precomputed up output [n_experts * N]
    std::vector<int32_t> expert_ids;  // expert IDs that were computed
    int64_t              N;           // output dimension per expert
    bool                 valid;
};

static thread_local std::unordered_map<const void *, precomputed_up_result> g_precomputed_up;

// ---------------------------------------------------------------------------
// Zero-warmup expert staging via gate weight norm sorting.
//
// Computes ||W_gate[i,:]||^2 for each expert row in each layer's
// ffn_gate_inp tensor.  Higher gate norm correlates with higher routing
// probability, so sorting by norm gives a good initial popularity ranking
// without running any inference tokens.
//
// Called from moe_hybrid_init_once() when GGML_SYCL_MOE_WARMUP_TOKENS=0.
// Fills g_moe_warmup.counts with synthetic frequencies proportional to
// gate norms, then calls moe_apply_popularity_placement() and
// moe_prestage_popular_experts() to upload hot experts to VRAM immediately.
// ---------------------------------------------------------------------------
static void moe_compute_gate_norm_placement(ggml_cgraph * cgraph, int device) {
    const int nl = g_moe_warmup.n_layers;
    const int ne = g_moe_warmup.n_experts;
    if (nl <= 0 || ne <= 0) {
        return;
    }

    // Collect gate_inp tensors from the graph.
    // Gate tensors appear as src of MUL_MAT ops with name pattern "blk.N.ffn_gate_inp".
    // Shape: [n_embd, n_experts] stored as f32.
    struct gate_info {
        const ggml_tensor * tensor;
        int                 block_num;
        int                 n_embd;
        int                 n_experts;
    };

    std::vector<gate_info> gates;

    for (int i = 0; i < cgraph->n_nodes; i++) {
        const ggml_tensor * node = cgraph->nodes[i];
        for (int s = 0; s < GGML_MAX_SRC; s++) {
            const ggml_tensor * src = node->src[s];
            if (!src || !src->name || !src->data) {
                continue;
            }
            if (!strstr(src->name, "ffn_gate_inp")) {
                continue;
            }
            // Skip shared expert gate and bias variants
            if (strstr(src->name, "ffn_gate_inp_shexp") || strstr(src->name, "ffn_gate_inp_b")) {
                continue;
            }

            int block_id = moe_extract_block_number(src->name);
            if (block_id < 0) {
                continue;
            }

            // Check for duplicates (same tensor can appear in multiple nodes)
            bool dup = false;
            for (const auto & g : gates) {
                if (g.block_num == block_id) {
                    dup = true;
                    break;
                }
            }
            if (dup) {
                continue;
            }

            const int gate_n_embd    = static_cast<int>(src->ne[0]);
            const int gate_n_experts = static_cast<int>(src->ne[1]);
            if (gate_n_embd <= 0 || gate_n_experts <= 0) {
                continue;
            }

            gates.push_back({ src, block_id, gate_n_embd, gate_n_experts });
        }
    }

    if (gates.empty()) {
        GGML_LOG_WARN(
            "[MOE-GATE-NORM] No ffn_gate_inp tensors found in graph, "
            "cannot compute gate norms. Falling back to uniform placement.\n");
        return;
    }

    GGML_LOG_INFO(
        "[MOE-GATE-NORM] Computing gate weight norms for %zu blocks, "
        "%d experts/block\n",
        gates.size(), ne);

    // For each gate tensor, compute ||W_gate[expert_i,:]||^2 per expert row.
    // Map block_num to all sequential layer indices in that block (gate/up/down
    // each have a separate sequential layer index).
    //
    // Build block_num -> set of sequential layer indices mapping.
    std::unordered_map<int, std::vector<int>> block_to_seq_layers;
    {
        std::shared_lock<std::shared_mutex> lock(g_moe_expert_meta_mutex);
        for (const auto & [hash_id, seq_id] : g_moe_layer_seq[device]) {
            for (const auto & meta : g_moe_expert_meta) {
                if (meta.layer_id == hash_id && meta.expert_idx == 0) {
                    if (meta.block_num >= 0) {
                        block_to_seq_layers[meta.block_num].push_back(seq_id);
                    }
                    break;
                }
            }
        }
    }

    int n_blocks_computed = 0;
    for (const auto & gate : gates) {
        // Get host-accessible pointer to gate weight data.
        // Gate weights are f32, typically in host or unified memory.
        const float * gate_data = nullptr;

        // Check if data is host-accessible via buffer type
        if (!gate.tensor->buffer || !ggml_backend_buffer_is_host(gate.tensor->buffer)) {
            // Data is in device VRAM — cannot read from host.
            // This shouldn't happen for gate_inp (usually f32 in host memory).
            GGML_LOG_WARN("[MOE-GATE-NORM] Gate tensor blk.%d is device-only, skipping\n", gate.block_num);
            continue;
        }

        // Host buffer — directly accessible
        gate_data = static_cast<const float *>(gate.tensor->data);
        if (!gate_data) {
            continue;
        }

        // Compute L2 norm squared for each expert row.
        // Gate shape: [n_embd, n_experts] — row stride = n_embd floats.
        const int n_exp  = std::min(gate.n_experts, ne);
        const int n_embd = gate.n_embd;

        std::vector<double> norms(n_exp, 0.0);
        for (int e = 0; e < n_exp; e++) {
            const float * row = gate_data + static_cast<size_t>(e) * n_embd;
            double        sum = 0.0;
            for (int d = 0; d < n_embd; d++) {
                double v = static_cast<double>(row[d]);
                sum += v * v;
            }
            norms[e] = sum;
        }

        // Convert norms to synthetic frequency counts.
        // Scale so that the max norm maps to 1000 and min maps to 1.
        // This preserves relative ordering for moe_apply_popularity_placement().
        double max_norm = *std::max_element(norms.begin(), norms.end());
        double min_norm = *std::min_element(norms.begin(), norms.end());
        double range    = max_norm - min_norm;
        if (range < 1e-12) {
            range = 1.0;  // all norms equal — uniform counts
        }

        // Find all sequential layer indices for this block
        auto it = block_to_seq_layers.find(gate.block_num);
        if (it == block_to_seq_layers.end()) {
            GGML_LOG_WARN("[MOE-GATE-NORM] No sequential layers found for block %d\n", gate.block_num);
            continue;
        }

        for (int seq_l : it->second) {
            if (seq_l < 0 || seq_l >= nl) {
                continue;
            }
            for (int e = 0; e < n_exp; e++) {
                // Map norm to synthetic count: higher norm = higher count
                uint32_t count = static_cast<uint32_t>(1.0 + 999.0 * (norms[e] - min_norm) / range);
                g_moe_warmup.counts[seq_l][e].store(count, std::memory_order_relaxed);
            }
        }

        n_blocks_computed++;

        // Log top-3 experts by gate norm for first few blocks
        if (n_blocks_computed <= 4) {
            std::vector<std::pair<double, int>> sorted;
            sorted.reserve(n_exp);
            for (int e = 0; e < n_exp; e++) {
                sorted.push_back({ norms[e], e });
            }
            std::sort(sorted.begin(), sorted.end(), [](const auto & a, const auto & b) { return a.first > b.first; });
            if (sorted.size() >= 3) {
                GGML_LOG_INFO(
                    "[MOE-GATE-NORM] Block %d top-3 by norm: "
                    "expert %d (%.2f), expert %d (%.2f), expert %d (%.2f)\n",
                    gate.block_num, sorted[0].second, sorted[0].first, sorted[1].second, sorted[1].first,
                    sorted[2].second, sorted[2].first);
            }
        }
    }

    if (n_blocks_computed == 0) {
        GGML_LOG_WARN("[MOE-GATE-NORM] Failed to compute norms for any block\n");
        return;
    }

    GGML_LOG_INFO(
        "[MOE-GATE-NORM] Computed gate norms for %d/%zu blocks, "
        "applying popularity placement\n",
        n_blocks_computed, gates.size());

    // Apply the synthetic frequency counts as popularity ranks
    moe_apply_popularity_placement();

    // Pre-stage hot experts to VRAM immediately
    moe_prestage_popular_experts();

    // Mark warmup as complete — skip the inference-based warmup loop
    g_moe_warmup.warmup_done.store(true, std::memory_order_release);

    // Enable periodic re-ranking for runtime adaptation
    g_moe_warmup.enable_reranking();

    GGML_LOG_INFO(
        "[MOE-GATE-NORM] Zero-warmup placement complete. "
        "Skipping inference-based warmup entirely.\n");
}

// Scan a compute graph for MUL_MAT_ID nodes, register experts with the unified cache,
// and set up prefetcher + predictor.
// Called once per device via std::call_once.
static void moe_hybrid_init_once(ggml_backend_sycl_context & ctx, ggml_cgraph * cgraph) {
    const int     device = ctx.device;
    sycl::queue & q      = *ctx.stream();

    // Scan graph for MUL_MAT_ID nodes to discover MoE architecture
    int     n_moe_layers        = 0;
    int     n_experts_per_layer = 0;
    int     n_experts_used      = 0;  // top-K from ids tensor
    size_t  expert_weight_bytes = 0;
    int64_t max_K               = 0;  // max input dimension (ne00)
    int64_t max_N               = 0;  // max output dimension (ne01)
    int     max_dispatch_count  = 0;  // max total expert dispatches per MUL_MAT_ID

    struct moe_expert_info {
        int                     layer_id;
        int                     expert_idx;
        const void *            data_ptr;      // may be host or device VRAM pointer
        const void *            host_src_ptr;  // host-accessible source for cross-device DMA
        size_t                  bytes;
        const ggml_tensor *     tensor;        // src0 tensor for cache key generation
        ggml_tensor_extra_gpu * extra;         // tensor extra for cache UUID
    };

    std::vector<moe_expert_info> expert_list;

    for (int i = 0; i < cgraph->n_nodes; i++) {
        const ggml_tensor * node = cgraph->nodes[i];
        if (node->op != GGML_OP_MUL_MAT_ID) {
            continue;
        }
        const ggml_tensor * src0         = node->src[0];
        const void *        src0_storage = ggml_sycl_host_data(src0);
        if (!src0 || !src0_storage) {
            continue;
        }

        // Use name-hash based layer_id so each distinct tensor
        // (gate/up/down within the same block) gets a unique cache key.
        int layer_id = moe_cache_layer_id(src0->name);

        // Build hash→sequential mapping for ExpertPredictor
        if (g_moe_layer_seq[device].find(layer_id) == g_moe_layer_seq[device].end()) {
            g_moe_layer_seq[device][layer_id] = static_cast<int>(g_moe_layer_seq[device].size());
        }

        const int64_t n_experts = src0->ne[2] > 0 ? src0->ne[2] : 1;
        const size_t  nb02      = src0->nb[2];

        // Extract top-K (n_experts_used) from the ids tensor (src[2]).
        // Use the minimum across MUL_MAT_ID nodes: warmup graphs may inflate
        // ids->ne[0] to n_experts (all experts), while normal graphs use the
        // actual top-K from the model's expert_used_count.
        const ggml_tensor * ids = node->src[2];
        if (ids && ids->ne[0] > 0) {
            int ids_k = static_cast<int>(ids->ne[0]);
            if (n_experts_used <= 0 || ids_k < n_experts_used) {
                n_experts_used = ids_k;
            }
        }

        if (n_experts > n_experts_per_layer) {
            n_experts_per_layer = static_cast<int>(n_experts);
        }
        if (nb02 > expert_weight_bytes) {
            expert_weight_bytes = nb02;
        }
        if (src0->ne[0] > max_K) {
            max_K = src0->ne[0];
        }
        if (src0->ne[1] > max_N) {
            max_N = src0->ne[1];
        }
        // Track max dispatch count (top-K * tokens) for pinned buffer sizing
        if (ids) {
            int dispatch = static_cast<int>(ids->ne[0] * std::max(ids->ne[1], (int64_t) 1));
            if (dispatch > max_dispatch_count) {
                max_dispatch_count = dispatch;
            }
        }
        n_moe_layers++;

        // Register each expert's pointer + tensor info for eager upload.
        // IMPORTANT: the tensor storage pointer may be a device VRAM pointer (not CPU-accessible)
        // when the buffer was allocated in device memory.  The mmap source data
        // may have been unmapped after model loading.  We store the pointer as-is
        // and resolve host accessibility at Phase 2 upload time.
        auto * src0_extra = static_cast<ggml_tensor_extra_gpu *>(src0->extra);

        // Host-resident expert tensors (SYCL_Host buffer) may not have
        // ggml_tensor_extra_gpu allocated because the host buffer type
        // does not call ggml_backend_sycl_buffer_init_tensor.  Without
        // extra, the MoE cache key generation fails (model_id = 0,
        // cache_uuid = 0) and Phase 1/2 placement skips all experts,
        // causing them to fall back to CPU-only dispatch.
        // Fix: allocate extra on-demand and attach it to the tensor.
        // Lifetime is managed by a static vector (freed at process exit).
        if (!src0_extra) {
            static std::vector<std::unique_ptr<ggml_tensor_extra_gpu>> s_host_extras;
            static std::mutex                                          s_host_extras_mutex;
            auto new_extra = std::make_unique<ggml_tensor_extra_gpu>();
            ggml_sycl_register_optimize_feature(&new_extra->optimized_feature);
            src0_extra                             = new_extra.get();
            const_cast<ggml_tensor *>(src0)->extra = src0_extra;
            std::lock_guard<std::mutex> lock(s_host_extras_mutex);
            s_host_extras.push_back(std::move(new_extra));
            GGML_LOG_INFO(
                "[MOE-HYBRID] Created ggml_tensor_extra_gpu for host-resident "
                "expert tensor %s (buffer=%s)\n",
                src0->name ? src0->name : "?", src0->buffer ? ggml_backend_buffer_name(src0->buffer) : "none");
        }

        // Validate the tensor storage pointer before computing expert offsets.
        const uintptr_t src0_addr = reinterpret_cast<uintptr_t>(src0_storage);
        if (src0_addr == 0 || (src0_addr >> 47) != 0) {
            // Null or non-canonical address (bits 47+ set = kernel space on x86-64)
            GGML_LOG_WARN(
                "[MOE-HYBRID] Skipping MUL_MAT_ID node with invalid src0 storage=%p "
                "(tensor=%s, buffer=%s)\n",
                src0_storage, src0->name ? src0->name : "?",
                src0->buffer ? ggml_backend_buffer_name(src0->buffer) : "none");
            continue;
        }

        for (int e = 0; e < n_experts; e++) {
            const void * ptr      = static_cast<const char *>(src0_storage) + static_cast<size_t>(e) * nb02;
            const void * host_ptr = ggml_sycl_is_device_vram_buffer(src0) ? nullptr : ptr;
            expert_list.push_back({ layer_id, e, ptr, host_ptr, nb02, src0, src0_extra });
        }
    }

    if (n_moe_layers == 0) {
        GGML_LOG_INFO("[MOE-HYBRID] No MUL_MAT_ID nodes found, MoE hybrid disabled\n");
        return;
    }

    // Check how many experts are host-resident vs device-resident.
    // Uses ggml_sycl_is_device_vram_buffer() which checks the buffer's managed_alloc.tier
    // (ground truth from unified cache) instead of sycl::get_pointer_type() which returns
    // 'unknown' in multi-device Level Zero contexts.
    int n_host_experts = 0;
    for (const auto & info : expert_list) {
        if (!ggml_sycl_is_device_vram_buffer(info.tensor)) {
            n_host_experts++;
        }
    }

    GGML_LOG_INFO(
        "[MOE-HYBRID] Detected MoE: %d layers, %d experts/layer, top-%d, %.1f KB/expert, "
        "%d/%zu host-resident\n",
        n_moe_layers, n_experts_per_layer, n_experts_used, expert_weight_bytes / 1024.0, n_host_experts,
        expert_list.size());

    // Pre-allocate a reusable temp VRAM buffer for GPU-side AOS→SOA reorder.
    // Must happen BEFORE S1-PRELOAD fills VRAM with dense weights, otherwise
    // per-expert sycl::malloc_device fails and all expert prestaging is lost.
    // The buffer is reused sequentially by each expert's fill_fn during prestage.
    // Allocate with ~12.5% margin over the largest expert tensor size.
    if (expert_weight_bytes > 0 && !ggml_sycl_gpu_reorder_disabled()) {
        const size_t               reorder_temp_size = expert_weight_bytes + (expert_weight_bytes / 8);
        ggml_sycl::unified_cache * gpu0_cache        = ggml_sycl::get_unified_cache_for_device(device);
        if (gpu0_cache) {
            gpu0_cache->reserve_reorder_temp(reorder_temp_size);
        }
        // Also reserve on secondary GPUs (for Phase 2 prestage)
        const int total_gpus = ggml_sycl_info().total_gpu_count;
        for (int d = 1; d < total_gpus && d < GGML_SYCL_MAX_DEVICES; d++) {
            ggml_sycl::unified_cache * sec_cache = ggml_sycl::get_unified_cache_for_device(d);
            if (sec_cache) {
                sec_cache->reserve_reorder_temp(reorder_temp_size);
            }
        }
    }

    // -----------------------------------------------------------------------
    // Initialize popularity tracking and warmup profiling
    // (ExpertPlacementTable removed — the cache IS the placement.)
    // -----------------------------------------------------------------------
    GGML_SYCL_DEBUG("[MOE-HYBRID] Popularity tracking initialized: %d layers, %d experts/layer\n", n_moe_layers,
                    n_experts_per_layer);

    // Initialize warmup profiling for popularity-aware placement
    g_moe_warmup.init(n_moe_layers, n_experts_per_layer);

    // Initialize adaptive prestage background thread (if enabled via env var)
    g_adaptive_prestage.init();

    // No separate placement table needed — the unified cache tracks all
    // expert tensors.  Expert residency is checked via is_expert_resident()
    // and get_expert_device_ptr() which query the cache directly.
    {
        int n_with_host_ptr = 0;
        for (const auto & info : expert_list) {
            if (info.host_src_ptr) {
                n_with_host_ptr++;
            }
        }
        GGML_LOG_INFO("[MOE-HYBRID] Expert registry: %zu entries, %d with host_src_ptr, %zu device-only\n",
                      expert_list.size(), n_with_host_ptr, expert_list.size() - n_with_host_ptr);
    }

    // Store per-expert metadata for proactive pre-staging after warmup.
    {
        std::unique_lock<std::shared_mutex> lock(g_moe_expert_meta_mutex);
        g_moe_expert_meta.clear();
        g_moe_expert_meta.reserve(expert_list.size());
        for (const auto & info : expert_list) {
            moe_expert_meta meta{};
            meta.tensor      = info.tensor;
            meta.extra       = info.extra;
            meta.type        = info.tensor->type;
            meta.ne0         = info.tensor->ne[0];
            meta.ne1         = info.tensor->ne[1];
            meta.data_ptr    = info.data_ptr;
            meta.bytes       = info.bytes;
            meta.layer_id    = info.layer_id;
            meta.expert_idx  = info.expert_idx;
            meta.tensor_role = moe_classify_tensor(info.tensor->name);
            meta.block_num   = moe_extract_block_number(info.tensor->name);
            g_moe_expert_meta.push_back(meta);
        }
        GGML_LOG_INFO("[MOE-HYBRID] Expert metadata stored: %zu entries for post-warmup pre-staging\n",
                      g_moe_expert_meta.size());
    }

    // -----------------------------------------------------------------------
    // Build expert group registry: maps (block_id, expert_id) -> cache keys
    // for gate/up/down tensors.  Used by is_expert_resident() for dispatch.
    // -----------------------------------------------------------------------
    {
        std::unique_lock<std::shared_mutex> lock(g_expert_groups_mutex);
        g_expert_groups.clear();

        std::shared_lock<std::shared_mutex> meta_lock(g_moe_expert_meta_mutex);
        int                                 n_groups_registered = 0;
        for (const auto & meta : g_moe_expert_meta) {
            if (meta.block_num < 0) {
                continue;
            }
            if (!meta.tensor || !meta.extra) {
                continue;
            }

            const int64_t gkey = expert_group_key(meta.block_num, meta.expert_idx);
            auto &        grp  = g_expert_groups[gkey];

            // Generate the cache key for this expert slice
            ggml_sycl_cache_id ckey = ggml_sycl_get_moe_expert_cache_key(meta.tensor, meta.extra, meta.expert_idx);
            if (!ckey.valid) {
                continue;
            }

            switch (meta.tensor_role) {
                case MOE_TENSOR_GATE:
                    grp.gate_key = ckey;
                    grp.has_gate = true;
                    break;
                case MOE_TENSOR_UP:
                    grp.up_key = ckey;
                    grp.has_up = true;
                    break;
                case MOE_TENSOR_DOWN:
                    grp.down_key = ckey;
                    grp.has_down = true;
                    break;
                default:
                    break;
            }
            n_groups_registered++;
        }

        // Count how many groups have all 3 tensors registered
        int n_complete = 0;
        for (const auto & [key, grp] : g_expert_groups) {
            if (grp.has_gate && grp.has_up && grp.has_down) {
                n_complete++;
            }
        }
        GGML_LOG_INFO(
            "[MOE-HYBRID] Expert group registry: %zu groups (%d complete with gate+up+down), "
            "%d entries registered\n",
            g_expert_groups.size(), n_complete, n_groups_registered);
    }

    // -----------------------------------------------------------------------
    // Early multi-GPU setup: register unified caches for secondary GPUs BEFORE
    // the eager VRAM upload so the upload loop can distribute experts across
    // all devices. Auto-enabled when multiple GPUs are visible and the model
    // has MoE layers. Override with GGML_SYCL_MOE_MULTI_GPU=0 to disable or
    // GGML_SYCL_MOE_MULTI_GPU=1 to force enable.
    // -----------------------------------------------------------------------
    if (device == 0) {
        const char * moe_opt_in   = std::getenv("GGML_SYCL_MOE_MULTI_GPU");
        const int    total_gpus   = ggml_sycl_info().total_gpu_count;
        // Auto-enable for MoE models with 2+ GPUs, unless explicitly disabled
        const bool   multi_gpu_on = moe_opt_in ? (std::atoi(moe_opt_in) != 0) : (total_gpus >= 2);

        if (multi_gpu_on && total_gpus >= 2) {
            // All secondary queues MUST share device 0's sycl::context so that
            // cross-device depends_on() works on Level Zero.  Without a shared
            // context each device gets its own ze_context_handle_t and
            // depends_on(cross_device_event) hard-aborts in L0.
            auto & dev0       = ggml_sycl_get_gpu_device(0);
            auto   shared_ctx = dev0.default_queue().get_context();

            int n_early_ok = 0;
            for (int gpu_d = 1; gpu_d < total_gpus && gpu_d < GGML_SYCL_MAX_DEVICES; gpu_d++) {
                try {
                    // Use ggml_sycl_get_gpu_device() which accesses the full
                    // pre-scheduler-hiding GPU map (gpu_dpct_ids[]).
                    // ggml_sycl_get_device() uses the scheduler-filtered map and
                    // falls back to identity for hidden devices, which is wrong
                    // when non-GPU devices are interleaved in dpct enumeration.
                    auto & dev_d = ggml_sycl_get_gpu_device(gpu_d);
                    // Create IOQ with device 0's context for cross-device event compat.
                    g_secondary_queues[gpu_d] =
                        new sycl::queue(shared_ctx, dev_d, default_queue_properties());
                    ggml_sycl::unified_cache_register_for_queue(gpu_d, *g_secondary_queues[gpu_d]);
                    n_early_ok++;
                    GGML_LOG_INFO("[MOE-MULTI-GPU] Device %d registered: %s (dpct_id=%d)\n", gpu_d,
                                  dev_d.get_info<sycl::info::device::name>().c_str(),
                                  ggml_sycl_info().gpu_dpct_ids[gpu_d]);
                } catch (const std::exception & e) {
                    GGML_LOG_WARN("[MOE-MULTI-GPU] Early init: device %d unavailable: %s\n", gpu_d, e.what());
                } catch (...) {
                    GGML_LOG_WARN(
                        "[MOE-MULTI-GPU] Early init: device %d unavailable "
                        "(unknown error)\n",
                        gpu_d);
                }
            }
            if (n_early_ok > 0) {
                g_moe_multi_gpu_active.store(true, std::memory_order_release);
                GGML_LOG_INFO("[MOE-MULTI-GPU] Enabled (%s): %d secondary GPUs registered\n",
                              moe_opt_in ? "env GGML_SYCL_MOE_MULTI_GPU=1" : "auto-detected MoE + multi-GPU",
                              n_early_ok);
            } else {
                GGML_LOG_WARN(
                    "[MOE-MULTI-GPU] No secondary GPUs registered "
                    "(tried %d devices)\n",
                    total_gpus - 1);
            }
        } else if (!multi_gpu_on) {
            GGML_LOG_INFO("[MOE-MULTI-GPU] Disabled: %s\n", moe_opt_in ?
                                                                "env GGML_SYCL_MOE_MULTI_GPU=0" :
                                                                "single GPU detected "
                                                                "(use ONEAPI_DEVICE_SELECTOR=\"level_zero:0,1\" "
                                                                "for dual GPU)");
        }
    }

    // -----------------------------------------------------------------------
    // Eager VRAM upload: two-pass distribution across ALL available GPUs.
    //
    // Phase 1: Default-assign ALL experts to GPU0 (device_id=0, device_ptr=nullptr).
    //   The dispatch code resolves actual VRAM pointers at runtime via the unified
    //   cache (update_moe_ptr_table → prestage_routed_experts → expert_ptrs_host).
    //   This is the same path used for single-GPU MoE inference.
    //
    // Phase 2: Distribute experts to secondary GPUs using greedy bin-packing by
    //   available VRAM.  Experts placed on secondary GPUs get explicit device_ptr
    //   and override the Phase 1 GPU0 assignment.  Remaining experts stay on GPU0.
    // -----------------------------------------------------------------------
    {
        using namespace ggml_sycl;

        const int n_gpu = g_moe_multi_gpu_active.load(std::memory_order_acquire) ? ggml_sycl_info().total_gpu_count : 1;

        std::vector<bool> placed(expert_list.size(), false);
        size_t            n_gpu0         = 0;
        size_t            total_uploaded = 0;

        // --- Phase 1: default-assign experts to GPU0 ----------------------------
        // At init time, expert weights haven't been materialized into VRAM yet
        // (the unified cache does this lazily during the first graph_compute).
        // We set device_id=0 with device_ptr=nullptr — the dispatch code resolves
        // the actual VRAM pointer via update_moe_ptr_table/expert_ptrs_host at
        // runtime. Phase 2 may override some experts to secondary GPUs.
        //
        // Mark experts as placed[] when GPU0's cache budget can hold the full model.
        // This prevents Phase 2 from overriding them to secondary GPUs when it's not
        // beneficial (20B fits entirely in GPU0's VRAM).  For oversized models (120B),
        // placed[] is NOT set — Phase 2 distributes excess to secondary GPUs.
        const size_t total_expert_bytes = expert_list.size() * expert_weight_bytes;
        const size_t gpu0_cache_budget  = unified_cache_total_managed(0);
        const bool   gpu0_can_hold_all  = (gpu0_cache_budget > 0) && (total_expert_bytes <= gpu0_cache_budget);
        if (expert_weight_bytes > 0) {
            for (size_t ei = 0; ei < expert_list.size(); ei++) {
                const auto & info = expert_list[ei];
                if (!info.extra) {
                    continue;
                }
                // No placement table update needed — the cache handles GPU0 placement
                // lazily during graph_compute.  is_expert_resident() checks the cache.
                n_gpu0++;
                if (gpu0_can_hold_all) {
                    placed[ei] = true;
                }
            }
            GGML_LOG_INFO("[MOE-HYBRID] Phase 1: GPU0 cache budget=%.1f MB, expert total=%.1f MB -> %s\n",
                          gpu0_cache_budget / (1024.0 * 1024.0), total_expert_bytes / (1024.0 * 1024.0),
                          gpu0_can_hold_all ? "all on GPU0 (fits)" : "overflow, Phase 2 distributes");
        }

        // --- Phase 2: distribute experts to secondary GPUs --------------------
        // Upload experts to secondary device VRAM (using direct_stage_expert).
        // Experts placed here override Phase 1's GPU0 assignment with an explicit
        // device_ptr on the secondary GPU.  Remaining experts stay on GPU0 (cache-resolved).
        struct device_budget {
            int             dev;
            size_t          n_slots;
            size_t          n_uploaded;
            size_t          bytes_remaining;  // actual VRAM budget tracking (SOA-aware)
            unified_cache * cache;
        };

        std::vector<device_budget> budgets;

        for (int d = 1; d < n_gpu && d < GGML_SYCL_MAX_DEVICES; d++) {
            size_t          avail   = unified_cache_available_for_compute(d);
            unified_cache * cache_d = get_unified_cache_for_device(d);
            if (!cache_d || expert_weight_bytes == 0) {
                continue;
            }
            size_t slots = avail / expert_weight_bytes;
            GGML_LOG_INFO("[MOE-PHASE2] GPU%d: %zu slots available (%.1f MB / %.1f KB per expert)\n", d, slots,
                          avail / (1024.0 * 1024.0), expert_weight_bytes / 1024.0);
            if (slots > 0) {
                budgets.push_back({ d, slots, 0, avail, cache_d });
            }
        }

        if (!budgets.empty()) {
            // Sort experts by expert_idx (ascending) for popularity-weighted placement.
            // Low-index experts (especially expert 0) are activated most frequently in
            // MoE models.  By placing them first, B50 caches the most-used experts
            // across ALL layers, rather than all experts from just the first few layers.
            std::vector<size_t> upload_order(expert_list.size());
            std::iota(upload_order.begin(), upload_order.end(), 0);
            std::sort(upload_order.begin(), upload_order.end(), [&](size_t a, size_t b) {
                if (expert_list[a].expert_idx != expert_list[b].expert_idx) {
                    return expert_list[a].expert_idx < expert_list[b].expert_idx;
                }
                return expert_list[a].layer_id < expert_list[b].layer_id;
            });

            // Secondary GPU dispatch uses SOA MMVQ kernels, so experts must be
            // cached in SOA layout with proper AOS→SOA reordering.
            ggml_sycl_reorder_fill_ctx reorder_ctx{};

            // Default: fill all available secondary GPU VRAM with experts.
            // Override via GGML_SYCL_PHASE2_MAX_UPLOAD or GGML_SYCL_B50_EXPERT_SLOTS env vars.
            size_t total_secondary_slots = 0;
            for (const auto & b : budgets) {
                total_secondary_slots += b.n_slots;
            }

            // GGML_SYCL_B50_EXPERT_SLOTS: cap total secondary GPU expert cache slots.
            // Set to 0 to disable B50 expert cache entirely.
            // Default -1 (auto: use full VRAM capacity).
            const char * b50_slots_env = std::getenv("GGML_SYCL_B50_EXPERT_SLOTS");
            if (b50_slots_env) {
                int val = std::atoi(b50_slots_env);
                if (val >= 0) {
                    size_t capped = static_cast<size_t>(val);
                    if (capped < total_secondary_slots) {
                        GGML_LOG_INFO(
                            "[MoE-GPU-INIT] B50 expert slots capped: %zu -> %zu (via GGML_SYCL_B50_EXPERT_SLOTS)\n",
                            total_secondary_slots, capped);
                        total_secondary_slots = capped;
                    }
                }
            }

            size_t       max_phase2_upload = total_secondary_slots;
            const char * phase2_env        = std::getenv("GGML_SYCL_PHASE2_MAX_UPLOAD");
            if (phase2_env) {
                int val = std::atoi(phase2_env);
                if (val >= 0) {
                    max_phase2_upload = static_cast<size_t>(val);
                }
            }

            // Time-budget Phase 2: stop uploading after 30s to avoid blocking init.
            // Override with GGML_SYCL_PHASE2_TIMEOUT_SEC.
            int          phase2_timeout_sec = 30;
            const char * timeout_env        = std::getenv("GGML_SYCL_PHASE2_TIMEOUT_SEC");
            if (timeout_env) {
                int val = std::atoi(timeout_env);
                if (val > 0) {
                    phase2_timeout_sec = val;
                }
            }
            const auto phase2_start    = std::chrono::steady_clock::now();
            const auto phase2_deadline = phase2_start + std::chrono::seconds(phase2_timeout_sec);
            bool       phase2_timeout  = false;

            for (size_t oi = 0; oi < upload_order.size() && total_uploaded < max_phase2_upload; oi++) {
                // Check time budget every 16 uploads to avoid clock overhead
                if ((total_uploaded & 15) == 0 && total_uploaded > 0) {
                    if (std::chrono::steady_clock::now() >= phase2_deadline) {
                        phase2_timeout = true;
                        GGML_LOG_INFO("[MOE-PHASE2] Time budget exhausted (%ds), stopping after %zu experts\n",
                                      phase2_timeout_sec, total_uploaded);
                        break;
                    }
                }
                size_t ei = upload_order[oi];
                if (placed[ei]) {
                    continue;
                }
                const auto & info = expert_list[ei];
                if (!info.extra) {
                    continue;
                }

                // Find secondary device with most remaining slots
                int    best_idx   = -1;
                size_t best_slots = 0;
                for (int i = 0; i < static_cast<int>(budgets.size()); i++) {
                    if (budgets[i].n_slots > best_slots) {
                        best_idx   = i;
                        best_slots = budgets[i].n_slots;
                    }
                }
                if (best_idx < 0) {
                    break;  // All secondary devices full
                }

                ggml_sycl_cache_id key = ggml_sycl_get_moe_expert_cache_key(info.tensor, info.extra, info.expert_idx);
                if (!key.valid) {
                    continue;
                }

                // Compute SOA layout size for this expert type
                const int64_t ncols  = info.tensor->ne[0];
                const int64_t nrows  = info.tensor->ne[1];
                auto &        budget = budgets[best_idx];
                const size_t  soa_bytes =
                    ggml_sycl_layout_bytes_for_dims(info.tensor->type, ncols, nrows, GGML_LAYOUT_SOA, budget.dev);
                const size_t dst_bytes = (soa_bytes > 0) ? soa_bytes : info.bytes;

                // Budget guard: stop uploading to this device if the SOA-expanded
                // expert size would exceed the remaining VRAM.  Without this check,
                // the slot count (computed from AOS bytes) overestimates capacity
                // and causes VRAM exhaustion + Level Zero SIGABRT.
                if (dst_bytes > budget.bytes_remaining) {
                    budget.n_slots = 0;  // mark device as full
                    GGML_LOG_INFO(
                        "[MOE-PHASE2] GPU%d VRAM budget exhausted: need %zu bytes, "
                        "remaining %zu bytes (uploaded %zu experts)\n",
                        budget.dev, dst_bytes, budget.bytes_remaining, budget.n_uploaded);
                    continue;  // try next expert (may fit on different device)
                }

                // Determine if source pointer is device memory (VRAM on device 0).
                // If so, D2H stage it via device 0's queue before passing to
                // direct_stage_expert on the secondary GPU.  The mmap source
                // may have been unmapped after model loading, so the only reliable
                // host-accessible copy for device-resident weights is via D2H.
                const bool src_on_device = (info.tensor->buffer && !ggml_backend_buffer_is_host(info.tensor->buffer));

                const void *                    upload_src = info.data_ptr;
                ggml_sycl::scoped_unified_alloc d2h_staging;

                if (src_on_device) {
                    // D2H stage from device 0 to pinned host buffer
                    ggml_sycl::alloc_request req{};
                    req.queue                               = &q;
                    req.device                              = ggml_sycl_get_device_id_from_queue(q);
                    req.size                                = info.bytes;
                    req.intent.role                         = ggml_sycl::alloc_role::STAGING;
                    req.intent.category                     = ggml_sycl::runtime_category::HOST_COMPUTE;
                    req.intent.constraints.must_host_pinned = true;
                    req.intent.constraints.use_pinned_pool  = true;
                    d2h_staging.allocate(req);
                    if (void * staged = d2h_staging.get()) {
                        q.memcpy(staged, info.data_ptr, info.bytes).wait();
                        upload_src = staged;
                    } else {
                        GGML_LOG_ERROR("[MOE-PHASE2] D2H staging alloc failed for L%d E%d (%zu bytes)\n", info.layer_id,
                                       info.expert_idx, info.bytes);
                        continue;
                    }
                }

                // Set up reorder context for AOS→SOA conversion
                reorder_ctx               = {};
                reorder_ctx.type          = info.tensor->type;
                reorder_ctx.ncols         = ncols;
                reorder_ctx.nrows         = nrows;
                reorder_ctx.nbytes        = info.bytes;
                reorder_ctx.dst_bytes     = dst_bytes;
                reorder_ctx.layout        = GGML_LAYOUT_SOA;
                reorder_ctx.src_is_device = false;  // upload_src is always host-accessible
                reorder_ctx.device_id     = budget.dev;

                GGML_SYCL_DEBUG(
                    "[MOE-PHASE2] Uploading expert #%zu L%d E%d to GPU%d "
                    "(type=%d dst_bytes=%zu)\n",
                    total_uploaded, info.layer_id, info.expert_idx, budget.dev, (int) info.tensor->type, dst_bytes);

                // Route H2D to BCS (copy engine) on the secondary GPU to prevent
                // CCS monopolization during Phase 2 expert uploads.
                sycl::queue * phase2_bcs = &budget.cache->get_bcs_queue();

                ggml_sycl::direct_stage_result stage_result{};
                try {
                    stage_result =
                        budget.cache->direct_stage_expert(key, upload_src, info.bytes, dst_bytes, GGML_LAYOUT_SOA,
                                                          ggml_sycl_fill_reordered_host, &reorder_ctx, phase2_bcs);
                } catch (const std::exception & e) {
                    GGML_LOG_ERROR("[MOE-PHASE2] direct_stage_expert EXCEPTION: %s\n", e.what());
                    continue;
                } catch (...) {
                    GGML_LOG_ERROR("[MOE-PHASE2] direct_stage_expert UNKNOWN EXCEPTION\n");
                    continue;
                }
                if (stage_result.ok && stage_result.ptr) {
                    set_expert_popularity_rank(info.layer_id, info.expert_idx, static_cast<int>(total_uploaded));
                    budget.n_slots--;
                    budget.n_uploaded++;
                    budget.bytes_remaining -= std::min(dst_bytes, budget.bytes_remaining);
                    total_uploaded++;
                    placed[ei] = true;
                }
            }

            // Log Phase 2 elapsed time
            const auto phase2_elapsed = std::chrono::steady_clock::now() - phase2_start;
            const auto phase2_ms      = std::chrono::duration_cast<std::chrono::milliseconds>(phase2_elapsed).count();
            GGML_LOG_INFO("[MOE-PHASE2] Completed: %zu experts uploaded in %.1f s%s\n", total_uploaded,
                          phase2_ms / 1000.0, phase2_timeout ? " (timeout)" : "");
        }

        // Verify Phase 2 placement via cache residency
        {
            int gpu1_count  = 0;
            int gpu0_count  = 0;
            int cpu_count   = 0;
            // Check first tensor's experts to see which are on GPU0 vs GPU1
            int first_lid   = expert_list.empty() ? -1 : expert_list[0].layer_id;
            int first_block = -1;
            if (!expert_list.empty()) {
                first_block = moe_extract_block_number(expert_list[0].tensor->name);
            }
            std::vector<int> gpu0_experts_v, gpu1_experts_v;
            for (const auto & info : expert_list) {
                int  blk     = moe_extract_block_number(info.tensor->name);
                bool on_gpu1 = (blk >= 0 && n_gpu > 1) ? is_expert_resident(blk, info.expert_idx, 1) : false;
                bool on_gpu0 = (blk >= 0) ? is_expert_resident(blk, info.expert_idx, 0) : false;
                if (on_gpu1) {
                    gpu1_count++;
                    if (info.layer_id == first_lid) {
                        gpu1_experts_v.push_back(info.expert_idx);
                    }
                } else if (on_gpu0) {
                    gpu0_count++;
                    if (info.layer_id == first_lid) {
                        gpu0_experts_v.push_back(info.expert_idx);
                    }
                } else {
                    cpu_count++;
                }
            }
            GGML_LOG_INFO("[MOE-HYBRID] Phase 2 verify: GPU0=%d GPU1=%d CPU=%d (cache-based)\n", gpu0_count, gpu1_count,
                          cpu_count);
            std::string gpu0_str;
            for (int e : gpu0_experts_v) {
                gpu0_str += std::to_string(e) + ",";
            }
            GGML_LOG_INFO("[MOE-HYBRID] First tensor L%d: GPU0 experts=[%s] (%zu), GPU1 experts=%zu\n", first_lid,
                          gpu0_str.c_str(), gpu0_experts_v.size(), gpu1_experts_v.size());
        }

        // --- Phase 4: CPU spill for oversized expert sets -----------------------
        // After Phase 1+2, experts that exceed GPU0+GPU1 VRAM are still assigned
        // to GPU0 (device_id=0) even though GPU0 can't hold them all.  The fused
        // dispatch would hang trying to upload 128 experts per layer into 10GB.
        //
        // Phase 4 SKIPPED: dispatch handles CPU fallback via device_ptr check.
        // Experts stay device_id=0 from Phase 1 with device_ptr=nullptr.
        // Prestage sets device_ptr for popular experts → GPU0 dispatch.
        // Unprestaged experts (device_ptr==nullptr) → CPU fallback naturally.
        // Phase 4 had bugs: gate/up/down spilled independently, ran before
        // popularity ranking. The dispatch fallback chain handles it correctly.
        // Phase 4 (CPU spill) REMOVED — dispatch handles CPU fallback via
        // is_expert_resident() checks.  Experts not in VRAM fall through to
        // CPU dispatch naturally.

        // Log distribution summary (cache-based, after Phase 2 upload)
        {
            std::string dist_summary = "GPU0=" + std::to_string(n_gpu0) + "(cache)";
            for (const auto & b : budgets) {
                dist_summary += " GPU" + std::to_string(b.dev) + "=" + std::to_string(b.n_uploaded);
            }
            GGML_LOG_INFO("[MOE-HYBRID] Expert distribution: %s (%zu total, %.1f KB/expert)\n", dist_summary.c_str(),
                          expert_list.size(), expert_weight_bytes / 1024.0);
        }
    }

    // Log available VRAM per device for expert cache sizing diagnostics.
    {
        using namespace ggml_sycl;
        const int n_gpu_devs =
            g_moe_multi_gpu_active.load(std::memory_order_acquire) ? ggml_sycl_info().total_gpu_count : 1;
        for (int d = 0; d < n_gpu_devs && d < GGML_SYCL_MAX_DEVICES; d++) {
            size_t avail = unified_cache_available_for_compute(d);
            GGML_SYCL_DEBUG("[MOE-HYBRID] device %d: available VRAM for expert cache = %.1f MB\n", d,
                            avail / (1024.0 * 1024.0));
        }
    }

    // Initialize ExpertPrefetcher for primary device
    auto & prefetcher = g_expert_prefetchers[device];
    prefetcher.init(q);

    // Initialize ExpertPrefetcher for secondary GPUs (demand-driven LRU)
    if (g_moe_multi_gpu_active.load(std::memory_order_acquire)) {
        for (int d = 0; d < ggml_sycl_info().total_gpu_count && d < GGML_SYCL_MAX_DEVICES; d++) {
            if (d == device) {
                continue;  // already initialized above
            }
            if (g_secondary_queues[d] != nullptr && !g_expert_prefetchers[d].is_initialized()) {
                g_expert_prefetchers[d].init(*g_secondary_queues[d]);
                GGML_LOG_INFO("[MOE-HYBRID] Initialized ExpertPrefetcher for GPU%d (demand-driven LRU)\n", d);
            }
        }
    }

    // --- Phase 3: GPU0 expert pre-loading via prefetch pool ---
    // Pre-fill the prefetch VRAM pool with the first N experts per MoE layer.
    // Expert 0 tends to be most frequently activated, so preloading low-index
    // experts gives good coverage even without runtime frequency data.
    //
    // Skip when unified cache is active: S1-PRELOAD already cached entire MoE tensors
    // as AOS in VRAM.  Per-expert SOA conversion here would take 10+ minutes for large
    // MoE models (e.g. 120B with 13824 experts).
    // The per-op dispatch converts AOS→SOA on-demand for activated experts.
    if (device == 0 && n_experts_per_layer > 0 && !ggml_sycl::unified_cache_enabled()) {
        // Collect unique layer IDs from expert_list.
        std::map<int, std::vector<int>> layer_experts;  // sorted by layer ID for deterministic order
        for (const auto & info : expert_list) {
            layer_experts[info.layer_id].push_back(info.expert_idx);
        }

        // Sort expert IDs within each layer, then preload round-robin
        // across layers so pool slots are distributed evenly.
        // With 8 slots and 40 layers, each of the first 8 layers gets 1
        // expert (expert 0, the most frequently activated).
        int max_per_layer = 0;
        for (auto & [lid, eids] : layer_experts) {
            std::sort(eids.begin(), eids.end());
            eids.erase(std::unique(eids.begin(), eids.end()), eids.end());
            max_per_layer = std::max(max_per_layer, static_cast<int>(eids.size()));
        }
        for (int round = 0; round < max_per_layer; round++) {
            for (auto & [lid, eids] : layer_experts) {
                if (round < static_cast<int>(eids.size())) {
                    prefetcher.preload_experts(lid, { eids[round] });
                }
            }
        }
        GGML_LOG_INFO("[MOE-HYBRID] Phase 3: GPU0 expert pre-loading complete (via unified cache)\n");
    } else if (ggml_sycl::unified_cache_enabled()) {
        GGML_LOG_INFO("[MOE-HYBRID] Phase 3: skipped — unified cache already staged dense weights as AOS in VRAM\n");
    }

    // Initialize ExpertPredictor using top-K detected from graph ids tensor.
    // During warmup, ids->ne[0] may equal n_experts_per_layer (all experts
    // activated for JIT compilation). Cap to a sensible max in that case.
    if (ggml_sycl::ggml_sycl_expert_predict_enabled()) {
        auto & predictor = g_expert_predictors[device];
        if (n_experts_used <= 0 || n_experts_used >= n_experts_per_layer) {
            n_experts_used = std::min(8, n_experts_per_layer);
        }
        const int n_seq_layers = static_cast<int>(g_moe_layer_seq[device].size());
        predictor.init(n_seq_layers, n_experts_per_layer, n_experts_used);
        GGML_LOG_INFO("[MOE-HYBRID] Predictor initialized: %d layers, %d experts, top-%d\n", n_seq_layers,
                      n_experts_per_layer, n_experts_used);

        // Pre-gated routing: scan graph for ffn_gate_inp tensors and register
        // their device pointers so predict_pregate() can run the actual router
        // gate computation 1 layer ahead during MoE dispatch.
        // Gate weights are dense f32 tensors, always in VRAM (not quantized).
        int n_gates_registered = 0;
        for (int i = 0; i < cgraph->n_nodes; i++) {
            const ggml_tensor * node = cgraph->nodes[i];
            // Gate tensors appear as src0 of MUL_MAT ops (the router MUL_MAT)
            // and also in the weight tensor list. Check all tensor sources.
            for (int s = 0; s < GGML_MAX_SRC; s++) {
                const ggml_tensor * src = node->src[s];
                if (!src || !src->name || !src->data) {
                    continue;
                }
                if (!strstr(src->name, "ffn_gate_inp")) {
                    continue;
                }
                // Skip shared expert gate (ffn_gate_inp_shexp) and bias (ffn_gate_inp_b)
                if (strstr(src->name, "ffn_gate_inp_shexp") || strstr(src->name, "ffn_gate_inp_b")) {
                    continue;
                }

                // Extract layer number from tensor name (e.g., "blk.5.ffn_gate_inp" -> 5)
                int block_id = ggml_sycl_tp_extract_layer_number(src->name);
                if (block_id < 0) {
                    continue;
                }

                // Map block_id to sequential layer index via the same mapping
                // used by ExpertPredictor. We need to find which seq_layer_id
                // corresponds to MoE layers for this block.
                // Gate weights have shape [n_experts, n_embd] stored as f32.
                const int gate_n_experts = static_cast<int>(src->ne[1]);
                const int gate_n_embd    = static_cast<int>(src->ne[0]);

                if (gate_n_experts != n_experts_per_layer || gate_n_embd <= 0) {
                    continue;
                }

                // Get device pointer for the gate weights
                const void *     gate_ptr = nullptr;
                sycl::usm::alloc atype    = ggml_sycl_get_alloc_type(src->data);
                if (atype == sycl::usm::alloc::device) {
                    gate_ptr = src->data;
                } else {
                    // Try extra->data_device
                    auto * extra = static_cast<ggml_tensor_extra_gpu *>(src->extra);
                    if (extra && extra->data_device_ptr(device)) {
                        gate_ptr = extra->data_device_ptr(device);
                    }
                }

                if (!gate_ptr) {
                    GGML_SYCL_DEBUG("[MOE-HYBRID] Gate tensor %s not on device, skipping pre-gate\n", src->name);
                    continue;
                }

                // Find the sequential layer index for this block's MoE layers.
                // We can't reverse the FNV hash in g_moe_layer_seq, so scan
                // MUL_MAT_ID nodes to find one in this block and get its seq_id.
                int seq_idx = -1;
                for (int j = 0; j < cgraph->n_nodes; j++) {
                    const ggml_tensor * mmid_node = cgraph->nodes[j];
                    if (mmid_node->op != GGML_OP_MUL_MAT_ID) {
                        continue;
                    }
                    const ggml_tensor * mmid_src0 = mmid_node->src[0];
                    if (!mmid_src0 || !mmid_src0->name) {
                        continue;
                    }
                    int mmid_block = ggml_sycl_tp_extract_layer_number(mmid_src0->name);
                    if (mmid_block != block_id) {
                        continue;
                    }
                    int  hash_id = moe_cache_layer_id(mmid_src0->name);
                    auto it      = g_moe_layer_seq[device].find(hash_id);
                    if (it != g_moe_layer_seq[device].end()) {
                        seq_idx = it->second;
                        break;
                    }
                }

                if (seq_idx >= 0) {
                    predictor.register_gate_weights(seq_idx, gate_ptr, gate_n_embd);
                    n_gates_registered++;
                    GGML_SYCL_DEBUG(
                        "[MOE-HYBRID] Registered gate weights for blk.%d "
                        "(seq=%d, n_embd=%d, ptr=%p)\n",
                        block_id, seq_idx, gate_n_embd, gate_ptr);
                    break;  // Found gate for this node, move to next node
                }
            }
        }
        if (n_gates_registered > 0) {
            GGML_LOG_INFO("[MOE-HYBRID] Pre-gated routing: registered %d gate weight tensors\n", n_gates_registered);
        }
    }

    // Initialize PinnedBufferPool for O(1) acquire/release of pinned staging
    // buffers used by CPU expert dispatch (replaces per-call malloc_host/free).
    // max_experts = n_experts_used (top-K per MUL_MAT_ID) for single-token TG.
    if (max_K > 0 && max_N > 0 && max_dispatch_count > 0) {
        auto & pool = g_pinned_buffer_pools[device];
        pool.init(q, device, static_cast<size_t>(max_dispatch_count), static_cast<size_t>(max_K),
                  static_cast<size_t>(max_N));
    }

    // Initialize CPU expert thread pool for persistent async dispatch.
    // Thread count auto-detected (hardware_concurrency - 2) or overridden
    // via GGML_SYCL_CPU_EXPERT_THREADS=N.
    if (max_K > 0 && max_N > 0 && max_dispatch_count > 0) {
        auto & cpu_pool = g_cpu_expert_pools[device];
        cpu_pool.init(0 /* auto thread count */, static_cast<size_t>(max_dispatch_count), static_cast<size_t>(max_K),
                      static_cast<size_t>(max_N), q);
    }

    // -----------------------------------------------------------------------
    // Multi-GPU MoE: complete secondary GPU init (staging buffers, buffer pools).
    // Queues and caches were already registered in the early init block above.
    // -----------------------------------------------------------------------
    if (device == 0 && g_moe_multi_gpu_active.load(std::memory_order_acquire)) {
        const int total_devices  = ggml_sycl_info().total_gpu_count;
        int       n_secondary_ok = 0;

        for (int gpu_d = 1; gpu_d < total_devices && gpu_d < GGML_SYCL_MAX_DEVICES; gpu_d++) {
            if (!g_secondary_queues[gpu_d]) {
                continue;  // Early init failed for this device
            }
            GGML_LOG_INFO("[MOE-MULTI-GPU] Initializing device %d for MoE expert dispatch\n", gpu_d);

            try {
                if (max_K > 0 && max_N > 0 && max_dispatch_count > 0) {
                    auto & pool_d = g_pinned_buffer_pools[gpu_d];
                    pool_d.init(*g_secondary_queues[gpu_d], gpu_d, static_cast<size_t>(max_dispatch_count),
                                static_cast<size_t>(max_K), static_cast<size_t>(max_N));
                }

                // Allocate malloc_host staging buffer for secondary GPU expert outputs.
                // malloc_host is PCIe zero-copy readable from primary GPU's compute queue.
                const size_t staging_floats = static_cast<size_t>(max_dispatch_count) * static_cast<size_t>(max_N);
                const size_t staging_bytes  = staging_floats * sizeof(float);
                try {
                    // Use device 0's queue for unified host-pinned allocation so the
                    // unified cache owns the staging lifetime even in multi-GPU mode.
                    if (g_secondary_staging_alloc[gpu_d].ensure(
                            q, device, staging_bytes, ggml_sycl::alloc_role::STAGING,
                            ggml_sycl::runtime_category::STAGING, "moe_secondary_staging", true)) {
                        g_secondary_staging_buffer[gpu_d] = g_secondary_staging_alloc[gpu_d].as<float>();
                        g_secondary_staging_size[gpu_d]   = staging_floats;
                        g_secondary_staging_max_N[gpu_d]  = static_cast<size_t>(max_N);
                    }
                    if (g_secondary_staging_buffer[gpu_d]) {
                        GGML_LOG_INFO(
                            "[MOE-MULTI-GPU] Device %d staging buffer: %.1f KB "
                            "(max_dispatch=%d, N=%ld)\n",
                            gpu_d, staging_bytes / 1024.0, max_dispatch_count, (long) max_N);
                    }
                } catch (const sycl::exception & e) {
                    GGML_LOG_WARN("[MOE-MULTI-GPU] Failed to allocate staging buffer for device %d: %s\n", gpu_d,
                                  e.what());
                    g_secondary_staging_buffer[gpu_d] = nullptr;
                    g_secondary_staging_size[gpu_d]   = 0;
                }

                if (g_secondary_staging_buffer[gpu_d]) {
                    n_secondary_ok++;
                    GGML_LOG_INFO("[MOE-MULTI-GPU] Device %d ready for MoE dispatch\n", gpu_d);
                } else {
                    GGML_LOG_WARN("[MOE-MULTI-GPU] Device %d initialization incomplete\n", gpu_d);
                }
            } catch (const sycl::exception & e) {
                GGML_LOG_WARN("[MOE-MULTI-GPU] Failed to initialize device %d: %s\n", gpu_d, e.what());
            } catch (const std::exception & e) {
                GGML_LOG_WARN("[MOE-MULTI-GPU] Failed to initialize device %d: %s\n", gpu_d, e.what());
            }
        }

        if (n_secondary_ok > 0) {
            GGML_LOG_INFO("[MOE-MULTI-GPU] Active: primary (dev 0) + %d secondary device(s)\n", n_secondary_ok);
        } else {
            // Early init registered caches but no staging buffers available.
            // Deactivate multi-GPU since activation shipping requires staging.
            g_moe_multi_gpu_active.store(false, std::memory_order_release);
            GGML_LOG_WARN(
                "[MOE-MULTI-GPU] No secondary devices completed init, "
                "falling back to single-GPU\n");
        }
    }

    // -----------------------------------------------------------------------
    // Build gate→up tensor pairing map for fused CPU expert dispatch.
    // Scans MUL_MAT_ID nodes for paired ffn_gate_exps/ffn_up_exps tensors.
    // -----------------------------------------------------------------------
    {
        // Collect all MUL_MAT_ID tensors by block number + type (gate/up/down)
        struct mmid_tensor_info {
            const ggml_tensor * tensor;
            int                 block_id;
            bool                is_gate;
            bool                is_up;
        };

        std::vector<mmid_tensor_info> mmid_tensors;

        for (int i = 0; i < cgraph->n_nodes; i++) {
            const ggml_tensor * node = cgraph->nodes[i];
            if (node->op != GGML_OP_MUL_MAT_ID || !node->src[0] || !node->src[0]->name) {
                continue;
            }
            const ggml_tensor * src0     = node->src[0];
            const char *        name     = src0->name;
            int                 block_id = ggml_sycl_tp_extract_layer_number(name);
            if (block_id < 0) {
                continue;
            }
            bool is_gate = (strstr(name, "ffn_gate") != nullptr);
            bool is_up   = (strstr(name, "ffn_up") != nullptr);
            if (is_gate || is_up) {
                mmid_tensors.push_back({ src0, block_id, is_gate, is_up });
            }
        }

        // Pair gate→up within same block
        int n_pairs = 0;
        for (const auto & gate_info : mmid_tensors) {
            if (!gate_info.is_gate) {
                continue;
            }
            for (const auto & up_info : mmid_tensors) {
                if (!up_info.is_up || up_info.block_id != gate_info.block_id) {
                    continue;
                }
                if (gate_info.tensor->ne[0] != up_info.tensor->ne[0] ||
                    gate_info.tensor->ne[1] != up_info.tensor->ne[1]) {
                    continue;
                }
                if (gate_info.tensor->type != up_info.tensor->type) {
                    continue;
                }

                gate_up_pair pair;
                // Only store up_data if it's host-accessible (safe for CPU vec_dot).
                // Device-resident tensor data must not be dereferenced from host.
                const bool up_host_accessible = up_info.tensor->buffer &&
                                                ggml_backend_buffer_is_host(up_info.tensor->buffer);
                pair.up_data                            = up_host_accessible ? up_info.tensor->data : nullptr;
                pair.nb02                               = up_info.tensor->nb[2];
                pair.type                               = up_info.tensor->type;
                pair.K                                  = up_info.tensor->ne[0];
                pair.N                                  = up_info.tensor->ne[1];
                // Map key: tensor->data as opaque identifier (not dereferenced)
                g_gate_up_pairs[gate_info.tensor->data] = pair;
                n_pairs++;
                break;  // One up per gate
            }
        }
        if (n_pairs > 0) {
            GGML_LOG_INFO("[MOE-FUSION] Paired %d gate→up tensors for fused CPU dispatch\n", n_pairs);
        }
    }

    // -----------------------------------------------------------------------
    // Zero-warmup gate-norm placement: when GGML_SYCL_MOE_WARMUP_TOKENS=0,
    // compute gate weight norms to rank experts by routing probability and
    // pre-stage hot experts to VRAM immediately — no inference warmup needed.
    // -----------------------------------------------------------------------
    if (g_moe_warmup.warmup_tokens == 0) {
        moe_compute_gate_norm_placement(cgraph, device);
    }

    // -----------------------------------------------------------------------
    // Pre-allocate pinned host memory chunks so that inference-time allocations
    // in the host arena never call sycl::malloc_host (which blocks the Level
    // Zero driver when the device has pending operations, causing MoE hangs).
    // Estimate: top-K experts * expert_size * 2 (double-buffer) per MoE layer,
    // plus generous headroom.  Allocate at least 2 GB to cover the working set
    // of a 120B MoE model's CPU expert dispatch.
    // -----------------------------------------------------------------------
    {
        auto * cache = ggml_sycl::get_unified_cache_for_device(device);
        if (cache) {
            const size_t estimated_working_set =
                static_cast<size_t>(n_experts_used > 0 ? n_experts_used : 4) * expert_weight_bytes * 2  // double-buffer
                * static_cast<size_t>(n_moe_layers > 0 ? std::min(n_moe_layers, 8) : 1);
            // At least 2 GB to handle burst demand without runtime malloc_host
            const size_t min_pre_alloc   = static_cast<size_t>(2ULL * 1024ULL * 1024ULL * 1024ULL);
            const size_t pre_alloc_bytes = std::max(estimated_working_set, min_pre_alloc);
            // 120B MoE safety net: pre-grow the pinned pool to the estimated expert working set
            // (double-buffered, up to 8 MoE layers, 2 GB floor) so runtime malloc_host never
            // stalls mid-token on bulk expert weight demand.
            const size_t chunks_grown    = cache->pre_allocate_host_pool(pre_alloc_bytes);
            if (chunks_grown > 0) {
                GGML_LOG_INFO("[MOE-HYBRID] Pre-allocated %zu pinned chunks for %.1f MB working set\n", chunks_grown,
                              pre_alloc_bytes / (1024.0 * 1024.0));
            }
        }
    }

    // -----------------------------------------------------------------------
    // Phase 4: Pre-allocate MoE inference buffers (expert pointer tables +
    // IDs staging) via the unified cache allocation API.  This eliminates
    // runtime malloc_device calls during graph_compute_impl.
    //
    // n_moe_layers here counts total MUL_MAT_ID nodes (gate+up+down for each
    // block), so use n_moe_tensors=1 and the sequential index from
    // g_moe_layer_seq as the table_index directly.
    // -----------------------------------------------------------------------
    {
        ggml_sycl::moe_buffer_params moe_params{};
        moe_params.n_experts     = n_experts_per_layer;
        moe_params.n_expert_used = n_experts_used > 0 ? n_experts_used : 4;
        moe_params.max_batch     = 512;
        moe_params.n_moe_layers  = n_moe_layers;  // total MUL_MAT_ID nodes
        moe_params.n_moe_tensors = 1;             // seq index is per-tensor already
        moe_params.n_embd        = max_K > 0 ? max_K : 4096;
        if (ggml_sycl::moe_preallocate_inference_buffers(device, moe_params)) {
            GGML_LOG_INFO(
                "[MOE-HYBRID] Phase 4: pre-allocated MoE inference buffers "
                "(device=%d, tables=%d, experts=%d)\n",
                device, n_moe_layers, n_experts_per_layer);
        } else {
            GGML_LOG_WARN(
                "[MOE-HYBRID] Phase 4: MoE buffer pre-allocation failed "
                "(device=%d) — falling back to runtime allocation\n",
                device);
        }
    }
}

// Layout-size helpers (defined later).
static size_t ggml_sycl_layout_bytes_for_tensor(const ggml_tensor * tensor, layout_mode layout, int device);
static size_t ggml_sycl_layout_bytes_for_dims(ggml_type   type,
                                              int64_t     ncols,
                                              int64_t     nrows,
                                              layout_mode layout,
                                              int         device);
static size_t ggml_sycl_layout_bytes_coalesced_for_dims(ggml_type type, int64_t ncols, int64_t nrows);
static int    ggml_sycl_layout_priority(layout_mode mode);

static constexpr size_t  k_reorder_guard_bytes   = 64;
static constexpr uint8_t k_reorder_guard_pattern = 0xA5;

struct ggml_sycl_canonical_checksum_info {
    size_t   bytes    = 0;
    uint64_t checksum = 0;
};

static std::mutex                                                         g_sycl_canonical_checksum_mutex;
static std::unordered_map<std::string, ggml_sycl_canonical_checksum_info> g_sycl_canonical_checksums;

static uint64_t ggml_sycl_fnv1a64(const uint8_t * data, size_t len) {
    uint64_t hash = 1469598103934665603ULL;  // FNV offset basis
    for (size_t i = 0; i < len; ++i) {
        hash ^= static_cast<uint64_t>(data[i]);
        hash *= 1099511628211ULL;  // FNV prime
    }
    return hash;
}

static void ggml_sycl_maybe_capture_canonical_checksum(const ggml_tensor * tensor, const void * data, size_t size) {
    if (!tensor || !data || size == 0 || tensor->name[0] == '\0') {
        return;
    }
    static int         enabled = -1;
    static std::string filter;
    static size_t      bytes_limit = 4096;
    if (enabled < 0) {
        const char * env = std::getenv("GGML_SYCL_CANONICAL_CHECKSUM_TENSOR");
        enabled          = (env && env[0] != '\0') ? 1 : 0;
        if (enabled) {
            filter = env;
        }
        if (const char * bytes_env = std::getenv("GGML_SYCL_CANONICAL_CHECKSUM_BYTES")) {
            const long long v = std::atoll(bytes_env);
            if (v > 0) {
                bytes_limit = static_cast<size_t>(v);
            }
        }
    }
    if (!enabled) {
        return;
    }
    if (filter[0] != '\0' && std::strstr(tensor->name, filter.c_str()) == nullptr) {
        return;
    }

    const size_t bytes    = std::min(bytes_limit, size);
    const auto   checksum = ggml_sycl_fnv1a64(static_cast<const uint8_t *>(data), bytes);
    {
        std::lock_guard<std::mutex> lock(g_sycl_canonical_checksum_mutex);
        g_sycl_canonical_checksums[std::string(tensor->name)] = ggml_sycl_canonical_checksum_info{ bytes, checksum };
    }
    GGML_LOG_INFO("[CANONICAL-CHECKSUM] captured tensor=%s bytes=%zu checksum=0x%016llx\n", tensor->name, bytes,
                  (unsigned long long) checksum);
}

static bool ggml_sycl_get_canonical_checksum(const char * name, ggml_sycl_canonical_checksum_info & out) {
    if (!name || name[0] == '\0') {
        return false;
    }
    std::lock_guard<std::mutex> lock(g_sycl_canonical_checksum_mutex);
    auto                        it = g_sycl_canonical_checksums.find(std::string(name));
    if (it == g_sycl_canonical_checksums.end()) {
        return false;
    }
    out = it->second;
    return true;
}

// Check if unified dispatch is enabled via environment variable
// Unified dispatch defaults to enabled; set GGML_SYCL_UNIFIED_DISPATCH=0 to disable.
static bool ggml_sycl_unified_dispatch_enabled() {
    int val = g_ggml_sycl_unified_dispatch.load(std::memory_order_acquire);
    if (val < 0) {
        const char * env     = std::getenv("GGML_SYCL_UNIFIED_DISPATCH");
        int          new_val = (env == nullptr || std::atoi(env) != 0) ? 1 : 0;
        // Only one thread will successfully CAS from -1
        g_ggml_sycl_unified_dispatch.compare_exchange_strong(val, new_val, std::memory_order_release,
                                                             std::memory_order_acquire);
        val = g_ggml_sycl_unified_dispatch.load(std::memory_order_acquire);
    }
    return val != 0;
}

// Check if VRAM placement is forced via environment variable
// When GGML_SYCL_FORCE_VRAM=1, always prefers VRAM placement regardless of budget
static bool ggml_sycl_force_vram_enabled() {
    int val = g_ggml_sycl_force_vram.load(std::memory_order_acquire);
    if (val < 0) {
        const char * env     = std::getenv("GGML_SYCL_FORCE_VRAM");
        int          new_val = (env != nullptr && std::atoi(env) != 0) ? 1 : 0;
        g_ggml_sycl_force_vram.compare_exchange_strong(val, new_val, std::memory_order_release,
                                                       std::memory_order_acquire);
        val = g_ggml_sycl_force_vram.load(std::memory_order_acquire);
    }
    return val != 0;
}

// SoA layout is ON by default for all batch sizes (TG and PP).
// TG: MMVQ reads SOA directly for coalesced access → 2-3x decode speedup.
// PP: dequant kernel converts SOA→FP16, oneDNN sees FP16 — no AOS needed.
// Set GGML_SYCL_UNIFIED_SOA=0 to force AoS layout (for debugging or if SoA causes issues).
static bool ggml_sycl_unified_soa_enabled() {
    static int enabled = -1;
    if (enabled < 0) {
        const char * env = std::getenv("GGML_SYCL_UNIFIED_SOA");
        enabled          = (env && std::atoi(env) == 0) ? 0 : 1;  // Default ON
        if (!enabled) {
            fprintf(stderr, "[SYCL] Unified kernel SoA layout DISABLED (GGML_SYCL_UNIFIED_SOA=0)\n");
        }
    }
    return enabled != 0;
}

// Persistent TG can request SoA independently of global UNIFIED_SOA.
static bool ggml_sycl_persistent_tg_soa_enabled() {
    static int enabled = -1;
    if (enabled < 0) {
        const char * persistent_tg = std::getenv("GGML_SYCL_PERSISTENT_TG");
        // Default ON — set =0 to disable
        const bool   persistent_on = (persistent_tg == nullptr || std::atoi(persistent_tg) != 0);
        const char * prefer_soa    = std::getenv("GGML_SYCL_PERSISTENT_TG_PREFER_SOA");
        const bool   prefer_on     = (prefer_soa == nullptr || std::atoi(prefer_soa) != 0);
        enabled                    = (persistent_on && prefer_on) ? 1 : 0;
    }
    return enabled != 0;
}

// Unified kernel previously required AoS inputs. Now it supports both layouts.
// Returns true if we should force AoS (for backward compatibility), false to allow SoA.
static bool ggml_sycl_unified_kernel_requires_aos(ggml_type type) {
    // If unified dispatch is not enabled, don't constrain layout
    if (!ggml_sycl_unified_dispatch_enabled() || !ggml_sycl::is_unified_kernel_enabled() ||
        !ggml_sycl::should_use_unified(type)) {
        return false;
    }
    // If SoA is explicitly enabled, allow it.
    if (ggml_sycl_unified_soa_enabled() || ggml_sycl_persistent_tg_soa_enabled()) {
        return false;
    }
    // Default: require AoS for backward compatibility
    return true;
}

static bool ggml_sycl_reorder_guard_enabled() {
    const char * env = std::getenv("GGML_SYCL_REORDER_GUARD");
    return env && std::atoi(env) != 0;
}

static bool ggml_sycl_debug_set_tensor_i32_enabled() {
    static int enabled = -1;
    if (enabled < 0) {
        const char * env = std::getenv("GGML_SYCL_DEBUG_SET_TENSOR_I32");
        enabled          = (env && std::atoi(env) != 0) ? 1 : 0;
    }
    return enabled != 0;
}

static bool ggml_sycl_check_reorder_guard(const void * base,
                                          size_t       size,
                                          size_t       guard_size,
                                          const char * where,
                                          const char * tensor_name) {
    if (guard_size == 0 || base == nullptr) {
        return true;
    }
    const uint8_t * guard = static_cast<const uint8_t *>(base) + size;
    for (size_t i = 0; i < guard_size; ++i) {
        if (guard[i] != k_reorder_guard_pattern) {
            GGML_LOG_ERROR("[SYCL] reorder guard corrupted at %s for %s (size=%zu guard=%zu)\n", where,
                           tensor_name ? tensor_name : "(unnamed)", size, guard_size);
            return false;
        }
    }
    return true;
}

static bool ggml_sycl_check_reorder_guard_dual(const void * base,
                                               size_t       size,
                                               size_t       guard_size,
                                               const char * where,
                                               const char * tensor_name) {
    if (guard_size == 0 || base == nullptr) {
        return true;
    }
    const uint8_t * raw = static_cast<const uint8_t *>(base);
    for (size_t i = 0; i < guard_size; ++i) {
        if (raw[i] != k_reorder_guard_pattern) {
            GGML_LOG_ERROR("[SYCL] reorder guard prefix corrupted at %s for %s (size=%zu guard=%zu)\n", where,
                           tensor_name ? tensor_name : "(unnamed)", size, guard_size);
            return false;
        }
    }
    const uint8_t * suffix = raw + guard_size + size;
    for (size_t i = 0; i < guard_size; ++i) {
        if (suffix[i] != k_reorder_guard_pattern) {
            GGML_LOG_ERROR("[SYCL] reorder guard suffix corrupted at %s for %s (size=%zu guard=%zu)\n", where,
                           tensor_name ? tensor_name : "(unnamed)", size, guard_size);
            return false;
        }
    }
    return true;
}

