bool ggml_sycl_reorder_enabled() {
    // Check environment variable to disable reordering
    static int disabled = -1;
    if (disabled < 0) {
        const char * env = std::getenv("GGML_SYCL_DISABLE_REORDER");
        disabled         = (env && std::atoi(env) != 0) ? 1 : 0;
    }
    if (disabled) {
        return false;
    }

    ggml_layout_mode override = GGML_LAYOUT_AOS;
    if (ggml_sycl::test_get_layout_override(&override) && override == GGML_LAYOUT_AOS) {
        return false;
    }
    return true;
}

static bool ggml_sycl_reorder_allowed_for_type(ggml_type type) {
    // Unified kernel requires AoS inputs and reorders internally.
    // Reordering ahead of time would double-reorder and corrupt results.
    if (ggml_sycl_unified_kernel_requires_aos(type)) {
        return false;
    }
    return ggml_sycl_reorder_enabled();
}

// =============================================================================
// Tensor Classification for Tiered Memory Placement
// =============================================================================

// Classify tensor for tiered placement
// Returns: 0=dense, 1=expert, 2=other
extern "C" int ggml_sycl_classify_tensor(const char * name) {
    if (!name) {
        return 2;
    }

    // Check for expert patterns (MoE layers)
    if (strstr(name, "_exps.") != nullptr || strstr(name, "_exps_") != nullptr) {
        return 1;  // Expert
    }

    // Check for dense layer patterns
    if (strstr(name, "blk.") != nullptr) {
        // Attention and FFN weights in blocks are dense
        if (strstr(name, "attn_") != nullptr || strstr(name, "ffn_") != nullptr) {
            return 0;  // Dense
        }
    }

    return 2;  // Other (embeddings, norms, etc.)
}

// Select buffer type for tensor based on tier availability
// This is a helper for model loading - actual routing happens in llama-model.cpp
// tensor_name: name of the tensor to place
// tensor_size: size of the tensor in bytes
// vram_available: available VRAM in bytes
// pinned_available: available pinned host memory in bytes
// Returns: appropriate buffer type for the tensor
extern "C" ggml_backend_buffer_type_t ggml_sycl_select_buffer_for_tensor(const char * tensor_name,
                                                                         size_t       tensor_size,
                                                                         size_t       vram_available,
                                                                         size_t       pinned_available) {
    (void) tensor_name;  // Currently unused - classification could influence placement in future

    // Try VRAM first for any tensor
    if (tensor_size <= vram_available) {
        return ggml_backend_sycl_buffer_type(0);  // VRAM
    }

    // Overflow to pinned host
    if (tensor_size <= pinned_available) {
        return ggml_backend_sycl_host_buffer_type();  // Pinned host
    }

    // Last resort: CPU buffer (will use mmap)
    return ggml_backend_cpu_buffer_type();
}

static const char * ggml_sycl_layout_mode_name(ggml_layout_mode mode) {
    switch (mode) {
        case GGML_LAYOUT_AOS:
            return "aos";
        case GGML_LAYOUT_SOA:
            return "soa";
        case GGML_LAYOUT_COALESCED:
            return "coalesced";
        case GGML_LAYOUT_XMX_TILED:
            return "xmx_tiled";
        case GGML_LAYOUT_XMX_GEMM_TILED:
            return "xmx_gemm_tiled";
        case GGML_LAYOUT_ONEDNN_PACKED:
            return "onednn_packed";
        case GGML_LAYOUT_ONEDNN_WOQ:
            return "onednn_woq";
        default:
            return "unknown";
    }
}

static bool ggml_sycl_layout_mode_from_string(const char * value, layout_mode * out) {
    if (!value || !out) {
        return false;
    }
    std::string lower(value);
    std::transform(lower.begin(), lower.end(), lower.begin(),
                   [](unsigned char c) { return static_cast<char>(std::tolower(c)); });

    if (lower == "aos" || lower == "none") {
        *out = GGML_LAYOUT_AOS;
        return true;
    }
    if (lower == "soa") {
        *out = GGML_LAYOUT_SOA;
        return true;
    }
    if (lower == "coalesced" || lower == "coa") {
        *out = GGML_LAYOUT_COALESCED;
        return true;
    }
    if (lower == "xmx_tiled" || lower == "xmx") {
        *out = GGML_LAYOUT_XMX_TILED;
        return true;
    }
    if (lower == "xmx_gemm_tiled" || lower == "xmx_gemm") {
        *out = GGML_LAYOUT_XMX_GEMM_TILED;
        return true;
    }
    if (lower == "onednn_packed" || lower == "onednn") {
        *out = GGML_LAYOUT_ONEDNN_PACKED;
        return true;
    }
    if (lower == "onednn_woq" || lower == "woq") {
        *out = GGML_LAYOUT_ONEDNN_WOQ;
        return true;
    }
    return false;
}

static void ggml_sycl_debug_dump_tensor_meta(const char * tag, const ggml_tensor * t) {
    if (t == nullptr) {
        fprintf(stderr, "[SYCL-ADD-DBG] %s: null tensor\n", tag);
        return;
    }
    const char * layout_mode = "none";
    const void * layout_ptr  = nullptr;
    size_t       layout_size = 0;
    if (t->layout) {
        layout_mode = ggml_sycl_layout_mode_name(t->layout->mode);
        layout_ptr  = t->layout->data_ptr;
        layout_size = t->layout->size;
    }
    fprintf(stderr,
            "[SYCL-ADD-DBG] %s: name=%s type=%s op=%s ne=[%lld,%lld,%lld,%lld] nb=[%zu,%zu,%zu,%zu] contig=%d "
            "data=%p view_src=%s view_offs=%zu layout_mode=%s layout_ptr=%p layout_size=%zu\n",
            tag, t->name, ggml_type_name(t->type), ggml_op_name(t->op), (long long) t->ne[0], (long long) t->ne[1],
            (long long) t->ne[2], (long long) t->ne[3], t->nb[0], t->nb[1], t->nb[2], t->nb[3], ggml_is_contiguous(t),
            t->data, t->view_src ? t->view_src->name : "none", t->view_offs, layout_mode, layout_ptr, layout_size);
}

// Maximum batch size for fused ESIMD MoE kernel.
// Larger batches (e.g., prefill with 512 tokens) fall back to host-side oneDNN batching
// which is ~7x faster for large batches (679 t/s vs 87 t/s on GPT-OSS 20B).
// The fused kernel excels at decode (single-token) but is slower than oneDNN for prefill.
// Override with GGML_SYCL_FUSED_MOE_MAX_BATCH=N env var (0 = always use oneDNN).
static int64_t get_fused_moe_max_batch() {
    static int64_t val = []() -> int64_t {
        const char * env = std::getenv("GGML_SYCL_FUSED_MOE_MAX_BATCH");
        if (env) {
            int v = std::atoi(env);
            GGML_LOG_INFO("[MoE] FUSED_MOE_MAX_BATCH override: %d\n", v);
            return v >= 0 ? v : 32;
        }
        return 32;
    }();
    return val;
}

#define GGML_SYCL_FUSED_MOE_MAX_BATCH (get_fused_moe_max_batch())

// Model load phase flag - when true, skip weight caching to avoid OOM during load
static std::atomic<bool> g_sycl_in_model_load{ false };

// Track backend lifetime for shared host-weight extras cleanup.
static std::atomic<int> g_sycl_backend_refcount{ 0 };

// Host-backed weight extras (Strategy B): track for cleanup on backend teardown.
static std::mutex                                                 g_sycl_host_weight_extras_mutex;
static std::unordered_map<ggml_tensor *, ggml_tensor_extra_gpu *> g_sycl_host_weight_extras;

const void * ggml_sycl_lookup_host_weight_ptr_by_name(const char * name) {
    if (name == nullptr || name[0] == '\0') {
        return nullptr;
    }

    std::lock_guard<std::mutex> lock(g_sycl_host_weight_extras_mutex);
    for (const auto & entry : g_sycl_host_weight_extras) {
        const ggml_tensor * tensor = entry.first;
        if (tensor == nullptr || tensor->name == nullptr) {
            continue;
        }
        if (std::strcmp(tensor->name, name) == 0) {
            const void * host_ptr = ggml_sycl_host_data(tensor);
            if (host_ptr != nullptr) {
                return host_ptr;
            }
        }
    }

    return nullptr;
}

static std::atomic<uint64_t> g_sycl_weight_cache_uuid{ 1 };

// Routing indices cache for MoE expert pre-staging.
// Captures argsort output for MoE router tensors to enable routing-aware caching.
// This allows pre-staging only the needed experts instead of all 128 (for large MoE models).
struct routing_indices_cache {
    int32_t *               host_indices = nullptr;  // Unified-cache pinned host buffer [ncols * nrows]
    size_t                  capacity     = 0;        // Number of int32_t elements allocated in host_indices
    ggml_sycl::alloc_handle host_alloc;              // Ownership for host_indices
    int                     ncols;                   // Number of columns (e.g., n_experts)
    int                     nrows;                   // Number of rows (e.g., n_tokens)
    std::string             tensor_name;             // Name of the argsort output tensor
    std::mutex              mutex;                   // Thread-safe access
    sycl::event             pending_event;           // Deferred D2H copy event (waited lazily on access)
    bool                    has_pending;             // True if pending_event needs waiting

    routing_indices_cache() : ncols(0), nrows(0), has_pending(false) {}

    // Complete any pending async copy. Caller must hold mutex.
    void wait_pending() {
        if (has_pending) {
            pending_event.wait();
            has_pending = false;
        }
    }
};

static routing_indices_cache g_routing_indices_cache;

// Check if tensor name indicates MoE routing (should capture indices)
static bool is_moe_routing_tensor(const char * name) {
    if (!name || name[0] == '\0') {
        return false;
    }
    // Look for common MoE tensor naming patterns:
    // - "ffn_moe_*" (llama.cpp MoE naming)
    // - "*moe*topk*" (top-k selection)
    // - "*router*" (router output)
    // - "*gate*" with "moe" somewhere
    const char * lower_name = name;  // Already lowercase in ggml typically
    return (strstr(lower_name, "moe") != nullptr) || (strstr(lower_name, "router") != nullptr) ||
           (strstr(lower_name, "topk") != nullptr);
}

static bool routing_index_capture_enabled() {
    static std::atomic<int> enabled{ -1 };
    int                     val = enabled.load(std::memory_order_acquire);
    if (val < 0) {
        const char * env  = std::getenv("GGML_SYCL_CAPTURE_ROUTING_INDICES");
        const int    next = (env && std::atoi(env) != 0) ? 1 : 0;
        enabled.compare_exchange_strong(val, next, std::memory_order_release, std::memory_order_acquire);
        val = enabled.load(std::memory_order_acquire);
    }
    return val != 0;
}

// Store routing indices in cache (called after argsort for MoE tensors)
static void store_routing_indices(const char *    tensor_name,
                                  const int32_t * indices,
                                  int             ncols,
                                  int             nrows,
                                  sycl::queue *   stream) {
    if (!tensor_name || !indices || ncols <= 0 || nrows <= 0) {
        return;
    }
    // Graph recording forbids event.wait(). Skip routing capture during recording to
    // keep MoE graphs compatible; blind preload handles <= threshold expert counts.
    if (g_ggml_sycl_graph_recording) {
        return;
    }

    const size_t            count = static_cast<size_t>(ncols) * static_cast<size_t>(nrows);
    ggml_sycl::alloc_handle new_alloc{};
    int32_t *               host_indices = nullptr;
    {
        std::lock_guard<std::mutex> lock(g_routing_indices_cache.mutex);
        if (g_routing_indices_cache.capacity < count || g_routing_indices_cache.host_indices == nullptr) {
            g_routing_indices_cache.wait_pending();
            if (g_routing_indices_cache.host_alloc.ptr) {
                (void) ggml_sycl::unified_free(g_routing_indices_cache.host_alloc);
                g_routing_indices_cache.host_alloc   = {};
                g_routing_indices_cache.host_indices = nullptr;
                g_routing_indices_cache.capacity     = 0;
            }

            ggml_sycl::alloc_request req{};
            req.queue                               = stream;
            req.device                              = ggml_sycl_get_device_id_from_queue(*stream);
            req.size                                = count * sizeof(int32_t);
            req.intent.role                         = ggml_sycl::alloc_role::STAGING;
            req.intent.category                     = ggml_sycl::runtime_category::HOST_COMPUTE;
            req.intent.constraints.must_host_pinned = true;
            req.intent.constraints.use_pinned_pool  = true;
            if (!ggml_sycl::unified_alloc(req, &new_alloc) || !new_alloc.ptr) {
                GGML_LOG_WARN("[ROUTING] Failed to allocate %zu bytes of pinned host staging for '%s'\n",
                              count * sizeof(int32_t), tensor_name);
                return;
            }
            g_routing_indices_cache.host_alloc   = new_alloc;
            g_routing_indices_cache.host_indices = static_cast<int32_t *>(new_alloc.ptr);
            g_routing_indices_cache.capacity     = count;
        }
        host_indices = g_routing_indices_cache.host_indices;
    }

    sycl::event copy_event{};
    try {
        // Async D2H copy — deferred wait on consumer access (get_routing_indices).
        // The in-order stream guarantees this memcpy completes before any subsequent
        // kernels on the same stream, so we only need to wait when the HOST reads it.
        copy_event = stream->memcpy(host_indices, indices, count * sizeof(int32_t));
    } catch (const sycl::exception & e) {
        GGML_LOG_WARN("[ROUTING] Failed to enqueue routing-index readback for '%s': %s\n", tensor_name, e.what());
        return;
    }

    {
        std::lock_guard<std::mutex> lock(g_routing_indices_cache.mutex);
        g_routing_indices_cache.ncols         = ncols;
        g_routing_indices_cache.nrows         = nrows;
        g_routing_indices_cache.tensor_name   = tensor_name;
        g_routing_indices_cache.pending_event = copy_event;
        g_routing_indices_cache.has_pending   = true;
    }

    GGML_SYCL_DEBUG("[ROUTING] Submitted async %d x %d indices for tensor '%s'\n", ncols, nrows, tensor_name);
}

// Public API: Get routing indices from cache
// Returns true if found, false otherwise
bool ggml_sycl_get_routing_indices(const char *           tensor_name,
                                   std::vector<int32_t> & out_indices,
                                   int &                  n_expert_used,
                                   int &                  n_tokens) {
    std::lock_guard<std::mutex> lock(g_routing_indices_cache.mutex);

    // Check if we have cached indices for this tensor
    if (g_routing_indices_cache.tensor_name.empty()) {
        return false;  // No cached data
    }

    // If tensor_name is provided, check for match
    if (tensor_name && tensor_name[0] != '\0') {
        if (g_routing_indices_cache.tensor_name != tensor_name) {
            return false;  // Different tensor
        }
    }

    // Complete deferred D2H copy before reading host buffer
    g_routing_indices_cache.wait_pending();

    // Return cached data
    const size_t count =
        static_cast<size_t>(g_routing_indices_cache.ncols) * static_cast<size_t>(g_routing_indices_cache.nrows);
    out_indices.assign(g_routing_indices_cache.host_indices, g_routing_indices_cache.host_indices + count);
    n_expert_used = g_routing_indices_cache.ncols;  // ncols = n_experts (sorted)
    n_tokens      = g_routing_indices_cache.nrows;

    return true;
}

// Public API: Clear routing indices cache
void ggml_sycl_clear_routing_indices_cache() {
    std::lock_guard<std::mutex> lock(g_routing_indices_cache.mutex);
    g_routing_indices_cache.wait_pending();
    if (g_routing_indices_cache.host_alloc.ptr) {
        (void) ggml_sycl::unified_free(g_routing_indices_cache.host_alloc);
        g_routing_indices_cache.host_alloc = {};
    }
    g_routing_indices_cache.host_indices = nullptr;
    g_routing_indices_cache.capacity     = 0;
    g_routing_indices_cache.ncols        = 0;
    g_routing_indices_cache.nrows        = 0;
    g_routing_indices_cache.tensor_name.clear();
}

