static int ggml_sycl_device_id_from_backend_dev(ggml_backend_dev_t dev) {
    if (!dev) {
        return -1;
    }

    ggml_backend_reg_t reg = ggml_backend_sycl_reg();
    const size_t       n   = ggml_backend_reg_dev_count(reg);
    for (size_t i = 0; i < n; ++i) {
        if (ggml_backend_reg_dev_get(reg, i) == dev) {
            return static_cast<int>(i);
        }
    }

    return -1;
}

static void ggml_sycl_release_host_weight_extras(ggml_sycl_host_weight_release_mode mode) {
    std::lock_guard<std::mutex> lock(g_sycl_host_weight_extras_mutex);
    if (mode == ggml_sycl_host_weight_release_mode::registry_only) {
        g_sycl_host_weight_extras.clear();
        return;
    }
    for (auto & entry : g_sycl_host_weight_extras) {
        ggml_tensor *           tensor = entry.first;
        ggml_tensor_extra_gpu * extra  = entry.second;
        if (extra) {
            // Clear tensor's pointers BEFORE releasing extra to prevent use-after-free.
            // The tensor may still be accessed later (e.g., during graph compute), and if
            // tensor->extra points to freed memory, we get heap corruption/SIGSEGV.
            if (tensor && tensor->extra == extra) {
                tensor->extra  = nullptr;
                tensor->layout = nullptr;
            }
            release_extra_gpu(extra);
        }
    }
    g_sycl_host_weight_extras.clear();
}

static void ggml_sycl_release_xmx_aos_staging(ggml_tensor_extra_gpu * extra, int device, sycl::queue * stream) {
    if (!extra || !stream || device < 0 || device >= GGML_SYCL_MAX_DEVICES) {
        return;
    }
    void * staging = extra->xmx_staging_ptr(device);
    if (staging) {
        if (extra->xmx_mxfp4_tiled_aos_staging_alloc[device].ptr) {
            ggml_sycl::unified_free(extra->xmx_mxfp4_tiled_aos_staging_alloc[device]);
            extra->xmx_mxfp4_tiled_aos_staging_alloc[device] = {};
        } else {
            GGML_ASSERT(
                false &&
                "xmx_mxfp4_tiled_aos_staging: legacy sycl::free path reached — alloc_handle should always be set");
        }
        extra->xmx_mxfp4_tiled_aos_staging[device]      = nullptr;
        extra->xmx_mxfp4_tiled_aos_staging_size[device] = 0;
    }
}

bool ggml_backend_sycl_weights_evictable(void) {
    // Check env var first (explicit user preference)
    static std::atomic<int> g_env_cached{ -1 };  // -1 = uninitialized, 0 = false, 1 = true, 2 = auto
    int                     env_cached = g_env_cached.load(std::memory_order_acquire);
    if (env_cached == -1) {
        int resolved = 2;  // default = auto (follow S1 all-weights-host mode)
        if (ggml_sycl::unified_cache_enabled()) {
            const char * env = std::getenv("GGML_SYCL_WEIGHTS_EVICTABLE");
            if (env != nullptr) {
                resolved = std::atoi(env) != 0 ? 1 : 0;
            }
        } else {
            resolved = 0;  // No unified cache means no eviction support
        }
        g_env_cached.store(resolved, std::memory_order_release);
        env_cached = resolved;
    }

    // Explicit enable/disable via env var
    if (env_cached == 1) {
        return true;
    }
    if (env_cached == 0) {
        return false;
    }

    // Auto mode: enable eviction when unified cache is active.
    // The cache manages VRAM placement for all weights; eviction is always needed.
    return ggml_sycl::unified_cache_enabled();
}

// --- MoE expert split tracking ---
// Set by llama-model.cpp when expert tensors are routed to host-pinned buffers.
// Queried by KV tiering to auto-enable host KV for MoE models.
static std::atomic<bool> g_moe_expert_split_active{ false };

void ggml_backend_sycl_set_moe_expert_split(int n_expert, int n_expert_used) {
    (void) n_expert;
    (void) n_expert_used;
    g_moe_expert_split_active.store(true, std::memory_order_release);
}

bool ggml_backend_sycl_query_moe_expert_split(void) {
    return g_moe_expert_split_active.load(std::memory_order_acquire);
}

void ggml_backend_sycl_set_unified_cache_budget_pct(int pct) {
    ggml_sycl::set_unified_cache_budget_pct(pct);
}

void ggml_backend_sycl_set_unified_cache_host_budget_pct(int pct) {
    ggml_sycl::set_unified_cache_host_budget_pct(pct);
}

void ggml_backend_sycl_set_onednn_pack_m(ggml_tensor * tensor, int64_t pack_m) {
    if (!tensor) {
        return;
    }
    ggml_tensor_extra_gpu * extra = static_cast<ggml_tensor_extra_gpu *>(tensor->extra);
    if (!extra) {
        return;
    }
    if (tensor->layout == nullptr) {
        tensor->layout = &extra->layout;
    }
    if (pack_m < 0) {
        pack_m = 0;
    }
    if (extra->layout.onednn_pack_m == pack_m) {
        return;
    }
    extra->layout.onednn_pack_m = pack_m;
    extra->layout_dirty         = true;
}

void ggml_backend_sycl_register_host_weight_tensor(ggml_backend_dev_t dev, ggml_tensor * tensor) {
    if (!dev || !tensor) {
        return;
    }
    if (!ggml_backend_sycl_weights_evictable()) {
        return;
    }

    ggml_tensor_extra_gpu * extra         = static_cast<ggml_tensor_extra_gpu *>(tensor->extra);
    const bool              created_extra = (extra == nullptr);
    if (extra == nullptr) {
        extra = new ggml_tensor_extra_gpu{};
        ggml_sycl_register_optimize_feature(&extra->optimized_feature);
        tensor->extra  = extra;
        tensor->layout = &extra->layout;

        int device_id = ggml_sycl_device_id_from_backend_dev(dev);
        if (device_id < 0) {
            device_id = 0;
        }
        ggml_sycl_init_layout_info(extra, tensor, device_id, /* use_tensor_data_ptr = */ false);
    } else if (tensor->layout == nullptr) {
        tensor->layout = &extra->layout;
    }

    ggml_sycl_assign_cache_uuid(extra);
    {
        // Try to find identity by pointer first, then fall back to name lookup
        std::lock_guard<std::mutex> lock_id(g_sycl_weight_identity_mutex);
        auto                        id_it = g_sycl_weight_identities.find(tensor);
        if (id_it != g_sycl_weight_identities.end()) {
            extra->model_id = id_it->second.model_id;
        } else {
            // Compute tensors have different addresses than metadata tensors
            const char * name = ggml_get_name(tensor);
            if (name && name[0]) {
                auto name_it = g_sycl_weight_identities_by_name.find(std::string(name));
                if (name_it != g_sycl_weight_identities_by_name.end()) {
                    extra->model_id = name_it->second.model_id;
                }
            }
        }
    }

    {
        std::lock_guard<std::mutex> lock(g_sycl_host_weight_extras_mutex);
        auto                        insert = g_sycl_host_weight_extras.emplace(tensor, extra);
        if (!insert.second) {
            if (insert.first->second != extra) {
                GGML_LOG_WARN("[SYCL] host weight registry mismatch for %s (existing=%p new=%p)\n",
                              tensor->name ? tensor->name : "unknown", (void *) insert.first->second, (void *) extra);
                // Treat as stale registry entry (tensor pointer reuse) and replace it.
                // Keep the old extra alive to avoid freeing resources still in use by in-flight kernels.
                insert.first->second = extra;
                tensor->extra        = extra;
                tensor->layout       = extra ? &extra->layout : nullptr;
                if (!created_extra) {
                    retain_extra_gpu(extra);
                }
            }
        } else if (!created_extra) {
            retain_extra_gpu(extra);
        }
    }

    int device_id = ggml_sycl_device_id_from_backend_dev(dev);
    if (device_id < 0) {
        device_id = 0;
    }
    if (tensor->name && ggml_sycl::unified_cache_enabled()) {
        ggml_sycl::layer_streaming_register_host_ptr(device_id, tensor->name, ggml_sycl_host_data(tensor),
                                                     ggml_nbytes(tensor));
    }
}

void ggml_backend_sycl_register_weight_identity(const ggml_tensor * tensor,
                                                uint16_t            file_idx,
                                                size_t              file_offs,
                                                size_t              tensor_nbytes,
                                                uint64_t            model_id) {
    if (tensor == nullptr) {
        return;
    }

    ggml_sycl::dispatch_tuning::ensure_model_loaded(model_id);

    const ggml_sycl_weight_identity identity = { file_idx, file_offs, tensor_nbytes, model_id };

    std::lock_guard<std::mutex> lock(g_sycl_weight_identity_mutex);

    // Store by pointer (for metadata tensor lookups)
    g_sycl_weight_identities[tensor] = identity;

    // Also store by name (for compute tensor lookups - they have different addresses)
    const char * name = ggml_get_name(tensor);
    if (name && name[0]) {
        g_sycl_weight_identities_by_name[std::string(name)] = identity;
    }

    // NOTE: We intentionally do NOT modify tensor->extra or tensor->layout here.
    // This function is called on METADATA tensors from the GGUF context during model loading.
    // Modifying these fields on metadata tensors causes memory corruption because:
    // 1. Metadata tensors are stored in a compact GGUF context, not in GPU buffer contexts
    // 2. Setting tensor->layout to an allocated pointer corrupts adjacent tensor fields
    //
    // COMPUTE tensors (created later during buffer allocation) will get their extra
    // initialized in ggml_backend_sycl_buffer_init_tensor(), which looks up the identity
    // by name via g_sycl_weight_identities_by_name.
}

static tensor_usage ggml_sycl_usage_from_api(ggml_backend_sycl_tensor_usage usage) {
    switch (usage) {
        case GGML_SYCL_TENSOR_USAGE_ATTENTION_WEIGHT:
            return tensor_usage::ATTENTION_WEIGHT;
        case GGML_SYCL_TENSOR_USAGE_FFN_WEIGHT:
            return tensor_usage::FFN_WEIGHT;
        case GGML_SYCL_TENSOR_USAGE_MOE_EXPERT_WEIGHT:
            return tensor_usage::MOE_EXPERT_WEIGHT;
        case GGML_SYCL_TENSOR_USAGE_MOE_GATE:
            return tensor_usage::MOE_GATE;
        case GGML_SYCL_TENSOR_USAGE_EMBEDDING:
            return tensor_usage::EMBEDDING;
        case GGML_SYCL_TENSOR_USAGE_NORM:
            return tensor_usage::NORM;
        default:
            return tensor_usage::UNKNOWN;
    }
}

void ggml_backend_sycl_register_weight_usage(const char * tensor_name, ggml_backend_sycl_tensor_usage usage) {
    if (tensor_name == nullptr || tensor_name[0] == '\0') {
        return;
    }

    const tensor_usage mapped = ggml_sycl_usage_from_api(usage);
    if (mapped == tensor_usage::UNKNOWN) {
        return;
    }

    std::lock_guard<std::mutex> lock(g_sycl_weight_usage_mutex);
    const std::string           name(tensor_name);
    auto                        it = g_sycl_weight_usages.find(name);
    if (it == g_sycl_weight_usages.end()) {
        g_sycl_weight_usages.emplace(name, mapped);
        return;
    }

    if (it->second != mapped) {
        it->second = tensor_usage::UNKNOWN;  // Tied weights: force safe layout
    }
}

tensor_usage ggml_sycl_get_tensor_usage(const ggml_tensor * tensor) {
    if (tensor == nullptr) {
        return tensor_usage::UNKNOWN;
    }

    const char * name = ggml_get_name(tensor);
    if (name && name[0]) {
        std::lock_guard<std::mutex> lock(g_sycl_weight_usage_mutex);
        auto                        it = g_sycl_weight_usages.find(std::string(name));
        if (it != g_sycl_weight_usages.end()) {
            return it->second;
        }
    }

    const tensor_usage inferred = infer_tensor_usage(tensor->name);
    if (inferred == tensor_usage::UNKNOWN && name && name[0]) {
        std::lock_guard<std::mutex> lock(g_sycl_usage_unknown_mutex);
        if (g_sycl_usage_unknown_once.emplace(name).second) {
            GGML_LOG_WARN("[SYCL] tensor usage UNKNOWN: name=%s type=%s ne=[%lld,%lld,%lld,%lld]\n", name,
                          ggml_type_name(tensor->type), (long long) tensor->ne[0], (long long) tensor->ne[1],
                          (long long) tensor->ne[2], (long long) tensor->ne[3]);
        }
    }
    return inferred;
}

ggml_sycl_cache_id ggml_backend_sycl_get_weight_cache_key(const ggml_tensor * tensor, int device) {
    ggml_sycl_cache_id id{};
    if (tensor == nullptr) {
        return id;
    }

    const int                         device_id = device < 0 ? 0 : device;
    const ggml_sycl_weight_tensor_key tensor_key{ tensor, device_id };

    const char * raw_name    = ggml_get_name(tensor);
    std::string  name        = (raw_name && raw_name[0]) ? std::string(raw_name) : std::string("unknown");
    uint64_t     name_hash   = static_cast<uint64_t>(std::hash<std::string>()(name));
    std::string  guard_where = "weight_cache_key:";
    guard_where += name;

    (void) weight_cache_guard_check_all(guard_where.c_str());

    ggml_tensor_extra_gpu * extra =
        const_cast<ggml_tensor_extra_gpu *>(static_cast<const ggml_tensor_extra_gpu *>(tensor->extra));
    if (!extra && tensor->buffer && ggml_backend_buffer_is_host(tensor->buffer) &&
        ggml_backend_sycl_weights_evictable()) {
        ggml_backend_reg_t reg = ggml_backend_sycl_reg();
        ggml_backend_dev_t dev = ggml_backend_reg_dev_get(reg, device_id);
        if (dev) {
            ggml_backend_sycl_register_host_weight_tensor(dev, const_cast<ggml_tensor *>(tensor));
            extra = static_cast<ggml_tensor_extra_gpu *>(const_cast<ggml_tensor *>(tensor)->extra);
        }
    }

    // MoE expert slice: delegate to the expert-specific key generator so that
    // the cache key matches what registration/prestage used (name ":eN" suffix,
    // per-expert dimensions, combined aux_id).  Without this, resolve_weight
    // generates a key with the full tensor name (no suffix) which never matches
    // the registered expert entries (IS-EXPERT-FAIL).
    if (extra && extra->moe_expert_id >= 0) {
        return ggml_sycl_get_moe_expert_cache_key(tensor, extra, extra->moe_expert_id);
    }

    uint64_t cache_uuid = ggml_sycl_assign_cache_uuid(extra);

    std::lock_guard<std::mutex> lock(g_sycl_weight_identity_mutex);
    if (g_sycl_weight_tensor_cache.bucket_count() == 0) {
        g_sycl_weight_tensor_cache.rehash(1);
        GGML_LOG_WARN("[SYCL] weight tensor cache had zero buckets; rehashing\n");
    }
    if (g_ggml_sycl_debug) {
        GGML_SYCL_DEBUG("[SYCL] weight tensor cache: size=%zu buckets=%zu\n", g_sycl_weight_tensor_cache.size(),
                        g_sycl_weight_tensor_cache.bucket_count());
        GGML_SYCL_DEBUG("[SYCL] weight cache lookup: tensor=%p name=%s device=%d\n", (const void *) tensor,
                        tensor->name ? tensor->name : "unknown", device_id);
    }

    // Try to find identity by pointer first, then fall back to name lookup
    auto                      identity_it       = g_sycl_weight_identities.find(tensor);
    bool                      has_gguf_identity = (identity_it != g_sycl_weight_identities.end());
    ggml_sycl_weight_identity identity{};

    if (has_gguf_identity) {
        identity = identity_it->second;
    } else if (!name.empty() && name != "unknown") {
        // Compute tensors have different addresses than metadata tensors,
        // so we need to look up by name
        auto name_it = g_sycl_weight_identities_by_name.find(name);
        if (name_it != g_sycl_weight_identities_by_name.end()) {
            identity          = name_it->second;
            has_gguf_identity = true;
        }
    }

    if (has_gguf_identity) {
        // Safety check: sync model_id back to extra if it's 0 and we have a valid identity.
        // This handles the case where the extra was created after register_weight_identity
        // was called (e.g., by buffer_init_tensor) and missed the model_id assignment.
        if (extra && extra->model_id == 0 && identity.model_id != 0) {
            extra->model_id = identity.model_id;
        }
        // Also ensure tensor->layout is set if we have an extra but layout is null.
        // This can happen if the extra was created elsewhere without setting layout.
        auto * mutable_tensor = const_cast<ggml_tensor *>(tensor);
        if (extra && mutable_tensor->layout == nullptr) {
            mutable_tensor->layout = &extra->layout;
        }
    }

    id.valid    = true;
    id.model_id = extra ? extra->model_id : identity.model_id;
    if (id.model_id == 0 && has_gguf_identity) {
        id.model_id = identity.model_id;
    }
    id.has_gguf  = has_gguf_identity;
    id.file_idx  = has_gguf_identity ? identity.file_idx : 0;
    id.file_offs = has_gguf_identity ? identity.file_offs : 0;
    id.nbytes    = has_gguf_identity ? identity.nbytes : ggml_nbytes(tensor);
    // Always preserve name_hash to ensure unique tensor identities.
    // Previously we discarded name_hash for GGUF-backed tensors assuming GGUF metadata
    // (file_idx, file_offs, nbytes) would be unique. However, this causes collisions when:
    // - Multiple MoE experts share file offsets (stored contiguously)
    // - Tensor views/reshapes share the same underlying data
    // - Intermediate tensors get GGUF identity via name lookup
    // The name_hash provides the additional uniqueness needed to distinguish them.
    id.name_hash = name_hash;
    id.type      = tensor->type;
    for (int i = 0; i < GGML_MAX_DIMS; ++i) {
        id.ne[i]           = tensor->ne[i];
        id.tp_local_ne[i]  = 0;
        id.tp_offset_ne[i] = 0;
    }
    id.tp_sharded    = false;
    id.tp_rank       = 0;
    id.tp_world_size = 1;
    if (extra && extra->tp_sharded && extra->tp_world_size > 1) {
        id.tp_sharded    = true;
        id.tp_rank       = extra->tp_rank;
        id.tp_world_size = extra->tp_world_size;
        for (int i = 0; i < GGML_MAX_DIMS; ++i) {
            id.tp_local_ne[i]  = extra->tp_local_ne[i];
            id.tp_offset_ne[i] = extra->tp_offset_ne[i];
        }
    }
    if (!has_gguf_identity) {
        if (cache_uuid == 0) {
            cache_uuid = g_sycl_weight_cache_uuid.fetch_add(1, std::memory_order_relaxed);
        }
        id.aux_id = cache_uuid;
    } else {
        id.aux_id = 0;
    }

    auto cache_it = g_sycl_weight_tensor_cache.find(tensor_key);
    if (cache_it != g_sycl_weight_tensor_cache.end()) {
        if (ggml_sycl::detail::cache_id_equal(cache_it->second.id, id)) {
            return cache_it->second.id;
        }
        g_sycl_weight_tensor_cache.erase(cache_it);
    }

    ggml_sycl_weight_tensor_cache_entry entry{};
    entry.id                               = id;
    entry.name                             = name;
    g_sycl_weight_tensor_cache[tensor_key] = std::move(entry);
    return id;
}

// Get a cache identity for ANY tensor (weight or non-weight).
// For non-weight tensors (MoE ids, get_rows indices, etc.), uses data pointer as unique identifier.
// This enables caching of mmap'd non-weight tensors to prevent DEVICE_LOST errors.
ggml_sycl_cache_id ggml_backend_sycl_get_tensor_cache_key(const ggml_tensor * tensor, int device) {
    ggml_sycl_cache_id id{};
    if (tensor == nullptr) {
        return id;
    }

    // Check if this is a weight tensor - if so, delegate to the weight-specific function
    // which has richer identity information (GGUF file offsets, etc.)
    if (ggml_sycl_tensor_is_weight(tensor)) {
        return ggml_backend_sycl_get_weight_cache_key(tensor, device);
    }

    // For non-weight tensors, create a stable cache key.
    // Use a monotonic UUID (same as weight tensors) instead of pointer address,
    // which is fragile when tensor->data is reallocated across batches.
    const char * raw_name  = ggml_get_name(tensor);
    std::string  name      = (raw_name && raw_name[0]) ? std::string(raw_name) : std::string("nonweight");
    uint64_t     name_hash = static_cast<uint64_t>(std::hash<std::string>()(name));

    id.valid     = true;
    id.model_id  = 0;  // No model ID for non-weight tensors
    id.has_gguf  = false;
    id.file_idx  = 0;
    id.file_offs = 0;
    id.nbytes    = ggml_nbytes(tensor);
    id.name_hash = name_hash;
    id.type      = tensor->type;
    for (int i = 0; i < GGML_MAX_DIMS; ++i) {
        id.ne[i]           = tensor->ne[i];
        id.tp_local_ne[i]  = 0;
        id.tp_offset_ne[i] = 0;
    }
    id.tp_sharded    = false;
    id.tp_rank       = 0;
    id.tp_world_size = 1;
    // Use stable UUID instead of pointer address for non-weight tensors.
    // Assign via extra->cache_uuid if available, otherwise use a monotonic counter.
    auto * nw_extra  = static_cast<ggml_tensor_extra_gpu *>(tensor->extra);
    if (nw_extra) {
        id.aux_id = ggml_sycl_assign_cache_uuid(nw_extra);
    } else {
        // No extra — use monotonic counter for stable identity
        id.aux_id = g_sycl_weight_cache_uuid.fetch_add(1, std::memory_order_relaxed);
    }

    return id;
}

static bool ggml_sycl_layout_override_active(layout_mode & override_layout);

// Tensor inventory storage for tiered memory placement
static std::mutex                                  g_tensor_inventory_mutex;
static std::vector<std::pair<std::string, size_t>> g_tensor_inventory;
static std::unordered_map<std::string, size_t>     g_tensor_inventory_index;  // name -> index for O(1) lookup
static size_t                                      g_tensor_inventory_total_size = 0;
static size_t                                      g_tensor_inventory_pp_pipeline_scratch_bytes = 0;
static int                                         g_tensor_inventory_device     = 0;
static size_t                                      g_moe_expert_total_bytes      = 0;
static int                                         g_moe_n_experts_total         = 0;
static int                                         g_moe_n_experts_used          = 0;
static uint32_t                                    g_model_n_layer               = 0;
static ggml_sycl::placement_kv_info                g_placement_kv_info{};
std::atomic<bool>                                  g_tiered_enabled{ false };

// P4: Priority-based static placement plan (computed in set_tensor_inventory,
// applied in preload_model_weights).  Gated by GGML_SYCL_VRAM_ARENA=1.
static ggml_sycl::placement_plan g_placement_plan;
static bool                      g_has_placement_plan = false;

static std::array<size_t, GGML_SYCL_MAX_DEVICES> g_tiered_headroom_reserve = {};

// Layer-to-device map for CPU offload dispatch
// Built lazily on first compute pass; maps layer_id -> true if layer's weights are host-resident
static std::vector<bool> g_layer_on_cpu;
static std::vector<bool> g_layer_plan_forced;
static std::atomic<bool> g_layer_map_initialized{ false };

// Helper: Get total system RAM in bytes
static size_t get_system_memory_bytes() {
#if defined(_WIN32)
    MEMORYSTATUSEX status;
    status.dwLength = sizeof(status);
    if (GlobalMemoryStatusEx(&status)) {
        return static_cast<size_t>(status.ullTotalPhys);
    }
    return 0;
#else
    long pages     = sysconf(_SC_PHYS_PAGES);
    long page_size = sysconf(_SC_PAGE_SIZE);
    if (pages <= 0 || page_size <= 0) {
        GGML_LOG_WARN("[SYCL] System RAM detection failed: pages=%ld, page_size=%ld\n", pages, page_size);
        return 0;
    }
    size_t total = static_cast<size_t>(pages) * static_cast<size_t>(page_size);
    GGML_LOG_INFO("[SYCL] System RAM detected: %.2f GB (%ld pages x %ld bytes)\n", total / (1024.0 * 1024.0 * 1024.0),
                  pages, page_size);
    return total;
#endif
}

void ggml_backend_sycl_set_tensor_inventory(ggml_backend_t backend, const ggml_sycl_tensor_inventory * inventory) {
    if (!backend || !inventory || (inventory->count > 0 && !inventory->tensors)) {
        return;
    }
    ggml_backend_sycl_context * ctx = (ggml_backend_sycl_context *) backend->context;
    if (!ctx) {
        return;
    }

    std::lock_guard<std::mutex> lock(g_tensor_inventory_mutex);
    // Clear existing inventory and index
    g_tensor_inventory.clear();
    g_tensor_inventory_index.clear();

    g_tensor_inventory_total_size = 0;
    g_tensor_inventory_pp_pipeline_scratch_bytes = 0;
    g_tensor_inventory_device     = ctx->device;
    // Store tensor inventory with O(1) lookup index
    g_tensor_inventory.reserve(inventory->count);
    g_tensor_inventory_index.reserve(inventory->count);
    for (size_t i = 0; i < inventory->count; i++) {
        if (inventory->tensors[i].name != nullptr) {
            std::string name(inventory->tensors[i].name);
            size_t      idx = g_tensor_inventory.size();
            g_tensor_inventory.emplace_back(name, inventory->tensors[i].size);
            g_tensor_inventory_index[name] = idx;
            g_tensor_inventory_total_size += inventory->tensors[i].size;
        }
    }
    {
        const char * env = std::getenv("GGML_SYCL_PP_PIPELINE");
        const bool   pp_pipeline_enabled = (env == nullptr || std::atoi(env) != 0);
        g_tensor_inventory_pp_pipeline_scratch_bytes =
            pp_pipeline_enabled ? inventory->pp_pipeline_scratch_bytes : 0;
    }
    ggml_sycl::unified_cache_set_planned_pp_pipeline_scratch_bytes(ctx->device,
                                                                   g_tensor_inventory_pp_pipeline_scratch_bytes);

    // Store model hparams for KV tiering
    g_model_n_layer                  = inventory->n_layer;
    g_placement_kv_info.n_layer      = inventory->n_layer;
    g_placement_kv_info.n_embd_k_gqa = inventory->n_embd_k_gqa;
    g_placement_kv_info.n_embd_v_gqa = inventory->n_embd_v_gqa;
    g_placement_kv_info.n_ctx        = inventory->n_ctx;
    g_placement_kv_info.n_ubatch     = inventory->n_ubatch;
    g_placement_kv_info.n_swa        = inventory->n_swa;
    g_placement_kv_info.n_swa_layers = inventory->n_swa_layers;
    // Copy per-layer SWA mask for heterogeneous KV cost charging.
    if (inventory->swa_layer_mask != nullptr && inventory->swa_layer_mask_count > 0) {
        g_placement_kv_info.swa_layer_mask.assign(inventory->swa_layer_mask,
                                                  inventory->swa_layer_mask + inventory->swa_layer_mask_count);
    } else {
        g_placement_kv_info.swa_layer_mask.clear();
    }
    // Current phase uses a conservative planner contract: model inventory
    // provides train-context sizing unless a runtime override is added later.
    g_placement_kv_info.n_ctx_is_runtime = false;
    if (g_placement_kv_info.valid()) {
        GGML_LOG_INFO(
            "[SYCL-PLAN] KV inputs: n_layer=%u n_embd_k_gqa=%u n_embd_v_gqa=%u n_ctx=%u (%s) kv_per_layer=%.1f MB\n",
            g_placement_kv_info.n_layer, g_placement_kv_info.n_embd_k_gqa, g_placement_kv_info.n_embd_v_gqa,
            g_placement_kv_info.n_ctx, g_placement_kv_info.n_ctx_is_runtime ? "runtime" : "conservative",
            g_placement_kv_info.kv_bytes_per_layer() / (1024.0 * 1024.0));
    }

    // Detect MoE expert tensors and store MoE hparams
    g_moe_n_experts_total             = inventory->n_expert;
    g_moe_n_experts_used              = inventory->n_expert_used;
    g_placement_kv_info.n_expert_used = inventory->n_expert_used;
    g_moe_expert_total_bytes          = 0;
    if (g_moe_n_experts_total > 0) {
        for (const auto & [name, size] : g_tensor_inventory) {
            // Expert tensors match patterns like "blk.N.ffn_up_exps.weight" or "blk.N.ffn_gate_exps.weight"
            if (name.find("_exps") != std::string::npos) {
                g_moe_expert_total_bytes += size;
            }
        }
        if (g_moe_expert_total_bytes > 0) {
            GGML_LOG_INFO("[SYCL-BUDGET] MoE model detected: %d experts, %d active, %.1f MB expert weights\n",
                          g_moe_n_experts_total, g_moe_n_experts_used, g_moe_expert_total_bytes / (1024.0 * 1024.0));
        }
    }

    // NOTE: MoE expert VRAM reserve is registered in ggml_sycl_preload_model_weights()
    // AFTER the unified cache is created.  Registering here (before cache creation)
    // gets absorbed into the cache's runtime_reserved_baseline and has no effect
    // on available_for_compute().
    g_moe_expert_vram_reserve.fill(0);

    // Check if tiered mode should be enabled based on VRAM budget
    size_t free_mem = 0, total_mem = 0;

    ggml_backend_sycl_get_device_memory(ctx->device, &free_mem, &total_mem);

    // Use total VRAM as base for budget calculation (not free_mem which depends on allocation order)
    // This matches how unified_cache calculates its budget
    const size_t base_mem = total_mem > 0 ? total_mem : free_mem;

    // Calculate already-allocated memory (KV cache, compute buffers, etc.)
    // This is the difference between total and free at this point
    const size_t already_allocated = base_mem > free_mem ? base_mem - free_mem : 0;

    // No artificial headroom — the unified cache manages all memory and
    // subsystems (compute scratch, KV cache) fall back to host-pinned
    // when VRAM is full.  The free_mem cap in the cache constructor
    // already handles the real constraint (actual free VRAM at startup).
    const size_t base_headroom = 0;

    // Apply GGML_SYCL_VRAM_BUDGET_PCT if set (same env var as unified cache and get_memory)
    int          budget_pct     = 100;  // Default: 100% — unified cache owns all VRAM
    const char * env_budget_pct = std::getenv("GGML_SYCL_VRAM_BUDGET_PCT");
    if (env_budget_pct) {
        budget_pct = std::max(1, std::min(100, std::atoi(env_budget_pct)));
    }

    size_t vram_budget_base = static_cast<size_t>(base_mem * (static_cast<double>(budget_pct) / 100.0));
    size_t vram_budget      = 0;
    if (vram_budget_base > base_headroom) {
        vram_budget = vram_budget_base - base_headroom;
    }

    // Enable tiered mode when unified cache is active (needed to upload weights to VRAM).
    // Always enabled so the cache can manage VRAM placement for all model sizes.
    // For MoE models, compute effective weight size (only active experts needed in VRAM)
    // for display/budget purposes.
    const size_t effective_model_size = ggml_sycl::compute_moe_effective_weight_bytes(
        g_tensor_inventory_total_size, g_moe_expert_total_bytes, g_moe_n_experts_total, g_moe_n_experts_used);
    // Unified non-blocking cache: no model_exceeds_vram branching.
    // All inference callers use the non-blocking try_get_cached_with_event path.
    // Dense weights are pinned after S1-PRELOAD; MoE experts use LRU eviction.
    //
    // Subtract arena zone overhead (SCRATCH, ONEDNN, RUNTIME) from the weight
    // budget comparison.  Without this, a model that barely fits raw VRAM
    // (e.g. 11.5 GB on 11.6 GB) appears to fit, but the ~1 GB of arena zones
    // leaves only ~10.6 GB for weights — the placement plan never triggers.
    size_t arena_zone_overhead = 0;
    if (ggml_sycl::vram_arena_enabled()) {
        auto * cache = ggml_sycl::get_unified_cache_for_device(ctx->device);
        if (cache && cache->arena_active()) {
            arena_zone_overhead = cache->zone_capacity(ggml_sycl::vram_zone_id::SCRATCH) +
                                  cache->zone_capacity(ggml_sycl::vram_zone_id::ONEDNN) +
                                  cache->zone_capacity(ggml_sycl::vram_zone_id::RUNTIME);
        }
    }
    const size_t weight_budget             = vram_budget > arena_zone_overhead ? vram_budget - arena_zone_overhead : 0;
    const bool   model_size_exceeds_budget = g_tensor_inventory_total_size > weight_budget;
    // Write-once at startup — relaxed ordering is sufficient because callers
    // are sequenced after model load (no cross-thread visibility requirement).
    g_tiered_enabled.store(ggml_sycl::unified_cache_enabled(), std::memory_order_relaxed);

    GGML_LOG_INFO(
        "[SYCL-BUDGET] budget_pct=%d%%, vram_budget=%.1f MB (free=%.1f MB), "
        "arena_zones=%.1f MB, weight_budget=%.1f MB, "
        "model_size=%.1f MB, exceeds_budget=%s\n",
        budget_pct, vram_budget / (1024.0 * 1024.0), free_mem / (1024.0 * 1024.0),
        arena_zone_overhead / (1024.0 * 1024.0), weight_budget / (1024.0 * 1024.0),
        effective_model_size / (1024.0 * 1024.0), model_size_exceeds_budget ? "true" : "false");

    // Initialize double-buffered layer streaming when:
    // 1. Model exceeds effective VRAM budget (auto-activation for non-MoE dense models)
    // 2. User forces streaming via GGML_SYCL_FORCE_STREAMING=1 (testing/override)
    // Layer streaming provides a device-side copy for GPU kernels that need weights.
    const char * force_stream          = std::getenv("GGML_SYCL_FORCE_STREAMING");
    const bool   streaming_forced      = force_stream && std::atoi(force_stream) == 1;
    const bool   cpu_offload_available = ggml_sycl_cpu_offload_enabled() && ggml_sycl_info().has_cpu_device;
    // MoE models handle expert weight streaming via their own dispatch path
    // (expert placement table + on-demand cache). Don't activate layer streaming
    // for MoE — it would waste VRAM on streaming buffers that MoE doesn't use.
    const bool   is_moe                = g_moe_n_experts_total > 0;
    if ((model_size_exceeds_budget && !is_moe) || streaming_forced) {
        auto & mgr = ggml_sycl::get_layer_stream_manager(ctx->device);
        mgr.build_layer_map(g_tensor_inventory.data(), g_tensor_inventory.size());
        {
            std::lock_guard<std::mutex> lock(g_sycl_host_weight_extras_mutex);
            for (const auto & entry : g_sycl_host_weight_extras) {
                const ggml_tensor * tensor = entry.first;
                if (tensor == nullptr || tensor->name == nullptr || tensor->name[0] == '\0') {
                    continue;
                }
                mgr.register_host_ptr(tensor->name, ggml_sycl_host_data(tensor), ggml_nbytes(tensor));
            }
        }
        sycl::queue & q = ggml_sycl_get_device(ctx->device).default_queue();
        if (mgr.allocate_buffers(q)) {
            // Register streaming buffer allocation with unified cache budget
            GGML_LOG_INFO(
                "[SYCL-BUDGET] Layer streaming enabled%s: %d layers, 2 x %.1f MB buffers (%.1f MB budgeted)\n",
                streaming_forced ? " (forced)" : "", mgr.n_layers(), mgr.max_layer_size() / (1024.0 * 1024.0),
                mgr.allocated_bytes() / (1024.0 * 1024.0));
        } else {
            GGML_LOG_ERROR("[SYCL-BUDGET] Layer streaming buffer allocation failed\n");
        }
    }

    // Diagnostic logging for VRAM budget calculation debugging
    GGML_LOG_INFO("[SYCL-BUDGET] base_mem=%.1f MB, already_allocated=%.1f MB, headroom=%.1f MB\n",
                  base_mem / (1024.0 * 1024.0), already_allocated / (1024.0 * 1024.0),
                  base_headroom / (1024.0 * 1024.0));
    GGML_LOG_INFO("[SYCL-BUDGET] vram_budget_base=%.1f MB, final_budget=%.1f MB, model_size=%.1f MB\n",
                  vram_budget_base / (1024.0 * 1024.0), vram_budget / (1024.0 * 1024.0),
                  g_tensor_inventory_total_size / (1024.0 * 1024.0));
    GGML_LOG_INFO("[SYCL-BUDGET] unified_cache_active=%s\n", unified_cache_active() ? "true" : "false");

    // Reserve extra VRAM headroom for large models (onemath/DNN scratch).
    // When CPU offload is available, CPU-dispatched layers don't need GPU scratch,
    // so skip the extra reservation to maximize VRAM available for weight caching.
    const size_t desired_headroom = std::max(base_headroom, base_mem / 4);
    const size_t desired_extra =
        model_size_exceeds_budget && desired_headroom > base_headroom && !cpu_offload_available ?
            (desired_headroom - base_headroom) :
            0;
    g_tiered_headroom_reserve[ctx->device] = desired_extra;
    if (desired_extra > 0) {
        GGML_LOG_INFO("[SYCL] Tiered headroom reserve: %.1f MB (base headroom %.1f MB, total %.1f MB)\n",
                      desired_extra / (1024.0 * 1024.0), base_headroom / (1024.0 * 1024.0),
                      base_mem / (1024.0 * 1024.0));
    }
    // VRAM budget breakdown by category priority
    {
        const double MB                = 1024.0 * 1024.0;
        const size_t dense_weights     = g_tensor_inventory_total_size - g_moe_expert_total_bytes;
        const size_t expert_reserve    = g_moe_expert_vram_reserve[ctx->device];
        const size_t total_headroom    = base_headroom + desired_extra;
        const size_t committed         = dense_weights + expert_reserve + total_headroom;
        const size_t scratch_remaining = vram_budget > committed ? vram_budget - committed : 0;

        GGML_LOG_INFO("[VRAM-BUDGET] Device %d: %.1f MB total, %.1f MB budget (%d%%)\n", ctx->device, base_mem / MB,
                      vram_budget / MB, budget_pct);
        GGML_LOG_INFO("[VRAM-BUDGET]   Weights (dense): %.1f MB  [priority 1]\n", dense_weights / MB);
        if (g_moe_expert_total_bytes > 0) {
            GGML_LOG_INFO("[VRAM-BUDGET]   Expert cache:    %.1f MB reserved (%.1f MB total)  [priority 2]\n",
                          expert_reserve / MB, g_moe_expert_total_bytes / MB);
        }
        GGML_LOG_INFO("[VRAM-BUDGET]   Headroom:        %.1f MB  (scratch + KV + runtime)\n", total_headroom / MB);
        GGML_LOG_INFO("[VRAM-BUDGET]   Available:       %.1f MB  (for KV [pri 0], scratch [pri 3], staging [pri 4])\n",
                      scratch_remaining / MB);
    }

    // -----------------------------------------------------------------------
    // Pre-allocate host-pinned memory for the full model working set so that
    // NO sycl::malloc_host calls occur during inference.  The model size is
    // now known from the tensor inventory; pre_allocate_all adds 20% headroom
    // for SOA conversion temporaries, staging buffers, and runtime allocations.
    // -----------------------------------------------------------------------
    {
        auto * cache = ggml_sycl::get_unified_cache_for_device(ctx->device);
        if (cache) {
            const size_t chunks_grown = cache->pre_allocate_all(g_tensor_inventory_total_size);
            if (chunks_grown > 0) {
                GGML_LOG_INFO(
                    "[SYCL] Host-pinned pre-allocate: %zu chunks for full model "
                    "(%.1f MB + 20%% headroom)\n",
                    chunks_grown, g_tensor_inventory_total_size / (1024.0 * 1024.0));
            }
        }
    }

    // P4/P4.5: Always compute placement plan when VRAM arena is active.
    // Small models: everything assigned to device.  Large models: spill to host.
    // Single GPU: P4 Unsloth-priority bin-packing.
    // Multi-GPU: P4.5 hybrid parallelism (layer split + expert distribution).
    if (ggml_sycl::vram_arena_enabled()) {
        const auto & info = ggml_sycl_info();
        if (info.total_gpu_count >= 2 && ggml_backend_sycl_moe_multi_gpu_requested()) {
            // P4.5: Multi-device placement
            std::vector<ggml_sycl::device_budget> budgets;
            budgets.reserve(info.total_gpu_count);
            for (int d = 0; d < info.total_gpu_count; d++) {
                size_t dev_free = 0, dev_total = 0;
                ggml_backend_sycl_get_device_memory(d, &dev_free, &dev_total);
                size_t dev_budget = static_cast<size_t>(dev_total * (static_cast<double>(budget_pct) / 100.0));
                budgets.push_back({ d, dev_budget, dev_total });
            }
            const auto gpu_mode = ggml_sycl::get_multi_gpu_mode(is_moe);
            g_placement_plan =
                ggml_sycl::compute_multi_device_plan(budgets, g_tensor_inventory, static_cast<int>(g_model_n_layer),
                                                     gpu_mode, g_placement_kv_info, g_moe_n_experts_total);
            g_has_placement_plan = true;
            GGML_LOG_INFO(
                "[SYCL] Multi-device placement plan computed: %zu entries, "
                "%.1f MB device + %.1f MB host (%d GPUs)\n",
                g_placement_plan.entries.size(), g_placement_plan.vram_bytes / (1024.0 * 1024.0),
                g_placement_plan.host_bytes / (1024.0 * 1024.0), info.total_gpu_count);
        } else {
            // P4: Single-device placement (with per-expert MoE splitting)
            // Use the actual arena shared zone size as the budget — this is the
            // real space available for weights + KV.  The arena subtracts zone
            // overheads internally, so the planner doesn't need to guess.
            size_t plan_budget = vram_budget;
            if (ggml_sycl::vram_arena_enabled()) {
                auto * cache = ggml_sycl::get_unified_cache_for_device(ctx->device);
                if (cache && cache->arena_active()) {
                    // Shared zone = arena total - (scratch + oneDNN + runtime)
                    const size_t arena_total   = cache->arena_total_size();
                    const size_t zone_overhead = cache->zone_capacity(ggml_sycl::vram_zone_id::SCRATCH) +
                                                 cache->zone_capacity(ggml_sycl::vram_zone_id::ONEDNN) +
                                                 cache->zone_capacity(ggml_sycl::vram_zone_id::RUNTIME);
                    plan_budget = arena_total > zone_overhead ? arena_total - zone_overhead : 0;
                    GGML_LOG_INFO(
                        "[SYCL] Plan budget tied to arena: %.1f MB shared zone "
                        "(arena=%.1f MB - zones=%.1f MB)\n",
                        plan_budget / (1024.0 * 1024.0), arena_total / (1024.0 * 1024.0),
                        zone_overhead / (1024.0 * 1024.0));
                }
            }
            g_placement_plan     = ggml_sycl::compute_placement_plan(g_tensor_inventory, plan_budget, ctx->device,
                                                                     g_placement_kv_info, g_moe_n_experts_total);
            g_has_placement_plan = true;
            GGML_LOG_INFO(
                "[SYCL] Placement plan computed: %zu entries, "
                "%.1f MB device + %.1f MB host\n",
                g_placement_plan.entries.size(), g_placement_plan.vram_bytes / (1024.0 * 1024.0),
                g_placement_plan.host_bytes / (1024.0 * 1024.0));
        }
    } else {
        g_has_placement_plan = false;
    }

    // Store plan in cache immediately so KV tier manager can use it.
    // Previously stored in preload_model_weights() which runs AFTER KV init,
    // causing the plan-driven KV path to be skipped.
    if (g_has_placement_plan) {
        for (int d = 0; d < ggml_sycl_info().total_gpu_count; d++) {
            auto * cache = ggml_sycl::get_unified_cache_for_device(d);
            if (cache && !cache->has_placement_plan()) {
                cache->set_placement_plan(ggml_sycl::placement_plan(g_placement_plan));
                GGML_SYCL_DEBUG("[SYCL] Early plan store for device %d\n", d);
            }
        }
        // NOTE: g_has_placement_plan intentionally left true here.
        // The graph-replay guard (g_has_placement_plan && graph_has_host_inputs)
        // protects against replaying graphs with host-resident leaf inputs
        // (e.g. token IDs) whose DATA changes between iterations.  SYCL graph
        // replay bakes the first iteration's data flow — autoregressive TG
        // needs input token + KV position updates between replays, which the
        // current recording infrastructure doesn't support.
    }

    GGML_LOG_INFO(
        "[SYCL] Tensor inventory set: %zu tensors, %.2f GB total "
        "(VRAM: %.2f GB free, tiered: %s)\n",
        g_tensor_inventory.size(), g_tensor_inventory_total_size / (1024.0 * 1024.0 * 1024.0),
        free_mem / (1024.0 * 1024.0 * 1024.0),
        g_tiered_enabled.load(std::memory_order_relaxed) ? "enabled" : "disabled");
}

void ggml_backend_sycl_set_runtime_n_ctx(ggml_backend_t backend, uint32_t n_ctx) {
    if (!backend || n_ctx == 0) {
        return;
    }

    ggml_backend_sycl_context * ctx = (ggml_backend_sycl_context *) backend->context;
    if (!ctx) {
        return;
    }

    std::lock_guard<std::mutex> lock(g_tensor_inventory_mutex);
    g_placement_kv_info.n_ctx            = n_ctx;
    g_placement_kv_info.n_ctx_is_runtime = true;

    if (g_has_placement_plan) {
        g_placement_plan.planner_n_ctx            = n_ctx;
        g_placement_plan.planner_n_ctx_is_runtime = true;
    }

    if (auto * cache = ggml_sycl::get_unified_cache_for_device(ctx->device)) {
        cache->update_placement_plan_runtime_n_ctx(n_ctx);
    }

    if (g_placement_kv_info.valid()) {
        GGML_LOG_INFO("[SYCL-PLAN] Runtime n_ctx update: n_ctx=%u kv_per_layer=%.1f MB\n", g_placement_kv_info.n_ctx,
                      g_placement_kv_info.kv_bytes_per_layer() / (1024.0 * 1024.0));
    }
}

void ggml_backend_sycl_notify_compute_buffer_sizes(ggml_backend_t backend, const size_t * sizes, int n_sizes) {
    if (!backend || !sizes || n_sizes <= 0) {
        return;
    }

    ggml_backend_sycl_context * ctx = (ggml_backend_sycl_context *) backend->context;
    if (!ctx) {
        return;
    }

    const int device = ctx->device;

    // Sum all sizes to get the total compute buffer footprint.
    // The scheduler may spread compute buffers across multiple backends
    // (e.g. GPU + CPU-offload), so we accumulate the full requirement.
    size_t total_bytes = 0;
    for (int i = 0; i < n_sizes; ++i) {
        total_bytes += sizes[i];
    }

    if (total_bytes == 0) {
        return;
    }

    GGML_LOG_INFO("[SYCL-PLAN] Compute buffer sizes notified: %.1f MB total (%d backends)\n",
                  total_bytes / (1024.0 * 1024.0), n_sizes);

    // Pre-size the VRAM compute arena and host SCRATCH zone using the actual
    // scheduler-derived sizes, replacing the heuristic defaults set at model
    // load time.  VRAM arena zones are a single pre-allocated device block
    // with fixed zone boundaries — they cannot grow after creation.  This
    // notification must be called BEFORE the arena is frozen (i.e. before
    // the first graph_compute call) so the correct sizes are locked in.
    //
    // unified_cache_reserve_compute_arena: no-op if arena already has enough
    // capacity; otherwise records the updated reservation for zone layout.
    // unified_cache_grow_host_scratch_zone: extends the host pinned SCRATCH
    // zone to accommodate host-side compute buffers (oneDNN reorder workspace,
    // CPU-offload staging) beyond what the planner estimated at load time.
    if (ggml_sycl::unified_cache_enabled()) {
        ggml_sycl::unified_cache_reserve_compute_arena(device, total_bytes);
        ggml_sycl::unified_cache_grow_host_scratch_zone(total_bytes);
    }
}

// Get the total model size from tensor inventory (for budget calculations)
size_t ggml_sycl_get_model_size() {
    std::lock_guard<std::mutex> lock(g_tensor_inventory_mutex);
    return g_tensor_inventory_total_size;
}

// Get MoE expert memory breakdown (for budget calculations)
void ggml_sycl_get_moe_info(size_t * expert_total_bytes, int * n_expert, int * n_expert_used) {
    std::lock_guard<std::mutex> lock(g_tensor_inventory_mutex);
    if (expert_total_bytes) {
        *expert_total_bytes = g_moe_expert_total_bytes;
    }
    if (n_expert) {
        *n_expert = g_moe_n_experts_total;
    }
    if (n_expert_used) {
        *n_expert_used = g_moe_n_experts_used;
    }
}

bool ggml_backend_sycl_is_tiered_enabled(ggml_backend_t backend) {
    (void) backend;  // Backend context not needed for current implementation
    return g_tiered_enabled.load(std::memory_order_relaxed);
}

// ggml_backend_sycl_model_exceeds_vram removed — unified non-blocking cache
// handles all model sizes.  Inference callers use the non-blocking try_get_cached_with_event path
// which returns FAILED on cache miss instead of blocking.  Dense weights are pinned
// after S1-PRELOAD; MoE experts use LRU eviction.

// Export unified cache budget for llama_params_fit integration
size_t ggml_backend_sycl_get_vram_budget(ggml_backend_t backend) {
    if (!backend) {
        return 0;
    }
    ggml_backend_sycl_context * ctx = (ggml_backend_sycl_context *) backend->context;
    if (!ctx) {
        return 0;
    }
    auto info = ggml_sycl::unified_cache_get_budget_info(ctx->device);
    return info.available_for_weights;
}

size_t ggml_backend_sycl_get_vram_margin(ggml_backend_t backend) {
    if (!backend) {
        return 0;
    }
    ggml_backend_sycl_context * ctx = (ggml_backend_sycl_context *) backend->context;
    if (!ctx) {
        return 0;
    }
    return ggml_sycl::unified_cache_get_margin_bytes(ctx->device);
}

bool ggml_backend_sycl_has_tensor_cache(ggml_backend_t backend) {
    (void) backend;
    return g_tiered_enabled.load(std::memory_order_relaxed);
}

void ggml_backend_sycl_get_cache_stats(ggml_backend_t backend, uint64_t * hits, uint64_t * misses) {
    (void) backend;
    if (hits) {
        *hits = 0;
    }
    if (misses) {
        *misses = 0;
    }
}

// Query tensor location from unified cache for tiered memory dispatch.
// Returns pointer to tensor data and its memory tier.
// If not in tiered mode or tensor not found, returns nullptr.
// Sets found_in_inventory to indicate if tensor is tracked (avoids second mutex lock).
// Uses O(1) hash lookup for performance in hot path.
// This is the integration point between mul_mat dispatch and the unified cache.

void * get_cached_tensor_ptr(const char * tensor_name, ggml_sycl::memory_tier * tier_out, bool * found_in_inventory) {
    if (found_in_inventory) {
        *found_in_inventory = false;
    }
    if (!tensor_name) {
        return nullptr;
    }
    // Only check tiered cache when unified cache is managing weights
    if (!unified_cache_active()) {
        return nullptr;
    }
    // First check inventory index (fast path for inventory check)
    {
        std::lock_guard<std::mutex> lock(g_tensor_inventory_mutex);
        auto                        it = g_tensor_inventory_index.find(tensor_name);
        if (it == g_tensor_inventory_index.end()) {
            return nullptr;  // Not a tracked tensor
        }
        if (found_in_inventory) {
            *found_in_inventory = true;
        }
    }
    // No tensor cache — return nullptr (unified_cache handles weight placement)
    if (tier_out) {
        *tier_out = ggml_sycl::memory_tier::MMAP;  // Fallback
    }
    return nullptr;
}

void * ggml_sycl_get_cached_tensor_ptr_for(const ggml_tensor *      tensor,
                                           int                      device,
                                           ggml_sycl::memory_tier * tier_out,
                                           bool *                   found_in_inventory,
                                           sycl::usm::alloc *       alloc_out) {
    if (alloc_out) {
        *alloc_out = sycl::usm::alloc::unknown;
    }
    if (found_in_inventory) {
        *found_in_inventory = false;
    }

    if (!tensor || tensor->name[0] == '\0') {
        return nullptr;
    }
    // Only check tiered cache when unified cache is managing weights
    if (!unified_cache_active()) {
        return nullptr;
    }
    if (g_sycl_tp_config.enabled && g_sycl_tp_config.world_size > 1) {
        return nullptr;
    }
    ggml_sycl::memory_tier tier         = ggml_sycl::memory_tier::MMAP;
    bool                   in_inventory = false;
    void *                 cached_ptr   = get_cached_tensor_ptr(tensor->name, &tier, &in_inventory);

    if (found_in_inventory) {
        *found_in_inventory = in_inventory;
    }
    if (tier_out) {
        *tier_out = tier;
    }

    if (!cached_ptr) {
        return nullptr;
    }
    sycl::queue &    q     = ggml_sycl_get_device(device).default_queue();
    sycl::usm::alloc alloc = ggml_sycl_get_alloc_type(cached_ptr);
    if (alloc_out) {
        *alloc_out = alloc;
    }
    auto * extra = static_cast<ggml_tensor_extra_gpu *>(tensor->extra);
    if (extra && !(g_sycl_tp_config.enabled && g_sycl_tp_config.world_size > 1)) {
        // Don't overwrite WEIGHT handles — they resolve through the cache
        if (!extra->data_handle[device].is_weight()) {
            if (tier == ggml_sycl::memory_tier::VRAM && alloc == sycl::usm::alloc::device) {
                extra->set_data_device(device, cached_ptr);
            } else {
                extra->set_data_device(device, nullptr);
            }
        }
        if (extra->layout.mode == GGML_LAYOUT_AOS) {
            extra->layout.data_ptr  = cached_ptr;
            extra->layout.size      = ggml_nbytes(tensor);
            extra->layout.device_id = (alloc == sycl::usm::alloc::device) ? device : -1;
        }
    }
    return cached_ptr;
}

// Per-graph-compute pointer resolution cache.  Avoids repeated slow-path
// resolution for the same tensor within a single graph compute.  Cleared at
// the start of each ggml_backend_sycl_graph_compute_impl() call.
// Values are mem_handle so weight handles auto-revalidate via generation counter.
static thread_local std::unordered_map<const ggml_tensor *, ggml_sycl::mem_handle> g_data_ptr_cache;

void ggml_sycl_data_ptr_cache_new_graph() {
    g_data_ptr_cache.clear();
}

// Build the right mem_handle for a resolved pointer.
// Weight tensors: use from_cache_id so resolve() re-validates via generation
// counter on eviction/promotion.  Non-weight tensors (KV, activations, staged
// buffers) get a DIRECT handle since those pointers are stable within a graph.
static ggml_sycl::mem_handle make_data_ptr_handle(const ggml_tensor * tensor, int device, void * ptr) {
    if (ggml_sycl_tensor_is_weight(tensor) && ggml_sycl::unified_cache_enabled()) {
        ggml_sycl_cache_id key = ggml_backend_sycl_get_weight_cache_key(tensor, device);
        if (key.valid) {
            return ggml_sycl::mem_handle::from_cache_id(key, device);
        }
    }
    const bool on_device = (ptr != nullptr) && (ggml_sycl_get_alloc_type(ptr) == sycl::usm::alloc::device);
    return ggml_sycl::mem_handle::from_direct(ptr, GGML_LAYOUT_AOS, on_device);
}

// ---------------------------------------------------------------------------
// MoE expert IDs D2H cache
// ---------------------------------------------------------------------------
// During CPU-TG MUL_MAT_ID dispatch, each call copies expert IDs from device
// to host with stream->memcpy + stream->wait().  For MoE models this happens
// ~108 times per token (once per MUL_MAT_ID node), and each wait() drains
// the entire GPU command queue — accounting for ~30% of CPU-TG time.
//
// Solution: cache the D2H result per unique device pointer within a graph.
// Multiple MUL_MAT_ID nodes within a single MoE layer share the same ids
// tensor pointer, so only the first call per layer does the host copy.
// Subsequent calls read from cache with zero GPU sync.
// Cache is invalidated at graph boundaries via new_graph().
// ---------------------------------------------------------------------------

struct moe_ids_cache_entry {
    std::vector<int32_t> host_ids;
    size_t               n_elements = 0;   // number of int32 elements
    sycl::event          d2h_event;        // async D2H completion event (lazy sync)
    bool                 pending = false;  // true = D2H submitted but not yet waited

    // Block until the async D2H completes, then clear pending flag.
    void wait() {
        if (pending) {
            d2h_event.wait();
            pending = false;
        }
    }
};

// Keyed by the ggml_tensor pointer (avoids unnecessary device round-trips).
static thread_local std::unordered_map<const ggml_tensor *, moe_ids_cache_entry> g_moe_ids_d2h_cache;

// ---------------------------------------------------------------------------
// Per-layer IDs D2H + expert pointer cache for MoE sub-op batching (Task 1E).
// Gate/Up/Down sub-ops within the same MoE block share the same expert IDs.
// The GATE sub-op populates this cache; UP and DOWN reuse it to avoid
// redundant D2H copies and placement table lookups.
// ---------------------------------------------------------------------------
struct moe_layer_ids_cache_entry {
    std::vector<int32_t>               ids_host;  // Expert IDs (copied D2H once at GATE)
    // Task 1E: Pre-resolved expert pointers from GATE, reused at UP/DOWN.
    // Avoids redundant placement table lookups, cache queries, and stats tracking.
    // mem_handle instead of void* so that resolve() auto-revalidates on cache eviction.
    // graph_epoch and ptrs_valid removed — cache is cleared each graph boundary, and
    // mem_handle::resolve() returns nullptr on eviction (auto-staleness via generation counter).
    std::vector<ggml_sycl::mem_handle> expert_ptrs;  // Resolved expert pointer handles (indexed by expert_id)
    layout_mode                        ptrs_layout = GGML_LAYOUT_AOS;  // Layout used when pointers were cached

    // Task 1E: Cached expert partitioning from first sub-op for fusion path reuse.
    // Avoids redundant placement table lookups at subsequent sub-ops (~1ms/token).
    struct cached_partition {
        std::vector<size_t> cpu_indices;

        struct sec_info {
            size_t ci;
            int    device_id;
            void * device_ptr;
        };

        std::vector<sec_info> sec_indices;
        std::vector<size_t>   gpu0_cached_indices;
        bool                  valid = false;
    } partition;
};

// Keyed by block-number layer_id (parsed from tensor name). Cleared each graph boundary.
static thread_local std::unordered_map<int, moe_layer_ids_cache_entry> g_moe_layer_ids_cache;

static void ggml_sycl_moe_ids_cache_new_graph() {
    // Wait for any in-flight async D2H before destroying the host vectors
    // that the OOQ memcpy is writing into.
    for (auto & [key, entry] : g_moe_ids_d2h_cache) {
        entry.wait();
    }
    g_moe_ids_d2h_cache.clear();
    // Clear the per-layer IDs cache so stale entries from the previous graph
    // are never reused.  graph_epoch was removed — clearing is simpler and
    // removes the epoch bookkeeping entirely.
    g_moe_layer_ids_cache.clear();
}

// Task 1E helper: re-resolve a secondary expert's device_ptr for the current sub-op's
// weight tensor.  The cached partition stores the pointer from whichever sub-op first
// populated it (e.g. GATE), but UP/DOWN weights live at different device addresses.
// Returns the freshly-resolved pointer, or nullptr if the expert is no longer on the
// expected device (evicted between sub-ops).
static inline void * moe_1e_re_resolve_sec_ptr(int cur_layer_hash, int32_t expert_id, int expected_device_id) {
    // Re-resolve the device pointer for this expert on the expected secondary GPU.
    // OLD: used placement_table.get() which failed due to FNV hash mismatch.
    // NEW: check the unified cache directly via expert group registry.
    //
    // This overload is called from paths where the block_id and tensor role are
    // not directly available.  We derive them from the cur_layer_hash by scanning
    // g_moe_expert_meta for a matching (layer_id, expert_idx).
    // Fallback: try all roles for each block containing this expert_id.
    {
        std::shared_lock<std::shared_mutex> meta_lock(g_moe_expert_meta_mutex);
        int                                 block_id = -1;
        moe_tensor_type                     role     = MOE_TENSOR_UNKNOWN;
        for (const auto & meta : g_moe_expert_meta) {
            if (meta.layer_id == cur_layer_hash && meta.expert_idx == expert_id) {
                block_id = meta.block_num;
                role     = meta.tensor_role;
                break;
            }
        }
        if (block_id >= 0 && role != MOE_TENSOR_UNKNOWN) {
            return get_expert_device_ptr(block_id, expert_id, role, expected_device_id);
        }
    }
    return nullptr;  // expert moved/evicted — caller must skip or CPU-fallback
}

static void ggml_sycl_moe_layer_ids_cache_new_graph() {
    for (auto & [_, entry] : g_moe_layer_ids_cache) {
        entry.partition.valid = false;
    }
    g_moe_layer_ids_cache.clear();
}

// ---------------------------------------------------------------------------
// MoE expert probability threshold: skip low-probability experts in TG
// ---------------------------------------------------------------------------
// Maps layer_id -> pointer to the final ffn_moe_weights tensor for this graph.
// Populated by a pre-scan in graph_compute_impl, consumed by mul_mat_id.
static thread_local std::unordered_map<int, const ggml_tensor *> g_moe_weights_by_layer;

static float ggml_sycl_moe_prob_threshold() {
    static float threshold = -1.0f;
    if (threshold < 0.0f) {
        const char * env = getenv("GGML_SYCL_MOE_PROB_THRESHOLD");
        float        val = env ? std::atof(env) : 0.0f;  // Default: disabled
        if (val < 0.0f || val >= 1.0f) {
            GGML_LOG_WARN("[MOE-SKIP] GGML_SYCL_MOE_PROB_THRESHOLD=%.4f out of range [0, 1), disabled\n", val);
            val = 0.0f;
        }
        threshold = val;
    }
    return threshold;
}

// ---------------------------------------------------------------------------
// Deferred CPU scatter: pipeline CPU expert compute with GPU work
// ---------------------------------------------------------------------------
// Instead of waiting for CPU compute to finish and scattering results
// immediately after each MUL_MAT_ID, we defer the scatter.  The next
// MUL_MAT_ID entry (or graph boundary) flushes the pending scatter.
// This overlaps CPU compute with the GPU attention/normalization ops
// that run between MoE layers, hiding CPU latency.
// ---------------------------------------------------------------------------

struct pending_cpu_scatter {
    std::future<void>       future;      // CPU compute completion
    float *                 out_pinned;  // Output buffer to scatter from
    float *                 act_pinned;  // Activation buffer (for deferred release)
    // Use .as_mem_handle() for read/resolve access; unified_free(alloc_handle) for ownership
    ggml_sycl::alloc_handle out_alloc;
    ggml_sycl::alloc_handle act_alloc;
    sycl::queue *           stream;    // GPU queue for H2D copies
    sycl::context           sycl_ctx;  // SYCL context for deferred sycl::free

    // Per-expert scatter metadata
    struct scatter_entry {
        char * dst_device;  // Device destination for this expert's output
        int    N;           // Output elements (floats) per expert
    };

    std::vector<scatter_entry> entries;

    // Legacy field, retained for ABI stability and backward compatibility
    // with paths that only use its clear()-on-flush semantics.  As of the
    // skgik fix, the CPU expert task storage lives inside the worker's
    // lambda (submit_batch takes the vector by value and moves it in), so
    // this field is never populated during a live submission.
    std::vector<cpu_expert_task> tasks;

    int  device_id;     // Device index for pool release
    bool from_pool;     // Whether buffers came from pool
    bool owns_buffers;  // Whether flush should free out_pinned/act_pinned
    bool active;        // Whether there's a pending scatter

    // Deferred scatter tracking: the MUL_MAT_ID output tensor that this
    // scatter writes to.  Used by selective flush to skip flushing when
    // the next op doesn't consume our destination tensor.
    const ggml_tensor * dst_tensor;

    // Deferred buffer cleanup: when we skip stream->wait() (async scatter),
    // the source buffers can't be freed until the memcpys complete.  We defer
    // cleanup to the next flush call — by then, at least one kernel on the
    // in-order queue has executed, guaranteeing the memcpys finished.
    struct deferred_bufs {
        float *                 out = nullptr;
        float *                 act = nullptr;
        ggml_sycl::alloc_handle out_alloc{};
        ggml_sycl::alloc_handle act_alloc{};
        sycl::context           ctx;
        int                     dev_id  = -1;
        bool                    pool    = false;
        bool                    pending = false;
    } prev_bufs;

    pending_cpu_scatter() :
        out_pinned(nullptr),
        act_pinned(nullptr),
        out_alloc(),
        act_alloc(),
        stream(nullptr),
        sycl_ctx(),
        device_id(-1),
        from_pool(false),
        owns_buffers(true),
        active(false),
        dst_tensor(nullptr) {}
};

static thread_local pending_cpu_scatter g_pending_scatter = {};

// Result struct for async CPU expert dispatch.  Carries compute output and
// metadata from the async thread back to the main thread so the main thread
// can populate g_pending_scatter (which is thread_local and therefore not
// visible from the async thread).
struct cpu_dispatch_result {
    std::future<void>                               future;  // CPU compute future (may still be running)
    float *                                         out_pinned = nullptr;
    float *                                         act_pinned = nullptr;
    ggml_sycl::alloc_handle                         out_alloc{};
    ggml_sycl::alloc_handle                         act_alloc{};
    std::vector<cpu_expert_task>                    tasks;  // must outlive future
    std::vector<pending_cpu_scatter::scatter_entry> entries;
    int                                             device_id    = -1;
    bool                                            from_pool    = false;
    bool                                            owns_buffers = true;
    bool                                            valid        = false;
};

// ---------------------------------------------------------------------------
// MoE gate+up+SiLU fusion state — Phase 4 simplified state machine.
//
// Expert routing is resolved ONCE on the first MUL_MAT_ID arrival (gate or
// up — ggml ordering varies by model).  The routing decision is cached in
// cpu_indices / sec_indices / gpu0_cached_indices and reused for all three
// sub-tensors (gate, up, down) within the same MoE layer.
//
// Phases:
//   IDLE         — no pending state
//   FIRST_SAVED  — first arrival seen; routing resolved, weight data saved
//   FUSED_READY  — gate+up+SiLU fused; fused_output ready for DOWN
// ---------------------------------------------------------------------------

// =============================================================================
// Arena-Routed Allocation Helpers (local to ggml-sycl.cpp)
// =============================================================================
// All helpers return alloc_handle. Callers call unified_free(handle) instead of
// tracking from_pool/from_arena booleans.

// Host-pinned allocation for fused MoE output buffers.
// Returns alloc_handle — call unified_free(handle) to release.
static ggml_sycl::alloc_handle arena_pinned_alloc(size_t bytes, sycl::queue & queue) {
    if (bytes == 0) {
        return {};
    }
    ggml_sycl::alloc_request req{};
    req.queue                               = &queue;
    req.device                              = ggml_sycl_get_device_id_from_queue(queue);
    req.size                                = bytes;
    req.intent.role                         = ggml_sycl::alloc_role::COMPUTE;
    req.intent.category                     = ggml_sycl::runtime_category::HOST_COMPUTE;
    req.intent.constraints.must_host_pinned = true;
    req.intent.constraints.use_pinned_pool  = false;
    ggml_sycl::alloc_handle handle{};
    if (!ggml_sycl::unified_alloc(req, &handle) || !handle.ptr) {
        GGML_LOG_WARN("[arena_pinned_alloc] pinned allocation failed for %zu bytes\n", bytes);
        return {};
    }
    return handle;
}

// Device allocation through the VRAM arena SCRATCH zone when available.
// Returns alloc_handle — call unified_free(handle) to release.
// Arena-backed handles have zone_managed=true (freed by zone_free through unified_free()).
// Fallback device handles have zone_managed=false (freed via sycl::free).
static ggml_sycl::alloc_handle arena_device_alloc(size_t bytes, int device_id, sycl::queue & queue) {
    if (bytes == 0) {
        return {};
    }
    pp_scratch_profile_note_device_alloc(bytes);
    if (ggml_sycl::vram_arena_enabled() && device_id >= 0) {
        auto * cache = ggml_sycl::get_unified_cache_for_device(device_id);
        void * ptr   = (cache && cache->arena_active()) ? cache->arena_alloc(bytes) : nullptr;
        if (ptr) {
            ggml_sycl::alloc_handle h{};
            h.ptr          = ptr;
            h.size         = bytes;
            h.device       = device_id;
            h.tier         = ggml_sycl::alloc_tier::DEVICE_VRAM;
            h.zone_managed = true;
            h.vram_zone    = ggml_sycl::vram_zone_id::SCRATCH;
            return h;
        }
    }
    ggml_sycl::alloc_request req{};
    req.queue                          = &queue;
    req.device                         = device_id;
    req.size                           = bytes;
    req.intent.role                    = ggml_sycl::alloc_role::COMPUTE;
    req.intent.category                = ggml_sycl::runtime_category::COMPUTE;
    req.intent.constraints.must_device = true;
    ggml_sycl::alloc_handle h{};
    ggml_sycl::unified_alloc(req, &h);
    if (!h.ptr) {
        GGML_LOG_WARN("[arena_device_alloc] device fallback failed for %zu bytes\n", bytes);
    }
    return h;
}

enum moe_fusion_phase : int {
    MOE_FUSE_IDLE        = 0,
    MOE_FUSE_FIRST_SAVED = 1,
    MOE_FUSE_FUSED_READY = 2,
};

struct moe_fusion_state {
    // Phase tracking
    moe_fusion_phase phase         = MOE_FUSE_IDLE;
    bool             first_is_gate = false;  // true if gate arrived first

    // Weight data pointers (set as each sub-tensor arrives)
    const void * gate_data = nullptr;  // Gate tensor src0->data
    const void * up_data   = nullptr;  // Up tensor src0->data
    size_t       gate_nb02 = 0;        // Gate expert stride in bytes
    size_t       up_nb02   = 0;        // Up expert stride in bytes

    // Shared state (resolved once on first arrival, reused for up/down)
    const float *   act_host = nullptr;        // Activation vector (host-accessible)
    const int32_t * ids_data = nullptr;        // Expert IDs (shared across gate/up/down)
    size_t          n_ids    = 0;              // Number of CPU expert dispatches
    int64_t         n_as     = 0;              // Total number of experts in layer
    int             K        = 0;              // Input dimension
    int             N_gate   = 0;              // Gate/up output dimension (intermediate size)
    ggml_type       type     = GGML_TYPE_F32;  // Weight quantization type
    int             layer_id = -1;             // Layer number for matching

    // Fused output buffer
    float *                 fused_output = nullptr;  // Pinned buffer: SiLU(gate*act) * (up*act)
    size_t                  fused_cap    = 0;        // Capacity of fused_output in floats
    // Use fused_alloc.as_mem_handle() for read/resolve; unified_free(fused_alloc) for ownership
    ggml_sycl::alloc_handle fused_alloc{};

    // Expert routing — resolved ONCE on first arrival, reused for up and down
    std::vector<size_t> cpu_indices;  // CPU-dispatched expert indices

    struct sec_expert_info {
        size_t ci;  // Original expert index
        int    device_id;
        void * device_ptr;
    };

    std::vector<sec_expert_info> sec_indices;          // Secondary-GPU experts
    std::vector<size_t>          gpu0_cached_indices;  // GPU0-cached experts (MMVQ)

    // Bias pointers (resolved once on first arrival)
    const float * gate_bias_data = nullptr;
    const float * up_bias_data   = nullptr;
    const float * down_bias_data = nullptr;
    size_t        bias_nb        = 0;

    // Async activation D2H event
    sycl::event act_d2h_event;
    bool        act_d2h_pending = false;

    // Drain the activation D2H event if pending.
    void wait_act_d2h() {
        if (act_d2h_pending) {
            act_d2h_event.wait();
            act_d2h_pending = false;
        }
    }

    ~moe_fusion_state() {
        if (fused_alloc.ptr) {
            (void) ggml_sycl::unified_free(fused_alloc);
        }
    }

    void ensure_fused_buf(size_t n, sycl::queue & q) {
        if (n <= fused_cap) {
            return;
        }
        if (fused_alloc.ptr) {
            (void) ggml_sycl::unified_free(fused_alloc);
            fused_output = nullptr;
            fused_alloc  = {};
        }
        const size_t bytes = n * sizeof(float);
        fused_alloc        = arena_pinned_alloc(bytes, q);
        fused_output       = static_cast<float *>(fused_alloc.ptr);
        fused_cap          = fused_alloc.ptr ? n : 0;
    }

    // Convenience: check if fused output is ready (used by GLU/ADD_ID skip guards)
    bool fused_pending() const { return phase == MOE_FUSE_FUSED_READY; }

    // Timing: set at GATE save, read at FUSE and DOWN
    std::chrono::high_resolution_clock::time_point t_layer_start{};

    void reset() {
        wait_act_d2h();
        phase          = MOE_FUSE_IDLE;
        first_is_gate  = false;
        layer_id       = -1;
        gate_data      = nullptr;
        up_data        = nullptr;
        gate_nb02      = 0;
        up_nb02        = 0;
        gate_bias_data = nullptr;
        up_bias_data   = nullptr;
        down_bias_data = nullptr;
        bias_nb        = 0;
        cpu_indices.clear();
        sec_indices.clear();
        gpu0_cached_indices.clear();
    }
};

static thread_local std::unordered_map<int, moe_fusion_state> g_moe_fusions;

static inline moe_fusion_state * moe_fusion_find(const int layer_id) {
    if (layer_id < 0) {
        return nullptr;
    }

    auto it = g_moe_fusions.find(layer_id);
    return it != g_moe_fusions.end() ? &it->second : nullptr;
}

static inline moe_fusion_state & moe_fusion_get_or_create(const int layer_id) {
    GGML_ASSERT(layer_id >= 0);
    return g_moe_fusions[layer_id];
}

static inline void moe_fusion_erase(const int layer_id) {
    if (layer_id < 0) {
        return;
    }

    auto it = g_moe_fusions.find(layer_id);
    if (it != g_moe_fusions.end()) {
        g_moe_fusions.erase(it);
    }
}

static inline void moe_fusion_clear_all() {
    g_moe_fusions.clear();
}

// ---------------------------------------------------------------------------
// MoE Per-Phase Profiling (GGML_SYCL_MOE_PROFILE=1)
// ---------------------------------------------------------------------------
// Measures exact per-phase timings in the 120B MoE token generation path.
// Zero overhead when the env var is not set.

static bool g_moe_profile_enabled     = false;
static bool g_moe_profile_initialized = false;

// PP-specific profile mode: no warmup, profile first graph_compute
static bool g_moe_pp_profile_enabled = false;

static inline void moe_profile_init() {
    if (g_moe_profile_initialized) {
        return;
    }
    g_moe_profile_initialized = true;
    const char * env          = getenv("GGML_SYCL_MOE_PROFILE");
    g_moe_profile_enabled     = (env && std::atoi(env) != 0);
    // GGML_SYCL_MOE_PP_PROFILE=1: zero warmup, profile first graph (for PP)
    const char * pp_env       = getenv("GGML_SYCL_MOE_PP_PROFILE");
    if (pp_env && std::atoi(pp_env) != 0) {
        g_moe_profile_enabled    = true;
        g_moe_pp_profile_enabled = true;
    }
    if (g_moe_profile_enabled) {
        int warmup  = g_moe_pp_profile_enabled ? 0 : 2;
        int profile = g_moe_pp_profile_enabled ? 1 : 10;
        fprintf(stderr, "[MOE-PROFILE] Enabled%s: %d warmup + %d profiled tokens\n",
                g_moe_pp_profile_enabled ? " (PP mode)" : "", warmup, profile);
    }
}

struct moe_profile_layer {
    double ids_d2h_us     = 0;  // IDs D2H copy time
    double routing_us     = 0;  // Expert routing/partitioning
    double cpu_compute_us = 0;  // CPU expert compute (gate+up+silu+down)
    double gpu_compute_us = 0;  // GPU expert compute (secondary dispatch)
    double scatter_us     = 0;  // H2D scatter of results
    double inter_op_us    = 0;  // Time between MUL_MAT_ID calls within layer (SILU, norms, scatter flush)
    double weight_load_us = 0;  // Weight ensure/streaming time (PCIe)
    double layer_total_us = 0;  // Total MoE layer time (entry to exit)
    int    n_cpu_experts  = 0;  // Number of CPU-dispatched experts
    int    n_gpu_experts  = 0;  // Number of GPU-dispatched experts
    int    n_calls        = 0;  // Number of MUL_MAT_ID calls in this layer (gate/up/down)

    // Scatter decomposition (U6): break scatter_us into sub-phases
    double scatter_cpu_wait_us   = 0;  // Time waiting for CPU future.get()
    double scatter_submit_us     = 0;  // Time submitting memcpy to queue
    double scatter_event_wait_us = 0;  // Time inside event::wait / stream->wait()
    int    scatter_n_calls       = 0;  // Number of scatter calls in this layer
    int    scatter_n_entries     = 0;  // Total scatter entries (expert results)
    double scatter_bytes         = 0;  // Total bytes scattered H2D

    // PP profile: cache hit/miss/S1 bailout counters
    int cache_hits         = 0;  // Experts found in VRAM cache (device-resident)
    int cache_misses       = 0;  // Experts requiring CPU compute or staging
    int sec_gpu_experts    = 0;  // Experts dispatched to secondary GPU
    int s1_bailout_count   = 0;  // Times fused kernel bailed due to S1 mode
    int fused_esimd_count  = 0;  // Times fused ESIMD kernel handled the op
    int xmx_sorted_count   = 0;  // Times XMX sorted dispatch handled the op
    int host_routing_count = 0;  // Times host-side routing was used
};

struct moe_profile_token {
    double                         token_start_us = 0;
    double                         token_total_us = 0;
    double                         moe_total_us   = 0;  // Sum of all MoE layer times
    double                         attention_us   = 0;  // Time between MoE layers (non-MoE ops)
    double                         other_us       = 0;  // Everything else (norms, embed, etc.)
    int                            n_moe_layers   = 0;
    std::vector<moe_profile_layer> layers;
};

struct moe_profile_state {
    using hrc = std::chrono::high_resolution_clock;

    // Per-token state
    hrc::time_point token_start;
    hrc::time_point last_moe_exit;  // When the last MoE op finished
    hrc::time_point moe_entry;      // Current MoE layer entry
    bool            in_moe_layer     = false;
    int             current_layer    = -1;
    double          non_moe_accum_us = 0;  // Accumulated non-MoE time

    // Current layer accumulator (across gate/up/down calls)
    moe_profile_layer cur_layer;

    // Per-MUL_MAT_ID sub-phase timestamps
    hrc::time_point op_start;
    hrc::time_point ids_done;
    hrc::time_point routing_done;
    hrc::time_point gpu_compute_done_tp;  // GPU MMVQ dispatch end
    hrc::time_point compute_done;         // All compute end (GPU + CPU)
    hrc::time_point scatter_done;
    hrc::time_point last_op_end;          // End of previous MUL_MAT_ID in same layer
    bool            has_last_op_end = false;
    int             op_n_cpu        = 0;
    int             op_n_gpu        = 0;

    // Collected tokens
    std::vector<moe_profile_token> tokens;
    int                            n_tokens_seen = 0;
    int                            n_warmup      = 2;   // Skip first N tokens
    int                            n_profile     = 10;  // Profile N tokens after warmup
    bool                           token_active  = false;

    // Apply PP profile settings (called once after init)
    void configure_pp_mode() {
        n_warmup  = 0;
        n_profile = 1;  // Single graph_compute call for PP
    }

    // Helper
    static double us(hrc::time_point a, hrc::time_point b) {
        return std::chrono::duration<double, std::micro>(b - a).count();
    }

    void begin_token() {
        n_tokens_seen++;
        if (n_tokens_seen <= n_warmup || n_tokens_seen > n_warmup + n_profile) {
            token_active = false;
            return;
        }
        token_active     = true;
        token_start      = hrc::now();
        last_moe_exit    = token_start;
        in_moe_layer     = false;
        current_layer    = -1;
        non_moe_accum_us = 0;
        cur_layer        = {};
        // Push a new token entry for this token
        tokens.emplace_back();
        tokens.back().token_start_us = 0;
    }

    void end_token() {
        if (!token_active) {
            return;
        }
        auto now = hrc::now();

        // Finalize current layer if still open
        if (in_moe_layer) {
            // Layer total = entry to last op exit (not to token end)
            cur_layer.layer_total_us = has_last_op_end ? us(moe_entry, last_op_end) : us(moe_entry, now);
            if (!tokens.empty()) {
                moe_profile_token & tok = tokens.back();
                tok.layers.push_back(cur_layer);
                tok.moe_total_us += cur_layer.layer_total_us;
            }
            in_moe_layer = false;
        }

        if (tokens.empty()) {
            // No MoE ops seen — create a minimal entry
            tokens.emplace_back();
        }
        moe_profile_token & tok = tokens.back();
        tok.token_total_us      = us(token_start, now);

        // Non-MoE time = everything outside MoE layers (attention, norms, embed, etc.)
        tok.attention_us = tok.token_total_us - tok.moe_total_us;
        tok.other_us     = 0;  // Not splitting further
        tok.n_moe_layers = static_cast<int>(tok.layers.size());

        token_active = false;

        // Print report when done collecting
        if (static_cast<int>(tokens.size()) >= n_profile) {
            print_report();
        }
    }

    // Called at MoE MUL_MAT_ID entry
    void moe_op_begin(int layer_id) {
        if (!token_active) {
            return;
        }

        auto now = hrc::now();

        // If this is a new layer or first MoE call in this token
        if (!in_moe_layer || layer_id != current_layer) {
            // Finalize previous layer if any
            if (in_moe_layer) {
                // Layer total = entry to last op exit (NOT to next layer start)
                cur_layer.layer_total_us = us(moe_entry, last_moe_exit);
                moe_profile_token & tok  = tokens.back();
                tok.layers.push_back(cur_layer);
                tok.moe_total_us += cur_layer.layer_total_us;

                // Time between last MoE op exit and NOW = non-MoE time (attention/norms)
                non_moe_accum_us += us(last_moe_exit, now);
            } else {
                // First MoE op in token — accumulate pre-MoE time
                non_moe_accum_us += us(last_moe_exit, now);
            }

            // Start new layer
            cur_layer       = {};
            current_layer   = layer_id;
            in_moe_layer    = true;
            moe_entry       = now;
            has_last_op_end = false;
        } else if (has_last_op_end) {
            // Same layer, not first op — capture inter-op time (SILU, norms, scatter flush)
            cur_layer.inter_op_us += us(last_op_end, now);
        }

        op_start            = hrc::now();
        ids_done            = op_start;  // Default: no IDs D2H
        routing_done        = op_start;  // Default: no routing
        gpu_compute_done_tp = op_start;  // Default: no GPU compute
        compute_done        = op_start;  // Default: no compute
        op_n_cpu            = 0;
        op_n_gpu            = 0;
    }

    // Sub-phase timestamps within a MUL_MAT_ID call
    void moe_weight_load_done() {
        if (!token_active) {
            return;
        }
        auto now = hrc::now();
        cur_layer.weight_load_us += us(op_start, now);
        op_start = now;  // Shift op_start past weight load so IDs D2H starts fresh
    }

    void moe_ids_done() {
        if (token_active) {
            ids_done = hrc::now();
        }
    }

    void moe_routing_done() {
        if (token_active) {
            routing_done = hrc::now();
        }
    }

    void moe_gpu_compute_done() {
        if (token_active) {
            gpu_compute_done_tp = hrc::now();
        }
    }

    void moe_compute_done(int n_cpu, int n_gpu) {
        if (!token_active) {
            return;
        }
        compute_done = hrc::now();
        op_n_cpu     = n_cpu;
        op_n_gpu     = n_gpu;
    }

    void moe_scatter_done() {
        if (token_active) {
            scatter_done = hrc::now();
        }
    }

    // PP profile: record cache hit/miss counts for current layer
    void moe_cache_stats(int hits, int misses, int sec_gpu) {
        if (!token_active) {
            return;
        }
        cur_layer.cache_hits += hits;
        cur_layer.cache_misses += misses;
        cur_layer.sec_gpu_experts += sec_gpu;
    }

    // PP profile: record dispatch path taken
    void moe_dispatch_path(int s1_bailout, int fused_esimd, int xmx_sorted, int host_routing) {
        if (!token_active) {
            return;
        }
        cur_layer.s1_bailout_count += s1_bailout;
        cur_layer.fused_esimd_count += fused_esimd;
        cur_layer.xmx_sorted_count += xmx_sorted;
        cur_layer.host_routing_count += host_routing;
    }

    // Record scatter decomposition (U6 probes)
    void moe_scatter_detail(double cpu_wait_us, double submit_us, double event_wait_us, int n_entries, double bytes) {
        if (!token_active) {
            return;
        }
        cur_layer.scatter_cpu_wait_us += cpu_wait_us;
        cur_layer.scatter_submit_us += submit_us;
        cur_layer.scatter_event_wait_us += event_wait_us;
        cur_layer.scatter_n_calls++;
        cur_layer.scatter_n_entries += n_entries;
        cur_layer.scatter_bytes += bytes;
    }

    // Called at MoE MUL_MAT_ID exit
    void moe_op_end() {
        if (!token_active) {
            return;
        }
        auto now = hrc::now();

        // Default unset timestamps to op_start to avoid garbage values
        auto ids_t     = (ids_done > op_start) ? ids_done : op_start;
        auto routing_t = (routing_done > op_start) ? routing_done : ids_t;
        auto gpu_t     = (gpu_compute_done_tp > op_start) ? gpu_compute_done_tp : routing_t;
        auto compute_t = (compute_done > op_start) ? compute_done : gpu_t;

        cur_layer.ids_d2h_us += us(op_start, ids_t);
        cur_layer.routing_us += us(ids_t, routing_t);
        cur_layer.gpu_compute_us += us(routing_t, gpu_t);
        cur_layer.cpu_compute_us += us(gpu_t, compute_t);
        cur_layer.scatter_us += us(compute_t, now);
        cur_layer.n_cpu_experts += op_n_cpu;
        cur_layer.n_gpu_experts += op_n_gpu;
        cur_layer.n_calls++;

        // U6 diagnostic: detect when compute_done was never set (falls back to
        // op_start or routing_done), causing entire op time to be misattributed
        // to "scatter".  This happens on paths that skip moe_compute_done().
        bool compute_was_set = (compute_done > op_start);
        if (!compute_was_set) {
            n_compute_not_set++;
            unset_scatter_accum_us += us(compute_t, now);
        }

        last_moe_exit   = now;
        last_op_end     = now;
        has_last_op_end = true;
    }

    // U6 diagnostic counters
    int    n_compute_not_set      = 0;  // How many ops had compute_done unset
    double unset_scatter_accum_us = 0;  // Total "scatter" time from unset compute_done

    // Called when fusion completes a full gate+up+silu+down cycle
    void moe_fusion_phase(double ids_us,
                          double routing_us_val,
                          double compute_us_val,
                          double scatter_us_val,
                          int    n_cpu,
                          int    n_gpu) {
        if (!token_active) {
            return;
        }
        cur_layer.ids_d2h_us += ids_us;
        cur_layer.routing_us += routing_us_val;
        cur_layer.cpu_compute_us += compute_us_val;
        cur_layer.scatter_us += scatter_us_val;
        cur_layer.n_cpu_experts += n_cpu;
        cur_layer.n_gpu_experts += n_gpu;
        cur_layer.n_calls++;
        last_moe_exit = hrc::now();
    }

    void print_report() {
        if (tokens.empty()) {
            return;
        }

        // Print per-token summary table
        fprintf(stderr, "\n=== MoE Per-Phase Profile (%d tokens, %d warmup skipped) ===\n",
                static_cast<int>(tokens.size()), n_warmup);

        // Compute averages across all profiled tokens
        double avg_ids = 0, avg_routing = 0, avg_cpu = 0, avg_gpu = 0;
        double avg_scatter = 0, avg_inter_op = 0, avg_weight_load = 0;
        double avg_attn = 0, avg_other = 0, avg_total = 0;
        double avg_moe              = 0;
        // Scatter decomposition averages (U6)
        double avg_scatter_cpu_wait = 0, avg_scatter_submit = 0, avg_scatter_event_wait = 0;
        double avg_scatter_bytes   = 0;
        int    avg_scatter_entries = 0, avg_scatter_calls = 0;
        int    avg_layers = 0, avg_cpu_experts = 0, avg_gpu_experts = 0;

        for (auto & tok : tokens) {
            double tok_ids = 0, tok_routing = 0, tok_cpu = 0, tok_gpu = 0, tok_scatter = 0;
            double tok_inter_op = 0, tok_weight_load = 0;
            double tok_scat_cpu = 0, tok_scat_sub = 0, tok_scat_wait = 0, tok_scat_bytes = 0;
            int    tok_scat_ent = 0, tok_scat_calls = 0;
            int    tok_cpu_exp = 0, tok_gpu_exp = 0;
            for (auto & lay : tok.layers) {
                tok_ids += lay.ids_d2h_us;
                tok_routing += lay.routing_us;
                tok_cpu += lay.cpu_compute_us;
                tok_gpu += lay.gpu_compute_us;
                tok_scatter += lay.scatter_us;
                tok_inter_op += lay.inter_op_us;
                tok_weight_load += lay.weight_load_us;
                tok_cpu_exp += lay.n_cpu_experts;
                tok_gpu_exp += lay.n_gpu_experts;
                tok_scat_cpu += lay.scatter_cpu_wait_us;
                tok_scat_sub += lay.scatter_submit_us;
                tok_scat_wait += lay.scatter_event_wait_us;
                tok_scat_ent += lay.scatter_n_entries;
                tok_scat_calls += lay.scatter_n_calls;
                tok_scat_bytes += lay.scatter_bytes;
            }
            avg_ids += tok_ids;
            avg_routing += tok_routing;
            avg_cpu += tok_cpu;
            avg_gpu += tok_gpu;
            avg_scatter += tok_scatter;
            avg_inter_op += tok_inter_op;
            avg_weight_load += tok_weight_load;
            avg_attn += tok.attention_us;
            avg_other += tok.other_us;
            avg_total += tok.token_total_us;
            avg_moe += tok.moe_total_us;
            avg_layers += tok.n_moe_layers;
            avg_cpu_experts += tok_cpu_exp;
            avg_gpu_experts += tok_gpu_exp;
            avg_scatter_cpu_wait += tok_scat_cpu;
            avg_scatter_submit += tok_scat_sub;
            avg_scatter_event_wait += tok_scat_wait;
            avg_scatter_entries += tok_scat_ent;
            avg_scatter_calls += tok_scat_calls;
            avg_scatter_bytes += tok_scat_bytes;
        }

        const int nt = static_cast<int>(tokens.size());
        avg_ids /= nt;
        avg_routing /= nt;
        avg_cpu /= nt;
        avg_gpu /= nt;
        avg_scatter /= nt;
        avg_inter_op /= nt;
        avg_weight_load /= nt;
        avg_attn /= nt;
        avg_other /= nt;
        avg_total /= nt;
        avg_moe /= nt;
        avg_scatter_cpu_wait /= nt;
        avg_scatter_submit /= nt;
        avg_scatter_event_wait /= nt;
        avg_scatter_bytes /= nt;

        // Print one detailed token first (token index 2, or last if fewer)
        int    detail_idx = std::min(2, nt - 1);
        auto & dtok       = tokens[detail_idx];
        fprintf(stderr, "\n--- Detailed breakdown: profiled token #%d (%d MoE layers) ---\n", detail_idx + 1,
                dtok.n_moe_layers);
        fprintf(stderr, "%-25s | %10s | %13s | %8s\n", "Phase", "Total(ms)", "Per-Layer(ms)", "% Token");
        fprintf(stderr, "%-25s-+-%10s-+-%13s-+-%8s\n", "-------------------------", "----------", "-------------",
                "--------");

        auto print_row = [&](const char * name, double total_us, int n_layers_d) {
            double pct       = dtok.token_total_us > 0 ? 100.0 * total_us / dtok.token_total_us : 0;
            double per_layer = n_layers_d > 0 ? total_us / 1000.0 / n_layers_d : 0;
            fprintf(stderr, "%-25s | %10.1f | %13.2f | %7.1f%%\n", name, total_us / 1000.0, per_layer, pct);
        };

        double dtok_ids = 0, dtok_routing = 0, dtok_cpu = 0, dtok_gpu = 0, dtok_scatter = 0;
        double dtok_inter_op = 0;
        double dtok_scat_cpu = 0, dtok_scat_sub = 0, dtok_scat_wait = 0, dtok_scat_bytes = 0;
        int    dtok_scat_ent = 0, dtok_scat_calls = 0;
        int    dtok_cpu_exp = 0, dtok_gpu_exp = 0;
        for (auto & lay : dtok.layers) {
            dtok_ids += lay.ids_d2h_us;
            dtok_routing += lay.routing_us;
            dtok_cpu += lay.cpu_compute_us;
            dtok_gpu += lay.gpu_compute_us;
            dtok_scatter += lay.scatter_us;
            dtok_inter_op += lay.inter_op_us;
            dtok_cpu_exp += lay.n_cpu_experts;
            dtok_gpu_exp += lay.n_gpu_experts;
            dtok_scat_cpu += lay.scatter_cpu_wait_us;
            dtok_scat_sub += lay.scatter_submit_us;
            dtok_scat_wait += lay.scatter_event_wait_us;
            dtok_scat_ent += lay.scatter_n_entries;
            dtok_scat_calls += lay.scatter_n_calls;
            dtok_scat_bytes += lay.scatter_bytes;
        }

        // Accumulate weight_load
        double dtok_weight_load = 0;
        int    dtok_total_calls = 0;
        for (auto & lay : dtok.layers) {
            dtok_weight_load += lay.weight_load_us;
            dtok_total_calls += lay.n_calls;
        }

        // Compute unaccounted MoE time (layer_total - sum of sub-phases)
        double dtok_subphase_sum =
            dtok_ids + dtok_routing + dtok_cpu + dtok_gpu + dtok_scatter + dtok_inter_op + dtok_weight_load;
        double dtok_moe_unaccounted = dtok.moe_total_us - dtok_subphase_sum;

        print_row("MoE total", dtok.moe_total_us, dtok.n_moe_layers);
        fprintf(stderr, "  (MUL_MAT_ID calls: %d, expected: %d x 3 = %d)\n", dtok_total_calls, dtok.n_moe_layers,
                dtok.n_moe_layers * 3);
        // Sub-phase breakdown (only when instrumented, i.e., non-zero)
        if (dtok_ids > 0 || dtok_routing > 0 || dtok_cpu > 0 || dtok_gpu > 0) {
            print_row("  Weight load (PCIe)", dtok_weight_load, dtok.n_moe_layers);
            print_row("  IDs D2H", dtok_ids, dtok.n_moe_layers);
            print_row("  Expert routing", dtok_routing, dtok.n_moe_layers);
            print_row("  CPU expert compute", dtok_cpu, dtok.n_moe_layers);
            print_row("  GPU expert compute", dtok_gpu, dtok.n_moe_layers);
            print_row("  Scatter H2D", dtok_scatter, dtok.n_moe_layers);
            print_row("  Inter-op (SILU/etc)", dtok_inter_op, dtok.n_moe_layers);
            if (dtok_moe_unaccounted > 100) {  // Only show if > 0.1ms
                print_row("  MoE unaccounted", dtok_moe_unaccounted, dtok.n_moe_layers);
            }
            // U6: Scatter decomposition
            if (dtok_scat_cpu > 0 || dtok_scat_sub > 0 || dtok_scat_wait > 0) {
                print_row("    CPU future.get()", dtok_scat_cpu, dtok.n_moe_layers);
                print_row("    memcpy submit", dtok_scat_sub, dtok.n_moe_layers);
                print_row("    event::wait()", dtok_scat_wait, dtok.n_moe_layers);
                fprintf(stderr, "    Scatter: %d calls, %d entries, %.1f KB total\n", dtok_scat_calls, dtok_scat_ent,
                        dtok_scat_bytes / 1024.0);
                if (dtok_scat_calls > 0) {
                    double per_call_us    = (dtok_scat_cpu + dtok_scat_sub + dtok_scat_wait) / dtok_scat_calls;
                    double per_call_bytes = dtok_scat_bytes / dtok_scat_calls;
                    fprintf(stderr, "    Per scatter call: %.1f us (%.1f KB, %.2f GB/s effective)\n", per_call_us,
                            per_call_bytes / 1024.0,
                            per_call_bytes > 0 ? per_call_bytes / (per_call_us * 1e-6) / 1e9 : 0);
                }
            }
        }
        print_row("Non-MoE (attn+norms)", dtok.attention_us, dtok.n_moe_layers);
        fprintf(stderr, "%-25s-+-%10s-+-%13s-+-%8s\n", "-------------------------", "----------", "-------------",
                "--------");
        fprintf(stderr, "%-25s | %10.1f |               | %7.1f%%\n", "Token total", dtok.token_total_us / 1000.0,
                100.0);
        fprintf(stderr, "  Experts: %d CPU, %d GPU | MoE layers: %d\n", dtok_cpu_exp, dtok_gpu_exp, dtok.n_moe_layers);

        // PP profile: cache hit/miss and dispatch path breakdown
        if (g_moe_pp_profile_enabled) {
            int dtok_hits = 0, dtok_misses = 0, dtok_sec = 0;
            int dtok_s1 = 0, dtok_fused = 0, dtok_xmx = 0, dtok_host = 0;
            for (auto & lay : dtok.layers) {
                dtok_hits += lay.cache_hits;
                dtok_misses += lay.cache_misses;
                dtok_sec += lay.sec_gpu_experts;
                dtok_s1 += lay.s1_bailout_count;
                dtok_fused += lay.fused_esimd_count;
                dtok_xmx += lay.xmx_sorted_count;
                dtok_host += lay.host_routing_count;
            }
            fprintf(stderr, "\n--- PP Profile: Expert Cache & Dispatch ---\n");
            int total_routed = dtok_hits + dtok_misses + dtok_sec;
            fprintf(stderr, "  Cache hits (VRAM):    %d  (%.1f%%)\n", dtok_hits,
                    total_routed > 0 ? 100.0 * dtok_hits / total_routed : 0);
            fprintf(stderr, "  Cache misses (CPU):   %d  (%.1f%%)\n", dtok_misses,
                    total_routed > 0 ? 100.0 * dtok_misses / total_routed : 0);
            fprintf(stderr, "  Secondary GPU:        %d  (%.1f%%)\n", dtok_sec,
                    total_routed > 0 ? 100.0 * dtok_sec / total_routed : 0);
            fprintf(stderr, "  Total routed experts: %d\n", total_routed);
            fprintf(stderr, "\n  Dispatch paths (MUL_MAT_ID calls):\n");
            fprintf(stderr, "    S1 fused bailout:   %d\n", dtok_s1);
            fprintf(stderr, "    Fused ESIMD:        %d\n", dtok_fused);
            fprintf(stderr, "    XMX sorted:         %d\n", dtok_xmx);
            fprintf(stderr, "    Host routing:       %d\n", dtok_host);
        }

        // Print averages
        fprintf(stderr, "\n--- Averages across %d profiled tokens ---\n", nt);
        fprintf(stderr, "%-25s | %10s | %13s | %8s\n", "Phase", "Total(ms)", "Per-Layer(ms)", "% Token");
        fprintf(stderr, "%-25s-+-%10s-+-%13s-+-%8s\n", "-------------------------", "----------", "-------------",
                "--------");

        int  avg_nl    = avg_layers / nt;
        auto print_avg = [&](const char * name, double total_us) {
            double pct       = avg_total > 0 ? 100.0 * total_us / avg_total : 0;
            double per_layer = avg_nl > 0 ? total_us / 1000.0 / avg_nl : 0;
            fprintf(stderr, "%-25s | %10.1f | %13.2f | %7.1f%%\n", name, total_us / 1000.0, per_layer, pct);
        };

        print_avg("MoE total", avg_moe);
        double avg_subphase_sum =
            avg_ids + avg_routing + avg_cpu + avg_gpu + avg_scatter + avg_inter_op + avg_weight_load;
        double avg_moe_unaccounted = avg_moe - avg_subphase_sum;
        if (avg_ids > 0 || avg_routing > 0 || avg_cpu > 0 || avg_gpu > 0) {
            print_avg("  Weight load (PCIe)", avg_weight_load);
            print_avg("  IDs D2H", avg_ids);
            print_avg("  Expert routing", avg_routing);
            print_avg("  CPU expert compute", avg_cpu);
            print_avg("  GPU expert compute", avg_gpu);
            print_avg("  Scatter H2D", avg_scatter);
            print_avg("  Inter-op (SILU/etc)", avg_inter_op);
            if (avg_moe_unaccounted > 100) {
                print_avg("  MoE unaccounted", avg_moe_unaccounted);
            }
            // U6: Scatter decomposition averages
            if (avg_scatter_cpu_wait > 0 || avg_scatter_submit > 0 || avg_scatter_event_wait > 0) {
                print_avg("    CPU future.get()", avg_scatter_cpu_wait);
                print_avg("    memcpy submit", avg_scatter_submit);
                print_avg("    event::wait()", avg_scatter_event_wait);
                fprintf(stderr, "    Avg scatter: %.0f calls, %.0f entries, %.1f KB/token\n",
                        static_cast<double>(avg_scatter_calls) / nt, static_cast<double>(avg_scatter_entries) / nt,
                        avg_scatter_bytes / 1024.0);
                double avg_total_scatter_us = avg_scatter_cpu_wait + avg_scatter_submit + avg_scatter_event_wait;
                if (avg_total_scatter_us > 0) {
                    fprintf(stderr, "    Breakdown: CPU wait %.1f%%, submit %.1f%%, event::wait %.1f%%\n",
                            100.0 * avg_scatter_cpu_wait / avg_total_scatter_us,
                            100.0 * avg_scatter_submit / avg_total_scatter_us,
                            100.0 * avg_scatter_event_wait / avg_total_scatter_us);
                    double eff_bw = avg_scatter_bytes / (avg_total_scatter_us * 1e-6) / 1e9;
                    fprintf(stderr, "    Effective BW: %.3f GB/s (%.1f KB in %.1f us)\n", eff_bw,
                            avg_scatter_bytes / 1024.0, avg_total_scatter_us);
                }
            }
        }
        print_avg("Non-MoE (attn+norms)", avg_attn);
        fprintf(stderr, "%-25s-+-%10s-+-%13s-+-%8s\n", "-------------------------", "----------", "-------------",
                "--------");
        fprintf(stderr, "%-25s | %10.1f |               | %7.1f%%\n", "Token total", avg_total / 1000.0, 100.0);
        fprintf(stderr, "  Avg experts/token: %d CPU, %d GPU | MoE layers: %d\n", avg_cpu_experts / nt,
                avg_gpu_experts / nt, avg_nl);
        fprintf(stderr, "  Token rate: %.2f tok/s\n", avg_total > 0 ? 1e6 / avg_total : 0);

        // Per-expert GPU MMVQ dispatch cost
        const int total_gpu_exp = avg_gpu_experts;  // already summed
        if (total_gpu_exp > 0 && avg_gpu > 0) {
            const double per_expert_gpu_us = avg_gpu * nt / total_gpu_exp;
            fprintf(stderr, "\n--- GPU MMVQ Dispatch Cost ---\n");
            fprintf(stderr, "  Total GPU experts across %d tokens: %d\n", nt, total_gpu_exp);
            fprintf(stderr, "  Avg GPU dispatch/token:   %.1f us (%.3f ms)\n", avg_gpu, avg_gpu / 1000.0);
            fprintf(stderr, "  Per-expert dispatch:      %.1f us (%.3f ms)\n", per_expert_gpu_us,
                    per_expert_gpu_us / 1000.0);
            fprintf(stderr, "  GPU dispatch includes: ptr table build, Q8_1 quant, batch ID upload, kernel submit\n");
        }

        // Per-expert CPU compute cost
        const int total_cpu_exp = avg_cpu_experts;
        if (total_cpu_exp > 0 && avg_cpu > 0) {
            const double per_expert_cpu_us = avg_cpu * nt / total_cpu_exp;
            fprintf(stderr, "\n--- CPU Expert Compute Cost ---\n");
            fprintf(stderr, "  Total CPU experts across %d tokens: %d\n", nt, total_cpu_exp);
            fprintf(stderr, "  Avg CPU compute/token:    %.1f us (%.3f ms)\n", avg_cpu, avg_cpu / 1000.0);
            fprintf(stderr, "  Per-expert CPU compute:   %.1f us (%.3f ms)\n", per_expert_cpu_us,
                    per_expert_cpu_us / 1000.0);
        }
        // U6 diagnostic: misattributed scatter time
        if (n_compute_not_set > 0) {
            fprintf(stderr, "\n--- U6 Scatter Misattribution Diagnostic ---\n");
            fprintf(stderr, "  moe_compute_done() NOT called: %d sub-ops across %d tokens\n", n_compute_not_set, nt);
            fprintf(stderr, "  Time misattributed to scatter: %.1f ms (%.1f ms/token)\n",
                    unset_scatter_accum_us / 1000.0, unset_scatter_accum_us / 1000.0 / nt);
            fprintf(stderr, "  True scatter time (U6 probes): %.1f ms/token\n",
                    (avg_scatter_cpu_wait + avg_scatter_submit + avg_scatter_event_wait) / 1000.0);
            fprintf(stderr, "  => %.1f%% of reported 'Scatter H2D' is actually non-scatter overhead\n",
                    avg_scatter > 0 ? 100.0 * (unset_scatter_accum_us / nt) / avg_scatter : 0);
        } else {
            fprintf(stderr, "\n--- U6 Scatter Diagnostic ---\n");
            fprintf(stderr, "  All sub-ops had moe_compute_done() called (no misattribution)\n");
            fprintf(stderr, "  True scatter time (U6 probes): %.1f ms/token\n",
                    (avg_scatter_cpu_wait + avg_scatter_submit + avg_scatter_event_wait) / 1000.0);
            if (avg_scatter > 0) {
                double true_scatter = avg_scatter_cpu_wait + avg_scatter_submit + avg_scatter_event_wait;
                fprintf(stderr, "  Unaccounted scatter overhead: %.1f ms/token (%.1f%%)\n",
                        (avg_scatter - true_scatter) / 1000.0, 100.0 * (avg_scatter - true_scatter) / avg_scatter);
            }
        }
        fprintf(stderr, "\n");
    }
};

static thread_local moe_profile_state g_moe_profile;

// MoE activation variant detected from graph structure.
// Set once during first graph_compute, used by fusion to select correct activation.
static std::atomic<int> g_moe_fused_act_variant{ -1 };  // -1 = not yet detected
static float            g_moe_fused_act_alpha = 0.0f;
static float            g_moe_fused_act_limit = 0.0f;

// Per-layer expert bias pointers captured during graph scan.
// Maps layer_id -> {gate_bias, up_bias, down_bias} HOST data pointers + stride.
// Bias tensors in the graph have device pointers; we copy to host-owned buffers
// so the CPU fused kernel can access them safely.
struct layer_expert_biases {
    const float * gate_bias = nullptr;  // HOST copy of ffn_gate_exps bias base
    const float * up_bias   = nullptr;  // HOST copy of ffn_up_exps bias base
    const float * down_bias = nullptr;  // HOST copy of ffn_down_exps bias base
    size_t        nb        = 0;        // Expert stride in bytes (nb11)
};

static std::unordered_map<int, layer_expert_biases> g_moe_expert_biases;
// Host-side copies of bias data (owned memory, freed at static destruction).
static std::vector<std::vector<float>>              g_moe_bias_host_copies;

// MoE fusion env var: GGML_SYCL_MOE_FUSE (default: 1 = enabled)
static bool ggml_sycl_moe_fusion_enabled() {
    // Planner-authoritative residency is the conservative execution mode:
    // host-routed MoE experts must stay on the stable unfused CPU-primary path
    // until the gate/up/down fusion path fully respects planned residency.
    if (g_has_placement_plan) {
        static std::atomic<bool> warned{ false };
        if (!warned.exchange(true, std::memory_order_acq_rel)) {
            GGML_LOG_INFO("[MOE-FUSION] Disabled under placement-plan residency\n");
        }
        return false;
    }

    static std::atomic<int> moe_fusion_mode{ -1 };
    int                     val = moe_fusion_mode.load(std::memory_order_acquire);
    if (val < 0) {
        const char * env     = getenv("GGML_SYCL_MOE_FUSE");
        int          new_val = env ? std::atoi(env) : 1;
        moe_fusion_mode.compare_exchange_strong(val, new_val, std::memory_order_release, std::memory_order_acquire);
        val = moe_fusion_mode.load(std::memory_order_acquire);
    }
    return val != 0;
}

// Flush any pending deferred CPU scatter.  Called:
//  - At the start of each CPU-TG MUL_MAT_ID entry
//  - At graph boundaries (graph_compute_impl)
// Free deferred buffers from a previous async scatter.  By the time this
// is called, the in-order compute queue has processed at least one kernel
// after the memcpys, guaranteeing the copies have completed.
static void flush_prev_scatter_bufs() {
    auto & pb = g_pending_scatter.prev_bufs;
    if (!pb.pending) {
        return;
    }
    if (pb.pool) {
        g_pinned_buffer_pools[pb.dev_id].release({ pb.act, pb.out });
    } else if (pb.act_alloc.ptr != nullptr || pb.out_alloc.ptr != nullptr) {
        if (pb.act_alloc.ptr != nullptr) {
            (void) ggml_sycl::unified_free(pb.act_alloc);
        }
        if (pb.out_alloc.ptr != nullptr) {
            (void) ggml_sycl::unified_free(pb.out_alloc);
        }
    } else {
        // Legacy sycl::free path — dead code after migration to unified_alloc
        if (pb.act) {
            GGML_ASSERT(false && "pending_cpu_scatter.act: legacy sycl::free path — act_alloc should always be set");
        }
        if (pb.out) {
            GGML_ASSERT(false && "pending_cpu_scatter.out: legacy sycl::free path — out_alloc should always be set");
        }
    }
    pb.out       = nullptr;
    pb.act       = nullptr;
    pb.out_alloc = {};
    pb.act_alloc = {};
    pb.ctx       = sycl::context();
    pb.dev_id    = -1;
    pb.pool      = false;
    pb.pending   = false;
}

static void flush_pending_cpu_scatter() {
    if (!g_pending_scatter.active) {
        return;
    }

    // Free buffers from the PREVIOUS async scatter (safe now — in-order
    // queue has processed past those memcpys).
    flush_prev_scatter_bufs();

    using hrc = std::chrono::high_resolution_clock;
    auto t0   = hrc::now();

    try {
        // Wait for CPU compute to finish
        if (g_pending_scatter.future.valid()) {
            g_pending_scatter.future.get();
        }

        auto t1 = hrc::now();  // After CPU future.get()

        // Scatter results H2D — submit memcpys to the in-order compute queue.
        // Subsequent GPU kernels on this queue will wait for the copies to
        // complete (same-device in-order guarantee).  We skip stream->wait()
        // to let the host proceed to dispatch the next layer immediately.
        double total_bytes = 0;
        int    n_entries   = 0;
        if (g_pending_scatter.stream && g_pending_scatter.out_pinned) {
            // Batch contiguous scatter entries into single memcpy calls.
            // Source (out_pinned) is always contiguous; check if destination
            // addresses are also contiguous to merge.
            const auto &  entries  = g_pending_scatter.entries;
            const float * src_base = g_pending_scatter.out_pinned;
            size_t        i        = 0;
            while (i < entries.size()) {
                if (!entries[i].dst_device) {
                    src_base += entries[i].N;
                    i++;
                    continue;
                }
                // Start a new batch from entry i
                char *        batch_dst = entries[i].dst_device;
                const float * batch_src = src_base;
                size_t        batch_N   = static_cast<size_t>(entries[i].N);
                src_base += entries[i].N;
                size_t j = i + 1;
                // Merge subsequent entries if dst is contiguous
                while (j < entries.size() && entries[j].dst_device &&
                       entries[j].dst_device == batch_dst + batch_N * sizeof(float)) {
                    batch_N += static_cast<size_t>(entries[j].N);
                    src_base += entries[j].N;
                    j++;
                }
                g_pending_scatter.stream->memcpy(batch_dst, batch_src, batch_N * sizeof(float));
                total_bytes += static_cast<double>(batch_N) * sizeof(float);
                n_entries++;
                i = j;
            }

            auto t2 = hrc::now();  // After memcpy submissions

            // Record scatter timing (no event_wait since we skip stream->wait)
            if (g_moe_profile_enabled) {
                double cpu_wait_us = std::chrono::duration<double, std::micro>(t1 - t0).count();
                double submit_us   = std::chrono::duration<double, std::micro>(t2 - t1).count();
                g_moe_profile.moe_scatter_detail(cpu_wait_us, submit_us, 0, n_entries, total_bytes);
            }
        } else if (g_moe_profile_enabled) {
            // No stream/output — record only CPU wait
            double cpu_wait_us = std::chrono::duration<double, std::micro>(t1 - t0).count();
            g_moe_profile.moe_scatter_detail(cpu_wait_us, 0, 0, 0, 0);
        }
    } catch (const std::exception & ex) {
        GGML_LOG_ERROR("[CPU-TG] Deferred scatter failed: %s\n", ex.what());
    }

    // Defer buffer cleanup: memcpys are submitted but may not have executed
    // yet.  Move buffers to prev_bufs for cleanup at the next flush call
    // (by then, the in-order queue guarantees completion).
    if (g_pending_scatter.owns_buffers) {
        auto & pb    = g_pending_scatter.prev_bufs;
        pb.out       = g_pending_scatter.out_pinned;
        pb.act       = g_pending_scatter.act_pinned;
        pb.out_alloc = g_pending_scatter.out_alloc;
        pb.act_alloc = g_pending_scatter.act_alloc;
        pb.ctx       = g_pending_scatter.sycl_ctx;
        pb.dev_id    = g_pending_scatter.device_id;
        pb.pool      = g_pending_scatter.from_pool;
        pb.pending   = true;
    }

    g_pending_scatter.entries.clear();
    g_pending_scatter.tasks.clear();
    g_pending_scatter.out_pinned   = nullptr;
    g_pending_scatter.act_pinned   = nullptr;
    g_pending_scatter.out_alloc    = {};
    g_pending_scatter.act_alloc    = {};
    g_pending_scatter.stream       = nullptr;
    g_pending_scatter.sycl_ctx     = sycl::context();  // release ref
    g_pending_scatter.active       = false;
    g_pending_scatter.owns_buffers = true;
    g_pending_scatter.dst_tensor   = nullptr;
}

// Non-blocking try-flush: if CPU compute from the previous layer is already
// done (future ready), flush immediately to overlap H2D scatter with the
// current layer's activation D2H.  If CPU compute is still running, skip —
// the next consumption point will do a blocking flush.
static bool try_flush_pending_cpu_scatter() {
    if (!g_pending_scatter.active) {
        return false;
    }
    if (!g_pending_scatter.future.valid()) {
        // No future — flush unconditionally (e.g. already waited)
        flush_pending_cpu_scatter();
        return true;
    }
    // Check if CPU compute is already done (zero-timeout poll)
    auto status = g_pending_scatter.future.wait_for(std::chrono::seconds(0));
    if (status == std::future_status::ready) {
        flush_pending_cpu_scatter();
        return true;
    }
    return false;  // CPU compute still running — skip for now
}

// Selective flush: only flush if the pending scatter's destination tensor
// is consumed by the given op (i.e., dst_tensor matches one of consuming_dst's
// sources).  Returns true if a flush was performed.
// This enables expert deferral: cold CPU experts from layer N can compute
// in parallel with layer N+1's GPU attention window (~381us) as long as
// the attention ops don't read from the MoE output tensor.
static bool flush_pending_cpu_scatter_if_consumed(const ggml_tensor * consuming_dst) {
    if (!g_pending_scatter.active) {
        return false;
    }
    if (!consuming_dst) {
        return false;
    }

    // Opt-out: GGML_SYCL_EXPERT_DEFER=0 disables deferral (always flush)
    static std::atomic<int> expert_defer_mode{ -1 };
    int                     defer_val = expert_defer_mode.load(std::memory_order_acquire);
    if (defer_val < 0) {
        const char * env     = getenv("GGML_SYCL_EXPERT_DEFER");
        int          new_val = env ? std::atoi(env) : 1;  // Default: enabled
        expert_defer_mode.compare_exchange_strong(defer_val, new_val, std::memory_order_release,
                                                  std::memory_order_acquire);
        defer_val = expert_defer_mode.load(std::memory_order_acquire);
    }
    if (defer_val == 0) {
        flush_pending_cpu_scatter();
        return true;
    }

    const ggml_tensor * pending_dst = g_pending_scatter.dst_tensor;
    if (!pending_dst) {
        // No dst_tensor recorded — flush unconditionally (safety)
        flush_pending_cpu_scatter();
        return true;
    }

    // Check if any of consuming_dst's sources match the pending scatter's
    // destination tensor.  GGML_MAX_SRC is typically 10.
    for (int i = 0; i < GGML_MAX_SRC; i++) {
        if (consuming_dst->src[i] == pending_dst) {
            flush_pending_cpu_scatter();
            return true;
        }
    }

    // Also check view_src chain: if consuming_dst reads from a view
    // of the pending tensor, we must flush.
    for (int i = 0; i < GGML_MAX_SRC; i++) {
        const ggml_tensor * s = consuming_dst->src[i];
        while (s && s->view_src) {
            s = s->view_src;
            if (s == pending_dst) {
                flush_pending_cpu_scatter();
                return true;
            }
        }
    }

    GGML_SYCL_DEBUG("[MoE-DEFER] Deferring CPU scatter (pending=%s, op=%s)\n",
                    pending_dst->name ? pending_dst->name : "?", consuming_dst->name ? consuming_dst->name : "?");
    return false;  // No overlap — defer the scatter
}

// ----- Pipeline MoE: environment variable gate -----
// When GGML_SYCL_PIPELINE_MOE=1, B50 expert compute for layer N overlaps
// with GPU0 attention for layer N+1.  A background thread waits for B50
// D2H events and submits H2D scatter on a dedicated copy queue, so the
// main thread (feeding GPU0's compute queue) never blocks.
static bool ggml_sycl_pipeline_moe_enabled() {
    static std::atomic<int> val{ -1 };
    int                     v = val.load(std::memory_order_acquire);
    if (v < 0) {
        const char * env = getenv("GGML_SYCL_PIPELINE_MOE");
        int          nv  = env ? atoi(env) : 0;  // Default: OFF
        val.compare_exchange_strong(v, nv, std::memory_order_release, std::memory_order_acquire);
        v = val.load(std::memory_order_acquire);
    }
    return v != 0;
}

// ----- Pipeline CPU: environment variable gate -----
// When GGML_SYCL_PIPELINE_CPU=1, CPU expert compute from MoE layer N
// overlaps with GPU attention for layer N+1.  Instead of blocking until
// CPU experts finish and scattering results immediately, the merge is
// deferred to the start of the next MoE layer (or graph boundary).
// This gives one full (residual + norm + attention) cycle of overlap time.
static bool ggml_sycl_pipeline_cpu_enabled() {
    static std::atomic<int> val{ -1 };
    int                     v = val.load(std::memory_order_acquire);
    if (v < 0) {
        const char * env = getenv("GGML_SYCL_PIPELINE_CPU");
        int          nv  = env ? atoi(env) : 0;  // Default: OFF
        val.compare_exchange_strong(v, nv, std::memory_order_release, std::memory_order_acquire);
        v = val.load(std::memory_order_acquire);
    }
    return v != 0;
}

// ---------------------------------------------------------------------------
// Pipeline CPU: deferred cross-layer merge
// ---------------------------------------------------------------------------
struct pending_cpu_pipeline {
    std::future<void>       future;
    float *                 out_pinned;
    float *                 act_pinned;
    // Use .as_mem_handle() for read/resolve access; unified_free(alloc_handle) for ownership
    ggml_sycl::alloc_handle out_alloc;
    ggml_sycl::alloc_handle act_alloc;
    sycl::queue *           stream;
    sycl::context           sycl_ctx;

    struct scatter_entry {
        char * dst_device;
        int    N;
    };

    std::vector<scatter_entry>   entries;
    std::vector<cpu_expert_task> tasks;
    int                          device_id;
    bool                         from_pool;
    bool                         owns_buffers;
    bool                         active;
    const ggml_tensor *          dst_tensor;
    int                          layer_id;

    struct deferred_bufs {
        float *                 out = nullptr;
        float *                 act = nullptr;
        ggml_sycl::alloc_handle out_alloc{};
        ggml_sycl::alloc_handle act_alloc{};
        sycl::context           ctx;
        int                     dev_id  = -1;
        bool                    pool    = false;
        bool                    pending = false;
    } prev_bufs;

    pending_cpu_pipeline() :
        out_pinned(nullptr),
        act_pinned(nullptr),
        out_alloc(),
        act_alloc(),
        stream(nullptr),
        sycl_ctx(),
        device_id(-1),
        from_pool(false),
        owns_buffers(false),
        active(false),
        dst_tensor(nullptr),
        layer_id(-1) {}
};

static thread_local pending_cpu_pipeline g_pending_cpu_pipeline;

static void flush_prev_cpu_pipeline_bufs() {
    auto & pb = g_pending_cpu_pipeline.prev_bufs;
    if (!pb.pending) {
        return;
    }
    if (pb.pool) {
        g_pinned_buffer_pools[pb.dev_id].release({ pb.act, pb.out });
    } else if (pb.act_alloc.ptr != nullptr || pb.out_alloc.ptr != nullptr) {
        if (pb.act_alloc.ptr != nullptr) {
            (void) ggml_sycl::unified_free(pb.act_alloc);
        }
        if (pb.out_alloc.ptr != nullptr) {
            (void) ggml_sycl::unified_free(pb.out_alloc);
        }
    } else {
        // Legacy sycl::free path — dead code after migration to unified_alloc
        if (pb.act) {
            GGML_ASSERT(false && "cpu_pipeline.act: legacy sycl::free path — act_alloc should always be set");
        }
        if (pb.out) {
            GGML_ASSERT(false && "cpu_pipeline.out: legacy sycl::free path — out_alloc should always be set");
        }
    }
    pb.out       = nullptr;
    pb.act       = nullptr;
    pb.out_alloc = {};
    pb.act_alloc = {};
    pb.ctx       = sycl::context();
    pb.dev_id    = -1;
    pb.pool      = false;
    pb.pending   = false;
}

static void flush_pending_cpu_pipeline() {
    if (!g_pending_cpu_pipeline.active) {
        return;
    }
    flush_prev_cpu_pipeline_bufs();
    try {
        if (g_pending_cpu_pipeline.future.valid()) {
            g_pending_cpu_pipeline.future.get();
        }
        if (g_pending_cpu_pipeline.stream && g_pending_cpu_pipeline.out_pinned) {
            const float * src = g_pending_cpu_pipeline.out_pinned;
            for (auto & e : g_pending_cpu_pipeline.entries) {
                if (e.dst_device) {
                    g_pending_cpu_pipeline.stream->memcpy(e.dst_device, src, static_cast<size_t>(e.N) * sizeof(float));
                }
                src += e.N;
            }
        }
    } catch (const std::exception & ex) {
        GGML_LOG_ERROR("[PIPELINE-CPU] Deferred merge failed: %s\n", ex.what());
    }
    static std::atomic<int> pipeline_log{ 0 };
    if (pipeline_log.fetch_add(1, std::memory_order_relaxed) < 5) {
        GGML_LOG_INFO("[PIPELINE-CPU] Flushed deferred merge from layer %d (%zu entries)\n",
                      g_pending_cpu_pipeline.layer_id, g_pending_cpu_pipeline.entries.size());
    }
    if (g_pending_cpu_pipeline.owns_buffers) {
        auto & pb    = g_pending_cpu_pipeline.prev_bufs;
        pb.out       = g_pending_cpu_pipeline.out_pinned;
        pb.act       = g_pending_cpu_pipeline.act_pinned;
        pb.out_alloc = g_pending_cpu_pipeline.out_alloc;
        pb.act_alloc = g_pending_cpu_pipeline.act_alloc;
        pb.ctx       = g_pending_cpu_pipeline.sycl_ctx;
        pb.dev_id    = g_pending_cpu_pipeline.device_id;
        pb.pool      = g_pending_cpu_pipeline.from_pool;
        pb.pending   = true;
    }
    g_pending_cpu_pipeline.entries.clear();
    g_pending_cpu_pipeline.tasks.clear();
    g_pending_cpu_pipeline.out_pinned   = nullptr;
    g_pending_cpu_pipeline.act_pinned   = nullptr;
    g_pending_cpu_pipeline.out_alloc    = {};
    g_pending_cpu_pipeline.act_alloc    = {};
    g_pending_cpu_pipeline.stream       = nullptr;
    g_pending_cpu_pipeline.sycl_ctx     = sycl::context();
    g_pending_cpu_pipeline.device_id    = -1;
    g_pending_cpu_pipeline.from_pool    = false;
    g_pending_cpu_pipeline.owns_buffers = false;
    g_pending_cpu_pipeline.active       = false;
    g_pending_cpu_pipeline.dst_tensor   = nullptr;
    g_pending_cpu_pipeline.layer_id     = -1;
}

static bool flush_pending_cpu_pipeline_if_consumed(const ggml_tensor * consuming_dst) {
    if (!g_pending_cpu_pipeline.active) {
        return false;
    }
    if (!consuming_dst) {
        return false;
    }
    const ggml_tensor * pending_dst = g_pending_cpu_pipeline.dst_tensor;
    if (!pending_dst) {
        flush_pending_cpu_pipeline();
        return true;
    }
    for (int i = 0; i < GGML_MAX_SRC; i++) {
        const ggml_tensor * s = consuming_dst->src[i];
        while (s) {
            if (s == pending_dst) {
                flush_pending_cpu_pipeline();
                return true;
            }
            s = s->view_src;
        }
    }
    return false;
}

// ----- Deferred secondary GPU scatter (async B50 dispatch) -----
// Stores scatter metadata from dispatch_experts_secondary_gpu() so
// B50 GEMM kernels run in parallel with B580 primary GPU dispatch.
// Flushed after GPU0 dispatch completes.
struct pending_secondary_scatter {
    struct scatter_entry {
        char *        dst_device;    // Primary GPU dst pointer
        float *       out_staging;   // Host-pinned output buffer (from ring)
        size_t        bytes;         // Output size in bytes
        sycl::queue * target_queue;  // Secondary GPU queue that produced this result
        sycl::event   last_event;    // Last D2H memcpy event on target queue
    };

    std::vector<scatter_entry> entries;
    sycl::queue *              stream     = nullptr;  // Primary GPU queue for H2D scatter
    bool                       active     = false;
    const ggml_tensor *        dst_tensor = nullptr;  // MUL_MAT_ID output tensor being scattered into
};

static thread_local pending_secondary_scatter g_pending_secondary_scatter = {};

// ----- Pipeline MoE: background scatter thread -----
// When pipeline mode is active, the background thread waits for B50 D2H
// events and submits H2D scatter on a dedicated copy queue.  The main
// thread polls the completion flag instead of blocking on B50 events.
//
// Double-buffer: scatter slot 0 and 1 alternate between layers.
// g_pipeline_scatter[slot] holds the scatter from the PREVIOUS layer.
// The background thread processes it while the current layer runs.
struct pipeline_scatter_slot {
    pending_secondary_scatter scatter;
    sycl::queue *             copy_queue = nullptr;  // Dedicated IOQ on GPU0 for H2D
    std::atomic<bool>         done{ true };          // true = slot is free/flushed
    std::atomic<bool>         submitted{ false };    // true = background work queued
};

static constexpr int                      PIPELINE_SLOTS                     = 2;
static thread_local pipeline_scatter_slot g_pipeline_scatter[PIPELINE_SLOTS] = {};
static thread_local int                   g_pipeline_slot_idx                = 0;

// Dedicated copy queue for pipeline scatter (one per device, created lazily).
// In-order queue on GPU0 for H2D copies that don't block the compute queue.
static sycl::queue * g_pipeline_copy_queue[GGML_SYCL_MAX_DEVICES] = {};
static std::mutex    g_pipeline_copy_queue_mutex;

static sycl::queue * get_pipeline_copy_queue(int device) {
    if (g_pipeline_copy_queue[device]) {
        return g_pipeline_copy_queue[device];
    }
    std::lock_guard<std::mutex> lock(g_pipeline_copy_queue_mutex);
    if (g_pipeline_copy_queue[device]) {
        return g_pipeline_copy_queue[device];
    }
    auto & dev0 = ggml_sycl_get_gpu_device(0);
    auto & dev  = ggml_sycl_get_device(device);
    // Create in-order copy queue with device 0's context so cross-device
    // depends_on() works on Level Zero (events require matching ze_context).
    g_pipeline_copy_queue[device] =
        new sycl::queue(dev0.default_queue().get_context(), dev.default_queue().get_device(),
                        default_queue_properties());
    static std::atomic<int> log_count{ 0 };
    if (log_count.fetch_add(1, std::memory_order_relaxed) < 2) {
        GGML_LOG_INFO("[PIPELINE-MOE] Created dedicated copy queue for device %d\n", device);
    }
    return g_pipeline_copy_queue[device];
}

// Background flush: wait for B50 events and submit H2D on copy queue.
// Runs on std::async thread, sets slot.done = true when finished.
static void pipeline_scatter_background(pipeline_scatter_slot * slot) {
    try {
        auto & sc = slot->scatter;
        if (!sc.stream || sc.entries.empty()) {
            slot->done.store(true, std::memory_order_release);
            return;
        }
        for (auto & e : sc.entries) {
            if (e.dst_device && e.out_staging) {
                if (e.target_queue) {
                    // Cross-device dependency: wait for secondary GPU D2H via depends_on
                    // (secondary queues share device 0's context for L0 compat)
                    slot->copy_queue->submit([&](sycl::handler & cgh) {
                        cgh.depends_on(e.last_event);
                        cgh.memcpy(e.dst_device, e.out_staging, e.bytes);
                    });
                } else {
                    slot->copy_queue->memcpy(e.dst_device, e.out_staging, e.bytes);
                }
            } else if (e.dst_device && !e.out_staging) {
                slot->copy_queue->memset(e.dst_device, 0, e.bytes);
            }
        }
        // Wait for all H2D copies to land on GPU0 before marking done.
        slot->copy_queue->wait();
    } catch (const std::exception & ex) {
        GGML_LOG_ERROR("[PIPELINE-MOE] Background scatter failed: %s\n", ex.what());
    }
    slot->scatter.entries.clear();
    slot->scatter.stream     = nullptr;
    slot->scatter.active     = false;
    slot->scatter.dst_tensor = nullptr;
    slot->done.store(true, std::memory_order_release);
}

// Wait for a specific pipeline slot to finish.
static void pipeline_scatter_wait(int slot_idx) {
    auto & slot = g_pipeline_scatter[slot_idx];
    if (slot.done.load(std::memory_order_acquire)) {
        return;
    }
    // Spin-wait briefly, then yield
    for (int spin = 0; spin < 1000; spin++) {
        if (slot.done.load(std::memory_order_acquire)) {
            return;
        }
    }
    while (!slot.done.load(std::memory_order_acquire)) {
        std::this_thread::yield();
    }
}

// Wait for ALL pipeline slots to finish.
static void pipeline_scatter_drain() {
    for (int i = 0; i < PIPELINE_SLOTS; i++) {
        pipeline_scatter_wait(i);
    }
}

static void flush_pending_secondary_scatter() {
    // --- Pipeline mode: drain any in-flight background scatters first ---
    if (ggml_sycl_pipeline_moe_enabled()) {
        pipeline_scatter_drain();
    }

    if (!g_pending_secondary_scatter.active) {
        return;
    }

    try {
        // Cross-device dependency via depends_on: secondary queues are created
        // with device 0's sycl::context so cross-device events share one
        // ze_context_handle_t (required by Level Zero).
        if (g_pending_secondary_scatter.stream && !g_pending_secondary_scatter.entries.empty()) {
            for (auto & e : g_pending_secondary_scatter.entries) {
                if (e.dst_device && e.out_staging) {
                    if (e.target_queue) {
                        // Cross-device: wait for secondary GPU D2H via depends_on
                        g_pending_secondary_scatter.stream->submit([&](sycl::handler & cgh) {
                            cgh.depends_on(e.last_event);
                            cgh.memcpy(e.dst_device, e.out_staging, e.bytes);
                        });
                    } else {
                        g_pending_secondary_scatter.stream->memcpy(e.dst_device, e.out_staging, e.bytes);
                    }
                } else if (e.dst_device && !e.out_staging) {
                    // B50 local aggregation: zero-fill remaining expert slots
                    // whose contributions were folded into the aggregate.
                    g_pending_secondary_scatter.stream->memset(e.dst_device, 0, e.bytes);
                }
            }
        }
    } catch (const std::exception & ex) {
        GGML_LOG_ERROR("[MoE-GPU-ASYNC] Deferred secondary scatter failed: %s\n", ex.what());
    }

    g_pending_secondary_scatter.entries.clear();
    g_pending_secondary_scatter.stream     = nullptr;
    g_pending_secondary_scatter.active     = false;
    g_pending_secondary_scatter.dst_tensor = nullptr;
}

// Selective flush: only flush if the pending scatter's dst_tensor is consumed
// by the current operation (i.e., dst reads from the pending result).
static void flush_pending_secondary_scatter_if_consumed(const ggml_tensor * dst) {
    // --- Pipeline mode: check both pipeline slots and g_pending_secondary_scatter ---
    if (ggml_sycl_pipeline_moe_enabled()) {
        // Check pipeline slots: if the op consumes a pipeline slot's dst_tensor,
        // wait for that slot's background flush to complete.
        auto slot_consumes = [&](int slot_idx) -> bool {
            auto & slot = g_pipeline_scatter[slot_idx];
            if (slot.done.load(std::memory_order_acquire)) {
                return false;
            }
            const ggml_tensor * pdst = slot.scatter.dst_tensor;
            if (!pdst) {
                pipeline_scatter_wait(slot_idx);
                return true;
            }
            for (int si = 0; si < GGML_MAX_SRC; si++) {
                const ggml_tensor * s = dst->src[si];
                while (s) {
                    if (s == pdst) {
                        pipeline_scatter_wait(slot_idx);
                        return true;
                    }
                    s = s->view_src;
                }
            }
            return false;
        };
        for (int i = 0; i < PIPELINE_SLOTS; i++) {
            slot_consumes(i);
        }
    }

    if (!g_pending_secondary_scatter.active) {
        return;
    }

    const ggml_tensor * pending_dst = g_pending_secondary_scatter.dst_tensor;
    if (!pending_dst) {
        flush_pending_secondary_scatter();  // No tracking -> flush unconditionally (safety)
        return;
    }

    for (int i = 0; i < GGML_MAX_SRC; i++) {
        const ggml_tensor * s = dst->src[i];
        while (s) {
            if (s == pending_dst) {
                flush_pending_secondary_scatter();
                return;
            }
            s = s->view_src;
        }
    }
}

// Start pipeline background flush: move current g_pending_secondary_scatter
// into a pipeline slot and launch async processing.  Only called when
// GGML_SYCL_PIPELINE_MOE=1 and multi-GPU is active.
static void pipeline_scatter_start_async(int device) {
    if (!g_pending_secondary_scatter.active) {
        return;
    }

    // Pick the next slot (ping-pong)
    int slot_idx        = g_pipeline_slot_idx;
    g_pipeline_slot_idx = (g_pipeline_slot_idx + 1) % PIPELINE_SLOTS;

    auto & slot = g_pipeline_scatter[slot_idx];

    // Wait for previous occupant to finish
    pipeline_scatter_wait(slot_idx);

    // Get or create the copy queue
    slot.copy_queue = get_pipeline_copy_queue(device);

    // Move scatter data into the slot
    slot.scatter = std::move(g_pending_secondary_scatter);

    // Reset the global scatter
    g_pending_secondary_scatter.entries.clear();
    g_pending_secondary_scatter.stream     = nullptr;
    g_pending_secondary_scatter.active     = false;
    g_pending_secondary_scatter.dst_tensor = nullptr;

    // Mark slot as in-flight and launch background thread
    slot.done.store(false, std::memory_order_release);
    slot.submitted.store(true, std::memory_order_release);

    // Fire-and-forget async: background thread does event wait + H2D copies
    std::thread([&slot]() { pipeline_scatter_background(&slot); }).detach();
}

// Public entry point for graph boundary flush
void ggml_sycl_cpu_tg_flush_pending() {
    flush_pending_cpu_pipeline();
    flush_pending_cpu_scatter();
    flush_prev_cpu_pipeline_bufs();  // Final cleanup for last deferred pipeline scatter
    flush_prev_scatter_bufs();       // Final cleanup for last async scatter
    if (ggml_sycl_pipeline_moe_enabled()) {
        pipeline_scatter_drain();
    }
    flush_pending_secondary_scatter();
    moe_fusion_clear_all();
}

// Cold path for ggml_sycl_get_data_ptr: full resolution chain
// (tiered cache, get_pointer_type, unified cache, staging).
// Called only when the fast-path data_device[] cache misses.
void * ggml_sycl_get_data_ptr_slow(const ggml_tensor * tensor, int device) {
    if (tensor == nullptr) {
        return nullptr;
    }

    // Check per-graph pointer cache before expensive resolution.
    // resolve() re-validates WEIGHT handles via generation counter; DIRECT handles
    // always return their stored pointer.  If resolve() returns null (weight evicted),
    // erase the entry and fall through to re-resolve below.
    {
        auto it = g_data_ptr_cache.find(tensor);
        if (it != g_data_ptr_cache.end()) {
            auto resolved = it->second.resolve();
            if (resolved.ptr) {
                return resolved.ptr;
            }
            g_data_ptr_cache.erase(it);
        }
    }

    const bool is_input_tensor = (tensor->flags & GGML_TENSOR_FLAG_INPUT) != 0;
    const bool tp_enabled      = g_sycl_tp_config.enabled && g_sycl_tp_config.world_size > 1;

    // Graph replay INPUT staging DISABLED: INPUT tensors use stable malloc_host
    // addresses.  set_tensor writes new data to the same address, so L0 graph
    // replay sees updated data without needing a separate device staging buffer.
    // The redirect here caused a queue mismatch (staging refresh on default_queue
    // vs graph replay on sycl_ctx->stream()) that produced stale input data.

    if (tensor->name[0] != '\0' && g_tiered_enabled.load(std::memory_order_relaxed)) {
        sycl::usm::alloc alloc      = sycl::usm::alloc::unknown;
        void *           cached_ptr = ggml_sycl_get_cached_tensor_ptr_for(tensor, device, nullptr, nullptr, &alloc);
        if (cached_ptr != nullptr) {
            if (is_input_tensor && !tp_enabled && tensor->data) {
                ggml_sycl_refresh_cached_input_ptr(cached_ptr, tensor->data, ggml_nbytes(tensor), device);
            }
            g_data_ptr_cache[tensor] = make_data_ptr_handle(tensor, device, cached_ptr);
            return cached_ptr;
        }
    }
    if (tensor->extra != nullptr) {
        auto * extra   = static_cast<ggml_tensor_extra_gpu *>(tensor->extra);
        void * dev_ptr = extra->data_device_ptr(device);
        if (dev_ptr != nullptr) {
            if (is_input_tensor && !tp_enabled && tensor->data) {
                ggml_sycl_refresh_cached_input_ptr(dev_ptr, tensor->data, ggml_nbytes(tensor), device);
            }
            GGML_SYCL_DEBUG("ggml_sycl_get_data_ptr_slow: tensor=%s, device=%d, using extra->data_device[%d]=%p\n",
                            tensor->name, device, device, dev_ptr);
            g_data_ptr_cache[tensor] = make_data_ptr_handle(tensor, device, dev_ptr);
            return dev_ptr;
        }
    }

    // For view/permute tensors (e.g. KV cache views), extra may be NULL or
    // data_device unset.  Walk the view_src chain to find the base tensor
    // with a known device pointer, then compute the view offset.
    if (tensor->view_src != nullptr) {
        const ggml_tensor * base = tensor;
        while (base->view_src) {
            base = base->view_src;
        }
        GGML_SYCL_DEBUG(
            "ggml_sycl_get_data_ptr_slow: tensor=%s view_src chain -> base=%s, base->extra=%p, base->data=%p, "
            "tensor->data=%p\n",
            tensor->name, base->name ? base->name : "(null)", (void *) base->extra, base->data, tensor->data);
        if (base->extra != nullptr) {
            auto * base_extra   = static_cast<ggml_tensor_extra_gpu *>(base->extra);
            void * base_dev_ptr = base_extra->data_device_ptr(device);
            if (base_dev_ptr != nullptr && base->data != nullptr && tensor->data != nullptr) {
                ptrdiff_t offset = static_cast<char *>(tensor->data) - static_cast<char *>(base->data);
                void *    result = static_cast<char *>(base_dev_ptr) + offset;
                GGML_SYCL_DEBUG(
                    "ggml_sycl_get_data_ptr_slow: tensor=%s, device=%d, resolved via view_src %s + offset %td = %p\n",
                    tensor->name, device, base->name, offset, result);
                g_data_ptr_cache[tensor] = ggml_sycl::mem_handle::from_direct(result, GGML_LAYOUT_AOS, true);
                return result;
            }
        }
        // base->extra is NULL — the base tensor is likely in a SYCL buffer
        // where tensor->data IS the device pointer.  Check if base->data
        // is device USM directly, and if so, compute view offset from it.
        if (base->data != nullptr && tensor->data != nullptr) {
            // The base tensor's data might be a device USM pointer even without extra.
            // Try to use it directly with the view offset.
            std::optional<sycl::context> view_ctx_storage;
            sycl::context *              view_ctx = nullptr;
            try {
                view_ctx_storage.emplace(ggml_sycl_get_device(device).default_queue().get_context());
                view_ctx = &view_ctx_storage.value();
            } catch (...) {
                view_ctx = nullptr;
            }
            if (view_ctx != nullptr) {
                sycl::usm::alloc base_ptr_type = ggml_sycl_get_alloc_type(base->data);
                GGML_SYCL_DEBUG("ggml_sycl_get_data_ptr_slow: base=%s data=%p ptr_type=%d\n",
                                base->name ? base->name : "(null)", base->data, (int) base_ptr_type);
                if (base_ptr_type == sycl::usm::alloc::device || base_ptr_type == sycl::usm::alloc::shared) {
                    ptrdiff_t offset = static_cast<char *>(tensor->data) - static_cast<char *>(base->data);
                    void *    result = static_cast<char *>(base->data) + offset;
                    GGML_SYCL_DEBUG(
                        "ggml_sycl_get_data_ptr_slow: tensor=%s, device=%d, resolved via view_src base USM + offset "
                        "%td = %p\n",
                        tensor->name, device, offset, result);
                    g_data_ptr_cache[tensor] = ggml_sycl::mem_handle::from_direct(result, GGML_LAYOUT_AOS, true);
                    return result;
                }
            }
        }
    }

    // Check if tensor->data is mmap'd memory (non-USM) that can't be accessed by GPU kernels.
    if (tensor->data != nullptr) {
        // Fast check via alloc_registry before falling back to sycl::get_pointer_type.
        // Per-layer KV allocations may be in a different SYCL context, causing
        // get_pointer_type to return 'unknown'.  alloc_registry always knows.
        const auto * alloc_info = ggml_sycl::alloc_registry::instance().lookup(tensor->data);
        if (alloc_info && alloc_info->type == ggml_sycl::alloc_type::DEVICE) {
            g_data_ptr_cache[tensor] = make_data_ptr_handle(tensor, device, tensor->data);
            return tensor->data;
        }
        if (alloc_info && alloc_info->type == ggml_sycl::alloc_type::HOST_PINNED) {
            // Host-pinned is GPU-accessible via PCIe zero-copy — return directly
            g_data_ptr_cache[tensor] = ggml_sycl::mem_handle::from_direct(tensor->data, GGML_LAYOUT_AOS, false);
            return tensor->data;
        }

        std::optional<sycl::context> ctx_storage;
        sycl::context *              ctx = nullptr;
        if (g_sycl_tp_config.enabled && g_sycl_tp_config.world_size > 1) {
            ctx = ggml_sycl_get_tp_context();
        }
        if (ctx == nullptr) {
            try {
                ctx_storage.emplace(ggml_sycl_get_device(device).default_queue().get_context());
                ctx = &ctx_storage.value();
            } catch (...) {
                ctx = nullptr;
            }
        }

        if (ctx != nullptr) {
            sycl::usm::alloc ptr_type = ggml_sycl_get_alloc_type(tensor->data);

            if (ptr_type == sycl::usm::alloc::device) {
                if (tensor->extra != nullptr) {
                    auto * extra = static_cast<ggml_tensor_extra_gpu *>(tensor->extra);
                    if (extra->data_device_ptr(device) == nullptr && !extra->data_handle[device].is_weight()) {
                        extra->set_data_device(device, tensor->data);
                    }
                }
                GGML_SYCL_DEBUG("ggml_sycl_get_data_ptr_slow: tensor=%s, device=%d, using DEVICE USM tensor->data=%p\n",
                                tensor->name, device, tensor->data);
                g_data_ptr_cache[tensor] = make_data_ptr_handle(tensor, device, tensor->data);
                return tensor->data;
            }

            const bool is_weight = tensor->buffer && ggml_backend_buffer_is_valid(tensor->buffer) &&
                                   ggml_backend_buffer_get_usage(tensor->buffer) == GGML_BACKEND_BUFFER_USAGE_WEIGHTS;

            // Register host pointer with layer stream manager for DMA
            if (is_weight && tensor->name && tensor->data && unified_cache_active()) {
                ggml_sycl::layer_streaming_register_host_ptr(device, tensor->name, tensor->data, ggml_nbytes(tensor));
            }

            // NOTE: get_or_wait removed — legacy synchronous blocking pattern.
            // The async fill + try_get_cached_fast path handles all weight lookups.

            // Check layer stream manager for host-resident weight
            if (is_weight && ggml_sycl::layer_streaming_active(device) && tensor->name) {
                void * streamed = ggml_sycl::layer_streaming_get_weight_ptr(device, tensor->name);
                if (streamed) {
                    GGML_LOG_DEBUG("get_data_ptr_slow: %s from layer stream buffer\n", tensor->name);
                    g_data_ptr_cache[tensor] = ggml_sycl::mem_handle::from_direct(streamed, GGML_LAYOUT_AOS, true);
                    return streamed;
                }
            }

            size_t nbytes = ggml_nbytes(tensor);
            void * staged = ggml_sycl_get_staged_ptr_device(tensor->data, nbytes, device);
            if (staged != nullptr) {
                if (is_input_tensor && !tp_enabled) {
                    std::memcpy(staged, tensor->data, nbytes);
                }
                GGML_SYCL_DEBUG(
                    "ggml_sycl_get_data_ptr_slow: tensor=%s, device=%d, staged non-device %p -> %p (%zu bytes, "
                    "type=%d)\n",
                    tensor->name, device, tensor->data, staged, nbytes, (int) ptr_type);
                g_data_ptr_cache[tensor] = ggml_sycl::mem_handle::from_direct(staged, GGML_LAYOUT_AOS, true);
                return staged;
            }
            GGML_SYCL_DEBUG(
                "ggml_sycl_get_data_ptr_slow: tensor=%s, device=%d, staging FAILED for non-device (type=%d), using "
                "tensor->data=%p\n",
                tensor->name, device, (int) ptr_type, tensor->data);
        }
    }

    GGML_SYCL_DEBUG("ggml_sycl_get_data_ptr_slow: tensor=%s, device=%d, using tensor->data=%p\n", tensor->name, device,
                    tensor->data);
    g_data_ptr_cache[tensor] = ggml_sycl::mem_handle::from_direct(tensor->data, GGML_LAYOUT_AOS, false);
    return tensor->data;
}

static ggml_sycl_cache_id ggml_sycl_get_moe_expert_cache_key(const ggml_tensor *     tensor,
                                                             ggml_tensor_extra_gpu * extra,
                                                             int                     expert_id) {
    ggml_sycl_cache_id id{};
    if (!extra || expert_id < 0) {
        return id;
    }
    const uint64_t cache_uuid = ggml_sycl_assign_cache_uuid(extra);
    if (cache_uuid == 0) {
        return id;
    }

    // Use name-based key: tensor name + expert_id suffix for per-expert uniqueness.
    // This ensures different experts have distinct name hashes while keeping the
    // key derivable from tensor metadata alone (name + type + dimensions).
    const char * raw_name    = tensor ? ggml_get_name(tensor) : "unknown";
    std::string  expert_name = (raw_name && raw_name[0]) ? std::string(raw_name) : std::string("unknown");
    expert_name += ":e";
    expert_name += std::to_string(expert_id);
    uint64_t name_hash = static_cast<uint64_t>(std::hash<std::string>()(expert_name));

    id.valid         = true;
    id.model_id      = extra->model_id;
    id.has_gguf      = false;
    id.file_idx      = 0;
    id.file_offs     = 0;
    id.nbytes        = 0;
    id.name_hash     = name_hash;
    // Use proper tensor type and per-expert dimensions instead of sentinels.
    // This makes the key compatible with resolve_weight() which expects real
    // tensor metadata in cache entries.
    id.type          = tensor ? tensor->type : GGML_TYPE_COUNT;
    id.tp_sharded    = false;
    id.tp_rank       = 0;
    id.tp_world_size = 1;
    // Per-expert dimensions: ne[0]=K, ne[1]=N (rows per expert), ne[2]=1, ne[3]=1
    for (int i = 0; i < GGML_MAX_DIMS; ++i) {
        id.ne[i]           = 0;
        id.tp_local_ne[i]  = 0;
        id.tp_offset_ne[i] = 0;
    }
    if (tensor) {
        id.ne[0] = tensor->ne[0];
        id.ne[1] = tensor->ne[1];
        id.ne[2] = 1;
        id.ne[3] = 1;
    }
    if (extra->tp_sharded && extra->tp_world_size > 1) {
        id.tp_sharded    = true;
        id.tp_rank       = extra->tp_rank;
        id.tp_world_size = extra->tp_world_size;
        for (int i = 0; i < GGML_MAX_DIMS; ++i) {
            id.tp_local_ne[i]  = extra->tp_local_ne[i];
            id.tp_offset_ne[i] = extra->tp_offset_ne[i];
        }
    }
    // Combine cache_uuid with expert_id for per-expert uniqueness
    uint64_t aux = cache_uuid;
    aux          = ggml_sycl_hash_combine(aux, static_cast<uint64_t>(expert_id));
    id.aux_id    = aux;
    return id;
}

// Cross-device staging cache for multi-GPU (Intel Arc has no P2P)

// Key: (slot_idx << 32 | target_device) -> staged pointer
std::unordered_map<uint64_t, void *> g_expert_staging;
std::mutex                           g_expert_staging_mutex;

