// buffer pool for sycl (legacy)
struct ggml_sycl_alloc_trace_entry {
    uint64_t count = 0;
    uint64_t bytes = 0;
};

static std::mutex                                                   g_sycl_alloc_trace_mutex;
static std::unordered_map<std::string, ggml_sycl_alloc_trace_entry> g_sycl_alloc_trace_entries;
static void ggml_sycl_alloc_trace_dump_if_requested(const char * reason);

struct ggml_sycl_alloc_trace_guard {
    ~ggml_sycl_alloc_trace_guard() { ggml_sycl_alloc_trace_dump_if_requested("dlclose"); }
};

static ggml_sycl_alloc_trace_guard & ggml_sycl_alloc_trace_guard_instance() {
    static ggml_sycl_alloc_trace_guard guard;
    return guard;
}

static bool ggml_sycl_alloc_trace_enabled_impl() {
    static int enabled = -1;
    if (enabled >= 0) {
        return enabled != 0;
    }
    const char * env = std::getenv("GGML_SYCL_ALLOC_TRACE");
    enabled          = (env && std::atoi(env) != 0) ? 1 : 0;
    return enabled != 0;
}

bool ggml_sycl_alloc_trace_enabled() {
    return ggml_sycl_alloc_trace_enabled_impl();
}

static void ggml_sycl_alloc_trace_dump_atexit() {
    ggml_sycl_alloc_trace_dump_if_requested("atexit");
}

static void ggml_sycl_alloc_trace_init() {
    static std::once_flag once;
    if (!ggml_sycl_alloc_trace_enabled_impl()) {
        return;
    }
    std::call_once(once, []() { std::atexit(ggml_sycl_alloc_trace_dump_atexit); });
    (void) ggml_sycl_alloc_trace_guard_instance();
}

void ggml_sycl_alloc_trace_record(const char * kind, size_t size, const char * tag) {
    if (!ggml_sycl_alloc_trace_enabled_impl()) {
        return;
    }
    ggml_sycl_alloc_trace_init();
    std::string                 key = std::string(kind ? kind : "unknown") + ":" + (tag ? tag : "unknown");
    std::lock_guard<std::mutex> lock(g_sycl_alloc_trace_mutex);
    auto &                      entry = g_sycl_alloc_trace_entries[key];
    entry.count += 1;
    entry.bytes += size;
}

void ggml_sycl_alloc_trace_dump(const char * reason) {
    if (!ggml_sycl_alloc_trace_enabled_impl()) {
        return;
    }
    std::lock_guard<std::mutex> lock(g_sycl_alloc_trace_mutex);
    if (g_sycl_alloc_trace_entries.empty()) {
        fprintf(stderr, "[SYCL] Alloc trace (%s): no entries\n", reason ? reason : "manual");
        fflush(stderr);
        return;
    }
    size_t top_n = 10;
    if (const char * env = std::getenv("GGML_SYCL_ALLOC_TRACE_TOP")) {
        long parsed = std::strtol(env, nullptr, 10);
        if (parsed > 0) {
            top_n = static_cast<size_t>(parsed);
        }
    }
    std::vector<std::pair<std::string, ggml_sycl_alloc_trace_entry>> entries;
    entries.reserve(g_sycl_alloc_trace_entries.size());
    for (const auto & it : g_sycl_alloc_trace_entries) {
        entries.emplace_back(it.first, it.second);
    }
    std::sort(entries.begin(), entries.end(), [](const auto & a, const auto & b) {
        if (a.second.bytes == b.second.bytes) {
            return a.second.count > b.second.count;
        }
        return a.second.bytes > b.second.bytes;
    });
    fprintf(stderr, "[SYCL] Alloc trace (%s): top %zu entries\n", reason ? reason : "manual", top_n);
    size_t shown = 0;
    for (const auto & entry : entries) {
        fprintf(stderr, "[SYCL]   %s count=%llu bytes=%.2f MB\n", entry.first.c_str(),
                static_cast<unsigned long long>(entry.second.count),
                static_cast<double>(entry.second.bytes) / (1024.0 * 1024.0));
        if (++shown >= top_n) {
            break;
        }
    }
    fflush(stderr);
}

static void ggml_sycl_alloc_trace_dump_if_requested(const char * reason) {
    if (!ggml_sycl_alloc_trace_enabled_impl()) {
        return;
    }
    const char * env = std::getenv("GGML_SYCL_ALLOC_TRACE_DUMP");
    if (!env || std::atoi(env) == 0) {
        return;
    }
    static std::once_flag once;
    std::call_once(once, [reason]() { ggml_sycl_alloc_trace_dump(reason); });
}

static int ggml_sycl_direct_alloc_guard_mode() {
    static std::atomic<int> mode{ -1 };
    int                     cached = mode.load(std::memory_order_acquire);
    if (cached >= 0) {
        return cached;
    }
    const char * env   = std::getenv("GGML_SYCL_DIRECT_ALLOC_GUARD");
    int          value = 0;
    if (env) {
        value = std::max(0, std::atoi(env));
    } else if (ggml_sycl::unified_cache_enabled()) {
        value = 1;
    }
    mode.store(value, std::memory_order_release);
    return value;
}

void ggml_sycl_note_direct_allocation(const char * api, size_t size, const char * tag) {
    const int mode = ggml_sycl_direct_alloc_guard_mode();
    if (mode <= 0 || !ggml_sycl::unified_cache_enabled()) {
        return;
    }
    if (tag != nullptr) {
        const bool unified_internal =
            std::strncmp(tag, "unified_alloc:", 14) == 0 || std::strncmp(tag, "unified_cache:", 14) == 0 ||
            std::strncmp(tag, "copy_stage_", 11) == 0 || std::strcmp(tag, "pinned_chunk") == 0;
        if (unified_internal) {
            return;
        }
    }

    const ggml_sycl::offload_phase phase      = ggml_sycl::offload_stats_phase();
    const char *                   phase_name = ggml_sycl::offload_phase_name(phase);
    std::string key = std::string(api ? api : "unknown") + "|" + phase_name + "|" + (tag ? tag : "unknown");

    static std::mutex                      once_mutex;
    static std::unordered_set<std::string> warned;
    bool                                   first_hit = false;
    {
        std::lock_guard<std::mutex> lock(once_mutex);
        first_hit = warned.insert(key).second;
    }

    if (!first_hit) {
        return;
    }

    GGML_LOG_WARN("[SYCL] direct allocation bypassed unified_cache: api=%s size=%.2f MB tag=%s phase=%s\n",
                  api ? api : "unknown", size / (1024.0 * 1024.0), tag ? tag : "unknown", phase_name);

    if (mode >= 2) {
        GGML_ABORT("GGML_SYCL_DIRECT_ALLOC_GUARD detected a direct allocation outside unified_cache");
    }
}

// Raw device allocation — no budget tracking, used internally by unified_alloc
// and the unified cache itself (which manages its own budget via used_).
void * ggml_sycl_malloc_device_raw(size_t size, const sycl::queue & queue, const char * tag) {
    void * ptr = ggml_sycl::unified_cache_raw_malloc_device(size, queue);
    if (!ptr) {
        GGML_SYCL_DEBUG("[SYCL] malloc_device failed (%zu bytes, %s)\n", size, tag ? tag : "unknown");
        return nullptr;
    }
    if (ptr != nullptr) {
        int dev_id = ggml_sycl_get_device_id_from_queue(const_cast<sycl::queue &>(queue));
        ggml_sycl::alloc_registry::instance().register_alloc(ptr, size, dev_id, ggml_sycl::alloc_type::DEVICE);
        ggml_sycl_alloc_trace_record("device", size, tag);
        if (size >= 1024 * 1024) {
            GGML_SYCL_DEBUG("[ALLOC] device %.1f MB  tag=%s\n", size / (1024.0f * 1024.0f), tag ? tag : "unknown");
        }
    }
    return ptr;
}

// Re-entrancy guard: unified_cache_allocate → unified_alloc → ggml_sycl_malloc_device.
// When called from inside the cache, skip the cache route and use raw allocation.
static thread_local bool g_inside_unified_allocate = false;

struct scoped_allocate_guard {
    scoped_allocate_guard() { g_inside_unified_allocate = true; }

    ~scoped_allocate_guard() { g_inside_unified_allocate = false; }
};

void * ggml_sycl_malloc_device(size_t size, const sycl::queue & queue, const char * tag) {
    // If we're already inside unified_cache_allocate (re-entrant call from
    // unified_alloc or cache internals), use raw allocation to avoid recursion.
    if (g_inside_unified_allocate) {
        return ggml_sycl_malloc_device_raw(size, queue, tag);
    }

    // Strict mode: refuse allocation if budget is already exceeded
    static const bool strict_mode = ([] {
        const char * env = getenv("GGML_SYCL_MEMORY_STRICT");
        return env && (env[0] == '1');
    })();
    if (strict_mode) {
        int device = ggml_sycl_get_device_id_from_queue(const_cast<sycl::queue &>(queue));
        if (ggml_sycl::unified_cache_is_budget_exceeded(device)) {
            GGML_LOG_ERROR(
                "[SYCL] MEMORY_STRICT: refusing allocation of %zu bytes on device %d "
                "(budget exceeded, tag=%s)\n",
                size, device, tag ? tag : "?");
            return nullptr;
        }
    }

    // Route through the unified cache allocator for budget tracking.
    // Default category is COMPUTE_SCRATCH — individual callers will be
    // migrated to pass explicit categories in T5.
    int device = ggml_sycl_get_device_id_from_queue(const_cast<sycl::queue &>(queue));
    if (device >= 0 && ggml_sycl::unified_cache_enabled()) {
        scoped_allocate_guard guard;
        auto result = ggml_sycl::unified_cache_allocate(device, size, ggml_sycl::alloc_category::COMPUTE_SCRATCH,
                                                        const_cast<sycl::queue &>(queue));
        if (result.ptr != nullptr) {
            return result.ptr;
        }
        // mubmt.12: In strict mode, unified_cache failure is a hard error on the planned path.
        // Do not fall through to raw allocation — this preserves the zero-runtime-alloc contract.
        if (strict_mode || ggml_sycl::unified_alloc_strict_mode()) {
            GGML_LOG_ERROR(
                "[SYCL] UNIFIED_ALLOC_STRICT: refusing fallback to raw allocator on planned path "
                "(%zu bytes, device %d, tag=%s) — unified_cache allocation failed\n",
                size, device, tag ? tag : "?");
            return nullptr;
        }
        // Legacy fallback: unified_cache_allocate failed — fall through to raw allocation
        // as a last resort (preserves existing behavior for callers that
        // handle nullptr themselves). This path is deprecated and will be removed.
        GGML_LOG_WARN(
            "[SYCL] DEPRECATED: falling back to raw device allocator after unified_cache failure "
            "(%zu bytes, device %d, tag=%s) — set GGML_SYCL_UNIFIED_ALLOC_STRICT=1 to fail instead\n",
            size, device, tag ? tag : "?");
    }

    return ggml_sycl_malloc_device_raw(size, queue, tag);
}

// Track total host-pinned allocations for diagnostics.
static std::atomic<size_t> g_total_host_pinned_bytes{ 0 };

void * ggml_sycl_malloc_host(size_t size, const sycl::queue & queue, const char * tag) {
    ggml_sycl_note_direct_allocation("ggml_sycl_malloc_host(queue)", size, tag);
    // Always use sycl::malloc_host — pinned host memory with GPU DMA access.
    // Verified: 60 GB pinned works fine on Xe2/BMG (test-sycl-pinned-memory).
    // The GGTT overflow hypothesis was disproven — modern Intel GPUs use
    // per-process page tables, not a fixed-size GGTT for USM allocations.
    void * ptr = ggml_sycl::unified_cache_raw_malloc_host(size, queue);
    if (!ptr) {
        GGML_LOG_WARN("[SYCL] malloc_host failed (%zu bytes, %s)\n", size, tag ? tag : "unknown");
        return nullptr;
    }
    g_total_host_pinned_bytes.fetch_add(size, std::memory_order_relaxed);
    ggml_sycl::alloc_registry::instance().register_alloc(ptr, size, -1, ggml_sycl::alloc_type::HOST_PINNED);
    ggml_sycl_alloc_trace_record("host", size, tag);
    ggml_sycl::offload_stats_note_host_alloc(tag ? tag : "malloc_host", size);
    return ptr;
}

void * ggml_sycl_malloc_host(size_t size, const sycl::context & ctx, const char * tag) {
    ggml_sycl_note_direct_allocation("ggml_sycl_malloc_host(context)", size, tag);
    // Context-based overload: avoids queue contention when the queue has pending
    // async operations (e.g. prestage/inference DMA).  The queue-based overload
    // of sycl::malloc_host may internally synchronise the queue on Level Zero,
    // causing a hang.  Using the context directly side-steps this entirely.
    void * ptr = ggml_sycl::unified_cache_raw_malloc_host(size, ctx);
    if (!ptr) {
        GGML_LOG_WARN("[SYCL] malloc_host(ctx) failed (%zu bytes, %s)\n", size, tag ? tag : "unknown");
        return nullptr;
    }
    g_total_host_pinned_bytes.fetch_add(size, std::memory_order_relaxed);
    ggml_sycl::alloc_registry::instance().register_alloc(ptr, size, -1, ggml_sycl::alloc_type::HOST_PINNED);
    ggml_sycl_alloc_trace_record("host", size, tag);
    ggml_sycl::offload_stats_note_host_alloc(tag ? tag : "malloc_host", size);
    return ptr;
}

void * ggml_sycl_malloc_shared(size_t size, const sycl::queue & queue, const char * tag) {
    ggml_sycl_note_direct_allocation("ggml_sycl_malloc_shared", size, tag);
    void * ptr = ggml_sycl::unified_cache_raw_malloc_shared(size, queue);
    if (!ptr) {
        GGML_SYCL_DEBUG("[SYCL] malloc_shared failed (%zu bytes, %s)\n", size, tag ? tag : "unknown");
        return nullptr;
    }
    int dev_id = ggml_sycl_get_device_id_from_queue(const_cast<sycl::queue &>(queue));
    ggml_sycl::alloc_registry::instance().register_alloc(ptr, size, dev_id, ggml_sycl::alloc_type::SHARED);
    ggml_sycl_alloc_trace_record("shared", size, tag);
    return ptr;
}

static size_t ggml_sycl_pool_round_size(size_t size) {
    constexpr size_t k4K      = 4 * 1024;
    constexpr size_t k64K     = 64 * 1024;
    constexpr size_t k1MB     = 1024 * 1024;
    auto             align_up = [](size_t value, size_t align) {
        return (value + align - 1) / align * align;
    };
    if (size <= k64K) {
        return align_up(size, k4K);
    }
    if (size <= k1MB) {
        return align_up(size, k64K);
    }
    return align_up(size, k1MB);
}

struct ggml_sycl_pool_leg : public ggml_sycl_pool {
    static const int MAX_SYCL_BUFFERS = 1024;
    int              device;
    queue_ptr        qptr;

    struct ggml_sycl_buffer {
        void * ptr = nullptr;

        size_t size = 0;
    };

    ggml_sycl_buffer buffer_pool[MAX_SYCL_BUFFERS] = {};
    size_t           pool_size                     = 0;

    // Cache the arena-enabled flag at construction time — avoids repeated
    // getenv() lookups on every alloc/free in the hot path.
    bool arena_mode_ = false;

    explicit ggml_sycl_pool_leg(queue_ptr qptr_, int device_) :
        device(device_),
        qptr(qptr_),
        arena_mode_(ggml_sycl::vram_arena_enabled()) {}

    ~ggml_sycl_pool_leg() {
        // When arena is active, no buffers should be in the free list —
        // all allocations came from the compute arena and were never cached.
        if (arena_mode_) {
            return;
        }

        for (int i = 0; i < MAX_SYCL_BUFFERS; ++i) {
            ggml_sycl_buffer & b = buffer_pool[i];

            if (b.ptr != nullptr) {
                // Only free non-arena allocations.  Arena memory is freed
                // by the unified_cache destructor.
                ggml_sycl::unified_cache_deallocate(b.ptr, device);
                pool_size -= b.size;
            }
        }
        GGML_ASSERT(pool_size == 0);
    }

    void * alloc(size_t size, size_t * actual_size) override {
        const size_t rounded_size = ggml_sycl_pool_round_size(size);

        // --- VRAM arena fast path ---
        // When the VRAM arena is active, compute scratch comes from the
        // compute arena's SCRATCH TLSF zone. No free list, no malloc_device.
        // The zone resets between graph_compute calls.
        if (arena_mode_) {
            auto * cache = ggml_sycl::get_unified_cache_for_device(device);
            void * ptr   = (cache && cache->arena_active()) ? cache->arena_alloc(rounded_size) : nullptr;
            pp_scratch_profile_note_pool_alloc(rounded_size, ptr != nullptr);
            if (ptr) {
                *actual_size = rounded_size;
                return ptr;
            }
            GGML_LOG_WARN("[POOL-LEG] arena exhausted (requested %zu bytes)\n", rounded_size);
            return nullptr;
        }

        // --- Legacy path (arena OFF) ---
#ifdef DEBUG_sycl_MALLOC
        int    nnz      = 0;
        size_t max_size = 0;
#endif
        size_t best_diff = 1ull << 36;
        int    ibest     = -1;

        for (int i = 0; i < MAX_SYCL_BUFFERS; ++i) {
            ggml_sycl_buffer & b = buffer_pool[i];
            if (b.ptr != nullptr) {
#ifdef DEBUG_sycl_MALLOC

                ++nnz;
                if (b.size > max_size) {
                    max_size = b.size;
                }

#endif
                if (b.size >= rounded_size) {
                    size_t diff = b.size - rounded_size;
                    if (diff < best_diff) {
                        best_diff = diff;

                        ibest = i;
                        if (!best_diff) {
                            void * ptr   = b.ptr;
                            *actual_size = b.size;
                            b.ptr        = nullptr;
                            b.size       = 0;
                            return ptr;
                        }
                    }
                }
            }
        }

        if (ibest >= 0) {
            ggml_sycl_buffer & b   = buffer_pool[ibest];
            void *             ptr = b.ptr;
            *actual_size           = b.size;
            b.ptr                  = nullptr;
            b.size                 = 0;
            return ptr;
        }
        void * ptr;

        // Try the pre-reserved compute arena first.
        {
            auto * cache = ggml_sycl::get_unified_cache_for_device(device);
            ptr = (cache && cache->arena_active()) ? cache->arena_alloc(rounded_size) : nullptr;
            if (ptr) {
                *actual_size = rounded_size;
                return ptr;
            }
        }
        // Arena full or not reserved — fall back to unified cache.
        // When VRAM is available, this returns device memory.  When VRAM is
        // full (weights + KV consumed most of it), the cache automatically
        // falls back to host-pinned memory (sycl::malloc_host) which the GPU
        // can still access via PCIe zero-copy — slower but correct.
        {
            auto alloc_result = ggml_sycl::unified_cache_allocate(device, rounded_size,
                                                                  ggml_sycl::alloc_category::COMPUTE_SCRATCH, *qptr);
            ptr               = alloc_result.ptr;
        }

        if (!ptr) {
            GGML_LOG_WARN("%s: can't allocate %lu bytes (neither VRAM nor host-pinned)\n", __func__, rounded_size);
            return nullptr;
        }
        *actual_size = rounded_size;
        pool_size += rounded_size;
#ifdef DEBUG_SYCL_MALLOC
        GGML_LOG_DEBUG("%s[%d]: %d buffers, max_size = %u MB, pool_size = %u MB, requested %u MB\n", __func__, id, nnz,
                       (uint32_t) (max_size / 1024 / 1024), (uint32_t) (g_sycl_pool_size[id] / 1024 / 1024),
                       (uint32_t) (size / 1024 / 1024));
#endif
        // GGML_SYCL_DEBUG("ggml_sycl_pool_malloc_leg look_ahead_size=%lu, return %p\n", look_ahead_size, ptr);
        return ptr;
    }

    void free(void * ptr, size_t size) override {
        // Arena pointers are ephemeral — the SCRATCH zone resets between
        // graph_compute calls, and individual frees return blocks to TLSF.
        if (arena_mode_) {
            if (ggml_sycl::unified_cache_arena_owns(device, ptr)) {
                pp_scratch_profile_note_pool_free(size);
                ggml_sycl::unified_cache_arena_free(device, ptr, size);
            }
            return;
        }

        // Legacy (arena OFF): arena pointers can still appear from the hybrid
        // path in alloc() — skip them, they are not in the free list.
        if (ggml_sycl::unified_cache_arena_owns(device, ptr)) {
            return;
        }

        for (int i = 0; i < MAX_SYCL_BUFFERS; ++i) {
            ggml_sycl_buffer & b = buffer_pool[i];
            if (b.ptr == nullptr) {
                b.ptr  = ptr;
                b.size = size;
                return;
            }
        }
        GGML_LOG_WARN("WARNING: sycl buffer pool full, increase MAX_sycl_BUFFERS\n");
        ggml_sycl::alloc_registry::instance().unregister_alloc(ptr);
        SYCL_CHECK(CHECK_TRY_ERROR(sycl::free(ptr, *qptr)));
        pool_size -= size;
    }
};

struct ggml_sycl_pool_host : public ggml_sycl_pool {
    queue_ptr qptr;
    int       device;

    struct ggml_sycl_buffer {
        void * ptr  = nullptr;
        size_t size = 0;
    };

    // Set to a larger pool to reduce malloc churn
    static constexpr int          MAX_POOL_SIZE{ 256 };
    std::vector<ggml_sycl_buffer> buffer_pool = std::vector<ggml_sycl_buffer>(MAX_POOL_SIZE);
    size_t                        pool_size   = 0;

    explicit ggml_sycl_pool_host(queue_ptr qptr_, int device_) : qptr(qptr_), device(device_) {}

    ~ggml_sycl_pool_host() override {
        for (int i = 0; i < MAX_POOL_SIZE; ++i) {
            ggml_sycl_buffer & b = buffer_pool[i];
            if (b.ptr != nullptr) {
                ggml_sycl::alloc_registry::instance().unregister_alloc(b.ptr);
                SYCL_CHECK(CHECK_TRY_ERROR(sycl::free(b.ptr, *qptr)));
                b.ptr = nullptr;
                pool_size -= b.size;
                b.size = 0;
            }
        }
    }

    void * alloc(size_t size, size_t * actual_size) override {
        const size_t rounded_size = ggml_sycl_pool_round_size(size);
        size_t       best_diff    = 1ull << 36;
        int          ibest        = -1;
        for (int i = 0; i < MAX_POOL_SIZE; ++i) {
            ggml_sycl_buffer & b = buffer_pool[i];
            if (b.ptr != nullptr && b.size >= rounded_size) {
                const size_t diff = b.size - rounded_size;
                if (diff < best_diff) {
                    best_diff = diff;
                    ibest     = i;
                    if (!best_diff) {
                        void * ptr   = b.ptr;
                        *actual_size = b.size;
                        b.ptr        = nullptr;
                        b.size       = 0;
                        return ptr;
                    }
                }
            }
        }
        if (ibest >= 0) {
            ggml_sycl_buffer & b   = buffer_pool[ibest];
            void *             ptr = b.ptr;
            *actual_size           = b.size;
            b.ptr                  = nullptr;
            b.size                 = 0;
            return ptr;
        }
        void * ptr;
        ptr = ggml_sycl_malloc_host(rounded_size, *qptr, "pool_host");
        if (!ptr) {
            GGML_LOG_ERROR("%s: can't allocate %lu Bytes of memory on host\n", __func__, rounded_size);
            return nullptr;
        }
        pool_size += rounded_size;
        *actual_size = rounded_size;
        return ptr;
    }

    void free(void * ptr, size_t size) override {
        // if the pool is not completed add the pointer to it in place of the first nullptr found.
        // Otherwise do nothing, pointers will be freed once the pool is deallocated.

        for (int i = 0; i < MAX_POOL_SIZE; ++i) {
            ggml_sycl_buffer & b = buffer_pool[i];
            if (b.ptr == nullptr) {
                b.ptr  = ptr;
                b.size = size;
                return;
            }
        }
        ggml_sycl::alloc_registry::instance().unregister_alloc(ptr);
        SYCL_CHECK(CHECK_TRY_ERROR(sycl::free(ptr, *qptr)));
        pool_size -= size;
    }
};

std::unique_ptr<ggml_sycl_pool> ggml_backend_sycl_context::new_pool_for_host(queue_ptr qptr, int device) {
    // return pool for the host to speed up memory management
    return std::unique_ptr<ggml_sycl_pool>(new ggml_sycl_pool_host(qptr, device));
}

