// Pre-stage all non-device tensors in a compute graph before SYCL graph recording.
// This ensures that all non-device (mmap'd) tensors are uploaded to device memory
// BEFORE graph recording begins, since we cannot use .wait() during recording.
//
// IMPORTANT: The cgraph->leafs array may be empty (scheduler may not populate it),
// so we must also scan ALL source tensors from ALL nodes in the graph to find
// non-device memory that needs staging.
static void graph_prestage_leaf_tensors(ggml_backend_sycl_context * ctx, const ggml_cgraph * cgraph) {
    GGML_SYCL_DEBUG("[GRAPH-PRESTAGE] Entering: cgraph=%p n_nodes=%d n_leafs=%d\n", (void *) cgraph,
                    cgraph ? cgraph->n_nodes : -1, cgraph ? cgraph->n_leafs : -1);
    if (!cgraph || cgraph->n_nodes == 0) {
        GGML_SYCL_DEBUG("[GRAPH-PRESTAGE] Early exit: no nodes\n");
        return;
    }

    const int device               = ctx->device;
    int       staged_count         = 0;
    int       already_device_count = 0;
    int       cache_hit_count      = 0;
    int       skipped_weight_count = 0;
    int       skipped_host_planned = 0;

    // Check if tiered mode is enabled - if so, weight tensors in HOST need promotion to VRAM
    const bool tiered_enabled = g_tiered_enabled.load(std::memory_order_relaxed);

    // Get the unified cache for this device
    ggml_sycl::unified_cache * cache = nullptr;
    if (ggml_sycl::unified_cache_enabled()) {
        cache = ggml_sycl::get_unified_cache_for_device(device);
    }

    // Get context for pointer type checking
    std::optional<sycl::context> ctx_storage;
    sycl::context *              sycl_ctx = nullptr;
    try {
        ctx_storage.emplace(ggml_sycl_get_device(device).default_queue().get_context());
        sycl_ctx = &ctx_storage.value();
    } catch (...) {
        GGML_LOG_ERROR("[GRAPH-PRESTAGE] Failed to get SYCL context for device %d\n", device);
        return;
    }

    // Track already-staged pointers to avoid duplicates
    std::unordered_set<void *> staged_pointers;

    // Helper lambda to stage a tensor
    auto stage_tensor = [&](const ggml_tensor * tensor, const char * source_desc) {
        if (!tensor || !tensor->data) {
            return;
        }

        // Skip if already staged (same data pointer)
        if (staged_pointers.count(tensor->data)) {
            return;
        }

        // Handle weight tensors specially in tiered mode
        if (ggml_sycl_tensor_is_weight(tensor)) {
            if (cache && ggml_sycl_weight_is_planned_on_host(tensor, device)) {
                skipped_weight_count++;
                skipped_host_planned++;
                staged_pointers.insert(tensor->data);
                return;
            }
            if (!tiered_enabled) {
                // Non-tiered mode: weights are handled by the weight cache with layout transformations
                skipped_weight_count++;
                return;
            }

            // Tiered mode: check if weight is in HOST tier and needs promotion to VRAM
            ggml_sycl::memory_tier tier               = ggml_sycl::memory_tier::MMAP;
            bool                   found_in_inventory = false;
            void *                 cached_ptr         = get_cached_tensor_ptr(tensor->name, &tier, &found_in_inventory);

            if (!found_in_inventory) {
                // Weight not tracked by tiered cache - skip (handled elsewhere)
                skipped_weight_count++;
                return;
            }

            if (tier == ggml_sycl::memory_tier::VRAM) {
                // Already in VRAM - no promotion needed
                already_device_count++;
                staged_pointers.insert(tensor->data);
                return;
            }

            // Weight is in HOST or MMAP tier — unified_cache handles placement
            staged_pointers.insert(tensor->data);
            return;
        }

        // Check if this is already device memory
        sycl::usm::alloc ptr_type = ggml_sycl_get_alloc_type(tensor->data);
        if (ptr_type == sycl::usm::alloc::device) {
            already_device_count++;
            staged_pointers.insert(tensor->data);
            return;
        }

        // Non-device memory - needs staging
        size_t nbytes = ggml_nbytes(tensor);

        // INPUT tensors: stage to a STABLE device buffer that persists across graph iterations.
        // The ggml allocator may reassign tensor->data between iterations, but L0 graph replay
        // bakes the pointer at finalize time. The stable staging buffer survives across replays.
        if ((tensor->flags & GGML_TENSOR_FLAG_INPUT) && tensor->name && tensor->name[0] != '\0') {
            sycl::queue & q = ggml_sycl_get_device(device).default_queue();
            void * dev_ptr = ctx->graph_input_stage(tensor->name, tensor->data, nbytes, q);
            if (dev_ptr) {
                {
                    std::lock_guard<std::mutex> lock(g_graph_input_staged_mutex);
                    g_graph_input_staged_ptrs[tensor->name] = dev_ptr;
                }
                staged_count++;
                staged_pointers.insert(tensor->data);
                GGML_SYCL_DEBUG("[GRAPH-PRESTAGE] INPUT staged %s tensor %s (data=%p, %zu bytes) -> dev %p\n",
                                source_desc, tensor->name, tensor->data, nbytes, dev_ptr);
                return;
            }
        }

        // Try unified cache first
        if (cache) {
            ggml_sycl_cache_id cache_key = ggml_backend_sycl_get_tensor_cache_key(tensor, device);
            if (cache_key.valid) {
                // DEBUG: Log full cache key during pre-staging
                GGML_SYCL_DEBUG(
                    "[CACHE-KEY-PRESTAGE] %s: name=%s hash=%llu type=%d nbytes=%zu ne=[%lld,%lld,%lld,%lld] "
                    "aux_id=%llu data=%p\n",
                    source_desc, tensor->name, (unsigned long long) cache_key.name_hash, (int) cache_key.type,
                    cache_key.nbytes, (long long) cache_key.ne[0], (long long) cache_key.ne[1],
                    (long long) cache_key.ne[2], (long long) cache_key.ne[3], (unsigned long long) cache_key.aux_id,
                    tensor->data);

                // Check if already cached
                void * cached = cache->get(cache_key, GGML_LAYOUT_AOS);
                if (cached) {
                    cache_hit_count++;
                    staged_pointers.insert(tensor->data);
                    return;
                }

                // Upload to cache (uses .wait() which is OK since we're not in graph recording yet)
                void * uploaded =
                    cache->ensure_cached(cache_key, tensor->data, nbytes, ggml_sycl::cache_entry_type::DENSE_WEIGHT, -1,
                                         -1, GGML_LAYOUT_AOS, false);
                if (uploaded) {
                    staged_count++;
                    staged_pointers.insert(tensor->data);
                    GGML_SYCL_DEBUG("[GRAPH-PRESTAGE] Staged %s tensor %s (data=%p, %zu bytes) -> %p\n", source_desc,
                                    tensor->name, tensor->data, nbytes, uploaded);
                    return;
                }
            }
        }

        // Fall back to staging cache
        void * staged = ggml_sycl_get_staged_ptr_device(tensor->data, nbytes, device);
        if (staged) {
            staged_count++;
            staged_pointers.insert(tensor->data);
            GGML_SYCL_DEBUG("[GRAPH-PRESTAGE] Staged %s tensor %s (data=%p, %zu bytes) via staging cache -> %p\n",
                            source_desc, tensor->name, tensor->data, nbytes, staged);
        } else {
            GGML_LOG_WARN("[GRAPH-PRESTAGE] Failed to stage %s tensor %s (data=%p, %zu bytes)\n", source_desc,
                          tensor->name, tensor->data, nbytes);
        }
    };

    // Stage tensors from cgraph->leafs (if any)
    for (int i = 0; i < cgraph->n_leafs; i++) {
        stage_tensor(cgraph->leafs[i], "leaf");
    }

    // CRITICAL: Also scan ALL source tensors from ALL nodes in the graph.
    // The cgraph->leafs array may be empty even when nodes reference non-device tensors.
    // This is the ROOT CAUSE of the DEVICE_LOST error - leaf tensors like "leaf_5" are
    // referenced by nodes but not in cgraph->leafs, so they weren't being pre-staged.
    for (int i = 0; i < cgraph->n_nodes; i++) {
        const ggml_tensor * node = cgraph->nodes[i];
        if (!node) {
            continue;
        }

        // Check all source tensors
        for (int j = 0; j < GGML_MAX_SRC; j++) {
            const ggml_tensor * src = node->src[j];
            if (src) {
                stage_tensor(src, "node_src");
            }
        }
    }

    GGML_SYCL_DEBUG(
        "[GRAPH-PRESTAGE] Complete: %d staged, %d cache hits, %d already device, %d weights skipped "
        "(host-planned=%d)\n",
        staged_count, cache_hit_count, already_device_count, skipped_weight_count, skipped_host_planned);
}

// When reusing an executable SYCL command graph, the usual per-op pointer refresh
// paths are not executed. We must explicitly refresh dynamic input tensors (e.g. tokens)
// on device before replaying the graph.
//
// Optimization: On first call, discover and cache the input tensor list (~5-10 tensors).
// On subsequent calls, only refresh the cached list instead of scanning the full graph
// (avoids iterating all n_nodes x GGML_MAX_SRC sources per token).
static void graph_refresh_input_tensors(ggml_backend_sycl_context * ctx, const ggml_cgraph * cgraph) {
    if (!ctx || !cgraph || cgraph->n_nodes == 0) {
        return;
    }

    // Use pre-cached input tensor list if available.
    // On replay, do direct async memcpy for tensors whose resolved device pointer
    // differs from tensor->data, avoiding expensive sycl::get_pointer_type() driver calls
    // (~1.15ms each). For tensors where resolved_ptr == tensor->data, set_tensor_async
    // already copied the data so no additional work is needed.
    // INPUT tensor staging refresh DISABLED: INPUT tensors use stable malloc_host
    // addresses that L0 graph replay reads directly.  The staging fast path that
    // copied to device buffers and returned early was removed because its refresh
    // used default_queue() while graph replay ran on sycl_ctx->stream(), causing
    // a data race that produced stale input tokens.

    // Legacy path: use pre-cached input tensor list.
    if (ctx->input_tensors_cached && !ctx->cached_input_tensors.empty()) {
        sycl::queue & q          = ggml_sycl_get_device(ctx->device).default_queue();
        const size_t  n          = ctx->cached_input_tensors.size();
        int           copy_count = 0;
        int           skip_count = 0;
        for (size_t idx = 0; idx < n; idx++) {
            ggml_tensor * tensor = ctx->cached_input_tensors[idx];
            if (!tensor || !tensor->data) {
                continue;
            }
            void * dev_ptr = ctx->cached_input_dev_ptrs[idx];
            if (!dev_ptr) {
                continue;
            }
            if (dev_ptr == tensor->data) {
                // Device pointer IS tensor->data: set_tensor_async already refreshed it
                skip_count++;
                continue;
            }
            // Device pointer differs from tensor->data: direct async memcpy needed
            size_t nbytes = ggml_nbytes(tensor);
            q.memcpy(dev_ptr, tensor->data, nbytes);
            copy_count++;
        }
        GGML_SYCL_DEBUG("[SYCL-GRAPH] refreshed %d input tensors (skipped %d same-ptr)\n", copy_count, skip_count);
        return;
    }

    // First call: discover and cache input tensors + their resolved device pointers
    std::unordered_set<const void *> seen_ptrs;
    ctx->cached_input_tensors.clear();
    ctx->cached_input_dev_ptrs.clear();

    auto discover_input = [&](ggml_tensor * tensor) {
        if (!tensor || !tensor->data) {
            return;
        }
        if (ggml_sycl_tensor_is_weight(tensor)) {
            return;
        }
        if (!(tensor->flags & GGML_TENSOR_FLAG_INPUT)) {
            return;
        }
        if (!seen_ptrs.insert(tensor->data).second) {
            return;
        }

        // Resolve device pointer once (slow path OK for one-time discovery)
        void * resolved_ptr = ggml_sycl_resolve_tensor_ptr(tensor, ctx->device);
        ctx->cached_input_tensors.push_back(tensor);
        ctx->cached_input_dev_ptrs.push_back(resolved_ptr);
        GGML_SYCL_DEBUG("[SYCL-GRAPH] discovered input %s -> %p (tensor->data=%p, %s)\n",
                        tensor->name ? tensor->name : "?", resolved_ptr, tensor->data,
                        resolved_ptr == tensor->data ? "same" : "DIFFERENT");
    };

    for (int i = 0; i < cgraph->n_leafs; ++i) {
        discover_input(cgraph->leafs[i]);
    }
    for (int i = 0; i < cgraph->n_nodes; ++i) {
        if (!cgraph->nodes[i]) {
            continue;
        }
        for (int j = 0; j < GGML_MAX_SRC; ++j) {
            discover_input(cgraph->nodes[i]->src[j]);
        }
    }

    ctx->input_tensors_cached = true;
    GGML_SYCL_DEBUG("[SYCL-GRAPH] cached %zu input tensors for future replays\n", ctx->cached_input_tensors.size());
}

static uint64_t ggml_sycl_graph_signature(const ggml_cgraph * cgraph) {
    if (!cgraph) {
        return 0;
    }
    // DEBUG: Check cgraph integrity
    GGML_SYCL_DEBUG("[DEBUG-GRAPH-SIG] cgraph=%p n_nodes=%d n_leafs=%d\n", (void *) cgraph, cgraph->n_nodes,
                    cgraph->n_leafs);

    // Sanity check for obviously corrupted values
    if (cgraph->n_nodes < 0 || cgraph->n_nodes > 100000) {
        GGML_SYCL_DEBUG("[DEBUG-GRAPH-SIG] ERROR: cgraph->n_nodes looks corrupted: %d\n", cgraph->n_nodes);
        return 0;
    }
    uint64_t h   = 1469598103934665603ULL;  // FNV-1a offset basis
    auto     mix = [&h](uint64_t v) {
        h ^= v;
        h *= 1099511628211ULL;
    };
    auto hash_shape = [&mix](const ggml_tensor * t) {
        if (!t) {
            mix(0);
            return;
        }
        // DEBUG: Validate pointer looks reasonable before dereferencing
        uintptr_t ptr_val = reinterpret_cast<uintptr_t>(t);
        if (ptr_val < 0x1000 || ptr_val > 0x7FFFFFFFFFFF) {
            GGML_SYCL_DEBUG("[DEBUG-GRAPH-SIG] ERROR: tensor ptr looks invalid: %p\n", (void *) t);
            mix(0);
            return;
        }
        mix(static_cast<uint64_t>(t->type));
        for (int i = 0; i < GGML_MAX_DIMS; ++i) {
            mix(static_cast<uint64_t>(t->ne[i]));
            mix(static_cast<uint64_t>(t->nb[i]));
        }
    };
    mix(static_cast<uint64_t>(cgraph->n_nodes));

    mix(static_cast<uint64_t>(cgraph->n_leafs));
    for (int i = 0; i < cgraph->n_nodes; ++i) {
        const ggml_tensor * node = cgraph->nodes[i];
        if (!node) {
            mix(0);
            continue;
        }
        mix(static_cast<uint64_t>(node->op));
        mix(static_cast<uint64_t>(node->type));
        mix(static_cast<uint64_t>(node->flags));
        mix(static_cast<uint64_t>(node->view_offs));
        for (int j = 0; j < GGML_MAX_DIMS; ++j) {
            mix(static_cast<uint64_t>(node->ne[j]));
            mix(static_cast<uint64_t>(node->nb[j]));
        }
        for (int j = 0; j < GGML_MAX_OP_PARAMS / (int) sizeof(node->op_params[0]); ++j) {
            mix(static_cast<uint64_t>(node->op_params[j]));
        }
        for (int j = 0; j < GGML_MAX_SRC; ++j) {
            hash_shape(node->src[j]);
        }
    }
    return h;
}

// =============================================================================
// Persistent Kernel Graph Extraction
// =============================================================================

/**
 * Extract layer index from a tensor name.
 * Tensor names follow the pattern "blk.N.component.weight" where N is the layer.
 * Returns -1 if no layer index is found.
 */
static int extract_layer_index(const char * name) {
    if (!name) {
        return -1;
    }
    const char * blk = std::strstr(name, "blk.");
    if (blk) {
        return std::atoi(blk + 4);  // Parse number after "blk."
    }

    // Fallback: suffix "-N" (e.g. "norm-0", "Qcur-1", "Qcur-0 (reshaped)").
    const char * dash = std::strrchr(name, '-');
    if (!dash || dash[1] == '\0') {
        return -1;
    }
    char *     end   = nullptr;
    const long layer = std::strtol(dash + 1, &end, 10);
    if (end && end != dash + 1 && layer >= 0) {
        return (int) layer;
    }
    return -1;
}

// Test hook: expose layer parsing for unit tests.
int ggml_sycl_test_extract_layer_index(const char * name) {
    return extract_layer_index(name);
}

static const ggml_tensor * ggml_sycl_get_view_root(const ggml_tensor * tensor, size_t & view_offs) {
    view_offs               = 0;
    const ggml_tensor * cur = tensor;
    while (cur && cur->view_src) {
        view_offs += cur->view_offs;
        cur = cur->view_src;
    }
    return cur;
}

static void * ggml_sycl_get_data_ptr_view(const ggml_tensor * tensor, int device) {
    if (!tensor) {
        return nullptr;
    }
    size_t              view_offs = 0;
    const ggml_tensor * root      = ggml_sycl_get_view_root(tensor, view_offs);
    void *              base_ptr  = ggml_sycl_get_data_ptr(root, device);
    if (!base_ptr) {
        return nullptr;
    }
    if (root != tensor || view_offs != 0) {
        return static_cast<char *>(base_ptr) + view_offs;
    }
    return base_ptr;
}

/**
 * Classify a MUL_MAT weight tensor into a MatmulType.
 * Weight tensor name determines the projection type.
 */
static MatmulType classify_matmul(const char * weight_name) {
    if (!weight_name) {
        return MatmulType::GENERIC;
    }

    if (std::strstr(weight_name, "attn_q")) {
        return MatmulType::Q_PROJ;
    }
    if (std::strstr(weight_name, "attn_k")) {
        return MatmulType::K_PROJ;
    }
    if (std::strstr(weight_name, "attn_v")) {
        return MatmulType::V_PROJ;
    }
    if (std::strstr(weight_name, "attn_output")) {
        return MatmulType::OUT_PROJ;
    }
    if (std::strstr(weight_name, "ffn_gate")) {
        return MatmulType::GATE;
    }
    if (std::strstr(weight_name, "ffn_up")) {
        return MatmulType::UP;
    }
    if (std::strstr(weight_name, "ffn_down")) {
        return MatmulType::DOWN;
    }

    return MatmulType::GENERIC;  // Default fallback
}

/**
 * Extract model dimensions from the compute graph.
 * Analyzes tensor shapes to determine hidden_dim, intermediate_dim, etc.
 *
 * @param cgraph Compute graph to analyze
 * @param[out] n_layers      Number of transformer layers
 * @param[out] hidden_dim    Hidden dimension (from RMS_NORM weights)
 * @param[out] intermediate_dim  FFN intermediate dimension
 * @param[out] n_heads       Number of attention heads
 * @param[out] n_kv_heads    Number of KV heads (for GQA)
 * @param[out] head_dim      Dimension per head
 * @param[out] quant_type    Weight quantization type
 * @return true if dimensions were successfully extracted
 */
static bool extract_model_dimensions(ggml_cgraph * cgraph,
                                     int &         n_layers,
                                     int &         hidden_dim,
                                     int &         intermediate_dim,
                                     int &         n_heads,
                                     int &         n_kv_heads,
                                     int &         head_dim,
                                     int &         quant_type) {
    n_layers         = 0;
    hidden_dim       = 0;
    intermediate_dim = 0;
    n_heads          = 0;
    n_kv_heads       = 0;
    head_dim         = 0;
    quant_type       = -1;  // -1 = unset (0 is GGML_TYPE_F32)

    for (int i = 0; i < cgraph->n_nodes; i++) {
        ggml_tensor * node = cgraph->nodes[i];

        if (node->op == GGML_OP_RMS_NORM && hidden_dim == 0) {
            // RMS_NORM input dimension gives hidden_dim
            hidden_dim = (int) node->src[0]->ne[0];
        }

        if (node->op == GGML_OP_MUL_MAT && node->src[0]) {
            const char * weight_name = node->src[0]->name;
            int          layer       = extract_layer_index(weight_name);
            if (layer >= n_layers) {
                n_layers = layer + 1;
            }

            // Extract quant type from first weight
            if (quant_type < 0) {
                quant_type = node->src[0]->type;
            }

            // FFN gate/up gives intermediate_dim (N dimension of weight)
            if (std::strstr(weight_name, "ffn_gate") || std::strstr(weight_name, "ffn_up")) {
                if (intermediate_dim == 0) {
                    intermediate_dim = (int) node->src[0]->ne[1];
                }
            }

            // Q projection gives n_heads * head_dim
            if (std::strstr(weight_name, "attn_q") && n_heads == 0) {
                int q_dim = (int) node->src[0]->ne[1];
                // head_dim is typically 128 for Mistral/LLaMA
                head_dim  = 128;
                n_heads   = q_dim / head_dim;
                if (n_heads == 0) {
                    head_dim = 64;
                    n_heads  = q_dim / head_dim;
                }
            }

            // K projection gives n_kv_heads * head_dim
            if (std::strstr(weight_name, "attn_k") && n_kv_heads == 0) {
                int k_dim = (int) node->src[0]->ne[1];
                if (head_dim > 0) {
                    n_kv_heads = k_dim / head_dim;
                }
            }
        }
    }

    bool valid = (n_layers > 0 && hidden_dim > 0 && intermediate_dim > 0 && n_heads > 0 && head_dim > 0);
    if (n_kv_heads == 0) {
        n_kv_heads = n_heads;  // Default to MHA if GQA not detected
    }

    GGML_SYCL_DEBUG(
        "[PERSISTENT-TG] Extracted dims: layers=%d hidden=%d intermediate=%d "
        "heads=%d kv_heads=%d head_dim=%d quant=%d valid=%d\n",
        n_layers, hidden_dim, intermediate_dim, n_heads, n_kv_heads, head_dim, quant_type, valid ? 1 : 0);

    return valid;
}

