static ggml_guid_t ggml_backend_sycl_guid() {
    static ggml_guid guid = { 0x58, 0x05, 0x13, 0x8f, 0xcd, 0x3a, 0x61, 0x9d,
                              0xe7, 0xcd, 0x98, 0xa9, 0x03, 0xfd, 0x7c, 0x53 };
    return &guid;
}

bool ggml_backend_is_sycl(ggml_backend_t backend) {
    return backend != NULL && ggml_guid_matches(backend->guid, ggml_backend_sycl_guid());
}

int ggml_backend_sycl_get_device_count() {
    return ggml_sycl_info().device_count;
}

bool ggml_backend_sycl_moe_multi_gpu_requested() {
    // Auto-enabled when 2+ GPUs are available. MoE models benefit from
    // distributing experts across secondary GPU VRAM for higher cache hit
    // rates (B50 MMVQ = 0.085ms, 4.6x faster than CPU fallback).
    // Opt-out: GGML_SYCL_MOE_MULTI_GPU=0 to force single-GPU MoE.
    const char * env = std::getenv("GGML_SYCL_MOE_MULTI_GPU");
    if (env) {
        return std::atoi(env) != 0 && ggml_sycl_info().total_gpu_count >= 2;
    }
    return ggml_sycl_info().total_gpu_count >= 2;
}

// backend device
struct ggml_backend_sycl_device_context {
    int         device;
    std::string name;
    std::string description;
};

static const char * ggml_backend_sycl_device_get_name(ggml_backend_dev_t dev) {
    ggml_backend_sycl_device_context * ctx = (ggml_backend_sycl_device_context *) dev->context;
    return ctx->name.c_str();
}

static const char * ggml_backend_sycl_device_get_description(ggml_backend_dev_t dev) {
    ggml_backend_sycl_device_context * ctx = (ggml_backend_sycl_device_context *) dev->context;
    return ctx->description.c_str();
}

static void ggml_backend_sycl_device_get_memory(ggml_backend_dev_t dev, size_t * free, size_t * total) {
    ggml_backend_sycl_device_context * ctx = (ggml_backend_sycl_device_context *) dev->context;

    // When tensor split is active, hide non-primary devices from model loading.
    // Tensor split manages these devices directly via the 3-device dispatch path.
    static const char * split_env = std::getenv("GGML_SYCL_SPLIT_RATIO");
    if (split_env && ctx->device > 0) {
        *free  = 0;
        *total = 0;
        return;
    }

    ggml_sycl_set_device(ctx->device);
    SYCL_CHECK(CHECK_TRY_ERROR(ggml_sycl_get_device(ctx->device).get_memory_info(*free, *total)));

    // Apply VRAM budget percentage so llama_params_fit sees the same budget
    // as the unified cache, preventing over-allocation that triggers streaming fallback.
    const char * env_pct = std::getenv("GGML_SYCL_VRAM_BUDGET_PCT");
    if (env_pct) {
        int    pct      = std::max(1, std::min(100, std::atoi(env_pct)));
        size_t base_mem = ggml_sycl_info().devices[ctx->device].total_vram;
        if (base_mem == 0) {
            base_mem = *total;
        }
        size_t       budget       = static_cast<size_t>(base_mem * (static_cast<double>(pct) / 100.0));
        const size_t min_headroom = 256ull * 1024ull * 1024ull;
        const size_t headroom     = std::max(min_headroom, base_mem / 10);
        if (base_mem > headroom && budget > base_mem - headroom) {
            budget = base_mem - headroom;
        }
        if (budget > *free) {
            budget = *free;
        }
        *free = budget;
    }
}

static enum ggml_backend_dev_type ggml_backend_sycl_device_get_type(ggml_backend_dev_t dev) {
    GGML_UNUSED(dev);
    return GGML_BACKEND_DEVICE_TYPE_GPU;
}

static void ggml_backend_sycl_device_get_props(ggml_backend_dev_t dev, ggml_backend_dev_props * props) {
    props->name        = ggml_backend_sycl_device_get_name(dev);
    props->description = ggml_backend_sycl_device_get_description(dev);
    props->type        = ggml_backend_sycl_device_get_type(dev);
    ggml_backend_sycl_device_get_memory(dev, &props->memory_free, &props->memory_total);
    bool host_buffer = getenv("GGML_SYCL_NO_PINNED") == nullptr;
#ifdef GGML_SYCL_NO_PEER_COPY
    bool events = false;

#else
    bool events = true;
#endif
    props->caps = {
        /* .async                 = */ true,
        /* .host_buffer           = */ host_buffer,
        /* .buffer_from_host_ptr  = */ false,
        /* .events                = */ events,
    };
}

static ggml_backend_t ggml_backend_sycl_device_init(ggml_backend_dev_t dev, const char * params) {
    GGML_UNUSED(params);
    ggml_backend_sycl_device_context * ctx = (ggml_backend_sycl_device_context *) dev->context;
    return ggml_backend_sycl_init(ctx->device);
}

static ggml_backend_buffer_type_t ggml_backend_sycl_device_get_buffer_type(ggml_backend_dev_t dev) {
    ggml_backend_sycl_device_context * ctx = (ggml_backend_sycl_device_context *) dev->context;
    return ggml_backend_sycl_buffer_type(ctx->device);
}

static ggml_backend_buffer_type_t ggml_backend_sycl_device_get_host_buffer_type(ggml_backend_dev_t dev) {
    GGML_UNUSED(dev);
    return ggml_backend_sycl_host_buffer_type();
}

ggml_backend_buffer_type_t ggml_backend_sycl_kv_buffer_type_from_dev(ggml_backend_dev_t dev) {
    if (!dev || ggml_backend_dev_backend_reg(dev) != ggml_backend_sycl_reg()) {
        return dev ? ggml_backend_dev_buffer_type(dev) : nullptr;
    }
    ggml_backend_sycl_device_context * ctx = (ggml_backend_sycl_device_context *) dev->context;
    return ggml_backend_sycl_kv_buffer_type(ctx->device);
}

static ggml_backend_buffer_t ggml_backend_sycl_device_buffer_from_host_ptr(ggml_backend_dev_t dev,
                                                                           void *             ptr,
                                                                           size_t             size,
                                                                           size_t             max_tensor_size) {
    GGML_UNUSED(dev);
    GGML_UNUSED(ptr);
    GGML_UNUSED(size);
    GGML_UNUSED(max_tensor_size);
    return nullptr;
}

static int  ggml_sycl_extract_planned_layer_id(const ggml_tensor * op);
static bool ggml_sycl_op_is_planned_on_host(const ggml_tensor * op, int device);

static bool ggml_backend_sycl_device_supports_op(ggml_backend_dev_t dev, const ggml_tensor * op) {
    ggml_backend_sycl_device_context * sycl_ctx = (ggml_backend_sycl_device_context *) dev->context;
    int                                device   = sycl_ctx->device;

    // NOTE: When VRAM arena is active, the ggml scheduler may still place some
    // attention intermediates on the CPU backend.  The proper fix is to eliminate
    // the direct staging API and have the arena manage all buffer allocation directly.
    // See llama.cpp-b6y89 for the remaining PP512 fix.

    if (ggml_sycl_op_is_planned_on_host(op, device)) {
        GGML_SYCL_DEBUG("[SYCL-SUPPORT] planner rejects %s on SYCL backend (op=%s layer=%d)\n",
                        op && op->name[0] != '\0' ? op->name : "(unnamed)", ggml_op_name(op->op),
                        ggml_sycl_extract_planned_layer_id(op));
        return false;
    }

    switch (op->op) {
        case GGML_OP_CONV_TRANSPOSE_1D:
            {
                ggml_type src0_type = op->src[0]->type;
                ggml_type src1_type = op->src[1]->type;
                if (src0_type == GGML_TYPE_F32 && src1_type == GGML_TYPE_F32) {
                    return true;
                }
                return false;
            }
        case GGML_OP_UNARY:
            {
                const ggml_type src0_type = op->src[0]->type;
                const ggml_type dst_type  = op->type;

                auto unary_type_supported = [&](ggml_type src_type, ggml_type out_type) -> bool {
#if defined(GGML_SYCL_F16)
                    return (src_type == GGML_TYPE_F32 || src_type == GGML_TYPE_F16) && src_type == out_type;
#else
                    return src_type == GGML_TYPE_F32 && out_type == GGML_TYPE_F32;
#endif
                };
                switch (ggml_get_unary_op(op)) {
                    case GGML_UNARY_OP_SGN:
                    case GGML_UNARY_OP_ABS:
                    case GGML_UNARY_OP_NEG:
                    case GGML_UNARY_OP_STEP:
                    case GGML_UNARY_OP_RELU:
                    case GGML_UNARY_OP_HARDSIGMOID:
                    case GGML_UNARY_OP_TANH:
                    case GGML_UNARY_OP_GELU:
                    case GGML_UNARY_OP_SILU:
                    case GGML_UNARY_OP_SIGMOID:
                    case GGML_UNARY_OP_HARDSWISH:
                    case GGML_UNARY_OP_GELU_QUICK:
                    case GGML_UNARY_OP_GELU_ERF:
                    case GGML_UNARY_OP_EXP:
                    case GGML_UNARY_OP_ELU:

                        return unary_type_supported(src0_type, dst_type);
                    case GGML_UNARY_OP_FLOOR:
                    case GGML_UNARY_OP_CEIL:
                    case GGML_UNARY_OP_ROUND:
                    case GGML_UNARY_OP_TRUNC:
                        return ggml_is_contiguous(op->src[0]) && unary_type_supported(src0_type, dst_type);
                    default:
                        return false;
                }
            }
        case GGML_OP_GLU:
            {
                const ggml_type src0_type = op->src[0]->type;
                const ggml_type dst_type  = op->type;
#if defined(GGML_SYCL_F16)
                const bool type_ok =
                    (src0_type == GGML_TYPE_F32 || src0_type == GGML_TYPE_F16) && src0_type == dst_type;
#else
                const bool type_ok = src0_type == GGML_TYPE_F32 && dst_type == GGML_TYPE_F32;
#endif
                if (!type_ok) {
                    return false;
                }
                switch (ggml_get_glu_op(op)) {
                    case GGML_GLU_OP_REGLU:
                    case GGML_GLU_OP_GEGLU:
                    case GGML_GLU_OP_SWIGLU:
                    case GGML_GLU_OP_SWIGLU_OAI:
                    case GGML_GLU_OP_GEGLU_ERF:

                    case GGML_GLU_OP_GEGLU_QUICK:
                        return ggml_is_contiguous_1(op->src[0]);
                    default:
                        return false;
                }
            }
            break;
        case GGML_OP_MUL_MAT:
        case GGML_OP_MUL_MAT_ID:
            {
                struct ggml_tensor * a = op->src[0];
                struct ggml_tensor * b = op->src[1];
                if (a->ne[3] != b->ne[3]) {
                    return false;
                }
                ggml_type a_type = a->type;
                if (op->op == GGML_OP_MUL_MAT_ID) {
                    // Known NaN issues for these quantized types in the MoE host-routing path when n==1.
                    if ((a_type == GGML_TYPE_Q8_0 || a_type == GGML_TYPE_Q6_K) && (b->ne[1] == 1 || b->ne[2] == 1)) {
                        return false;
                    }
                    // MXFP4 MoE with non-broadcast src1 (ne11 > 1): the per-expert
                    // dispatch assumes ne11==1 for shared activation optimization.
                    // This only occurs in test-backend-ops with b=0 and n_used>1;
                    // real MoE models always have ne11==1 during inference.
                    if (a_type == GGML_TYPE_MXFP4 && b->ne[1] > 1 && b->ne[2] <= 1) {
                        return false;
                    }
                }
                if (op->op == GGML_OP_MUL_MAT && a_type == GGML_TYPE_Q4_0) {
                    // Q4_0 kernels currently do not handle broadcasted batch dims or large batch slices reliably.
                    // Treat these shapes as unsupported to avoid incorrect results.
                    if (a->ne[2] != b->ne[2] || a->ne[2] > 2) {
                        return false;
                    }
                }
                if (op->op == GGML_OP_MUL_MAT && a_type == GGML_TYPE_Q4_1 && b->ne[1] == 1) {
                    // Q4_1 small-n path can exceed error tolerance; prefer fallback.
                    return false;
                }
                if (a_type == GGML_TYPE_IQ4_NL || a_type == GGML_TYPE_IQ4_XS || a_type == GGML_TYPE_IQ3_XXS ||
                    a_type == GGML_TYPE_IQ3_S || a_type == GGML_TYPE_IQ2_XXS || a_type == GGML_TYPE_IQ2_XS ||
                    a_type == GGML_TYPE_IQ2_S || a_type == GGML_TYPE_IQ1_S || a_type == GGML_TYPE_IQ1_M) {
                    if (b->ne[1] == 1 && ggml_nrows(b) > 1) {
                        return false;
                    }
                }
                ggml_type src0_type = op->src[0]->type;
                if (src0_type == GGML_TYPE_BF16) {
                    // TODO: support BF16 in mul_mat properly
                    // FIXME: keep a list of supported types to avoid breaking the backend when a new type is added
                    return false;
                }
                // Note: MXFP4 is supported via MMVQ kernel in mmvq.cpp for MUL_MAT_ID
                // TODO: The configuration below needs more work to be supported with oneDNN
                if (ggml_is_permuted(a) && !ggml_is_contiguous(a) && a->ne[2] > 1 && a->ne[3] > 1 &&
                    src0_type == GGML_TYPE_F16) {
                    return false;
                }
                // TODO: This specific configuration can fail with oneDNN and needs more debugging
                if (!ggml_is_permuted(a) && ggml_is_permuted(b) && b->ne[2] > 1 && b->ne[3] > 1 && a->ne[0] > 128 &&
                    a->ne[2] == 1 && src0_type == GGML_TYPE_F16) {
                    return false;
                }
                return true;
            }
        case GGML_OP_OUT_PROD:
            // OUT_PROD shows NaNs on SYCL for some shapes; disable until fixed.
            return false;
        case GGML_OP_GET_ROWS:
            {
                switch (op->src[0]->type) {
                    case GGML_TYPE_F16:
                    case GGML_TYPE_F32:
                    case GGML_TYPE_Q4_0:
                    case GGML_TYPE_Q4_1:
                    case GGML_TYPE_Q5_0:
                    case GGML_TYPE_Q5_1:
                    case GGML_TYPE_Q8_0:
                    case GGML_TYPE_Q6_K:
                        return true;
                    default:
                        return false;
                }
            }
        case GGML_OP_SET:
            return (op->type == GGML_TYPE_F32) && (op->src[0] && op->src[1]) && (op->src[0]->type == GGML_TYPE_F32) &&
                   (op->src[1]->type == GGML_TYPE_F32);
        case GGML_OP_SET_ROWS:
            {
                return ((op->type == GGML_TYPE_F32 || op->type == GGML_TYPE_F16 || op->type == GGML_TYPE_BF16 ||
                         op->type == GGML_TYPE_F8_E4M3 ||  // FP8 KV cache support
                         op->type == GGML_TYPE_Q8_0 || op->type == GGML_TYPE_Q5_1 || op->type == GGML_TYPE_Q5_0 ||
                         op->type == GGML_TYPE_Q4_1 || op->type == GGML_TYPE_Q4_0 || op->type == GGML_TYPE_IQ4_NL) &&
                        (op->src[1]->type == GGML_TYPE_I64 || op->src[1]->type == GGML_TYPE_I32));
            }
            break;
        case GGML_OP_SET_ROWS_PAGED:
            {
                // Paged attention KV write with type conversion support
                // src[0] = source data, src[1] = indices, src[2] = block_table, src[3] = dst_orig
                if (op->src[0] == nullptr || op->src[1] == nullptr || op->src[2] == nullptr || op->src[3] == nullptr) {
                    return false;
                }
                // Source type must be F32 or F16
                const bool src_type_ok     = (op->src[0]->type == GGML_TYPE_F32 || op->src[0]->type == GGML_TYPE_F16);
                // Destination type (op->type which is view of dst_orig) must be F32 or F16
                const bool dst_type_ok     = (op->type == GGML_TYPE_F32 || op->type == GGML_TYPE_F16);
                // Indices can be I32 or I64
                const bool indices_type_ok = (op->src[1]->type == GGML_TYPE_I32 || op->src[1]->type == GGML_TYPE_I64);
                // Block table must be I32
                const bool block_table_type_ok = (op->src[2]->type == GGML_TYPE_I32);
                return src_type_ok && dst_type_ok && indices_type_ok && block_table_type_ok;
            }
            break;
        case GGML_OP_CPY:
            {
                ggml_type src0_type = op->src[0]->type;
                ggml_type src1_type = op->src[1]->type;
                if (src0_type == src1_type && (ggml_is_contiguous(op->src[0]) && ggml_is_contiguous(op->src[1])) &&
                    src0_type != GGML_TYPE_BF16) {
                    return true;
                }
                if (src0_type == GGML_TYPE_F32 && src1_type == GGML_TYPE_F32) {
                    return true;
                }
                if (src0_type == GGML_TYPE_F32 && src1_type == GGML_TYPE_F16) {
                    return true;
                }
                if (src0_type == GGML_TYPE_F32 && src1_type == GGML_TYPE_Q8_0) {
                    return true;
                }
                if (src0_type == GGML_TYPE_F32 && src1_type == GGML_TYPE_Q4_0) {
                    return true;
                }
                if (src0_type == GGML_TYPE_F32 && src1_type == GGML_TYPE_Q4_1) {
                    return true;
                }
                if (src0_type == GGML_TYPE_F16 && src1_type == GGML_TYPE_F16) {
                    return true;
                }
                if (src0_type == GGML_TYPE_F16 && src1_type == GGML_TYPE_F32) {
                    return true;
                }
                if (src0_type == GGML_TYPE_Q8_0 && src1_type == GGML_TYPE_F32) {
                    return true;
                }
                if (src0_type == GGML_TYPE_Q4_0 && src1_type == GGML_TYPE_F32) {
                    return true;
                }
                if (src0_type == GGML_TYPE_Q4_1 && src1_type == GGML_TYPE_F32) {
                    return true;
                }
                if (src0_type == GGML_TYPE_F32 && src1_type == GGML_TYPE_Q5_0) {
                    return true;
                }
                if (src0_type == GGML_TYPE_Q5_0 && src1_type == GGML_TYPE_F32) {
                    return true;
                }
                if (src0_type == GGML_TYPE_F32 && src1_type == GGML_TYPE_Q5_1) {
                    return true;
                }
                if (src0_type == GGML_TYPE_Q5_1 && src1_type == GGML_TYPE_F32) {
                    return true;
                }
                if (src0_type == GGML_TYPE_F32 && src1_type == GGML_TYPE_IQ4_NL) {
                    return true;
                }
                if (src0_type == GGML_TYPE_Q8_0 && src1_type == GGML_TYPE_Q8_0) {
                    return true;
                }
                if (src0_type == GGML_TYPE_Q5_0 && src1_type == GGML_TYPE_Q5_0) {
                    return true;
                }
                if (src0_type == GGML_TYPE_Q5_1 && src1_type == GGML_TYPE_Q5_1) {
                    return true;
                }
                if (src0_type == GGML_TYPE_Q4_0 && src1_type == GGML_TYPE_Q4_0) {
                    return true;
                }
                if (src0_type == GGML_TYPE_Q4_1 && src1_type == GGML_TYPE_Q4_1) {
                    return true;
                }
                // F32 <-> I32 conversions
                if (src0_type == GGML_TYPE_F32 && src1_type == GGML_TYPE_I32) {
                    return true;
                }
                if (src0_type == GGML_TYPE_I32 && src1_type == GGML_TYPE_F32) {
                    return true;
                }
                // BF16 conversions
                if (src0_type == GGML_TYPE_F32 && src1_type == GGML_TYPE_BF16) {
                    return true;
                }
                if (src0_type == GGML_TYPE_F16 && src1_type == GGML_TYPE_BF16) {
                    return true;
                }
                if (src0_type == GGML_TYPE_BF16 && src1_type == GGML_TYPE_BF16) {
                    return true;
                }
                if (src0_type == GGML_TYPE_BF16 && src1_type == GGML_TYPE_F16) {
                    return true;
                }
                if (src0_type == GGML_TYPE_BF16 && src1_type == GGML_TYPE_F32) {
                    return true;
                }
                return false;
            }
        case GGML_OP_REPEAT_BACK:
            {
                ggml_type src0_type = op->src[0]->type;
                return src0_type == GGML_TYPE_F32;
            }
        case GGML_OP_CONCAT:
        case GGML_OP_DUP:
        case GGML_OP_ARGMAX:
        case GGML_OP_NONE:
        case GGML_OP_RESHAPE:
        case GGML_OP_VIEW:
        case GGML_OP_PERMUTE:
        case GGML_OP_TRANSPOSE:
        case GGML_OP_ADD:
        case GGML_OP_ADD1:
        case GGML_OP_ADD_ID:
        case GGML_OP_SUB:
        case GGML_OP_COUNT_EQUAL:
        case GGML_OP_MUL:
        case GGML_OP_DIV:
        case GGML_OP_REPEAT:
            return true;
        case GGML_OP_PAD_REFLECT_1D:
            return ggml_is_contiguous(op->src[0]) && op->type == GGML_TYPE_F32 && op->src[0]->type == GGML_TYPE_F32;
        case GGML_OP_SQR:
        case GGML_OP_SQRT:
        case GGML_OP_SIN:
        case GGML_OP_COS:
        case GGML_OP_CLAMP:
        case GGML_OP_LOG:
#if defined(GGML_SYCL_F16)
            return ((op->type == GGML_TYPE_F32 || op->type == GGML_SYCL_F16) &&
                    (op->src[0]->type == GGML_TYPE_F32 || op->src[0]->type == GGML_SYCL_F16) &&
                    (op->type == op->src[0]->type));
#else
            return (op->type == GGML_TYPE_F32 && op->src[0]->type == GGML_TYPE_F32) && (op->type == op->src[0]->type);
#endif
        case GGML_OP_NORM:
            return true;
        case GGML_OP_L2_NORM:
        case GGML_OP_GROUP_NORM:
            return ggml_is_contiguous(op->src[0]);
        case GGML_OP_RMS_NORM:
            return ((op->src[0]->ne[0] % WARP_SIZE) == 0);
        case GGML_OP_RMS_NORM_BACK:
            return ((op->src[0]->ne[0] % WARP_SIZE) == 0);

        case GGML_OP_SCALE:
            return true;

        case GGML_OP_CONT:
            return op->src[0]->type != GGML_TYPE_BF16;
        case GGML_OP_DIAG_MASK_INF:
            return true;
        case GGML_OP_SOFT_MAX:
            return true;
        case GGML_OP_SOFT_MAX_BACK:

            {
                float max_bias = 0.0f;
                memcpy(&max_bias, (const float *) op->op_params + 1, sizeof(float));
                return max_bias == 0.0f;
            }
        case GGML_OP_ROPE:
        case GGML_OP_IM2COL:
            return true;
        case GGML_OP_UPSCALE:
            return op->src[0]->type == GGML_TYPE_F32 && op->op_params[0] == GGML_SCALE_MODE_NEAREST &&
                   !(op->op_params[0] & GGML_SCALE_FLAG_ANTIALIAS);
        case GGML_OP_SUM:
        case GGML_OP_SUM_ROWS:

        case GGML_OP_MEAN:
            return ggml_is_contiguous(op->src[0]);
        case GGML_OP_ARGSORT:
            return op->src[0]->ne[0] * sizeof(int) <= ggml_sycl_info().devices[device].smpbo;

        case GGML_OP_TOP_K:
            // TOP_K uses shared memory: BLOCK_SIZE * MAX_K * (sizeof(float) + sizeof(int))
            // = 256 * 32 * 8 = 64KB (well within typical 128KB SLM limit)
            return ggml_is_contiguous(op->src[0]) && op->src[0]->type == GGML_TYPE_F32 && op->ne[0] <= SYCL_TOPK_MAX_K;
        case GGML_OP_POOL_2D:

        case GGML_OP_ACC:
            return true;

        case GGML_OP_PAD:
            // TODO: add circular padding support for syscl, see https://github.com/ggml-org/llama.cpp/pull/16985
            if (ggml_get_op_params_i32(op, 8) != 0) {
                return false;
            }
            return ggml_is_contiguous(op->src[0]);
        case GGML_OP_LEAKY_RELU:
#if defined(GGML_SYCL_F16)
            return ((op->type == GGML_TYPE_F32 || op->type == GGML_TYPE_F16) && (op->src[0]->type == op->type));
#else
            return (op->type == GGML_TYPE_F32 && op->src[0]->type == GGML_TYPE_F32);
#endif
        case GGML_OP_TIMESTEP_EMBEDDING:

        case GGML_OP_RWKV_WKV6:
        case GGML_OP_RWKV_WKV7:
        case GGML_OP_GATED_LINEAR_ATTN:
            return true;
        case GGML_OP_SSM_CONV:
            return op->type == GGML_TYPE_F32 && op->src[0]->type == GGML_TYPE_F32 && op->src[1]->type == GGML_TYPE_F32;
        case GGML_OP_ROLL:
            return op->type == GGML_TYPE_F32;

        case GGML_OP_ARANGE:
            return op->type == GGML_TYPE_F32;
        case GGML_OP_FLASH_ATTN_EXT:
            return ggml_sycl_flash_attn_ext_supported(op);
        case GGML_OP_ALL_REDUCE_SUM:
            // All-reduce sum is supported for F32 and F16
            return op->type == GGML_TYPE_F32 || op->type == GGML_TYPE_F16;
        default:
            return false;
    }

    GGML_UNUSED(dev);
}

static bool ggml_backend_sycl_device_supports_buft(ggml_backend_dev_t dev, ggml_backend_buffer_type_t buft) {
    // Regular SYCL buffer type
    if (buft->iface.get_name == ggml_backend_sycl_buffer_type_get_name) {
        ggml_backend_sycl_buffer_type_context * buft_ctx = (ggml_backend_sycl_buffer_type_context *) buft->context;

        ggml_backend_sycl_device_context * sycl_ctx = (ggml_backend_sycl_device_context *) dev->context;
        return buft_ctx->device == sycl_ctx->device;
    }
    // TP buffer type - check if the device is one of the TP devices

    if (buft->iface.get_name == ggml_backend_sycl_tp_buffer_type_name) {
        ggml_backend_sycl_tp_buffer_type_context * buft_ctx =
            (ggml_backend_sycl_tp_buffer_type_context *) buft->context;
        ggml_backend_sycl_device_context * sycl_ctx = (ggml_backend_sycl_device_context *) dev->context;
        // Check if this device is in the list of TP devices

        for (int dev_id : buft_ctx->devices) {
            if (dev_id == sycl_ctx->device) {
                return true;
            }
        }
        return false;
    }
    // Tiered KV buffer type - check device match
    if (buft->iface.get_name == tiered_kv_buft_get_name) {
        auto *                             buft_ctx = static_cast<tiered_kv_buft_context *>(buft->context);
        ggml_backend_sycl_device_context * sycl_ctx = (ggml_backend_sycl_device_context *) dev->context;
        return buft_ctx->device == sycl_ctx->device;
    }

    // Host buffer type (CPU interface) - all SYCL devices can access host memory
    if (buft->iface.get_name == ggml_backend_sycl_host_buffer_type_name) {
        return true;
    }

    // Host compute buffer type (SYCL interface) - all SYCL devices can access host memory
    // This is used for TP compute buffers to allow cross-device data sharing
    if (buft->iface.get_name == ggml_backend_sycl_host_compute_buffer_type_name) {
        return true;
    }

    // CPU-offload compute buffer type - host-pinned with is_host=true
    if (buft->iface.get_name == ggml_backend_sycl_cpu_offload_compute_buffer_type_name) {
        return true;
    }

    return false;
}

static int64_t get_op_batch_size(const ggml_tensor * op) {
    switch (op->op) {
        case GGML_OP_GET_ROWS:

            return 0;
        case GGML_OP_MUL_MAT:
            return op->ne[1];

        case GGML_OP_MUL_MAT_ID:
        case GGML_OP_ROPE:
            return op->ne[2];
        default:
            return ggml_nrows(op);
    }
}

static int ggml_sycl_extract_planned_layer_id(const ggml_tensor * op) {
    if (!op) {
        return -1;
    }

    if (op->name[0] != '\0') {
        const int layer_id = ggml_sycl::extract_layer_id(op->name);
        if (layer_id >= 0) {
            return layer_id;
        }
    }

    for (int s = 0; s < GGML_MAX_SRC && op->src[s]; ++s) {
        if (op->src[s]->name[0] == '\0') {
            continue;
        }
        const int layer_id = ggml_sycl::extract_layer_id(op->src[s]->name);
        if (layer_id >= 0) {
            return layer_id;
        }
    }

    return -1;
}

static bool ggml_sycl_weight_executes_on_host(const ggml_tensor * tensor, int device);

static bool ggml_sycl_tensor_has_moe_routing_hint(const ggml_tensor * tensor, int depth = 0) {
    if (!tensor || depth > 2) {
        return false;
    }

    if (tensor->name[0] != '\0') {
        if (infer_tensor_usage(tensor->name) == tensor_usage::MOE_INTERMEDIATE) {
            return true;
        }
        if (strstr(tensor->name, "topk") != nullptr || strstr(tensor->name, "router") != nullptr ||
            strstr(tensor->name, "ffn_inp") != nullptr || strstr(tensor->name, "attn_post_norm") != nullptr ||
            strstr(tensor->name, "ffn_gate_inp") != nullptr || strstr(tensor->name, "ffn_moe_logits") != nullptr ||
            strstr(tensor->name, "ffn_moe_probs") != nullptr || strstr(tensor->name, "ffn_moe_weights") != nullptr) {
            return true;
        }
    }

    for (int s = 0; s < GGML_MAX_SRC && tensor->src[s] != nullptr; ++s) {
        if (ggml_sycl_tensor_has_moe_routing_hint(tensor->src[s], depth + 1)) {
            return true;
        }
    }

    return false;
}

static bool ggml_sycl_op_is_moe_routing_subgraph(const ggml_tensor * op) {
    if (!op) {
        return false;
    }

    switch (op->op) {
        case GGML_OP_MUL_MAT:
        case GGML_OP_ADD:
        case GGML_OP_ARGSORT:
        case GGML_OP_TOP_K:
        case GGML_OP_GET_ROWS:
        case GGML_OP_SOFT_MAX:
            return ggml_sycl_tensor_has_moe_routing_hint(op);
        default:
            return false;
    }
}

// Removed: ggml_sycl_tensor_has_host_gate_activation_hint()
// The old implementation used hard-coded tensor name checks (strstr("ffn_inp"))
// to guess if an op was part of a MoE gate activation chain. This was fragile
// and incorrectly matched dense models like Mistral 7B, routing their FFN norm
// MUL ops to CPU with D2H/H2D staging — a 17% PP regression.
//
// Replaced by ggml_sycl_tensor_depends_on_planned_host_weight() which queries
// the placement planner (the actual source of truth for data residency).

static bool ggml_sycl_layer_has_host_gate_weight(int layer_id, int device) {
    if (layer_id < 0 || device < 0) {
        return false;
    }

    auto * cache = ggml_sycl::get_unified_cache_for_device(device);
    if (!cache || !cache->has_placement_plan()) {
        return false;
    }

    const auto & plan             = cache->get_placement_plan();
    const auto   gate_weight_name = std::string("blk.") + std::to_string(layer_id) + ".ffn_gate_inp.weight";

    if (!plan.has_dense_entry(gate_weight_name)) {
        return false;
    }

    return !plan.is_on_device(gate_weight_name, device);
}

static bool ggml_sycl_op_is_host_gate_activation_chain(const ggml_tensor * op, int device) {
    if (!op || device < 0) {
        return false;
    }

    // Only consider lightweight activation ops (ADD, MUL, NORM, RMS_NORM)
    // that sit between host-dispatched MUL_MATs.  These should run on CPU
    // to avoid unnecessary D2H→H2D roundtrips when their source data is
    // already host-resident from a preceding host-dispatched MUL_MAT.
    //
    // Uses the placement planner as the source of truth for data residency
    // instead of fragile tensor name matching (the old strstr("ffn_inp")
    // approach incorrectly matched dense models).
    switch (op->op) {
        case GGML_OP_ADD:
        case GGML_OP_MUL:
        case GGML_OP_NORM:
        case GGML_OP_RMS_NORM:
            return ggml_sycl_tensor_depends_on_planned_host_weight(op, device, 0);
        default:
            return false;
    }
}

static bool ggml_sycl_tensor_depends_on_planned_host_weight(const ggml_tensor * tensor, int device, int depth = 0) {
    // Memoize visited tensors to avoid redundant graph traversals.
    // Cleared at the top-level call (depth == 0) so each per-op query gets a
    // fresh set without allocating/freeing across the per-graph call sequence.
    thread_local std::unordered_set<const ggml_tensor *> visited;
    if (depth == 0) {
        visited.clear();
    }

    if (!tensor || device < 0 || depth > 8) {
        return false;
    }

    if (visited.count(tensor)) {
        return false;
    }
    visited.insert(tensor);

    if ((tensor->op == GGML_OP_MUL_MAT || tensor->op == GGML_OP_MUL_MAT_ID) && tensor->src[0] != nullptr &&
        ggml_sycl_weight_executes_on_host(tensor->src[0], device)) {
        return true;
    }

    for (int s = 0; s < GGML_MAX_SRC && tensor->src[s] != nullptr; ++s) {
        if (ggml_sycl_tensor_depends_on_planned_host_weight(tensor->src[s], device, depth + 1)) {
            return true;
        }
    }

    return false;
}

static bool ggml_sycl_moe_tensor_all_experts_on_host(const ggml_tensor * tensor, int device) {
    if (!tensor || device < 0 || tensor->name[0] == '\0' ||
        ggml_sycl_get_tensor_usage(tensor) != tensor_usage::MOE_EXPERT_WEIGHT) {
        return false;
    }

    auto * cache = ggml_sycl::get_unified_cache_for_device(device);
    if (!cache || !cache->has_placement_plan()) {
        return false;
    }

    const auto &  plan      = cache->get_placement_plan();
    const int64_t n_experts = tensor->ne[2] > 0 ? tensor->ne[2] : 1;
    for (int64_t expert_id = 0; expert_id < n_experts; ++expert_id) {
        if (plan.expert_on_device(tensor->name, static_cast<int>(expert_id), device)) {
            return false;
        }
    }

    return true;
}

static bool ggml_sycl_weight_executes_on_host(const ggml_tensor * tensor, int device) {
    if (!tensor || device < 0 || !ggml_sycl_tensor_is_weight(tensor)) {
        return false;
    }

    if (ggml_sycl_weight_is_planned_on_host(tensor, device)) {
        return true;
    }

    if (ggml_sycl_moe_tensor_all_experts_on_host(tensor, device)) {
        return true;
    }

    if (ggml_sycl_planner_authoritative_residency_active(device)) {
        return false;
    }

    if (ggml_sycl_get_tensor_usage(tensor) == tensor_usage::MOE_EXPERT_WEIGHT) {
        return false;
    }

    auto resolved = ggml_sycl_resolve(tensor, device);
    return resolved.ptr != nullptr && !resolved.on_device;
}

static bool ggml_sycl_layer_plan_applies_to_op(const ggml_tensor * op) {
    if (!op) {
        return false;
    }

    switch (op->op) {
        case GGML_OP_NONE:
        case GGML_OP_VIEW:
        case GGML_OP_RESHAPE:
        case GGML_OP_PERMUTE:
        case GGML_OP_TRANSPOSE:
        case GGML_OP_CONT:
        case GGML_OP_CPY:
        case GGML_OP_SET_ROWS:
        case GGML_OP_SET_ROWS_PAGED:
            return false;
        default:
            return true;
    }
}

static bool ggml_sycl_op_is_planned_on_host(const ggml_tensor * op, int device) {
    if (!op || device < 0) {
        return false;
    }

    // llama.cpp-n04bq: trace layer-plan classification for blk.16 tensors.
    auto n04bq_tr_final = [&](bool ret, const char * reason) -> bool {
        if (n04bq_probe_enabled() && op) {
            const ggml_tensor * s0 = op->src ? op->src[0] : nullptr;
            const bool blk16_match =
                (op->name && (strstr(op->name, "-16") || strstr(op->name, "blk.16."))) ||
                (s0 && s0->name && strstr(s0->name, "blk.16."));
            if (blk16_match) {
                static std::mutex mtx;
                static std::unordered_set<std::string> seen;
                std::string key = std::string(op->name ? op->name : "(nn)") + "|" +
                                  ggml_op_name(op->op) + "|" + reason;
                std::lock_guard<std::mutex> lk(mtx);
                if (seen.insert(key).second) {
                    fprintf(stderr, "[N04BQ] planned_on_host op_name=%s op=%s result=%d reason=%s src0=%s\n",
                            op->name ? op->name : "(null)",
                            ggml_op_name(op->op), ret ? 1 : 0, reason,
                            s0 && s0->name ? s0->name : "(null)");
                }
            }
        }
        return ret;
    };

    if ((op->op == GGML_OP_MUL_MAT || op->op == GGML_OP_MUL_MAT_ID) && op->src[0] != nullptr &&
        ggml_sycl_weight_executes_on_host(op->src[0], device)) {
        return n04bq_tr_final(true, "weight_executes_on_host");
    }

    if (ggml_sycl_layer_plan_applies_to_op(op)) {
        for (int s = 0; s < GGML_MAX_SRC && op->src[s] != nullptr; ++s) {
            if (ggml_sycl_weight_executes_on_host(op->src[s], device)) {
                return n04bq_tr_final(true, "layer_plan_src_host");
            }
        }
    }

    if ((op->op == GGML_OP_ADD_ID || op->op == GGML_OP_GLU) &&
        ggml_sycl_tensor_depends_on_planned_host_weight(op, device)) {
        return n04bq_tr_final(true, "addid_glu_depends_host");
    }

    auto * cache = ggml_sycl::get_unified_cache_for_device(device);
    if (!cache || !cache->has_placement_plan()) {
        return n04bq_tr_final(false, "no_plan");
    }

    if (!ggml_sycl_layer_plan_applies_to_op(op)) {
        return n04bq_tr_final(false, "layer_plan_not_applicable");
    }

    const int layer_id = ggml_sycl_extract_planned_layer_id(op);
    if (layer_id < 0) {
        return n04bq_tr_final(false, "no_layer_id");
    }

    const int layer_dev = cache->get_placement_plan().get_layer_device(layer_id);
    const bool ret = layer_dev < 0;
    return n04bq_tr_final(ret, ret ? "layer_device<0" : "layer_device>=0");
}

static bool ggml_backend_sycl_device_offload_op(ggml_backend_dev_t dev, const ggml_tensor * op) {
    auto sycl_dev_index = [](ggml_backend_dev_t backend_dev) -> int {
        auto * reg = ggml_backend_sycl_reg();
        if (!reg || !backend_dev) {
            return -1;
        }
        for (int i = 0; i < ggml_backend_sycl_get_device_count(); ++i) {
            if (ggml_backend_reg_dev_get(reg, i) == backend_dev) {
                return i;
            }
        }
        return -1;
    };

    const int device_index = sycl_dev_index(dev);

    if (device_index >= 0 && ggml_sycl_planner_authoritative_residency_active(device_index) &&
        (ggml_sycl_op_is_moe_routing_subgraph(op) || ggml_sycl_op_is_host_gate_activation_chain(op, device_index))) {
        GGML_SYCL_DEBUG("[SYCL-OFFLOAD] planner keeps MoE host-path op %s on CPU backend (op=%s)\n",
                        op && op->name[0] != '\0' ? op->name : "(unnamed)", ggml_op_name(op->op));
        return false;
    }

    if (device_index >= 0 && ggml_sycl_op_is_planned_on_host(op, device_index)) {
        GGML_SYCL_DEBUG("[SYCL-OFFLOAD] planner keeps %s on CPU backend (op=%s layer=%d)\n",
                        op && op->name[0] != '\0' ? op->name : "(unnamed)", ggml_op_name(op->op),
                        ggml_sycl_extract_planned_layer_id(op));
        return false;
    }

    if (!(device_index >= 0 && ggml_sycl_planner_authoritative_residency_active(device_index))) {
        // Legacy streaming / host-weight mode keeps the full subgraph on GPU.
        static bool weight_streaming = (std::getenv("GGML_SYCL_WEIGHT_STREAMING") != nullptr);
        if (weight_streaming || ggml_backend_sycl_weights_evictable()) {
            return true;
        }
    }
    // For MUL_MAT_ID with types that lack CPU vec_dot support, always offload.
    // Types with vec_dot (Q4_0, Q8_0, MXFP4, etc.) can fall through to hybrid
    // dispatch which routes experts to CPU when weights are host-resident.
    if (op->op == GGML_OP_MUL_MAT_ID && op->src[0]) {
        const auto * cpu_traits = ggml_get_type_traits_cpu(op->src[0]->type);
        if (!cpu_traits || !cpu_traits->vec_dot) {
            return true;
        }
    }
    // ADD_ID is used for MoE output scatter - must match MUL_MAT_ID's backend
    // If we offload MUL_MAT_ID, we must also offload ADD_ID to avoid

    // tensor buffer mismatches between SYCL and CPU backends
    if (op->op == GGML_OP_ADD_ID) {
        return true;
    }

    const int min_batch_size = 32;
    return get_op_batch_size(op) >= min_batch_size;
    GGML_UNUSED(dev);
}

static ggml_backend_event_t ggml_backend_sycl_device_event_new(ggml_backend_dev_t dev) {
#ifdef GGML_SYCL_NO_PEER_COPY
    return nullptr;
#else
    sycl::event * event_ptr = new sycl::event();

    return new ggml_backend_event{
        /* .device = */ dev,

        /* .context = */ event_ptr,
    };
#endif
}

static void ggml_backend_sycl_device_event_free(ggml_backend_dev_t dev, ggml_backend_event_t event) try {
    GGML_UNUSED(dev);

    if (event == nullptr) {
        return;
    }
    if (event->context != nullptr) {
        sycl::event * sycl_event = static_cast<sycl::event *>(event->context);
        delete sycl_event;

        event->context = nullptr;
    }
    delete event;
} catch (const sycl::exception & exc) {
    std::cerr << exc.what() << "Exception caught at file:" << __FILE__ << ", line:" << __LINE__ << std::endl;
    std::exit(1);
}

static void ggml_backend_sycl_device_event_synchronize(ggml_backend_dev_t dev, ggml_backend_event_t event) try {
    GGML_UNUSED(dev);
    GGML_SYCL_DEBUG("[SYCL] call %s\n", __func__);

    sycl::event * sycl_event = static_cast<sycl::event *>(event->context);
    SYCL_CHECK(CHECK_TRY_ERROR(sycl_event->wait()));
} catch (const sycl::exception & exc) {
    std::cerr << exc.what() << "Exception caught at file:" << __FILE__ << ", line:" << __LINE__ << std::endl;
    std::exit(1);
}
static const ggml_backend_device_i ggml_backend_sycl_device_interface = {
    /* .get_name                = */ ggml_backend_sycl_device_get_name,
    /* .get_description         = */ ggml_backend_sycl_device_get_description,

    /* .get_memory              = */ ggml_backend_sycl_device_get_memory,

    /* .get_type                = */ ggml_backend_sycl_device_get_type,
    /* .get_props               = */ ggml_backend_sycl_device_get_props,

    /* .init_backend            = */ ggml_backend_sycl_device_init,

    /* .get_buffer_type         = */ ggml_backend_sycl_device_get_buffer_type,
    /* .get_host_buffer_type    = */ ggml_backend_sycl_device_get_host_buffer_type,
    /* .buffer_from_host_ptr    = */ ggml_backend_sycl_device_buffer_from_host_ptr,
    /* .supports_op             = */ ggml_backend_sycl_device_supports_op,
    /* .supports_buft           = */ ggml_backend_sycl_device_supports_buft,
    /* .offload_op              = */ ggml_backend_sycl_device_offload_op,

    /* .event_new               = */ ggml_backend_sycl_device_event_new,
    /* .event_free              = */ ggml_backend_sycl_device_event_free,
    /* .event_synchronize       = */ ggml_backend_sycl_device_event_synchronize,
};

// backend reg
struct ggml_backend_sycl_reg_context {
    std::vector<ggml_backend_dev_t> devices;
};

static const char * ggml_backend_sycl_reg_get_name(ggml_backend_reg_t reg) {
    GGML_UNUSED(reg);
    return GGML_SYCL_NAME;
}

static size_t ggml_backend_sycl_reg_get_device_count(ggml_backend_reg_t reg) {
    ggml_backend_sycl_reg_context * ctx = (ggml_backend_sycl_reg_context *) reg->context;
    return ctx->devices.size();
}

static ggml_backend_dev_t ggml_backend_sycl_reg_get_device(ggml_backend_reg_t reg, size_t index) {
    ggml_backend_sycl_reg_context * ctx = (ggml_backend_sycl_reg_context *) reg->context;
    GGML_ASSERT(index < ctx->devices.size());
    return ctx->devices[index];
}

static void * ggml_backend_sycl_reg_get_proc_address(ggml_backend_reg_t reg, const char * name) {
    GGML_UNUSED(reg);

    if (strcmp(name, "ggml_backend_split_buffer_type") == 0) {
        return (void *) ggml_backend_sycl_split_buffer_type;
    }
    if (strcmp(name, "ggml_backend_tp_buffer_type") == 0) {
        return (void *) ggml_backend_sycl_tp_buffer_type;
    }
    // SYCL doesn't support registering host memory, left here for reference
    // "ggml_backend_register_host_buffer"
    // "ggml_backend_unregister_host_buffer"
    GGML_UNUSED(name);
    return nullptr;
}

static const ggml_backend_reg_i ggml_backend_sycl_reg_interface = {
    /* .get_name          = */ ggml_backend_sycl_reg_get_name,

    /* .get_device_count  = */ ggml_backend_sycl_reg_get_device_count,

    /* .get_device        = */ ggml_backend_sycl_reg_get_device,
    /* .get_proc_address  = */ ggml_backend_sycl_reg_get_proc_address,
};

// backend registry
ggml_backend_reg_t ggml_backend_sycl_reg() {
    static ggml_backend_reg reg;
    static bool             initialized = false;
    {
        static std::mutex mutex;

        std::lock_guard<std::mutex> lock(mutex);
        if (!initialized) {
            ggml_backend_sycl_reg_context * ctx = new ggml_backend_sycl_reg_context;
            for (int i = 0; i < ggml_sycl_info().device_count; i++) {
                ggml_backend_sycl_device_context * dev_ctx = new ggml_backend_sycl_device_context;
                dev_ctx->device                            = i;

                dev_ctx->name = GGML_SYCL_NAME + std::to_string(i);
                ggml_sycl_set_device(i);
                dpct::device_info prop;
                SYCL_CHECK(CHECK_TRY_ERROR(dpct::get_device_info(prop, ggml_sycl_get_device(i))));
                dev_ctx->description = prop.get_name();
                ggml_backend_dev_t dev =
                    new ggml_backend_device{ /* .iface       = */ ggml_backend_sycl_device_interface,

                                             /* .reg         = */ &reg,
                                             /* .context     = */ dev_ctx };
                ctx->devices.push_back(dev);
            }
            reg = ggml_backend_reg{ /* .api_version = */ GGML_BACKEND_API_VERSION,
                                    /* .iface       = */ ggml_backend_sycl_reg_interface,

                                    /* .context     = */ ctx };
        }
        initialized = true;
    }
    return &reg;
}

ggml_backend_t ggml_backend_sycl_init(int device) {
    GGML_SYCL_DEBUG("[SYCL] call ggml_backend_sycl_init\n");
    if (ggml_sycl_alloc_trace_enabled_impl()) {
        ggml_sycl_alloc_trace_init();
    }

    ggml_check_sycl();
    // Watchdog deferred to first graph_compute — model loading (60GB for 120B)
    // can take >60s and doesn't need hang detection.
    check_allow_gpu_index(device);
    ggml_backend_sycl_context * ctx = new ggml_backend_sycl_context(device);
    if (ctx == nullptr) {
        GGML_LOG_ERROR("%s: error: failed to allocate context\n", __func__);
        return nullptr;
    };

    // Initialize L2 prefetch manager for TG optimization (owned by context)
    // Note: Can't use make_unique with custom deleter, use explicit construction
    if (ggml_sycl::is_l2_prefetch_enabled() && ctx->stream()) {
        try {
            ctx->l2_prefetch_manager.reset(new ggml_sycl::L2PrefetchManager(ctx->stream()));
        } catch (const sycl::exception & e) {
            GGML_LOG_ERROR("[L2-PREFETCH] Failed to create manager (SYCL): %s\n", e.what());
        } catch (const std::exception & e) {
            GGML_LOG_ERROR("[L2-PREFETCH] Failed to create manager (std): %s\n", e.what());
        }
    }

    ggml_backend_t sycl_backend =

        new ggml_backend{ /* .guid    = */ ggml_backend_sycl_guid(),
                          /* .iface   = */ ggml_backend_sycl_interface,
                          /* .device  = */ ggml_backend_reg_dev_get(ggml_backend_sycl_reg(), device),
                          /* .context = */ ctx };
    g_sycl_backend_refcount.fetch_add(1, std::memory_order_acq_rel);

    return sycl_backend;
}

// ============================================================================
// Flash Attention seq_ids host pointer support
// ============================================================================
// Thread-local storage for seq_ids host pointers
// These are set by llama layer before graph execution and used by fattn kernel
// The pointers must be valid SYCL_Host buffer memory (USM accessible from GPU)
struct ggml_sycl_seq_ids_cache {
    const int32_t * q_seq_ids = nullptr;

    size_t          q_count    = 0;
    const int32_t * kv_seq_ids = nullptr;
    size_t          kv_count   = 0;
};

static thread_local ggml_sycl_seq_ids_cache g_sycl_seq_ids_cache;

void ggml_backend_sycl_set_seq_ids_host(const int32_t * q_seq_ids,
                                        size_t          q_count,
                                        const int32_t * kv_seq_ids,
                                        size_t          kv_count) {
    g_sycl_seq_ids_cache.q_seq_ids  = q_seq_ids;
    g_sycl_seq_ids_cache.q_count    = q_count;
    g_sycl_seq_ids_cache.kv_seq_ids = kv_seq_ids;
    g_sycl_seq_ids_cache.kv_count   = kv_count;
}

void ggml_backend_sycl_clear_seq_ids_host(void) {
    g_sycl_seq_ids_cache.q_seq_ids  = nullptr;
    g_sycl_seq_ids_cache.q_count    = 0;
    g_sycl_seq_ids_cache.kv_seq_ids = nullptr;
    g_sycl_seq_ids_cache.kv_count   = 0;
}

// Internal getter for fattn.cpp to access the cached host pointers
const int32_t * ggml_sycl_get_seq_ids_host_q(size_t * count) {
    if (count) {
        *count = g_sycl_seq_ids_cache.q_count;
    }
    return g_sycl_seq_ids_cache.q_seq_ids;
}

const int32_t * ggml_sycl_get_seq_ids_host_kv(size_t * count) {
    if (count) {
        *count = g_sycl_seq_ids_cache.kv_count;
    }
    return g_sycl_seq_ids_cache.kv_seq_ids;
}

// ==============================================================================
// Thread-local cache for pending device tokens (multi-step GPU decode)
// ==============================================================================
struct ggml_sycl_device_token_cache {
    void * token_ptr = nullptr;  // Device pointer to token(s)
    size_t n_tokens  = 0;        // Number of tokens
};

static thread_local ggml_sycl_device_token_cache g_sycl_device_token_cache;

void ggml_backend_sycl_set_pending_device_token(void * token_ptr, size_t n_tokens) {
    g_sycl_device_token_cache.token_ptr = token_ptr;
    g_sycl_device_token_cache.n_tokens  = n_tokens;
}

void ggml_backend_sycl_clear_pending_device_token(void) {
    g_sycl_device_token_cache.token_ptr = nullptr;
    g_sycl_device_token_cache.n_tokens  = 0;
}

// Internal getter for llama-graph.cpp to access the pending device token
void * ggml_sycl_get_pending_device_token(size_t * n_tokens) {
    if (n_tokens) {
        *n_tokens = g_sycl_device_token_cache.n_tokens;
    }
    return g_sycl_device_token_cache.token_ptr;
}

// Copy from device memory to host memory (synchronous)
// Used when tokens tensor is on CPU backend but we have device tokens
void ggml_sycl_copy_device_to_host(void * src_device, void * dst_host, size_t bytes) {
    // Use device 0's queue for the copy (the token buffer is on the sampler's device)
    // In multi-step decode, the sampler device is the same as the model device
    auto & q = ggml_sycl_get_device(0).default_queue();
    q.memcpy(dst_host, src_device, bytes).wait();
}
